-- Poems batch 373
INSERT OR IGNORE INTO poems (id,title,author,dynasty,collection,collection_id,rhythmic,tags,excerpt,length,source_path,paragraphs) VALUES
('023e28e0-7ae1-401b-aa69-e1ab62cbc4a9','昨日召卿等自卿私第泛舟經景龍江游擷芳園靈沼聞卿有小詩今俯同其韻賜太師  其二','宋徽宗','宋','宋诗','song-poetry','','[]','登山想見留雲際，賞日還能傍水涯。',32,'全唐诗/poet.song.86000.json','["登山想見留雲際，賞日還能傍水涯。", "對此已多重九興，先輸黄髪賞黄花。"]'),
('ae78c95e-ba52-4fb7-99fd-0e8a3fcb9587','昨日召卿等自卿私第泛舟經景龍江游擷芳園靈沼聞卿有小詩今俯同其韻賜太師  其三','宋徽宗','宋','宋诗','song-poetry','','[]','錦繡煙霄碧玉山，縈紆靜練照晴川。',32,'全唐诗/poet.song.86000.json','["錦繡煙霄碧玉山，縈紆靜練照晴川。", "留連不惜厭厭去，雅興難忘既醉篇。"]'),
('76b97eec-4a06-49bd-9344-bba988004cb0','上清寶籙宮立冬日講經之次有羽鶴數千飛翔空際公卿士庶眾目仰瞻卿時預榮觀作詩紀實來上因俯同其韻賜太師以下','宋徽宗','宋','宋诗','song-poetry','','[]','上清講席鬰蕭臺，俄有青田萬侶來。',64,'全唐诗/poet.song.86000.json','["上清講席鬰蕭臺，俄有青田萬侶來。", "蔽翳晴空疑雪舞，低徊轉影類雲開。", "翻翰清唳遙相續，應瑞疑時尚不回。", "歸美一章歌盛事，喜今重見謫仙才。"]'),
('ad3cbb62-c3e4-4369-8e07-b84e83301a9c','上巳日賜太師','宋徽宗','宋','宋诗','song-poetry','','[]','金明春色正芳妍，修禊佳辰集眾賢。',64,'全唐诗/poet.song.86000.json','["金明春色正芳妍，修禊佳辰集眾賢。", "久矣愆陽罹暵旱，沛然膏雨潤農田。", "乘時剩挾花盈帽，胥樂何辭酒滿船。", "所賴燮調功有自，佇期高廩報豐年。"]'),
('c6e37cf3-ddce-409b-89c8-01bf91bb2f93','宣和元年九月十二日賜宴聯句','宋徽宗','宋','宋诗','song-poetry','','[]','桂子三秋七里香，麥雲九夏兩岐秀。',48,'全唐诗/poet.song.86000.json','["桂子三秋七里香，麥雲九夏兩岐秀。", "雞舌五年千載棗，菊英九日萬齡黄。", "君臣燕衎昇平際，屬句論文樂未央。"]'),
('238b2445-43af-4f48-b48d-cbdd0123106f','宣和己巳冬祀大禮卿以執綏侍玉輅回鑾禮畢以詩來上俯同元韻賜伸仍宣示俅傑','宋徽宗','宋','宋诗','song-poetry','','[]','羽衛森嚴錦繡成，夜寒璧月有餘清。',64,'全唐诗/poet.song.86000.json','["羽衛森嚴錦繡成，夜寒璧月有餘清。", "皇壇奠玉橫參近，柴燎升煙宿霧晴。", "晏粲九天風露迥，雍容群辟珮環聲。", "執綏更喜多儀肅，盛事應傳伯仲榮。"]'),
('5ea99dc4-0dbb-44d0-8890-03a262be83f0','汧州作  其一','宋徽宗','宋','宋诗','song-poetry','','[]','國破山河在，人非殿宇空。',24,'全唐诗/poet.song.86000.json','["國破山河在，人非殿宇空。", "中興何日是，搔首賦車攻。"]'),
('02930143-e5bf-4059-acd1-d1c0048aa9c4','汧州作  其二','宋徽宗','宋','宋诗','song-poetry','','[]','國破山河在，宮庭荆棘春。',24,'全唐诗/poet.song.86000.json','["國破山河在，宮庭荆棘春。", "衣冠今左衽，忍作北朝臣。"]'),
('f321abfc-c6ce-4081-997c-5a475a933a12','汧州作  其三','宋徽宗','宋','宋诗','song-poetry','','[]','投袂汧城北，西風又是秋。',48,'全唐诗/poet.song.86000.json','["投袂汧城北，西風又是秋。", "中原心耿耿，南淚思悠悠。", "嘗膽思賢佐，顒情憶舊游。", "故宮禾黍徧，行役閔宗周。"]'),
('19094d95-4a0e-435e-b200-1b52c76e109d','汧州作  其四','宋徽宗','宋','宋诗','song-poetry','','[]','杳杳神京路八千，宗祊隔越幾經年。',32,'全唐诗/poet.song.86000.json','["杳杳神京路八千，宗祊隔越幾經年。", "衰殘病渴那能久，茹苦窮荒敢怨天。"]'),
('43072d27-ef53-481c-833f-16b93d782ef6','清明日作','宋徽宗','宋','宋诗','song-poetry','','[]','茸母初生忍禁煙，無家對景倍悽然。',32,'全唐诗/poet.song.86000.json','["茸母初生忍禁煙，無家對景倍悽然。", "帝城春色誰爲主，遙指鄉關涕淚漣。"]'),
('b7e1f160-b918-48b6-8374-584259f0353e','元符萬寧宮慶成頌','宋徽宗','宋','宋诗','song-poetry','','[]','句曲之山，有居其顛。',160,'全唐诗/poet.song.86000.json','["句曲之山，有居其顛。", "誰氏之子，象帝之先。", "啟迪後人，淑修其身。", "守靜而篤，是爲葆真。", "在昔元符，作室其下。", "經始勿亟，以遺來者。", "我應受之，嗣紹厥緒。", "我儀圖之，繕此棟宇。", "考彼宮宇，因心而友。", "不日成之，克相其後。", "廼益其名，曰維萬寧。", "書以揭之，用妥明靈。", "道大無方，體用有常。", "以德則帝，以業而王。", "坐進此道，與道無極。", "神之聽之，洽此萬國。"]'),
('97da029c-3ec5-401c-a486-ba5a78310bdb','葆真觀妙沖先生歸山以詩送之','宋徽宗','宋','宋诗','song-poetry','','[]','當年問道屬高人，曾攬霞衣到紫宸。',64,'全唐诗/poet.song.86000.json','["當年問道屬高人，曾攬霞衣到紫宸。", "身是三山雲外侶，心無一點世間塵。", "征鴻望極幽棲遠，駕燕歸飛洞府新。", "多謝爲傳心法妙，此真真外更無真。"]'),
('2e1807ad-a304-49c4-90aa-7b7899afc287','在北題壁','宋徽宗','宋','宋诗','song-poetry','','[]','徹夜西風撼破扉，蕭條孤館一燈微。',32,'全唐诗/poet.song.86000.json','["徹夜西風撼破扉，蕭條孤館一燈微。", "家山回首三千里，目斷天南無雁飛。"]'),
('8048134c-3127-43df-b4c1-766e465e7a3c','題古村圖','宋徽宗','宋','宋诗','song-poetry','','[]','深村竹樹不知春，遠水殘霞接斷津。',32,'全唐诗/poet.song.86000.json','["深村竹樹不知春，遠水殘霞接斷津。", "野客衣冠渾懶散，相逢疑是避秦人。"]'),
('df933b66-4a8f-43c8-84fa-af8038e9c185','題院畫冊 修竹士女圖','宋徽宗','宋','宋诗','song-poetry','','[]','瑤臺無信託青鸞，一寸芳心思萬端。',32,'全唐诗/poet.song.86000.json','["瑤臺無信託青鸞，一寸芳心思萬端。", "莫向東風倚修竹，翠衫經得幾多寒。"]'),
('2afdb5f6-2538-457a-a8b4-716815af1707','題院畫冊 荷花士女圖','宋徽宗','宋','宋诗','song-poetry','','[]','消受南薰一味涼，藕絲新織舞裙長。',32,'全唐诗/poet.song.86000.json','["消受南薰一味涼，藕絲新織舞裙長。", "臨池試展凌波步，只恐紅蓮妬艷粧。"]'),
('6aabe076-e85e-483b-9eb6-ef4393306f4f','題院畫冊 芭蕉士女圖','宋徽宗','宋','宋诗','song-poetry','','[]','羅襪生香踏軟沙，釵橫玉燕鬢鬆鴉。',32,'全唐诗/poet.song.86000.json','["羅襪生香踏軟沙，釵橫玉燕鬢鬆鴉。", "春心正是芭蕉葉，羞見宜男並蒂花。"]'),
('7906fe34-96c4-456d-9c43-3b2317dcd1c8','題院畫冊 滌硯士女圖','宋徽宗','宋','宋诗','song-poetry','','[]','軟繡屏風小象牀，細風亭館玉肌涼。',32,'全唐诗/poet.song.86000.json','["軟繡屏風小象牀，細風亭館玉肌涼。", "含情學寫鴛鴦字，墨洗蕉花露水香。"]'),
('c60e15a8-0a3b-49f0-b168-1a1550f164fc','題院畫冊 團扇士女圖','宋徽宗','宋','宋诗','song-poetry','','[]','濃黛消香澹兩蛾，花陰試步學凌波。',32,'全唐诗/poet.song.86000.json','["濃黛消香澹兩蛾，花陰試步學凌波。", "專房自得傾城色，不怕涼風到扇羅。"]'),
('4fd7f0b1-4905-4b1f-922f-59c3cbdd52bb','海棠通花鳳','宋徽宗','宋','宋诗','song-poetry','','[]','錦棠天與麗，映日特妖嬈。',24,'全唐诗/poet.song.86000.json','["錦棠天與麗，映日特妖嬈。", "五色絢儀鳳，真堪上翠翹。"]'),
('7ca2c574-59e9-4a1b-b245-36d61fc946c2','杏花鸚鵡','宋徽宗','宋','宋诗','song-poetry','','[]','並亞隴雲飛，穩巢文杏枝。',24,'全唐诗/poet.song.86000.json','["並亞隴雲飛，穩巢文杏枝。", "高棲良自得，蜂蝶莫相疑。"]'),
('34755e8e-a0b4-4c6d-badd-17e899993763','千葉碧桃蘋茄','宋徽宗','宋','宋诗','song-poetry','','[]','太平蜀雀異，仍映碧桃間。',24,'全唐诗/poet.song.86000.json','["太平蜀雀異，仍映碧桃間。", "一秀三千歲，高枝永共攀。"]'),
('affeabe4-3d56-4161-902e-7af09000e8cf','聚八仙倒掛兒','宋徽宗','宋','宋诗','song-poetry','','[]','垂身如逮下，名冠八仙中。',24,'全唐诗/poet.song.86000.json','["垂身如逮下，名冠八仙中。", "最是天真處，櫻桃一點紅。"]'),
('b6e78f61-4b65-43eb-8350-1095804c7c62','桃竹黄鶯','宋徽宗','宋','宋诗','song-poetry','','[]','出谷傳聲美，遷喬立志高。',24,'全唐诗/poet.song.86000.json','["出谷傳聲美，遷喬立志高。", "故教桃竹映，不使近蓬蒿。"]'),
('e96d5685-fb75-4d3b-be51-b62722ee704e','金林檎游春鶯','宋徽宗','宋','宋诗','song-poetry','','[]','佳名何拔萃，美譽占遊春。',24,'全唐诗/poet.song.86000.json','["佳名何拔萃，美譽占遊春。", "三月來禽媚，嬉娛異眾倫。"]'),
('8e372ab4-0f19-4960-b27e-51df68aa2f00','香梅山白頭','宋徽宗','宋','宋诗','song-poetry','','[]','山禽矜逸態，梅粉弄輕柔。',24,'全唐诗/poet.song.86000.json','["山禽矜逸態，梅粉弄輕柔。", "已有丹青約，千秋指白頭。"]'),
('7a1d7ad8-4b99-4476-a20f-0149b5ed6818','趙昌江梅山茶','宋徽宗','宋','宋诗','song-poetry','','[]','趙昌下筆摘韶光，一軸黄金滿斛量。',32,'全唐诗/poet.song.86000.json','["趙昌下筆摘韶光，一軸黄金滿斛量。", "借我圭田三百畝，真須買取作花王。"]'),
('16015568-c986-49dd-95ac-138c65077dd2','題梨花圖','宋徽宗','宋','宋诗','song-poetry','','[]','樓臺影裏和風煖，絃管聲中瑞日長。',32,'全唐诗/poet.song.86000.json','["樓臺影裏和風煖，絃管聲中瑞日長。", "從聽嬌鸚說來路，莫教蜂蝶損濃芳。"]'),
('ff336380-7c88-44ad-8392-c0b3b74d7d3c','題唐十八學士圖二首  其一','宋徽宗','宋','宋诗','song-poetry','','[]','有唐至治詠康哉，闢館登延經濟才。',32,'全唐诗/poet.song.86000.json','["有唐至治詠康哉，闢館登延經濟才。", "廱泮育賢今日盛，彙征無復隱蒿萊。"]'),
('ad6fc58e-dce7-40f8-9bcf-12a8bc7a76b9','題唐十八學士圖二首  其二','宋徽宗','宋','宋诗','song-poetry','','[]','儒林華國古今同，吟咏飛毫醒醉中。',32,'全唐诗/poet.song.86000.json','["儒林華國古今同，吟咏飛毫醒醉中。", "多士作新知入彀，畫圖猶喜見文雄。"]'),
('d353b245-a16a-4e2c-83f6-2b2cbf20d7d0','詩一首','宋徽宗','宋','宋诗','song-poetry','','[]','乍覺生風喜雨涼，農家得地發田穰。',32,'全唐诗/poet.song.86000.json','["乍覺生風喜雨涼，農家得地發田穰。", "卻緣暑退秋光滿，點滴高梧似漏長。"]'),
('cb4df5cc-7057-4e0d-8074-96a7a8707c6d','詩二首  其一','宋徽宗','宋','宋诗','song-poetry','','[]','欲借嵯峨萬仞崇，故將工巧狀層峰。',64,'全唐诗/poet.song.86000.json','["欲借嵯峨萬仞崇，故將工巧狀層峰。", "數尋蒼色如煙合，一片盤根似蘚封。", "院宇接連常藉竹，池亭掩映卻憑松。", "分明裝出依巖寺，只欠清宵幾韻鐘。"]'),
('8e5b5b10-ccc5-4d58-884e-6213185e0729','詩二首  其二','宋徽宗','宋','宋诗','song-poetry','','[]','風霜正臘晨，早見幾枝新。',48,'全唐诗/poet.song.86000.json','["風霜正臘晨，早見幾枝新。", "預荷東皇化，偷回北苑春。", "旗槍雖不類，荈蘖似堪倫。", "已有清榮諭，終難混棘蓁。"]'),
('8ed28ff9-dc1e-4d8d-a629-0751e1830ef5','夏日','宋徽宗','宋','宋诗','song-poetry','','[]','清和節後綠枝稠，寂寞黄梅雨乍收。',64,'全唐诗/poet.song.86000.json','["清和節後綠枝稠，寂寞黄梅雨乍收。", "畏日正長凝碧漢，薰風微度到丹樓。", "池荷成蓋閑相倚，徑草鋪裀色更柔。", "永晝搖紈避繁溽，杯盤時欲對清流。"]'),
('915dcfe6-5bfa-4b00-8f6b-bbaea9598e9b','詩一首','宋徽宗','宋','宋诗','song-poetry','','[]','十二樓藏玉蝶中，鳳凰雙宿碧梧桐。',32,'全唐诗/poet.song.86000.json','["十二樓藏玉蝶中，鳳凰雙宿碧梧桐。", "流霞淺酌留君醉，今夜吹簫第幾重。"]'),
('5cb95812-19d8-4bd8-ae67-e52558e0c4fd','蔡謨諫議大夫兼樞密使都督諸路軍馬戶部尚書賜歸田','宋徽宗','宋','宋诗','song-poetry','','[]','獨善傳家久，功名冠世豪。',48,'全唐诗/poet.song.86000.json','["獨善傳家久，功名冠世豪。", "平原滂雨澤，嶺外息風濤。", "緩拜恩箋盛，相傳道義高。", "嗟予塵世隔，安得自陪叨。"]'),
('8829f279-0982-4cfc-9746-9f934cce632f','幸徐常廬','宋徽宗','宋','宋诗','song-poetry','','[]','人生何事厭囂塵，汎宅浮家冬復春。',32,'全唐诗/poet.song.86000.json','["人生何事厭囂塵，汎宅浮家冬復春。", "今日暫來猿鶴語，他年應召白雲人。"]'),
('3682f840-cfca-48c0-8c61-5cc7695f8994','牡丹','宋徽宗','宋','宋诗','song-poetry','','[]','異品殊葩共翠柯，嫩紅拂拂醉金荷。',64,'全唐诗/poet.song.86000.json','["異品殊葩共翠柯，嫩紅拂拂醉金荷。", "春羅幾疊敷丹陛，雲縷重縈浴絳河。", "玉鑑和鳴鸞對舞，寶枝連理錦成窼。", "東君造化勝前歲，吟繞清香故琢磨。"]'),
('da41b9da-9f9b-4e46-a143-46a8bca01670','題繁杏鸚鵡圖','宋徽宗','宋','宋诗','song-poetry','','[]','天產乾皋此異禽，遐陬來貢九重深。',64,'全唐诗/poet.song.86000.json','["天產乾皋此異禽，遐陬來貢九重深。", "體全五色非凡質，惠吐多言更好音。", "飛翥似憐毛羽貴，徘徊如飽稻粱心。", "緗膺紺趾誠端雅，爲賦新篇步武吟。"]'),
('9bd82c9a-4965-4691-9e6d-d6df1ae3c165','怪石','宋徽宗','宋','宋诗','song-poetry','','[]','殊狀難名各蔽虧，高□崒屼□巍巍。',63,'全唐诗/poet.song.86000.json','["殊狀難名各蔽虧，高□崒屼□巍巍。", "直疑伏獸身將動，常恐長蛟勢□□。", "裂幾層蒼檜□，凝嵐四接老松圍。", "名封三品非無美，飲羽曾令壯奮□。"]'),
('2fdce9c4-c183-48e2-9241-348923b48ada','句  其一','宋徽宗','宋','宋诗','song-poetry','','[]','雅燕酒酣添逸興，玉真軒內看安妃。',16,'全唐诗/poet.song.86000.json','["雅燕酒酣添逸興，玉真軒內看安妃。"]'),
('59fbcb44-b6cc-4e4a-88f1-372ad55ff6ad','句  其二','宋徽宗','宋','宋诗','song-poetry','','[]','相公公相子。',6,'全唐诗/poet.song.86000.json','["相公公相子。"]'),
('e11f7956-f753-4bd3-9d78-a641e0cf1c4a','句  其三','宋徽宗','宋','宋诗','song-poetry','','[]','北斗七星三四點。',8,'全唐诗/poet.song.86000.json','["北斗七星三四點。"]'),
('048437a6-1d52-4774-ab91-2bd3f345f051','句  其四','宋徽宗','宋','宋诗','song-poetry','','[]','選飯來時不喜餐，御廚空費八珍盤。',16,'全唐诗/poet.song.86000.json','["選飯來時不喜餐，御廚空費八珍盤。"]'),
('22258913-bb6b-42c1-959b-7cdbda4c0140','句  其五','宋徽宗','宋','宋诗','song-poetry','','[]','方當月白風清夜，正是霜高木落時。',16,'全唐诗/poet.song.86000.json','["方當月白風清夜，正是霜高木落時。"]'),
('935de35b-1d03-4ca9-9bf3-d489fb0be2eb','句  其六','宋徽宗','宋','宋诗','song-poetry','','[]','落花滿地春光晚，芳草連雲暮色深。',16,'全唐诗/poet.song.86000.json','["落花滿地春光晚，芳草連雲暮色深。"]'),
('2881dee4-5a60-410e-866f-424d3a9fe1e2','句  其七','宋徽宗','宋','宋诗','song-poetry','','[]','網羅今不密，回首不須驚。',12,'全唐诗/poet.song.86000.json','["網羅今不密，回首不須驚。"]'),
('4495daa9-33b1-4a15-af5f-6973f6c0145b','句  其八','宋徽宗','宋','宋诗','song-poetry','','[]','午夜笙歌連海嶠，春風燈火過湟中。',16,'全唐诗/poet.song.86000.json','["午夜笙歌連海嶠，春風燈火過湟中。"]'),
('3a79a07e-b2e2-4066-bc7d-8bbb5bbc14cd','句  其九','宋徽宗','宋','宋诗','song-poetry','','[]','暖河消雪带，風柳散冰絲。',12,'全唐诗/poet.song.86000.json','["暖河消雪带，風柳散冰絲。"]'),
('f8f85b17-f8e1-4762-a31a-a2409a6afb13','句  其一○','宋徽宗','宋','宋诗','song-poetry','','[]','玉階齊種女貞子，大覺金仙采擷來。',16,'全唐诗/poet.song.86000.json','["玉階齊種女貞子，大覺金仙采擷來。"]'),
('2de69dcf-f35a-4c5a-bd04-2d8c9204b201','句  其一一','宋徽宗','宋','宋诗','song-poetry','','[]','日射晚霞金世界，月臨天宇玉乾坤。',16,'全唐诗/poet.song.86000.json','["日射晚霞金世界，月臨天宇玉乾坤。"]'),
('20f71120-c81f-47b3-acc4-74d40e628b69','句  其一二','宋徽宗','宋','宋诗','song-poetry','','[]','危樓日暮人千里，欹枕風秋雁一聲。',16,'全唐诗/poet.song.86000.json','["危樓日暮人千里，欹枕風秋雁一聲。"]'),
('b541938d-2855-4da2-8745-7fb9c8011674','存目  其一','宋徽宗','宋','宋诗','song-poetry','','[]','詩題：宮詞首句：日冷天晴近臘時，嫌羅不著索輕□。',32,'全唐诗/poet.song.86000.json','["詩題：宮詞首句：日冷天晴近臘時，嫌羅不著索輕□。", "後宮宮女無多少。"]'),
('dfbcecc4-0a4b-4af3-978e-5ccb35f2baff','存目  其二','宋徽宗','宋','宋诗','song-poetry','','[]','詩題：宮詞首句：翡翠盤龍裝繡額。',16,'全唐诗/poet.song.86000.json','["詩題：宮詞首句：翡翠盤龍裝繡額。"]'),
('fea05f68-5a2f-4dfa-917b-60894d189878','吹臺曲','周紫芝','宋','宋诗','song-poetry','','[]','天門玉鑰雙龍開，霓旌羽蓋天上來。',104,'全唐诗/poet.song.86000.json','["天門玉鑰雙龍開，霓旌羽蓋天上來。", "管絃嘈雜入霄漢，美人侍燕黄金臺。", "羽觴行酒歡未足，燕姬成行列紅玉。", "梁王半醉起更衣，夜按玉簫親度曲。", "曲終舉袂俱爭妍，拜舞樽前稱萬年。", "三山玉女朝羣仙，當時弄玉飛上天，至今臺下草如烟。"]'),
('011fdb2c-fd2b-41f0-b66f-0deb50c201ae','越臺曲','周紫芝','宋','宋诗','song-poetry','','[]','玉顔如花越王女，自小嬌癡不歌舞。',124,'全唐诗/poet.song.86000.json','["玉顔如花越王女，自小嬌癡不歌舞。", "嫁作江南國主妃，日日思歸淚如雨。", "江南江北梅子黄，潮頭夜漲秦淮江。", "江邊雨多地卑濕，旋築高臺匀曉粧。", "千艘命載越中土，喜見越人仍越語。", "人生脚踏鄉土難，無復歸心越中去。", "高臺何易傾，曲池亦復平。", "越姬一去向千載，不見此臺空有名。"]'),
('b4d503b8-ddc7-46ed-a47f-e979a4ec175c','巫山曲','周紫芝','宋','宋诗','song-poetry','','[]','楚宫夜半旌旗動，曉逐君王獵雲夢。',160,'全唐诗/poet.song.86000.json','["楚宫夜半旌旗動，曉逐君王獵雲夢。", "君王醉挽金僕姑，笑射雙鵰落飛鞚。", "霜風獵獵吹白羽，狨鞍下時日未午。", "天上臺高翠被寒，雨濕煙霏夢神女。", "行雲飛去不可留，却望陽臺無處所。", "魂凝睇遠煙淒迷，猿啼巫峽東復西。", "江邊獵火一萬炬，貂裘醉擁君王歸。", "章華千門復萬户，侍女焚香迎輦步。", "君心誰能念舊恩，忍淚悲啼不成語。", "願壽君王一萬年，常向陽臺夢雲雨。"]'),
('aa80e9b3-9688-47ee-b639-b3c6749209cb','白苧歌','周紫芝','宋','宋诗','song-poetry','','[]','大垂手，小垂手，江南白符世希有。',128,'全唐诗/poet.song.86000.json','["大垂手，小垂手，江南白符世希有。", "吳姬十指玉纖纖，白苧新裁舞衣小。", "秋江四面繞吳宫，吳宫霜橘樹樹紅。", "吳王夜燕不知曉，但見紅日昇曈曨。", "美人低鬟復回袖，持酒獻君君一笑。", "人生得意不行樂，白日如梭夜催晝。", "吳山依舊吳江清，離宫故苑難爲情。", "不知誰遣南山鹿，還向姑蘇臺下行。"]'),
('5fc8c39c-5061-46ae-8d1d-ba4e63715355','五雜俎  其一','周紫芝','宋','宋诗','song-poetry','','[]','五雜俎，壠頭水。',24,'全唐诗/poet.song.86000.json','["五雜俎，壠頭水。", "往復來，玉關騎。", "不得已，從士子。"]'),
('48809050-8b98-48e3-9c3a-e1a9eeeea144','五雜俎  其二','周紫芝','宋','宋诗','song-poetry','','[]','五雜俎，雲際翮。',24,'全唐诗/poet.song.86000.json','["五雜俎，雲際翮。", "往復來，長安陌。", "不得已，千里客。"]'),
('79f5457a-4dac-4498-b4f4-c1e6da5dc964','五雜俎  其三','周紫芝','宋','宋诗','song-poetry','','[]','五雜俎，夜茫茫。',24,'全唐诗/poet.song.86000.json','["五雜俎，夜茫茫。", "往復來，雁南翔。", "不得已，思故鄉。"]'),
('7ff26cf0-1fe5-4228-9bd4-a76ba300fad6','荔枝香','周紫芝','宋','宋诗','song-poetry','','[]','千秋節當八月五，御樓卷簾看馬舞。',160,'全唐诗/poet.song.86000.json','["千秋節當八月五，御樓卷簾看馬舞。", "黄衫玉带分兩行，繡衣宫人擊雷鼓。", "梨園法曲凄且清，相傳猶是隋家聲。", "宜春北院蛾眉小，初按新聲未有名。", "侍女焚香跪瑤席，更看真妃作生日。", "恰值南方驛使來，旋採風枝露猶濕。", "當時盛事人爭傳，荔枝香曲是新翻。", "宫中行樂事亦秘，此曲不許人間聞。", "馬嵬夢斷香塵息，滿山荔子無人摘。", "却歸西內冷如冰，一聽遺音淚空滴。"]'),
('284950c8-542b-4a56-b085-79f8ab151f01','武谿深','周紫芝','宋','宋诗','song-poetry','','[]','五谿妖蠻盤瓠種，穴狐跳梁恃餘勇。',144,'全唐诗/poet.song.86000.json','["五谿妖蠻盤瓠種，穴狐跳梁恃餘勇。", "漢庭老驥聞朔風，兩耳如錐四蹄踴。", "南方毒霧堕跕鳶，五谿谿深軍不前。", "健兒六月半病死，欲渡五谿無渡船。", "將軍誓死心獨苦，本爲官家誅黠虜。", "誰知君側有讒徒，剛道將軍似賈胡。", "人生富貴一衰歇，會令薏苡成明珠。", "祁連高結衞青冢，文淵藁葬無人送。", "至今行客武溪傍，誰爲將軍一悲慟。"]'),
('6d07534e-95bd-49fe-bdeb-735bc987c41b','公無渡河','周紫芝','宋','宋诗','song-poetry','','[]','清江漫漫日夜流，江邊無風人自愁。',88,'全唐诗/poet.song.86000.json','["清江漫漫日夜流，江邊無風人自愁。", "馮夷擊鼓河伯怒，蛟龍掉尾魚吞舟。", "人生一死亦難處，何不相從聽媪語。", "公無渡河公自苦，人心險過山嵯峨，豺狼當路君奈何。", "勸君收淚且勿歌，世間平地多風波。"]'),
('70dbf968-00b5-4a44-8dcc-5d3fab02a7e1','飲馬長城窟行','周紫芝','宋','宋诗','song-poetry','','[]','長安城邊邊地永，萬里沙場地無井。',124,'全唐诗/poet.song.86000.json','["長安城邊邊地永，萬里沙場地無井。", "秦人掘土土作城，城下窟深胡水冷。", "漢家將軍號都護，西征上隴寒日暮。", "野駝跑水無處尋，飲馬長城窟邊去。", "長城窟，古來戰死多白骨。", "征人半作馬下塵，猶向陰山鬬馳突。", "去時胡天霜雁鳴，歸見玉關春草生。", "將軍功高封列城，鬬死伍符無姓名。"]'),
('c06d9cbb-23ca-4931-b8ae-c415b2ddbea1','金銅歌','周紫芝','宋','宋诗','song-poetry','','[]','武皇開疆三萬里，滇池初穿柏梁起。',144,'全唐诗/poet.song.86000.json','["武皇開疆三萬里，滇池初穿柏梁起。", "更鑄仙人承露盤，萬歳千秋奉天子。", "當時謾說邜金刀，誰知更有當塗高。", "銅雀臺高阿瞞死，八方才人閙如蟻。", "玉井綺欄心未厭，猶取金仙着前殿。", "金仙辭漢憶漢主，登車殷勤垂玉筯。", "獨捧金盤出故宫，回頭忍看咸陽樹。", "魏宫羣臣眼親見，朝着魏冠暮歸晉。", "可憐長安肉食兒，不如頑銅猶有知。"]'),
('ab79d968-3b5f-47ed-bf62-cd43f3e3d66d','日出東南隅行','周紫芝','宋','宋诗','song-poetry','','[]','春風淡蕩春雲淺，陌上柔桑青宛宛。',160,'全唐诗/poet.song.86000.json','["春風淡蕩春雲淺，陌上柔桑青宛宛。", "青天易雨亦易晴，吳蠶催眠欲成繭。", "羅敷採桑南陌頭，翠鬟皴鬌光欲流。", "羅襦吹香白玉佩，青絲絡籠黄金鈎。", "君王年少如秋水，欲學鴛鴦對飛起。", "贈君身上雙明璫，結君同生亦同死。", "羅敷歛衽前致詞，詞多慷慨中含悲。", "念言夫婿良家子，委身結髪爲夫妻。", "人生匹配各有偶，願逐狗走隨雞飛。", "江水可竭山可移，妾心皎皎君當知。"]'),
('8da8fd4a-c854-4037-91eb-29d9645f4c40','烏夜啼','周紫芝','宋','宋诗','song-poetry','','[]','黄門急詔下，趣封南郡王。',288,'全唐诗/poet.song.86000.json','["黄門急詔下，趣封南郡王。", "鸞輅儼且深，班劍列成行。", "建以左纛旆，樹以羽葆幢。", "骨肉厚恩義，門户生輝光。", "分封得大國，四境彌土疆。", "那知以嫌猜，將身觸嗔怒。", "徵我還上都，令我不得住。", "奪我封侯印，被我五兩組。", "低頭屏氣息，對客不敢語。", "紅窗昏夜燈，白淚墮秋雨。", "鬱鬱兩大樹，依依近牆宇。", "鴉鴉枝上啼，腷腷振兩羽。", "沉沉夜未央，紞紞方三鼓。", "侍兒聞之喜，攬衣中夜起。", "起敲齋閤門，秉燭具肴旨。", "再拜前致詞，靈烏未可鄙。", "吾聞烏夜啼，霈澤覃萬里。", "杲杲方平旦，使者已在門。", "官家有詔書，爲君敦厚恩。", "舊憤知己釋，徙封意增勤。", "客有鮑書記，當代稱能文。", "命作啼烏曲，樂府傳清芬。", "人生欲富貴，生身恨不早。", "富貴豈不好，危機亦難蹈。"]'),
('6a24deaf-b7d1-4077-9c1b-784609e51f7e','上之回','周紫芝','宋','宋诗','song-poetry','','[]','漢宫三十六，複道高崔嵬。',72,'全唐诗/poet.song.86000.json','["漢宫三十六，複道高崔嵬。", "皇情極遊豫，警蹕北之回。", "蒼螭挾龍輈，風伯清路埃。", "羽衞森戞擊，玉輿久徘徊。", "青娥絕望幸，故宫秋葉催。", "舉頭望霄漢，白露零玉階。"]'),
('ff986180-2439-485d-a6eb-a3800f587f59','得寶子','周紫芝','宋','宋诗','song-poetry','','[]','蓬萊宫中春草綠，君王無事歡不足。',192,'全唐诗/poet.song.86000.json','["蓬萊宫中春草綠，君王無事歡不足。", "宜春北院小蛾眉，日日霓裳按新曲。", "侍女傾心復盡計，歌舞君前不如意。", "今年新得太真妃，從此龍顔不勝喜。", "望春楼下紇那歌，枉說揚州古銅器。", "梨園樂府兩部齊，盡歌樂府新歌詞。", "君門誰道九重遠，歲久歡聲聞遠夷。", "漁陽萬騎倉黄入，帳中妃子吞聲泣。", "當時掌上不忍看，玉骨埋時煙雨濕。", "屬車塵遠空郵亭，郵亭牧豎嗟娉婷。", "凌波襪在香未絕，萬人爭看俱傷情。", "一朝持入咸陽市，空得千金賈客驚。"]'),
('2a18a4db-56ca-42e6-9c8e-39d07e28166f','昭君行','周紫芝','宋','宋诗','song-poetry','','[]','漢宫侍女知幾千，爭妍取寵俱可憐。',128,'全唐诗/poet.song.86000.json','["漢宫侍女知幾千，爭妍取寵俱可憐。", "誰知恩愛託畫手，黄金買得昭陽眠。", "昭君自恃玉顔好，未信光陰鏡中老。", "不知萬里嫁胡兒，憔悴蛾眉葬秋草。", "憶得昭君初嫁時，含羞忍淚無人知。", "胡天漫漫沙漠遠，空抱琵琶說别離。", "捐金得寵固可恥，委身胡酋不如死。", "世間妍醜何曾分，自古賢愚亦如此。"]'),
('21b7ea70-665d-4104-b506-6ed5e037f701','烏飛曲','周紫芝','宋','宋诗','song-poetry','','[]','江雲欲雪江風吹，王敦城頭烏夜啼。',139,'全唐诗/poet.song.86000.json','["江雲欲雪江風吹，王敦城頭烏夜啼。", "雲深月暗風轉急，驚烏繞樹無安枝。", "狂風忽來飛不定，夜半無巢何所依。", "情知天公有風雨，何不結巢高樹棲。", "君不見秦氏庭中雙桂美，庭烏生雛八九子。", "烏生豈不念高飛，託君庭陰飛不起。", "那知君家輕薄兒，彈丸脫手兩翅垂。", "無巢悔不巢巍巍，有巢悔不常高飛，人生禍福難豫期。"]'),
('e74b70a6-4a55-46ac-9bdc-2cd869280773','秋蘭詞','周紫芝','宋','宋诗','song-poetry','','[]','藝蘭當九畹，蘭生香滿路。',84,'全唐诗/poet.song.86000.json','["藝蘭當九畹，蘭生香滿路。", "紉君身上衣，光明奪縑素。", "孤芳一衰歇，凋零濕秋露。", "佩服得君子，亦足慰遲暮。", "採摘良不辭，新枝忽成故。", "向來桃李場，紅顔照當户。", "紛紛自芳菲，榮枯復誰顧。"]'),
('46d0cc3a-cda8-468e-b6a6-da1963c14cb5','金錯刀','周紫芝','宋','宋诗','song-poetry','','[]','美人臨曉鏡，睡足含春嬌。',156,'全唐诗/poet.song.86000.json','["美人臨曉鏡，睡足含春嬌。", "手持白玉尺，睥睨金錯刀。", "欲将雙綵鳳，對飛宫錦袍。", "誰知遊冶郎，經年事遊遨。", "但知山上山，不說大刀頭。", "君看良家子，盡屬六郡豪。", "一朝著鎧甲，萬里隨炊刁。", "家人剪春衫，欲寄道里遙。", "緘封望絕塞，蓬首時自搔。", "蕩子會當歸，行人日儦儦。", "别去隔生死，不保夕與朝。", "寄言樓中婦，清淚且當收。", "猶勝作征衣，遠寄邊城秋。"]'),
('4c6f4cf7-da97-43dd-be55-ffa285944d60','湖陰行','周紫芝','宋','宋诗','song-poetry','','[]','石頭城南五馬渡，一馬成龍上天去。',144,'全唐诗/poet.song.86000.json','["石頭城南五馬渡，一馬成龍上天去。", "晉家天子再御朝，洛陽胡騎空無數。", "當時枉道馬與王，高官飽食豐豺狼。", "車前已賜蘭斑物，江上空餘劍戟場。", "日光射天驚賊壘，封豖長蛇夢中起。", "倉皇只欲玩遺鞭，誰信龍媒已千里。", "黄鬚有智人豈知，不料將軍未死時。", "着新脫故真是賊，白犬下齧天應遲。", "誰道晉朝公與相，不及金谷園中兒。"]'),
('5c441de4-0da1-4e0f-b749-d26e3e3baa9c','隋渠行','周紫芝','宋','宋诗','song-poetry','','[]','黄榆落盡河水冰，隋渠兩岸無人行。',112,'全唐诗/poet.song.86000.json','["黄榆落盡河水冰，隋渠兩岸無人行。", "雪花漫天大如掌，北風吹馬南人驚。", "縣官藏冰避炎熱，健兒鑿冰手流血。", "安得身隨花石官，當路誰人敢呵喝。", "黄流千里凍徹底，舳艫相仍凍銜尾。", "天公便合回陽和，桃花水暖流春波。", "望春樓上天顔喜，齊聲爭唱紇那歌。"]'),
('d80cf3af-60ca-4bfa-a616-85d41670fbaa','長干曲','周紫芝','宋','宋诗','song-poetry','','[]','黄昏明月上朱樓，簾旌射月香霧浮。',64,'全唐诗/poet.song.86000.json','["黄昏明月上朱樓，簾旌射月香霧浮。", "畫欄垂手樓中女，對月低眉不舉頭。", "人似長干橋下水，一去悠悠幾千里。", "謾道嫁雞逐雞飛，長干夫婿那得知。"]'),
('dda88da3-5a9e-41ef-93ca-39ecff53aa3f','五男父','周紫芝','宋','宋诗','song-poetry','','[]','白頭垂垂五男父，一生辛勤立門户。',64,'全唐诗/poet.song.86000.json','["白頭垂垂五男父，一生辛勤立門户。", "五男炊白割紅鮮，阿翁採薪供五男。", "悲風慘慘寒日暮，翁入採山遭猛虎。", "猛虎磨牙臥道邊，五男持戟誰敢前。"]'),
('ab6213da-95d4-4c26-82fe-4da3aa137747','魔軍行','周紫芝','宋','宋诗','song-poetry','','[]','五嶺南來山最多，驅軍日涉千坡陁。',112,'全唐诗/poet.song.86000.json','["五嶺南來山最多，驅軍日涉千坡陁。", "山中食菜不食肉，十室九家俱事魔。", "縣官給錢捕魔鬼，八萬魔軍同日起。", "將軍新破强虜回，馬前班劍如流水。", "生斬妖精拔羽幢，傳首天庭藁街死。", "當時平田作戰場，至今遺骼無人藏。", "舊居雖在人不見，破屋蕭蕭圍短牆。"]'),
('c6877a76-978e-4750-807a-603f82d3cac6','野婦行','周紫芝','宋','宋诗','song-poetry','','[]','新安野婦雙鬢垂，紅膏塗靨深畫眉。',128,'全唐诗/poet.song.86000.json','["新安野婦雙鬢垂，紅膏塗靨深畫眉。", "青襜兩幅不掩骭，赤脚一雙深染泥。", "餉耕如賓有翁媪，頭戴銀冠相媚好。", "銀冠猶是嫁時粧，馬上不知人絕倒。", "長年相見無别離，竟死不識愁眉啼。", "紅顔暗逐春光老，暮櫛常隨落日低。", "秋娘一尺春風髻，下蔡陽城盡風靡。", "傾城可愛亦可憐，野婦誰知有西子。"]'),
('d5f9d088-6428-4489-a08f-79435ad82986','輸粟行','周紫芝','宋','宋诗','song-poetry','','[]','天寒村落家家忙，飯牛穫稻催滌場。',156,'全唐诗/poet.song.86000.json','["天寒村落家家忙，飯牛穫稻催滌場。", "燎薪炊黍呼婦子，夜半舂粟輸官倉。", "大兒擔囊小負槖，掃廪傾囷不須惡。", "縣胥里正不到門，了得官租舉家樂。", "去年有米不願餘，今年米白要如珠。", "路傍老人拍手笑，盡道官兵嫌米麤。", "良農飬兵與胡競，胡騎不來自亡命。", "田家終歲負耕縻，十農飬得一兵肥。", "一兵唱亂千兵隨，千家一炬無孑遺。", "莫飬兵，飬兵殺人人不知。"]'),
('d35137cd-94ad-4314-9c40-858a67e570c2','寒食曲','周紫芝','宋','宋诗','song-poetry','','[]','三月江南好春色，買酒家家作寒食。',147,'全唐诗/poet.song.86000.json','["三月江南好春色，買酒家家作寒食。", "男呼女喚俱出遊，扶路醉歸歡樂極。", "街頭盡日無人行，多在山村少在城。", "踏歌賽願一時了，上冢歸來聞笑聲。", "豈料如今一百五，畫戟滿城椎戰鼓。", "子孫半作泉下人，薄酒不澆山上土。", "死者已往生者存，隨分歡娛各兒女。", "烹魚裹菜當盤飱，花作紅粧鳥歌舞。", "君不見江南江北多戰場，去年白骨無人藏。"]'),
('37b92bcc-6ff6-4dd6-bfbf-c44d2f5d8453','木芙蓉歌','周紫芝','宋','宋诗','song-poetry','','[]','吳江十月霜華淺，秋空無雲霜日暖。',144,'全唐诗/poet.song.86000.json','["吳江十月霜華淺，秋空無雲霜日暖。", "芭蕉樹暗簾幕垂，木芙蓉開紅婉婉。", "銀床露重梧葉飛，金錢掃地秋蘭萎。", "無人自對秋風笑，黄菊葵花不同調。", "慢綠妖紅解醉人，徐娘未老秋娘少。", "少年時節歡樂多，紅蓮影落秋江波。", "若耶女兒白如玉，夜半採蓮聞棹歌。", "驚風吹浪鴛鴦起，回頭日月飛梭裏。", "對花不飲今蹉跎，淚濕秋風當奈何。"]'),
('d4f59d6a-9922-451e-b131-8d5f9a0ff216','雍門行','周紫芝','宋','宋诗','song-poetry','','[]','憶昔長安晝閉門，胡兵四面如雲屯。',112,'全唐诗/poet.song.86000.json','["憶昔長安晝閉門，胡兵四面如雲屯。", "嗣皇明聖日月出，盡剗宿蠧清妖氛。", "黄門急詔忽夜下，驛騎四出爭馳奔。", "明朝都人看傳首，賀客縱横各持酒。", "利劍空膏六貴人，富貴回頭信何有。", "一身成粉骨成塵，當時近前丞相嗔。", "高臺曲池已荆棘，援琴誰作雍門吟。"]'),
('2d00ac90-d5ab-4b5b-bb00-2cb72d0ebd5a','艨艟行','周紫芝','宋','宋诗','song-poetry','','["\u6d1e\u5ead\u6e56"]','漢作樓船三百尺，江南父老何曾識。',128,'全唐诗/poet.song.86000.json','["漢作樓船三百尺，江南父老何曾識。", "船頭擊鼓轉紅旗，船尾踏車人不知。", "君王英略似漢武，要挽江心射蛟弩。", "天戈指日殄匈奴，先遣偏舟下江浦。", "三年血滿秋江紅，洞庭搖落悲秋風。", "漫山柵水作城寨，逆氣不腥河伯宫。", "驚濤捲地噴飛雪，艨艟一出千艘空。", "將軍自駕木城去，莫歎龍驤作阿童。"]'),
('d6f04490-5967-4025-ae59-7d5b16847521','五谿道中見羣牛蔽野問之容州來感其道里之遠乃作短歌以補樂府之闕','周紫芝','宋','宋诗','song-poetry','','[]','淮田一廢不復秋，五夫扶犁當一牛。',160,'全唐诗/poet.song.86000.json','["淮田一廢不復秋，五夫扶犁當一牛。", "番兵大入郡不守，青窠未熟官來收。", "狐狸晝嘯荆棘裏，此事最貽廊廟憂。", "羽檄徵牛牛蔽野，問言萬里來容州。", "容州價賤苦易得，四蹄纔堪一劍易。", "來時草青今草黄，道路既遠多死傷。", "沙場草淺食不飽，夕陽時見烏銜創。", "江北江南幾阡陌，幾牛能滿千家倉。", "願言田父各努力，會見西風禾黍長。", "將軍官大馬亦壯，肯使胡兒窺漢疆。"]'),
('8ce53a49-6c4e-46da-8ec8-f2f8391e697c','黥奴行','周紫芝','宋','宋诗','song-poetry','','[]','山西驍將真黥奴，兩斛笑彎金僕姑。',184,'全唐诗/poet.song.86000.json','["山西驍將真黥奴，兩斛笑彎金僕姑。", "偶然浮雲變蒼狗，身騎高馬稱金吾。", "胡兵倉黄忽南渡，地黑天昏兩龍去。", "賊臣僭僞誰適從，將軍一呵百官懼。", "仗劍前驅趣翠華，路人辟易空回顧。", "至今願返河陽狩，荆棘艱難窘天步。", "未懸北闕新頭顱，猶带安西舊都護。", "前年縱兵肥水頭，横屍千里行人愁。", "帳前騎士勇如虎，帳下嬌娥雙臉羞。", "藁街流血天忽怒，小兒跳梁健兒舞。", "寄語盧龍與范陽，中書相公今尚父，慎勿更如奴跋扈。"]'),
('22e75f48-c5cb-4c7a-874a-ac3ca64f0a7c','秣陵行','周紫芝','宋','宋诗','song-poetry','','[]','秣陵城門夜不開，城頭椎鼓鳴春雷。',176,'全唐诗/poet.song.86000.json','["秣陵城門夜不開，城頭椎鼓鳴春雷。", "緋衣擎火燎民屋，萬井一炬飛紅埃。", "道傍横屍人不識，血流但見秦淮赤。", "府中官吏一百人，盡取姓名書罪籍。", "元戎被執不得歸，賊坐黄堂縱呵斥。", "明朝傳檄下九州，九州牧伯不敢收。", "可笑官軍櫜羽箭，環視走卒攖城樓。", "將軍樓船下巫峽，膽落雙旌俱卷甲。", "日梟五十三頭顱，一戰何曾短兵接。", "今年新起故將軍，灞陵醉尉勿浪嗔。", "文致太平武定亂，非渠誰復清風塵。"]'),
('607c0c40-8a65-4c91-b72d-151eb6f9dfa0','射鹿行','周紫芝','宋','宋诗','song-poetry','','[]','白羽紅旌繞山麓，爭向山南射奔鹿。',128,'全唐诗/poet.song.86000.json','["白羽紅旌繞山麓，爭向山南射奔鹿。", "獵夫舉網常苦辛，誰寢其皮食其肉。", "腹中着子初成斑，梅花碎點真珠圓。", "雙桃壓髻玉簪短，去作誰家頭上冠。", "貴家金多逐時好，尚蹙蛾眉嫌不早。", "一皮可直三萬錢，競作苞苴當珍寶。", "大者有茸胎有紋，舉無遺族如何冤。", "玉纓瓊弁者誰子，始作此俑知非賢。"]'),
('1e8c9300-b937-4f49-93e8-3a03504d4cf0','督耨詞','周紫芝','宋','宋诗','song-poetry','','[]','十里一候五里置，渡海梯山來萬里。',128,'全唐诗/poet.song.86000.json','["十里一候五里置，渡海梯山來萬里。", "賜入長安卿相家，夜暖金猊香徹髓。", "瓊香入骨作曉酲，斗帳燒煙隔秋水。", "青娥添火窗欲明，紅錦薫衣人未起。", "梅花不用波律來，零藿何勞香傳記。", "蘭閨半掩春晝長，參差吹竹羅紅粧。", "令君一去三日香，更遣小兒縫紫囊。", "夜來賓客滿高堂，誰家有女嫁韓郎。"]'),
('973d6385-882a-42e1-a730-84776f20652f','漢宫詞','周紫芝','宋','宋诗','song-poetry','','[]','漢宫五月多南風，宫槐覆砌花陰濃。',112,'全唐诗/poet.song.86000.json','["漢宫五月多南風，宫槐覆砌花陰濃。", "彤庭破曉瑞霧薄，寶檻茙葵迎日紅。", "池面雞頭青蹙衄，菖蒲有花池水綠。", "殿閣風清白日長，五絲結綵獻君王。", "漢皇年來新受籙，自篆天書辟邪毒。", "六宫此日多歡娛，就中何人恩寵殊。", "黄金釵横絳囊小，爭带君王親寫符。"]'),
('cf622cbc-0b47-44e0-90be-01b3a8501f7c','競渡曲','周紫芝','宋','宋诗','song-poetry','','[]','江風獵獵吹紅旗，舟人結束誇水嬉。',128,'全唐诗/poet.song.86000.json','["江風獵獵吹紅旗，舟人結束誇水嬉。", "短衣青帽錦半臂，横波鼓鬛飛鯨鯢。", "江潮漫漫江水闊，浪花擊碎千堆雪。", "畫橈擘水挽不回，白羽離絃箭初脫。", "巋來醉作踏浪歌，應笑吳兒拜浪婆。", "朱樓相映綠陰裏，兩岸人家歡樂多。", "飯筒角黍纒五綵，楚俗至今猶未改。", "日暮空歌何在斯，不見三閭憔悴時。"]'),
('bce28619-c886-4459-999a-e9b9950b4ab3','牛女行','周紫芝','宋','宋诗','song-poetry','','[]','天孫曉織雲錦章，跂彼終日成七襄。',112,'全唐诗/poet.song.86000.json','["天孫曉織雲錦章，跂彼終日成七襄。", "含情倚杼長脈脈，靈河南北遙相望。", "天風吹衣香冉冉，烏鵲梁成月華淺。", "青童侍女驂翔鸞，玉闕瓊樓降華幰。", "明朝脩渚曠清容，歸期苦短歡期遠。", "昔離今聚自有期，天帝令嚴何敢違。", "猶勝姮娥竊仙藥，一入廣寒無嫁時。"]'),
('bd316dde-18cc-4ea9-9f31-31a24d95fcc9','雙鵠飛行','周紫芝','宋','宋诗','song-poetry','','[]','憶昔江鄉遭亂離，兩翁避地雙鵠飛。',128,'全唐诗/poet.song.86000.json','["憶昔江鄉遭亂離，兩翁避地雙鵠飛。", "一鵠南翔一鵠北，北鵠墮地南鵠栖。", "天長地遠去不返，巢傾卵覆令人悲。", "去年賊兵初聚黨，今歲王師方解圍。", "舂陵萬户纔有幾，駱谷一家空獨歸。", "歸尋故里不知處，白骨支撐滿塗路。", "城西有屋無人居，城東有地無屋廬。", "仿彿相從舊遊處，淚栖雙睫還欷歔。"]'),
('e27abf8b-8b4d-4df1-9597-8e73aa0c5f63','燕銜柏行','周紫芝','宋','宋诗','song-poetry','','[]','雙燕何時來瀚海，寄巢脩椽巢不改。',128,'全唐诗/poet.song.86000.json','["雙燕何時來瀚海，寄巢脩椽巢不改。", "春深巢稳初養雛，雙雛引頸仰哺呼。", "雄將雌出雙雛孤，雛危墮地聲呱呱。", "雌隨雄歸見雛泣，主人將雛納其室。", "雙雛脫死翅欲開，玄衣素臆去復來。", "明年主人開壽燕，畫鼓停撾歌舞遍。", "雙雛傍席爭回旋，共銜青柏置樽前。", "口不能言對以臆，再拜壽君如柏年。"]'),
('36badb89-67e0-404e-8fd0-d93dd25855a3','石婦行二首  其一','周紫芝','宋','宋诗','song-poetry','','[]','貞婦生江南，少小稱丰穠。',156,'全唐诗/poet.song.86000.json','["貞婦生江南，少小稱丰穠。", "委身事良人，相與歡笑同。", "良人去不返，兩鬢常蓬鬆。", "謂言有膏沐，未識誰爲容。", "日日上山望，水遠山複重。", "藁砧竟不來，望望終無窮。", "一朝化作石，僵立由天公。", "天公表堅貞，令與山始終。", "仙衣綉蘚暈，寶髻搖花叢。", "滔滔日月逝，此石存高峰。", "清名閲千古，勁節摩蒼穹。", "恨無採詩官，作詩頌遺蹤。", "用之邦國間，庶以消淫風。"]'),
('46375bbb-390e-4dc1-9ad2-7ed4659df840','石婦行二首  其二','周紫芝','宋','宋诗','song-poetry','','[]','生男有閨房，莫娶青樓倡。',120,'全唐诗/poet.song.86000.json','["生男有閨房，莫娶青樓倡。", "生女事姑嫜，莫嫁遊冶郎。", "倡家從人無定準，遊子一去忘故鄉。", "山頭義婦無人識，踴身上山生死隔。", "人將此婦作石看，不信此心元是石。", "相從豈復無它人，髧彼兩髦真我特。", "江流可盡山可平，不盡悠悠千古情。", "早知郎去無消息，悔不將身事尾生。"]'),
('2e1c7238-25ac-4c52-9954-83976cd0c3b6','擬客從遠方來','周紫芝','宋','宋诗','song-poetry','','[]','客從遠方來，遺我故人書。',120,'全唐诗/poet.song.86000.json','["客從遠方來，遺我故人書。", "故人久别離，一别萬里餘。", "相望不相見，各在天一隅。", "感君慇懃意，字字如明珠。", "上陳昔懽樂，次問今何如。", "昔别俱少年，老大今蒼鬚。", "良時不我與，歲月空躊躇。", "餘生如夢寐，尺素徒卷舒。", "爲我謝故人，遠致雙鯉魚。", "恨無木瓜篇，報君以瓊琚。"]'),
('7e0e2d1b-d718-452a-8d30-76d3d5f450ee','擬青青河畔草','周紫芝','宋','宋诗','song-poetry','','[]','四序相推遷，日月倏已逝。',108,'全唐诗/poet.song.86000.json','["四序相推遷，日月倏已逝。", "春風入猗蘭，光艶照羅綺。", "一朝霜雪至，容華苦憔悴。", "佳人惜朱顔，結褵奉君子。", "安知遠征途，中道成棄置。", "昔持鴛鴦錦，裁成合歡被。", "今織迴文機，中有相思字。", "相思日夜切，尺書無雁寄。", "誰能知妾心，脈脈含遠意。"]'),
('fa978f6e-6a39-43ef-9d23-29a9f321996a','擬燕趙多佳人','周紫芝','宋','宋诗','song-poetry','','[]','沙丘有餘風，趙女多跕纚。',108,'全唐诗/poet.song.86000.json','["沙丘有餘風，趙女多跕纚。", "燕丹養勇士，後宫出女子。", "至今餘倡優，吹彈滿都市。", "佳人北方來，傾城盡風靡。", "妙舞縈纖腰，清歌發皓齒。", "一歌四座歡，再歌賓客起。", "回眸與目成，哀絃忍重理。", "願爲雙飛燕，與君共棲止。", "人生不行樂，歲月如流水。"]'),
('19a5868d-ee93-4a06-bcb0-e5091db8adb8','擬梁父吟','周紫芝','宋','宋诗','song-poetry','','[]','駕言方北征，遵彼淮陰路。',72,'全唐诗/poet.song.86000.json','["駕言方北征，遵彼淮陰路。", "悠悠墟落間，中有淮陰墓。", "將軍藴奇略，功名照今古。", "談笑下燕齊，北面師降虜。", "一朝遭讒誣，銜冤復誰訴。", "誰能爲此謀，宫中漢家婦。"]'),
('b3fcd5e0-fc43-4d8f-af97-29c91090487f','擬司馬相如琴歌代文君答二首  其一','周紫芝','宋','宋诗','song-poetry','','[]','鳳兮鳳兮胡不歸，胡爲四海求其雌。',56,'全唐诗/poet.song.86000.json','["鳳兮鳳兮胡不歸，胡爲四海求其雌。", "其室良邇知者誰，邂逅相遇君獨知。", "彼美人兮偉容儀，願與君兮相追隨，歸丹山兮棲高枝。"]'),
('9c33a229-3249-4010-9a35-a6dfd06f1a63','擬司馬相如琴歌代文君答二首  其二','周紫芝','宋','宋诗','song-poetry','','[]','鳳兮鳳兮鳴噰噰，雄將飛兮雌將從。',48,'全唐诗/poet.song.86000.json','["鳳兮鳳兮鳴噰噰，雄將飛兮雌將從。", "天寒慘慘多悲風，雙翮欲舉心所同。", "山石可鑿金可鎔，妾心皎皎如日中。"]'),
('3d6e31c3-2409-4fff-9f38-40f2eca77f80','莫愁歌','周紫芝','宋','宋诗','song-poetry','','[]','蓮花深紅蓮葉綠，平沙月上鴛鴦宿。',96,'全唐诗/poet.song.86000.json','["蓮花深紅蓮葉綠，平沙月上鴛鴦宿。", "青腰三板蘭作橈，月下莫愁歌一曲。", "移船入花花轉深，花深調苦難爲音。", "江邊夜半誰爲語，只有嬋娟知此心。", "露華漸白月漸午，刺舟自覓來時路。", "明朝繫纜柳邊門，卻在夜來潮落處。"]'),
('78132ef4-93ce-4deb-b8b9-37cb6ac62535','擬桃葉團扇歌三首  其一','周紫芝','宋','宋诗','song-poetry','','[]','倚杼織冰紈，殷勤作團扇。',24,'全唐诗/poet.song.86000.json','["倚杼織冰紈，殷勤作團扇。", "爲君惜朱顔，相期日相見。"]'),
('22a347dc-28fb-4460-91bc-619ec0d51c2d','擬桃葉團扇歌三首  其二','周紫芝','宋','宋诗','song-poetry','','[]','裁紈作團扇，纖纖如白玉。',24,'全唐诗/poet.song.86000.json','["裁紈作團扇，纖纖如白玉。", "歳寒不改姿，持用可郎目。"]'),
('150598e4-18cc-4318-bec3-4390f3f5d3aa','擬桃葉團扇歌三首  其三','周紫芝','宋','宋诗','song-poetry','','[]','團扇復團扇，團扇亦已好。',24,'全唐诗/poet.song.86000.json','["團扇復團扇，團扇亦已好。", "但恐秋風至，棄捐在中道。"]'),
('9261cbe0-387b-4830-aa11-0147209dd16e','秋閨詞','周紫芝','宋','宋诗','song-poetry','','[]','西風動簾幙，蟋蟀鳴高堂。',144,'全唐诗/poet.song.86000.json','["西風動簾幙，蟋蟀鳴高堂。", "蔓草濕零露，秋閨知夜長。", "佳人掩朱户，背燭解羅裳。", "願言鴛鴦夢，雙飛入方塘。", "清影横疏櫺，奈此明月光。", "依依照長夜，炯炯明愁腸。", "不恨郎不歸，恨月入我床。", "披衣復起坐，嚬翠挑殘缸。", "開緘取素書，解結羅带傍。", "一讀再三歎，再讀淚數行。", "終夜不成寢，曙色忽滿窗。", "雖云有膏沐，誰能理晨粧。"]'),
('4b8259dd-cc1a-4401-b5f5-0d9283bddc50','倡樓詞','周紫芝','宋','宋诗','song-poetry','','[]','桃李艷春風，榮華照京洛。',144,'全唐诗/poet.song.86000.json','["桃李艷春風，榮華照京洛。", "九陌飛香塵，朱樓響弦索。", "美人倚脩欄，青娥卷珠箔。", "白面誰家郎，巴商載金槖。", "大艑何岢峨，繫舟樓下泊。", "哀彈雜清歌，日日樓中樂。", "謂言如江流，偕老有盟約。", "一朝買嬋娟，蟬鬢輕梳掠。", "情從新人歡，恩與舊人薄。", "去年與青棠，今年贈芍藥。", "人生有榮謝，曾不待衰落。", "倡女不嫁人，深心失期約。"]'),
('f19557cc-1239-4c47-a4d6-8e0c8343e00f','霽月謠','周紫芝','宋','宋诗','song-poetry','','[]','江鼉吹浪江水急，雷師鞭鼓旌旗濕。',64,'全唐诗/poet.song.86000.json','["江鼉吹浪江水急，雷師鞭鼓旌旗濕。", "黑風駕雨霹靂鳴，怒龍拏空半天立。", "須臾陰雲空四垂，廣寒殿冷風披披。", "玉觴燕罷王母歸，紅鸞簇扇香霧飛。"]'),
('b87a9ea9-f10f-497c-a7d9-51779b83df8a','插秧歌','周紫芝','宋','宋诗','song-poetry','','[]','田中水滿風淒淒，青秧没壠村路迷。',128,'全唐诗/poet.song.86000.json','["田中水滿風淒淒，青秧没壠村路迷。", "家家趁水秧稻畦，共唱俚歌聲調齊。", "樹頭幽鳥聲剝啄，半雨半晴雲漠漠。", "五白草斑誰敢閑，農夫餉田翁自作。", "去年兩經羣盗來，婦兒垂泣翁更哀。", "蠶藂燒盡不成繭，陵陂宿麥無根荄。", "今年插秧憂夏旱，旱得雨時兵復亂。", "官軍捕賊何時平，處處村村聞鼓聲。"]'),
('c8f0d984-72a4-44a1-b1aa-f3e5d6ba6ff4','古離别二首  其一','周紫芝','宋','宋诗','song-poetry','','[]','絃斷何由續，鏡分難再圓。',36,'全唐诗/poet.song.86000.json','["絃斷何由續，鏡分難再圓。", "感君綢繆意，贈我雙紋鴛。", "百年會有盡，此意終難捐。"]'),
('ac01846e-b945-4298-b4cd-6441c8d23929','古離别二首  其二','周紫芝','宋','宋诗','song-poetry','','[]','行行重行行，此别深可惜。',36,'全唐诗/poet.song.86000.json','["行行重行行，此别深可惜。", "臨分意難傳，欲語淚復滴。", "我欲從君遊，恨乏雙飛翮。"]'),
('3cfe4ab3-d6d4-4e63-a254-b07cf916627f','長短歌','周紫芝','宋','宋诗','song-poetry','','[]','礲石磨磚作新壘，角樓亭亭四邊起。',115,'全唐诗/poet.song.86000.json','["礲石磨磚作新壘，角樓亭亭四邊起。", "誰家一曲長短歌，長安貴人葬蒿里。", "東方作矣事若何，口珠腰带黄金多。", "墓門重閉子孫泣，樹上紙錢空滿柯。", "君不見胡騎南來相州路，倉皇尚覓韓王墓。", "解鞍下馬拜墓前，更遣羌兵作調護。", "憑誰試問爾何爲，定恐當年識吾父。"]'),
('bd412bf5-cf74-4aab-91a3-f9a61ded7047','壬午秋日觀橋刈穫五首  其一','周紫芝','宋','宋诗','song-poetry','','[]','清晨起盥櫛，卷箔坐南軒。',108,'全唐诗/poet.song.86000.json','["清晨起盥櫛，卷箔坐南軒。", "紅日忽滿樹，飛鳥相喧翻。", "農夫告銍艾，導我之前村。", "露晞芒屨滑，地僻秋蕪繁。", "行行不逾里，委蛇到其門。", "父老喜客至，爲黍烹雞豚。", "勸我當力穡，醉中多好言。", "低頭謝父老，我志久已存。", "歸來三歎息，默誦歸田園。"]'),
('117b9ebc-1122-4eb5-803c-05b872378844','壬午秋日觀橋刈穫五首  其二','周紫芝','宋','宋诗','song-poetry','','[]','交親不相知，笑我營小築。',96,'全唐诗/poet.song.86000.json','["交親不相知，笑我營小築。", "人生如風燈，一滅不容續。", "勝負棋一枰，信手安用覆。", "與君共此世，百歲但信宿。", "進退均有求，要各隨所欲。", "君軌趨朝市，我履在林麓。", "胡爲浪相笑，吾計念已熟。", "客來不與辨，聊用銘我屋。"]'),
('5b51755b-2e91-4ea7-8f51-33eb2140bf94','壬午秋日觀橋刈穫五首  其三','周紫芝','宋','宋诗','song-poetry','','[]','胡馬嘶北風，遊子思故鄉。',108,'全唐诗/poet.song.86000.json','["胡馬嘶北風，遊子思故鄉。", "富貴人所羡，危機亦難防。", "幕上巢豈安，劍頭炊易傷。", "乃知三畝耕，此策爲最良。", "寒士但藜藿，肉食餘膏粱。", "脱粟衆所食，萬錢誰得甞。", "終然均一飽，果腹俱徜徉。", "飯蔬豈不樂，厚味生禍殃。", "以此較得失，豈復無短長。"]'),
('7824e128-4cbc-4475-9c8d-d88f536063ce','壬午秋日觀橋刈穫五首  其四','周紫芝','宋','宋诗','song-poetry','','[]','人言秋日短，無事日更長。',84,'全唐诗/poet.song.86000.json','["人言秋日短，無事日更長。", "籬落既補治，稼穡已滌場。", "薄暮有微興，悠然步東岡。", "東岡棗與梨，纍纍半青黄。", "幽菊雖未吐，已含風露香。", "風物良可喜，客來有杯觴。", "但使常如此，貧賤亦何傷。"]'),
('1d450995-e69b-4cd1-89ac-9341f8ae9dce','壬午秋日觀橋刈穫五首  其五','周紫芝','宋','宋诗','song-poetry','','[]','祠宫昔所築，古屋棲真靈。',96,'全唐诗/poet.song.86000.json','["祠宫昔所築，古屋棲真靈。", "誰知員嶠徙，亦歎曲池平。", "我即廢址北，結茅寄幽情。", "高秋肅萬籟，彷彿聞簫笙。", "夜夢着瓊冠，結佩朝玉京。", "談笑悟至理，俯仰了八紘。", "安能事香火，餐霞學長生。", "明朝日復出，抱耒還躬耕。"]'),
('62e5ce48-9860-4523-8a8a-c1934f54d3e1','題龍眠畫四馬圖','周紫芝','宋','宋诗','song-poetry','','[]','裕陵神謨與天通，崑崙以西俱鑿空。',240,'全唐诗/poet.song.86000.json','["裕陵神謨與天通，崑崙以西俱鑿空。", "渥洼初來九夷服，盡得大宛三象龍。", "于闐鳳腦世未識，但見蹴踏長秋風。", "鬼章錦膊驚絕代，更看吐蕃獅子驄。", "胡兒骯髒雙眼碧，錦韀錯落青絲籠。", "最後一匹號雄健，見自往來天仗中。", "羽林騎士鐵撾肅，鳴珂蹀躞纓垂紅。", "諸番入貢御閑溢，君王晝坐蓬萊宫。", "爲臨玉陛閱神駿，詔寫真形誰最工。", "龍眠妙伎非俗畫，不數當年老曹霸。", "三驄豈是拳毛騧，俶儻權奇頗閑暇。", "籋雲之姿迣萬里，太一來貺天馬下。", "內人傳看十二蹄，一笑微生咫尺威。", "自從鼎湖弓劍墜，龍媒上天久不歸。", "只今空對畫圖泣，忍聽鳥呼金粟堆。"]'),
('31df12d7-83a0-495a-b139-73885c849b62','遊麻姑觀','周紫芝','宋','宋诗','song-poetry','','[]','清秋禾黍罷，南畝幽事少。',132,'全唐诗/poet.song.86000.json','["清秋禾黍罷，南畝幽事少。", "凌晨有佳興，振策事輕矯。", "微蹤躡飛猱，雄眺高木杪。", "上有仙子祠，棟宇頗傾撓。", "騰虚想雲軿，遺像空鳥爪。", "黄冠三四輩，生意良草草。", "更欲問丹爐，雲山遂窮討。", "道人笑不言，此意未遽曉。", "但云須趣轅，山靜虎出早。", "勝踐良獨難，仙事亦杳渺。", "了知世俗人，塵凡隔蓬島。"]'),
('c22841e3-3637-459b-92ae-07f24312c891','小壺貯江蠟二梅幽絕俱可喜作三絕  其一','周紫芝','宋','宋诗','song-poetry','','[]','遮眼梅花不要多，着人無復奈香何。',32,'全唐诗/poet.song.86000.json','["遮眼梅花不要多，着人無復奈香何。", "月明羞看銅壺影，矮樹斜枝憶短坡。"]'),
('7f59e9db-eeff-4687-92cd-abcc194ba08a','小壺貯江蠟二梅幽絕俱可喜作三絕  其二','周紫芝','宋','宋诗','song-poetry','','[]','吳娘解滴酥成蘂，天女能融蠟作花。',32,'全唐诗/poet.song.86000.json','["吳娘解滴酥成蘂，天女能融蠟作花。", "付與詩人說妍醜，風流二士本同家。"]'),
('3a1204de-31bf-4878-ae03-02b6b65430ef','小壺貯江蠟二梅幽絕俱可喜作三絕  其三','周紫芝','宋','宋诗','song-poetry','','[]','天上姮娥白玉肌，蘂珠宫女鬰金衣。',32,'全唐诗/poet.song.86000.json','["天上姮娥白玉肌，蘂珠宫女鬰金衣。", "相逢月下渾無語，笑指蓬壺作伴歸。"]'),
('2744d07c-86de-428b-bdd6-38a6d560d570','病中戲作本草詩','周紫芝','宋','宋诗','song-poetry','','[]','長空青雲晝風卷，雨餘凉生開病眼。',342,'全唐诗/poet.song.86000.json','["長空青雲晝風卷，雨餘凉生開病眼。", "垣衣洗雨綠生光，芍藥翻階紅照晚。", "幽人却掃驚半夏，獨杜衡門心頗遠。", "提壺勸酒意甚勞，花間伏翼終日號。", "大棗如爪安可得，竹葉豈宜空蟹螯。", "何當如淮注石斛，天南星移碎紅燭。", "錦纒更命劉寄奴，回雪香柔體如玉。", "人生富貴不早休，烏頭成白空自愁。", "浩歌自駕木蘭去，范蠡實能知遠遊。", "君不見赤車使者將君命，五加皮幣不少留。", "一朝逐客便當去，王不留行空淚流。", "又不見浪蕩子長負羈槖，石下長卿無住着。", "賈論空高遠志孤，屈草初成奇禍作。", "何如獨活考澗槃，不遇自然同此樂。", "嗟余知此解馬衘，蝸廬僻在陵陽角。", "誰能更朝紫真壇，丹砂豈解駐衰顔。", "五色神符亦安用，菖蒲謾說能引年。", "玉泉泠泠漱虚壑，獨尋鶴虱負朝暄。", "故人遠引羈旅夕，寒水石畔思清言。", "何時從容乃如此，煙蓑去作牽牛子。", "平生甘遂丘壑貧，常有憂懷思洗耳。"]'),
('2508aa0b-7462-42c0-bbd5-ed33adda6798','道由於潛將遊西菩問之路人則云過之已遠','周紫芝','宋','宋诗','song-poetry','','[]','人生如落花，隨寓皆可喜。',120,'全唐诗/poet.song.86000.json','["人生如落花，隨寓皆可喜。", "但恐兜羅綿，牽連入荆杞。", "我馬今未羈，猶堪作幽事。", "道逢西菩山，欲問參寥子。", "舉鞭信蹇驢，褰裳渡流水。", "隱約望三山，展轉纔十里。", "吳兒指似儂，但隔一山耳。", "塗窮殊可笑，興盡亦復止。", "吾曹坐天阨，萬事無不爾。", "小者今復然，大者斯已矣。"]'),
('8370ea25-9e11-4058-91f9-4ad2fb7a3470','越臺夜雨','周紫芝','宋','宋诗','song-poetry','','[]','夜暗秦淮雨，燈昏越女祠。',48,'全唐诗/poet.song.86000.json','["夜暗秦淮雨，燈昏越女祠。", "寒窗歸夢短，秋枕客情知。", "鳧雁初何定，雞蟲事亦卑。", "明朝江上去，重理釣魚絲。"]'),
('14495599-8a05-4bd8-9000-3de806a63913','晚遊戒珠寺寺王逸少舊宅寺僧秉燭觀王右軍畫像出訪鵝墨二池歸已三更','周紫芝','宋','宋诗','song-poetry','','[]','悠悠倦徂征，忽忽厭羈旅。',144,'全唐诗/poet.song.86000.json','["悠悠倦徂征，忽忽厭羈旅。", "出門復風埃，况乃迫繁暑。", "兹遊愜初心，突兀見精宇。", "高人昔所廬，樹木亦奇古。", "微風入冠裳，林影散廊廡。", "僧窗靜無塵，燈火照眉宇。", "閱此坦腹姿，鬚髪稀可數。", "樂死固不虚，顔色如處女。", "平池渺清深，淅瀝過新雨。", "誰言臨池工，至技本天與。", "鵝羣久已空，團扇復何許。", "興盡且當歸，夜半月方吐。"]'),
('78d45b17-930d-4f56-b20c-63b6577efcb0','歸雲洞','周紫芝','宋','宋诗','song-poetry','','[]','南華老明師，遺像頗清古。',108,'全唐诗/poet.song.86000.json','["南華老明師，遺像頗清古。", "昔爲掛空月，今作歸雲土。", "雲來初無心，雲去定何處。", "空餘暗竇泉，翠盎含白乳。", "華堂誰復枝，缺甃久未補。", "林深自成風，山潤疑欲雨。", "窮幽眼未饜，曳杖足已苦。", "入山無與迎，出山信誰阻。", "有客自去來，山僧無一語。"]'),
('84efd26e-6d49-4c08-a477-e86711a89ab6','次韵次卿見寄','周紫芝','宋','宋诗','song-poetry','','[]','此生懷抱向誰開，唯有華顛苦見催。',64,'全唐诗/poet.song.86000.json','["此生懷抱向誰開，唯有華顛苦見催。", "萬事只今渾是夢，寸心堪笑已成灰。", "路長安得詩飛去，交淺唯愁雨不來。", "此意喜君無冷暖，尺書頻寄塞鴻回。"]'),
('9c699959-ff24-4a61-b93a-eb29405c1283','食瓜二首  其一','周紫芝','宋','宋诗','song-poetry','','[]','酇侯昔微時，刀筆一小吏。',108,'全唐诗/poet.song.86000.json','["酇侯昔微時，刀筆一小吏。", "起依日月光，勛業高百世。", "道大原不容，功高亦爲累。", "所以韓彭徒，纍纍就庖胾。", "蕭何于是時，身任天下寄。", "坐安劉帝心，賴有東陵計。", "東陵固明哲，避地有深意。", "此物原不凡，世俗豈知味。", "此味當自知，未可語兒輩。"]'),
('585523e5-28b6-4e74-a896-ef9e3cf7be1e','食瓜二首  其二','周紫芝','宋','宋诗','song-poetry','','[]','元和數才子，例指到元白。',84,'全唐诗/poet.song.86000.json','["元和數才子，例指到元白。", "香山詆中奄，進寸輒退尺。", "元侯躐要塗，崔子實卵翼。", "兩公賢與愚，何啻白與黑。", "二武有直氣，詆評恣呵斥。", "蒼蠅從何來，汙我盤中食。", "想像懷昔人，撫几三歎息。"]'),
('cb0a7fdf-aa9e-483b-9391-aa27b2fdaab7','遊衡廊山山中有梁武帝杯渡禪師像','周紫芝','宋','宋诗','song-poetry','','[]','瀛渤從來是一漚，何妨飛錫到中州。',32,'全唐诗/poet.song.86000.json','["瀛渤從來是一漚，何妨飛錫到中州。", "解將瓶鉢橫雲海，懶向秦淮障逆流。"]'),
('cd9cc728-961e-4b52-acc8-188123f90c2d','次韻韋深道見寄','周紫芝','宋','宋诗','song-poetry','','[]','不見蘇州五字詩，韋郎有句解人頤。',64,'全唐诗/poet.song.86000.json','["不見蘇州五字詩，韋郎有句解人頤。", "長鑱白柄林間事，折角烏巾世外姿。", "失馬未應無後福，亡羊政恐坐多岐。", "人生一笑真難事，白髮逢君苦恨遲。"]'),
('76f970b4-9e35-407f-9bc9-b94650a2de79','宿琴高巖二首  其一','周紫芝','宋','宋诗','song-poetry','','[]','琴高古仙人，控鯉飛上天。',144,'全唐诗/poet.song.86000.json','["琴高古仙人，控鯉飛上天。", "丹鑪訪遺跡，邂逅餘山巔。", "石壁削寒玉，萬仭凌雲煙。", "隱雨有石屋，垂釣臨平川。", "舊聞釣處石，可坐八九筵。", "邑宰頗呼客，醉歌日留連。", "里胥厭追索，挽石沈深淵。", "高秋見涯涘，巨石呈方圓。", "斯民不可擾，此理甚坦然。", "豈非仙聖居，未易汙葷羶。", "餘生欣晚遇，想像追真仙。", "净綠不敢唾，薄暮聊周旋。"]'),
('51b73f90-a69f-4cef-bcb7-40d6996c9281','宿琴高巖二首  其二','周紫芝','宋','宋诗','song-poetry','','[]','長川抱空巖，春水三月深。',144,'全唐诗/poet.song.86000.json','["長川抱空巖，春水三月深。", "有魚歲一來，瑣細如寸針。", "網魚聚乾腊，白艇爭分陰。", "與人作苞苴，囊紗走權門。", "人言投鱠殘，成魚只侵尋。", "豈有仙家庖，烹鮮赤刀砧。", "又言棄藥滓，入水成纖鱗。", "仙事亦渺茫，詎可窮本因。", "不知誰作古，遺禍今猶存。", "殺魚歲億萬，可易千黄金。", "僅令貴公子，醉嚼聊一欣。", "世俗自乃爾，仙人亦何心。"]'),
('cbe2c951-f2bb-4b5e-b486-5ccc3c6dc637','宿隱靜作','周紫芝','宋','宋诗','song-poetry','','[]','短策羸驂山路長，松陰十里午風涼。',64,'全唐诗/poet.song.86000.json','["短策羸驂山路長，松陰十里午風涼。", "飛來一水自碧落，屹立五峰叢寶坊。", "青鳥也隨人聽法，老禪聊爲客燒香。", "泉聲繞枕渾如雨，月色滿巖疑是霜。"]'),
('78413efa-5b46-402b-a4ea-3620061e8754','次韻石端若惠長句','周紫芝','宋','宋诗','song-poetry','','[]','仲容無雙天下士，草木自應殊臭味。',256,'全唐诗/poet.song.86000.json','["仲容無雙天下士，草木自應殊臭味。", "嵇康似鶴在雞羣，子陽如蛙真井底。", "小巫神氣驚大巫，一見斂顔羞欲死。", "眼無皂白敢妍媸，口有雌黄誰𧬈訾。", "借令卷舌終自羞，吾顙嶢然寧不泚。", "伯仁大腹號空洞，步兵醉語無臧否。", "君方二子不啻過，視我當如發蒙耳。", "浪將五字比長城，要爲庖丁作餘地。", "人言政似韓潮州，欲借新聲與侯喜。", "蒼顔槁項日摧頹，回雪流風更雄偉。", "乃知愚知本相懸，何啻人間三十里。", "我詩頗似西臺書，時雖可喜終可鄙。", "人言嫫毋不自憐，捧心成顰亦成恥。", "少年有意慕黄初，豈料永嘉聞正始。", "詩壇新拜少陵侯，頗笑棘門兒子戲。", "勸君此語勿浪傳，俗物還來敗人意。"]'),
('bdafdd8c-3221-4834-ac57-696ca69b1b7d','次韻端若再惠長句','周紫芝','宋','宋诗','song-poetry','','[]','功名本是兒時事，過是懸知終少味。',256,'全唐诗/poet.song.86000.json','["功名本是兒時事，過是懸知終少味。", "向來欲度驊騮前，無命能居百僚底。", "未容晚輩識風流，頓遣前賢隔生死。", "黨獄十年猶未開，讒口囂囂苦相訾。", "且將皮裏著陽秋，敢復眼前分濁泚。", "顔之厚矣終自羞，論少卑之人亦否。", "路逢俗士呼與言，公獨未知其趣耳。", "無人爲弔楚客魂，誰肯更作將軍地。", "此心此語只自知，聞君足音驚且喜。", "詞傾三峽頗壯觀，氣吞雲夢真奇偉。", "時從霧豹得一斑，行看飛黄日千里。", "如君人物尚淹留，此事寧非肉食鄙。", "枘方雖自與鑿乖，瓶竭那知是罍恥。", "一生恨未識荆州，萬事政須咨伯始。", "忘形已自到爾汝，論事何妨雜嘲戲。", "人生一笑不易得，莫遣征航有歸意。"]'),
('c23a9c8d-e8a4-4fa5-8233-6e9cfdf8ef2a','次韵伯尹贈奇童二絕句  其一','周紫芝','宋','宋诗','song-poetry','','[]','它人有子但豚犬，是家此郎真芝蘭。',32,'全唐诗/poet.song.86000.json','["它人有子但豚犬，是家此郎真芝蘭。", "异時筆底問珠玉，已在只今眉宇間。"]'),
('0164d2b7-ea22-4a2c-8580-499902a8caa7','次韵伯尹贈奇童二絕句  其二','周紫芝','宋','宋诗','song-poetry','','[]','昔聞徐卿有二子，今喜衞家稱一兒。',32,'全唐诗/poet.song.86000.json','["昔聞徐卿有二子，今喜衞家稱一兒。", "只有九方真具眼，固應知是渥洼姿。"]'),
('18636142-28b5-4d6b-9cac-d52deecb7f4f','次韵伯尹晚遊松林寺','周紫芝','宋','宋诗','song-poetry','','[]','詹侯學古淡，胸次無炎冷。',156,'全唐诗/poet.song.86000.json','["詹侯學古淡，胸次無炎冷。", "高情屏嗜好，邃宇極深靜。", "清心樂幽禪，世外得佳境。", "靜悟已聞法，踴躍更深省。", "應復嗤衛侯，耄期猶自警。", "能事兩禪師，句法頗清穎。", "無誰可悟言，舉世我獨醒。", "故來追若人，兩耳靜蛙黽。", "我生塵埃中，況迫桑榆景。", "安得薝蔔林，婆娑共清影。", "君今富春秋，器業窺魏丙。", "兹遊慎無厭，流光不俄頃。", "恐未免簪纓，問道勤造請。"]'),
('30bd5a5d-6397-426c-8f9b-038776849872','次韻韋深道獨樂堂十絕  其一','周紫芝','宋','宋诗','song-poetry','','[]','廊廟登元勳，四海歌畫一。',24,'全唐诗/poet.song.86000.json','["廊廟登元勳，四海歌畫一。", "羣公各交章，君乃卜少室。"]'),
('373ab8c5-085a-4ba6-b011-1e5fbbe1fe23','次韻韋深道獨樂堂十絕  其二','周紫芝','宋','宋诗','song-poetry','','[]','人生幾蠟屐，千古一草堂。',24,'全唐诗/poet.song.86000.json','["人生幾蠟屐，千古一草堂。", "得失了自判，較然不須量。"]'),
('a5165147-ca7e-4dd3-a868-1e73f5e1b82c','次韻韋深道獨樂堂十絕  其三','周紫芝','宋','宋诗','song-poetry','','[]','棐几坐永日，巖花動微風。',24,'全唐诗/poet.song.86000.json','["棐几坐永日，巖花動微風。", "未知堂中人，此樂誰與同。"]'),
('da614df3-8e40-4a8a-a0b9-0bd8efa9896b','次韻韋深道獨樂堂十絕  其四','周紫芝','宋','宋诗','song-poetry','','[]','達人信死生，過眼閱暖冷。',24,'全唐诗/poet.song.86000.json','["達人信死生，過眼閱暖冷。", "了知夢境中，此味獨差永。"]'),
('cb4cabd1-94a9-4a06-a6cc-69d3d8b113c0','次韻韋深道獨樂堂十絕  其五','周紫芝','宋','宋诗','song-poetry','','[]','曩喜韋蘇州，有句盡平淡。',24,'全唐诗/poet.song.86000.json','["曩喜韋蘇州，有句盡平淡。", "只今把君詩，去眼不可暫。"]'),
('53a5f7db-f614-46e4-9f21-0ed743daac65','次韻韋深道獨樂堂十絕  其六','周紫芝','宋','宋诗','song-poetry','','[]','鬻錢走京師，我笑員半千。',24,'全唐诗/poet.song.86000.json','["鬻錢走京師，我笑員半千。", "玉階求自試，北牖輸高眠。"]'),
('c2cd282c-1b46-4ec6-9cdc-428d7117ed61','次韻韋深道獨樂堂十絕  其七','周紫芝','宋','宋诗','song-poetry','','[]','聞君開華堂，圖書富千古。',24,'全唐诗/poet.song.86000.json','["聞君開華堂，圖書富千古。", "應笑碧衣郎，試吏坐藍縷。"]'),
('d6c5d2f5-0039-4ea4-90c2-cc4c1188b091','次韻韋深道獨樂堂十絕  其八','周紫芝','宋','宋诗','song-poetry','','[]','愛酒惜杯乾，懶衣愁客至。',24,'全唐诗/poet.song.86000.json','["愛酒惜杯乾，懶衣愁客至。", "世無錦江翁，誰識幽人意。"]'),
('7035fcf1-e340-4a40-81bd-8bb0971e6fa7','次韻韋深道獨樂堂十絕  其九','周紫芝','宋','宋诗','song-poetry','','[]','草木各有態，臭味久已分。',24,'全唐诗/poet.song.86000.json','["草木各有態，臭味久已分。", "願言蘭芷藂，東風佩微薫。"]'),
('461a1046-0352-4827-b12b-d9090eff8fa8','次韻韋深道獨樂堂十絕  其一○','周紫芝','宋','宋诗','song-poetry','','[]','跂首望蘅皋，遠目聊增明。',24,'全唐诗/poet.song.86000.json','["跂首望蘅皋，遠目聊增明。", "相逢定何夕，劇談到參橫。"]'),
('ebc8b3aa-a81d-4e32-ac06-6f5bb3cfdbd1','病後二首  其一','周紫芝','宋','宋诗','song-poetry','','[]','山有生前約，花留病後開。',48,'全唐诗/poet.song.86000.json','["山有生前約，花留病後開。", "得閑如我少，扶步與誰來。", "閉戶深防客，哦詩穩送杯。", "夕陽如有意，催月與徘徊。"]'),
('e4d58063-2928-4531-8ffc-960a508fff72','病後二首  其二','周紫芝','宋','宋诗','song-poetry','','[]','病起身還健，憑高喜欲顛。',48,'全唐诗/poet.song.86000.json','["病起身還健，憑高喜欲顛。", "亂山推不去，一水忽當前。", "遠碧飛雙鷺，平湍落釣船。", "自今如不死，餘日盡詩年。"]'),
('9b1bac13-8b37-453d-b47f-49e5ca83dc60','次韻詹伯尹舒天用和答二首  其一','周紫芝','宋','宋诗','song-poetry','','[]','豫章有奇氣，鏗然兩青萍。',48,'全唐诗/poet.song.86000.json','["豫章有奇氣，鏗然兩青萍。", "埋光久未識，神焰凌太清。", "二子廊廟姿，肯負丘壑情。", "會當束冠裳，未可終巖坰。"]'),
('03821da9-319b-4751-87ad-6f618eb425d9','次韻詹伯尹舒天用和答二首  其二','周紫芝','宋','宋诗','song-poetry','','[]','我生如眢井，蕪穢久不鑿。',48,'全唐诗/poet.song.86000.json','["我生如眢井，蕪穢久不鑿。", "况此一日别，輒作數日惡。", "碧雲晚自合，紅日麗林薄。", "思君在何許，行行繞飛閣。"]'),
('bb6858c8-f8c6-463a-8b1d-d6681235fa30','白桃','周紫芝','宋','宋诗','song-poetry','','[]','緗桃落盡又春回，雪白桃花最後開。',64,'全唐诗/poet.song.86000.json','["緗桃落盡又春回，雪白桃花最後開。", "怪我此生新入眼，問君何處舊移栽。", "枝頭已暖猶餘雪，江上從今不數梅。", "只有玉人宜玉樹，翠鬟應近小粧臺。"]'),
('22d02908-8ae6-4101-b7da-170f730ff932','次韻劉元素','周紫芝','宋','宋诗','song-poetry','','[]','白頭煩惱不堪醒，滿引休嫌酒趣行。',64,'全唐诗/poet.song.86000.json','["白頭煩惱不堪醒，滿引休嫌酒趣行。", "世事可驚嗟豆落，人生安得俟河清。", "舊交傾盖由來久，年少論心苦不情。", "誰與寄聲劉校尉，肯來同此看春耕。"]'),
('ce65a4db-3254-49c1-ab79-0addd2494b96','次韻黄夢及見寄','周紫芝','宋','宋诗','song-poetry','','[]','長卿未老久倦遊，家無斗酒不得州。',296,'全唐诗/poet.song.86000.json','["長卿未老久倦遊，家無斗酒不得州。", "平生拙甚屋背鳩，羊頭可爛身不侯。", "言輒觸諱恐轉喉，怒逢醉尉常反眸。", "廟堂戛擊方鳴球，老人行歌聊飯牛。", "我貧木奴欠千頭，夜長晝短懷百憂。", "巖栖谷汲誰與儔，草木黄落空悲秋。", "饑鷹小呼即下韝，老頑不受良工鎪。", "長年憔悴擬四愁，浮生無根同舞漚。", "更以外物爲贅疣，黄侯皎皎清且修。", "憐我南冠如楚囚，落筆袞袞不肯休。", "人物眼前無此流，合持五線裨冕旒。", "姓名下覆黄金甌，萬里一秣看驊騮。", "去年操瑟不見收，聞君欲買吴江舟。", "明珠白璧惜暗投，千金價重苦未酬。", "感君尺鯉論綢繆，逝將好我那肯魗。", "微吟有句亦復搜，敢撼大樹看蚍蜉。", "元龍氣高百尺樓，此而未遇彼則不。", "人雖曰畸天乃侔，會當有馹旌林丘。", "釣絲未可歸滄洲。"]'),
('42b77a6a-c61a-46d3-a6ca-8114d0ac0a97','和鄭文昌雨中看花之作','周紫芝','宋','宋诗','song-poetry','','[]','鄭侯好客如鄭莊，客常滿座酒滿觴。',195,'全唐诗/poet.song.86000.json','["鄭侯好客如鄭莊，客常滿座酒滿觴。", "春來洛城被花惱，千金一醉姚家黄。", "慇懃置酒急招喚，更來古寺窺紅粧。", "春風微寒春雨細，秉燭看花花已睡。", "春光駘蕩與妖妍，夜色侵凌增娬媚。", "臥枝不起終無言，臉淚欲垂如有意。", "樽中有酒客當歌，我醉欲眠人未起。", "君不見春來雨急風屢顛，危芳墮地無餘妍。", "掃花恐被落紅笑，持杯欲倩何人傳。", "愁多滿懷樂事少，人自惜花天不憐。", "烹羊炰羔且爲樂，酒酣耳熱亦不惡。", "明朝有興却重來，莫遣殘紅抱青萼。"]'),
('49582f97-2f70-49bd-a5e5-1ec7b1d31ca8','題王摩詰畫袁邵公臥雪圖','周紫芝','宋','宋诗','song-poetry','','[]','東京數人物，矯矯稱袁公。',168,'全唐诗/poet.song.86000.json','["東京數人物，矯矯稱袁公。", "經綸有能事，早歲初未逢。", "何許結蓬茅，草樹風淅瀝。", "幽夢寄一椽，暮雪深幾尺。", "平田已無路，况復知公門。", "人言公苦寒，謂死寧當存。", "鳴騶入空谷，暖律破寒沍。", "豈伊逢異人，天實起僵仆。", "漢明號賢主，杖擊無名郎。", "冤囚我自理，微緒渠當昌。", "摩詰亦可人，六幅寫奇事。", "浩蕩懷遠圖，徘徊有佳思。", "炎天掛空壁，一洗毛骨寒。", "意豈在冰雪，高風薄雲端。"]'),
('ae80e4e1-190b-49db-aae8-4e0f6d980fb3','浴罷書妙嚴壁','周紫芝','宋','宋诗','song-poetry','','[]','雲散香槽客未回，月團重瀹睡餘杯。',32,'全唐诗/poet.song.86000.json','["雲散香槽客未回，月團重瀹睡餘杯。", "小窗斜日無人語，只有松聲入夢來。"]'),
('1f49e2af-b198-4149-b951-12451bd38ecd','杖藜','周紫芝','宋','宋诗','song-poetry','','[]','杖藜款幽步，苑囿粲景物。',108,'全唐诗/poet.song.86000.json','["杖藜款幽步，苑囿粲景物。", "汪灣小池間，草樹極幽鬱。", "潑剌跳魚鳴，聿役科斗出。", "高荷爲誰芳，清芬苦飄忽。", "鷺下復飛去，偃蹇不易屈。", "空餘扁舟閑，菱藻互蒙密。", "餘生本江湖，幸不困簪紱。", "豹席與椶轎，願此寄清逸。", "一水便有餘，焉用跨溟渤。"]'),
('04c37850-4ae7-4502-a509-ad82c4ad06b9','秋晚二絕  其一','周紫芝','宋','宋诗','song-poetry','','[]','涼月初欣薄露天，井梧吹葉又淒然。',32,'全唐诗/poet.song.86000.json','["涼月初欣薄露天，井梧吹葉又淒然。", "牆根可笑無名草，依倚秋風翹碧鮮。"]'),
('c5410cf8-a4d1-4916-b396-357c41c19aaa','秋晚二絕  其二','周紫芝','宋','宋诗','song-poetry','','[]','月向寒林欲上時，露從秋後已沾衣。',32,'全唐诗/poet.song.86000.json','["月向寒林欲上時，露從秋後已沾衣。", "微螢不自知時晚，猶抱餘光照水飛。"]'),
('a9b9e533-8455-4e4a-93c8-d97da7e025d9','次韻徐南美題趙彥符拳石','周紫芝','宋','宋诗','song-poetry','','[]','翩翩佳公子，逸氣凌青雲。',60,'全唐诗/poet.song.86000.json','["翩翩佳公子，逸氣凌青雲。", "戲寫蒼石姿，遂逼仇池真。", "平生三昧手，舉世誰與倫。", "清詩爲披拂，警語良亦神。", "一朝入雙眼，二妙俱可人。"]'),
('6801cfe5-8ed2-4014-89b8-2032b201334d','次韻南美再賦簡僕與王次卿賈善長','周紫芝','宋','宋诗','song-poetry','','[]','交游得二子，淡如秋空雲。',60,'全唐诗/poet.song.86000.json','["交游得二子，淡如秋空雲。", "長頭喜問事，坦腹意自真。", "但飽北山蔬，固應嗤阿倫。", "句法未得妙，畫品如入神。", "豈兹一漫士，可並千載人。"]'),
('150a3072-73bc-4ac6-bde4-e2957689159d','讀高帝紀','周紫芝','宋','宋诗','song-poetry','','[]','始皇坑儒生，秦室遂顛覆。',144,'全唐诗/poet.song.86000.json','["始皇坑儒生，秦室遂顛覆。", "取冠溺其中，何乃踵前躅。", "亭長初秦民，秦事鑒已熟。", "事有異取舎，安用自窘束。", "方從豐沛豪，起逐中原鹿。", "君王自神武，将士豈局促。", "當時分漢茅，素行甚汚辱。", "屠沽與刀筆，雜然非一族。", "叔孫晚見推，韓彭旋烹戮。", "一弛復一張，往往如轉軸。", "高皇躬獨斷，此理深照燭。", "英風渺何之，遺事空簡牘。"]'),
('afbbd644-f0a3-4030-b7fd-26c5829e0fd1','讀淮陰傳','周紫芝','宋','宋诗','song-poetry','','[]','淮陰一世豪，勳業滿天地。',168,'全唐诗/poet.song.86000.json','["淮陰一世豪，勳業滿天地。", "晚莭不自全，遺恨在百世。", "君臣如父子，焉得置猜忌。", "功高良易疑，地大苦難制。", "折箠下燕齊，羣豪自風靡。", "豈有須假王，而可鎮齊僞。", "禍生固有胎，失在此舉爾。", "沛公窘滎陽，齊卒盡精銳。", "頡頏楚漢間，事若反掌易。", "信豈不自王，何乃遣漢使。", "帝意自此疑，齊楚終易位。", "噲等何足羞，鞅鞅遂失意。", "晚路說陳豨，咄嗟甚兒戲。", "吕姥何能爲，公乃自失志。"]'),
('29396810-eea9-4f3c-a3fa-b99ca2f89812','二月二十八日雪晴步上西山亭示天用兄弟二首  其一','周紫芝','宋','宋诗','song-poetry','','[]','山崦猶殘雪，人家欲禁煙。',48,'全唐诗/poet.song.86000.json','["山崦猶殘雪，人家欲禁煙。", "客寧嫌鳥語，晴亦借花妍。", "愁色連千里，春風又一年。", "亭高莫回首，白髮滿江天。"]'),
('b5c35739-fe13-4695-a487-bcad6053594f','二月二十八日雪晴步上西山亭示天用兄弟二首  其二','周紫芝','宋','宋诗','song-poetry','','[]','晴色牽人出，春風惱不歸。',48,'全唐诗/poet.song.86000.json','["晴色牽人出，春風惱不歸。", "鳥爭呼永日，花各醉斜暉。", "杖策從誰去，持杯與願違。", "兵戈愁外滿，人物眼中稀。"]'),
('dfc9be85-8d3f-4b2f-abc1-36bf07afc5a7','和人摘茶','周紫芝','宋','宋诗','song-poetry','','[]','結廬聞似輞川家，更趁東風摘露芽。',64,'全唐诗/poet.song.86000.json','["結廬聞似輞川家，更趁東風摘露芽。", "短夢喚回春正好，枯腸搜盡句方嘉。", "酪奴語陋真堪笑，瑞草名高豈復加。", "明歲莫教煙雨裏，白薔薇秀小巖花。"]'),
('700a2f48-cdd2-4b67-bacb-9103d90d5a62','次韻姑谿興國寺晚眺','周紫芝','宋','宋诗','song-poetry','','[]','禪房花木有殘紅，此地還因曲徑通。',64,'全唐诗/poet.song.86000.json','["禪房花木有殘紅，此地還因曲徑通。", "竹影看搖金瑣碎，風鈴解語玉丁東。", "人來白鳥横空處，山在先生倚杖中。", "絕唱未酬才已盡，夜燈搔首鬢如蓬。"]'),
('f82b7266-d26b-40cc-9cb9-39a35f2b0a20','錢申仲大夫索四亭詩各賦一首 白雲亭','周紫芝','宋','宋诗','song-poetry','','[]','登臨思昔人，有意在山麓。',72,'全唐诗/poet.song.86000.json','["登臨思昔人，有意在山麓。", "舉首瞻孤雲，悵懷思宰木。", "雲亦初何心，意乃自感觸。", "人生風木念，此念何由足。", "忽忽不可留，悠悠空滿目。", "願言結斯廬，聊用慰幽獨。"]'),
('c6fea31a-9e4d-4102-ab20-7644df554b10','錢申仲大夫索四亭詩各賦一首 芳美亭','周紫芝','宋','宋诗','song-poetry','','[]','春風始用事，天意有反覆。',72,'全唐诗/poet.song.86000.json','["春風始用事，天意有反覆。", "坐令冰雪姿，吹作錦繡谷。", "粲粲玄都花，依依照人目。", "花氣欲薫人，醉眼眩紅綠。", "想當瓮頭春，頗爲客頻漉。", "慎勿遣紅雨，零亂飛滿屋。"]'),
('4f6e1793-f200-426f-bd1e-63da0b2bd3e6','錢申仲大夫索四亭詩各賦一首 遂初亭','周紫芝','宋','宋诗','song-poetry','','[]','爲貧作漫仕，未必勝陸沈。',72,'全唐诗/poet.song.86000.json','["爲貧作漫仕，未必勝陸沈。", "冠纓日羈縻，鬢髮空侵尋。", "昔爲雲出岫，今作鳥歸林。", "暮年一丘壑，往往諧初心。", "窗明設浄几，衣露張鳴琴。", "緬懷靖節翁，更賦歸來吟。"]'),
('27867c65-049a-4c5c-b968-481b6d6bded0','錢申仲大夫索四亭詩各賦一首 通惠亭','周紫芝','宋','宋诗','song-poetry','','[]','昔人品淄澠，惠山壓東南。',72,'全唐诗/poet.song.86000.json','["昔人品淄澠，惠山壓東南。", "誰知十里隔，通此一勺甘。", "初不勞籜龍，漫山走嵌巖。", "方池汲清碧，地脈通溶涵。", "甆甌落飛雪，石鼎鳴風杉。", "懸知與佳客，午夢回春酣。"]'),
('011901e5-3d56-4ae1-a274-8666b0240f70','次卿與余終日坐竹間以何人有酒身無事誰家多竹門可款爲韻余得上七字  其一','周紫芝','宋','宋诗','song-poetry','','[]','養痾慕夷曠，避俗蒙譏訶。',72,'全唐诗/poet.song.86000.json','["養痾慕夷曠，避俗蒙譏訶。", "用兹結神交，長年與婆娑。", "脩篁不見天，萬玉方森羅。", "隱几張淨琴，共鼓南風歌。", "人生要行樂，取樂不必多。", "儻無一笑適，奈此風月何。"]'),
('8a15bde3-0ff9-4447-a714-d8d909dac0f1','次卿與余終日坐竹間以何人有酒身無事誰家多竹門可款爲韻余得上七字  其二','周紫芝','宋','宋诗','song-poetry','','[]','典午方中否，舉世無賢人。',72,'全唐诗/poet.song.86000.json','["典午方中否，舉世無賢人。", "高爵豈不佳，奇禍終相因。", "七子各見幾，引身良及辰。", "至今白眼徒，往往多怒嗔。", "愚智不同調，孤高固難羣。", "自信苟不疑，俗說空紛紛。"]'),
('ffc26609-18dc-47bc-a6c9-9cf8d881e810','次卿與余終日坐竹間以何人有酒身無事誰家多竹門可款爲韻余得上七字  其三','周紫芝','宋','宋诗','song-poetry','','[]','人言不如意，十事常八九。',72,'全唐诗/poet.song.86000.json','["人言不如意，十事常八九。", "君看得意人，奪去亦難守。", "子雲草玄文，覆瓿人不取。", "更喜淵明門，春風五楊柳。", "當年富貴士，泯默亦何有。", "乃知百世下，静者差得久。"]'),
('5d2f4ddc-9686-4f1f-a4c9-086c0a8b3c6a','次卿與余終日坐竹間以何人有酒身無事誰家多竹門可款爲韻余得上七字  其四','周紫芝','宋','宋诗','song-poetry','','[]','昔年嗜酒人，常恐不到口。',72,'全唐诗/poet.song.86000.json','["昔年嗜酒人，常恐不到口。", "臥甕寧免賊，窺竇真若狗。", "幸兹身無事，家復有名酒。", "竹亦不待尋，清陰到窗牖。", "長嘯風滿襟，相勸杯在手。", "不知平生歡，重復有茲否。"]'),
('3a779794-fd20-40db-84fc-df2a45860c72','次卿與余終日坐竹間以何人有酒身無事誰家多竹門可款爲韻余得上七字  其五','周紫芝','宋','宋诗','song-poetry','','[]','人命甚脆弱，百歳良逡巡。',72,'全唐诗/poet.song.86000.json','["人命甚脆弱，百歳良逡巡。", "日月不可恃，齒髮寧長新。", "但恐㰦欠間，二首仍六身。", "塵冠急須彈，荷佩便可紉。", "願言同耦耕，永繼沮溺塵。", "會看此水頭，有人行問津。"]'),
('b8734a21-b488-4887-b933-5508e20c8aef','次卿與余終日坐竹間以何人有酒身無事誰家多竹門可款爲韻余得上七字  其六','周紫芝','宋','宋诗','song-poetry','','[]','子猷愛竹者，起臥與竹俱。',72,'全唐诗/poet.song.86000.json','["子猷愛竹者，起臥與竹俱。", "未知有何好，不可一日無。", "我亦澹少欲，鴻毛視金珠。", "眇觀霄壤間，無一可與娱。", "眷言此青士，平生有葭莩。", "可憐杜中舎，羽林觀萬夫。"]'),
('03724069-5fa3-4f66-8d85-c0f4626e3b62','次卿與余終日坐竹間以何人有酒身無事誰家多竹門可款爲韻余得上七字  其七','周紫芝','宋','宋诗','song-poetry','','[]','人生天宇間，動作均有寄。',72,'全唐诗/poet.song.86000.json','["人生天宇間，動作均有寄。", "誰知林下人，亦復有幽事。", "短步舒微芳，長吟抽逸思。", "有夢煩青奴，無絃須綠綺。", "寒日忽滿窗，香銷人未起。", "慎勿喚客來，昬昬敗人意。"]'),
('510473d5-470e-4259-b2d0-2de6b5babbae','次韻伯達大水見懷二絕  其一','周紫芝','宋','宋诗','song-poetry','','[]','雨漲平池綠似淮，半扉春水眼慵開。',32,'全唐诗/poet.song.86000.json','["雨漲平池綠似淮，半扉春水眼慵開。", "無錢得買扁舟去，莫道舊來今不來。"]'),
('523ef328-56dd-41a0-9af0-51d805b7eb50','次韻伯達大水見懷二絕  其二','周紫芝','宋','宋诗','song-poetry','','[]','相望千家信不通，懸知春在雨聲中。',32,'全唐诗/poet.song.86000.json','["相望千家信不通，懸知春在雨聲中。", "蹇驢欲去愁泥滑，安得西飛六尺鴻。"]'),
('dfa8df2b-7e7c-4593-b659-53f323c35feb','次韻趙思誠沈彥述春日和答','周紫芝','宋','宋诗','song-poetry','','[]','三千客裏賢公子，八詠詩中瘦沈郎。',64,'全唐诗/poet.song.86000.json','["三千客裏賢公子，八詠詩中瘦沈郎。", "他日功名垂竹帛，只今歌笑共杯觴。", "鳥能娱客時相勸，雨亦憐花不打香。", "喚取春來同一醉，天教閑日爲君長。"]'),
('de2f0e94-cdd9-47db-a5b6-4c82c3ca1b07','次韻次卿宴坐燒香二絕  其一','周紫芝','宋','宋诗','song-poetry','','[]','燕堂窗靜一簾垂，鵲尾薫濃客未知。',32,'全唐诗/poet.song.86000.json','["燕堂窗靜一簾垂，鵲尾薫濃客未知。", "稍憶風流王子晉，月明閑弄玉參差。"]'),
('dc26fae8-d799-4518-85d9-f3658a423d06','次韻次卿宴坐燒香二絕  其二','周紫芝','宋','宋诗','song-poetry','','[]','薄霧霏霏欲滿空，爐煙不動寶薫濃。',32,'全唐诗/poet.song.86000.json','["薄霧霏霏欲滿空，爐煙不動寶薫濃。", "莫将俗語譏時輩，更學東京范蔚宗。"]'),
('7312641b-1ffb-4acc-993c-ef731a569c9b','三月二十二日遊昭山前一日訥禪師死','周紫芝','宋','宋诗','song-poetry','','[]','今日天色佳，晴光與山秀。',108,'全唐诗/poet.song.86000.json','["今日天色佳，晴光與山秀。", "道人邀我出，共訪山中舊。", "馬首轉巖阿，佛屋露螭獸。", "殘花趣春事，白水決崖溜。", "山行亂人影，香火各奔輳。", "禪師秋月空，遺像孤鶴瘦。", "平生三昩句，高壓島與晝。", "風吹水成紋，妙語本天就。", "莫言鳩摩羅，臨死出神呪。"]'),
('b3a30abe-e939-48f6-b622-4475e07613ec','與松林道人求竹栽','周紫芝','宋','宋诗','song-poetry','','[]','人生殊臭味，不異蕕與薫。',120,'全唐诗/poet.song.86000.json','["人生殊臭味，不異蕕與薫。", "歲晚期金蘭，矯矯惟此君。", "緬懷古招提，脩竹如雲屯。", "道人淡無與，所居竹爲羣。", "餘陰滿窗戶，肯惜爲我分。", "他年蝸牛廬，浄几横清芬。", "疏疏便可意，靄靄亦足欣。", "千畝不足侯，萬夫寧是軍。", "客問有何好，仰屋不必言。", "幽徑儻可開，遲子日款門。"]'),
('242a16db-787e-4e93-b24d-869c1cb4fd10','次韻李姑谿過王次卿留終日','周紫芝','宋','宋诗','song-poetry','','[]','昔日風流李泰和，暮年流落竟如何。',64,'全唐诗/poet.song.86000.json','["昔日風流李泰和，暮年流落竟如何。", "追隨天驥元分路，蹭蹬金鑾不上坡。", "人物眼高誰睥睨，江山興在且婆娑。", "幅巾倒載歸時莭，想得扁舟漾月波。"]'),
('5b7ce2e3-5dae-4cd0-9f18-2daafb44d78a','次韻端叔題余所藏山谷茶詩尾','周紫芝','宋','宋诗','song-poetry','','[]','翰林門生兩蒼璧，似是天人人不識。',160,'全唐诗/poet.song.86000.json','["翰林門生兩蒼璧，似是天人人不識。", "學得黄初五字詩，不作人間萬錢食。", "晚向江頭看藥欄，花前一笑聊開顔。", "自言千載司玉局，尚記橋山分省宿。", "今朝玉乳打團龍，昨夜新詩刻紅燭。", "我識風流李元禮，人物流中有涇渭。", "平生漫刺不浪持，晚得龍門略相似。", "詩成袖手初相羊，便識從來錦作腸。", "夢回却誦矞雲句，彷彿官焙聞餘香。", "從今下客牛馬走，問字不妨時載酒。"]'),
('6e3e7a40-95b3-4eff-9858-818c6e575a60','次韻端叔疊前韻見貽因以爲别','周紫芝','宋','宋诗','song-poetry','','[]','夜光分得千金璧，從來有限未省識。',160,'全唐诗/poet.song.86000.json','["夜光分得千金璧，從來有限未省識。", "一從韶濩到兩耳，三月遂令忘肉食。", "高樓同倚百尺欄，江山滿眼方怡顔。", "先生官冷不坐局，古寺分牀雨中宿。", "清談亹亹不斷頭，幾度寒窗拔殘燭。", "晚歲升堂來問禮，誰遣黄流入清渭。", "金華上天朝紫皇，往事空勞公舉似。", "明日山中歸牧羊，九回日斷思公腸。", "他年華屋儻遂約，笑語尚聞蘭芷香。", "青絲絡馬不須走，一杯且飲姑谿酒。"]'),
('f3d14e6f-93d9-458e-9672-a1b65b03e7a1','次韻沈彥述官舎書事二絕  其一','周紫芝','宋','宋诗','song-poetry','','[]','幕中從事最能詩，恐是當年杜牧之。',32,'全唐诗/poet.song.86000.json','["幕中從事最能詩，恐是當年杜牧之。", "渠爲秋娘方覓句，莫將公事惱癡兒。"]'),
('a6de0bb9-d248-4a9b-8535-912bb2fbc2f1','次韻沈彥述官舎書事二絕  其二','周紫芝','宋','宋诗','song-poetry','','[]','晚得休文一解顔，識君曾是畫圖間。',32,'全唐诗/poet.song.86000.json','["晚得休文一解顔，識君曾是畫圖間。", "陽春白雪何由和，句有雌霓誦亦難。"]'),
('b44b5370-307f-4064-9a92-afd1e1aff690','擷野蔬示小兒','周紫芝','宋','宋诗','song-poetry','','[]','荒村無雞豚，何以供刀机。',144,'全唐诗/poet.song.86000.json','["荒村無雞豚，何以供刀机。", "山蔬雜百種，此物含妙理。", "幽居有勝事，一笑隨稚子。", "朝甑飯鳧茈，暮鼎羮馬齒。", "筍包出土肥，蕨芽含露紫。", "試採少陵苣，更擷天隨杞。", "舉杯香覆坐，搖喉滑流匕。", "悠然理塵策，果腹萬事已。", "君看金谷樓，步障五十里。", "韭虀及豆粥，爲具咄嗟耳。", "回觀奇禍作，一死政坐此。", "寄聲肉食徒，吾事勿輕鄙。"]'),
('bb4e1c46-a9f7-450f-88b3-e578670be206','題趙侯畫滄江遠岫圖','周紫芝','宋','宋诗','song-poetry','','[]','公子風流絕代無，名高當與大年俱。',32,'全唐诗/poet.song.86000.json','["公子風流絕代無，名高當與大年俱。", "自從剪得吴江水，不愛滕王蛺蝶圖。"]'),
('c151cf69-0d26-430a-bebc-b2d7ac10f79e','次韻吳思道贈姑谿道人','周紫芝','宋','宋诗','song-poetry','','[]','殘生擬覓山中伴，萬事厭從兒輩談。',64,'全唐诗/poet.song.86000.json','["殘生擬覓山中伴，萬事厭從兒輩談。", "笑我攜家常作客，羡君買地已成庵。", "早將遼海千年夢，換得曹谿一滴甘。", "聞與道人新結社，懶雲今不是常參。"]'),
('3f20e544-19a3-4405-8683-e4b20fdf4874','次韻次卿攜酒見過','周紫芝','宋','宋诗','song-poetry','','[]','睡過花時無好懷，柴門誰閉復誰開。',64,'全唐诗/poet.song.86000.json','["睡過花時無好懷，柴門誰閉復誰開。", "擬從月夜放舟去，更趁東風攜酒來。", "鬚髮且休論早白，悲歡正可付殘杯。", "君無舊雨仍今雨，相見應須日百回。"]'),
('265c870c-74c7-4353-88b6-55504a3b8a21','送虞伯瞻以宣城尉爲上元方田官','周紫芝','宋','宋诗','song-poetry','','[]','曩時人物詢石渠，風流文采知諸虞。',165,'全唐诗/poet.song.86000.json','["曩時人物詢石渠，風流文采知諸虞。", "老成不見典刑在，定識載行家有書。", "此郎胸中有涇渭，不比當年灞陵尉。", "可憐汗血名家駒，未有長途試千里。", "空鞭赤兔鞬臂弓，射殺窮山赤丸子。", "只今廊廟方賡歌，羣材並用肩相摩。", "将分壤地辨壚{擥手=木}，要追禹跡窮岷嶓。", "懸知使者欲推轂，豈止朱墨精研磨。", "簡書可畏君莫厭，會見天邊給飛傳。", "時來富貴亦偶然，且盡十分金瀲灧。"]'),
('fbb52baf-8787-4918-bcca-bc58a8b1b873','收次卿近書二首  其一','周紫芝','宋','宋诗','song-poetry','','[]','故國春空老，三吴信不通。',48,'全唐诗/poet.song.86000.json','["故國春空老，三吴信不通。", "客猶如社燕，書或寄賓鴻。", "鬢髮風埃裏，林廬夢寐中。", "西歸如有意，一笑復誰同。"]'),
('27cb0dd1-2ece-49a8-b7f7-1120819413eb','收次卿近書二首  其二','周紫芝','宋','宋诗','song-poetry','','[]','白水彭門道，秋風古戰場。',48,'全唐诗/poet.song.86000.json','["白水彭門道，秋風古戰場。", "人應思故國，樓更在斜陽。", "消息憑魚素，遊從問草堂。", "蘭芽知己茁，何日見諸郎。"]'),
('065f52d8-0678-40a3-9405-b755777b16b3','懷舊一首','周紫芝','宋','宋诗','song-poetry','','[]','三月既晦，維暮之春。',140,'全唐诗/poet.song.86000.json','["三月既晦，維暮之春。", "居我窮巷，門無雜賓。", "誰與晤語，千載一人。", "歌此好言，以侑清樽。", "酌我春醪，載笑載欣。", "言念我友，在彼彭門。", "江濆之别，于今三年。", "夐夐隻影，祗復自憐。", "素書聿至，式慰我心。", "蔚我嘉木，有鶯在林。", "尚求其友，載好其音。", "人而不如，有懷其愔。", "何當言歸，昔盟是尋。", "眷此二老，實爲蘭金。"]'),
('94ff4e57-ee2f-4c72-a337-cc59fddeb793','晚霽','周紫芝','宋','宋诗','song-poetry','','[]','翠葉看成幄，濃春喚不回。',48,'全唐诗/poet.song.86000.json','["翠葉看成幄，濃春喚不回。", "愁今連落絮，雨欲到黄梅。", "掃地花狼藉，開門燕往來。", "晴峰數點出，暝色一禽催。"]'),
('677aeff8-7092-45e2-94f2-6843bf6fdbe8','過張參軍故居曲肱亭舊基在焉山谷老人名亭且有詩所謂鄰雞呼不起擁被聽松風者是也','周紫芝','宋','宋诗','song-poetry','','[]','脫手新詩咳唾成，曹劉鮑謝未爲能。',64,'全唐诗/poet.song.86000.json','["脫手新詩咳唾成，曹劉鮑謝未爲能。", "少時不厭家如磬，歲晚聊因酒作丞。", "天與吾人終淡泊，才如此老不飛騰。", "盖棺何物無遺恨，太史知公解曲肱。"]'),
('34256a25-5d60-4311-8702-2b6b9266e376','雨餘便有秋意夜聞絡緯聲甚急','周紫芝','宋','宋诗','song-poetry','','[]','朝來三尺雨，一灑遍原隰。',144,'全唐诗/poet.song.86000.json','["朝來三尺雨，一灑遍原隰。", "秋風掃快霽，凉氣便相襲。", "幽人倚寒窗，睡眼已生澀。", "淅瀝聞井梧，風枝擺餘濕。", "推枕夜未央，牽幌月還入。", "凄然裘褐念，感此絡緯泣。", "嗟我豈不知，索衣寒無及。", "家機臥空軸，麻縷無可緝。", "殷勤語秋蟲，相煎何太急。", "誰能太早計，不死會當給。", "吾言甚酸寒，不足勞掇拾。", "書之示二豪，以當一笑集。"]'),
('68a27a22-0de3-4aa9-ab8f-d8bd7efd5702','入秋初種芭蕉','周紫芝','宋','宋诗','song-poetry','','[]','着葉芭蕉三四根，怕秋全似可憐人。',32,'全唐诗/poet.song.86000.json','["着葉芭蕉三四根，怕秋全似可憐人。", "老來安得無餘事，細聽維摩說是身。"]'),
('ffbd4fee-f8fe-4247-94d9-a27cc0f1a116','中秋無月夜半大雨忽憶去年江樓之會','周紫芝','宋','宋诗','song-poetry','','[]','去年秋半西江口，夜上江樓飲江酒。',160,'全唐诗/poet.song.86000.json','["去年秋半西江口，夜上江樓飲江酒。", "欲問青天借玉盤，等得浮雲變蒼狗。", "天風慘澹含清秋，夜色蒼茫江水流。", "移床傍簷看月出，月未肯出令人愁。", "圓蘆吹裂客罷語，恐在丹霄復何許。", "一聲初自耳邊來，三更却向樓前去。", "人生無定可堪論，東西南北似浮雲。", "故人吹散天一角，驚鴻零落秋江羣。", "今年不聽鳴江櫓，月黑風悲窗繞樹。", "一杯無酒可澆愁，夜閉蓬門聽風雨。"]'),
('88b2e30c-9520-43a9-9069-00df0c541cf9','九日至蘇家園','周紫芝','宋','宋诗','song-poetry','','[]','良辰不浪出，坐久無誰言。',144,'全唐诗/poet.song.86000.json','["良辰不浪出，坐久無誰言。", "閑攜老鈴去，旋覓登高樽。", "悠然理孤策，徐行當華軒。", "步穿鼪鼯徑，來過雞犬村。", "炊煙起茅廬，衍沃多平原。", "翳翳桑柘密，靄靄禾黍繁。", "黄童與白叟，相攜負朝暄。", "我求方寸地，擬設常關門。", "誰知南岡底，近有蘇家園。", "心知淳朴處，可避喧囂煩。", "歸來得好語，高意誰當論。", "他年劉子驥，定覓桃花源。"]'),
('2c9efe2f-9cee-4a80-8436-15984541c52a','過雙廟','周紫芝','宋','宋诗','song-poetry','','[]','巡遠功名絕古今，後先俱死只侵尋。',32,'全唐诗/poet.song.86000.json','["巡遠功名絕古今，後先俱死只侵尋。", "兩家子弟猶相訾，百世何由識此心。"]'),
('b1128de9-3829-4c9a-89a8-3cefa5e45d71','行邁一首','周紫芝','宋','宋诗','song-poetry','','[]','秋山凄無風，木葉寒自萎。',96,'全唐诗/poet.song.86000.json','["秋山凄無風，木葉寒自萎。", "羈客不得歸，行邁日靡靡。", "瘦馬嘶暮塗，忍饑渡寒水。", "落日晚更明，棲鳥驚復起。", "人生各有求，誰能異生死。", "行行重行行，辛苦那得爾。", "亂石摧前辀，旋車亦當止。", "饑寒苦見驅，臨風一長喟。"]'),
('cd4d4441-4bff-472b-b047-e38b6e19c65e','暮宿一首','周紫芝','宋','宋诗','song-poetry','','[]','朝行繞山麓，暮宿投孤村。',108,'全唐诗/poet.song.86000.json','["朝行繞山麓，暮宿投孤村。", "父老頗見招，落日猶在門。", "庖煙不滿竈，汲水復抱薪。", "爲我炊黄粱，一飽裁逡巡。", "百金得香醪，湛湛盈清樽。", "我雖不解飲，亦足濡我唇。", "濯足捫飽腹，燎衣暖餘薰。", "原言息劬勞，少浣塵埃昏。", "慇懃戒鳴雞，未用呼晨暾。"]'),
('210865f7-b03c-4aa6-9d49-a33051501cb7','汴隄冬日二首  其一','周紫芝','宋','宋诗','song-poetry','','[]','榆柳風微不動塵，平沙如粉襯車輪。',32,'全唐诗/poet.song.86000.json','["榆柳風微不動塵，平沙如粉襯車輪。", "今年汴上三冬暖，已带長安二月春。"]'),
('a50c718d-75af-4b35-af2d-66cb644f615d','汴隄冬日二首  其二','周紫芝','宋','宋诗','song-poetry','','[]','當年漫漫雪如塵，古汴重冰欲折輪。',32,'全唐诗/poet.song.86000.json','["當年漫漫雪如塵，古汴重冰欲折輪。", "暖日如今著行客，長安三度見青春。"]'),
('02dcaef7-80d7-4e8e-b056-64ac15271f2b','将出京','周紫芝','宋','宋诗','song-poetry','','[]','老恨愁千斛，饑須粟一囊。',48,'全唐诗/poet.song.86000.json','["老恨愁千斛，饑須粟一囊。", "遂成遲去魯，還作薄遊梁。", "客思風塵惡，鄉音道路長。", "何時秣歸馬，看我理晨裝。"]'),
('1fe57dbe-7c14-4a25-85e4-09cfe26b0740','雪後再至菊坡','周紫芝','宋','宋诗','song-poetry','','[]','長安二月春風裏，馬似遊龍車似水。',160,'全唐诗/poet.song.86000.json','["長安二月春風裏，馬似遊龍車似水。", "青鞋久慣踏江沙，黄帽豈堪隨馬尾。", "梁王舊築黄金臺，臺荒草滿誰復來。", "雲中羽蓋去不反，坡底菊苗寒欲開。", "老僧相對話鄉井，童子瀹苗分乳杯。", "爲言諸老有遺跡，細尋石刻摩蒼苔。", "春風無情固相似，倦客逢春還少味。", "籬邊踏雪憶故年，渡口呼船夢千里。", "人生萬事要隨緣，到處一身俱偶然。", "林間春動有佳興，更攜官焙來同煎。"]'),
('584a9452-e7df-47f8-b903-c91655b6b30f','寒食滁陽阻雨','周紫芝','宋','宋诗','song-poetry','','["\u957f\u6c5f"]','去年束書薄遊梁，今年下馬古滁陽。',160,'全唐诗/poet.song.86000.json','["去年束書薄遊梁，今年下馬古滁陽。", "滁陽寒食少人出，滿城山雨驚淋浪。", "閉門客舎頗無事，五白大呼同舎郎。", "樽前誰唱醉翁曲，鳥歌花舞催紅粧。", "竟須薄酒澆永日，肯放羈愁煎客腸。", "功名老矣白髮出，歲月幾何歸路長。", "江頭藉草作寒食，細雨梨花思故鄉。", "何當秣馬候明發，便可一葦横長江。", "千村萬落鳥呼客，山南嶺北花吹香。", "仍須戒婦速作黍，會見鹿門歸老龐。"]'),
('a273fba1-cbf1-46b2-b00c-0837f8558c58','遊醉翁亭','周紫芝','宋','宋诗','song-poetry','','[]','醉翁詩裏識滁山，蚤歲神遊只夢間。',64,'全唐诗/poet.song.86000.json','["醉翁詩裏識滁山，蚤歲神遊只夢間。", "雲外淺寒欺短帽，馬頭深秀得烟鬟。", "時攜妓女人猶說，倒著接䍦誰與還。", "文物風流今掃地，亂泉空繞玉孱顔。"]'),
('e715d691-ffe2-4b82-8263-022f32b579dc','謝公墩','周紫芝','宋','宋诗','song-poetry','','[]','風流謝文静，世俗未可屈。',144,'全唐诗/poet.song.86000.json','["風流謝文静，世俗未可屈。", "但怪東山雲，肯爲老桓出。", "誰知姦雄心，本自畏豪逸。", "君看新亭會，此意未易詰。", "坦之獨何者，手版遂倒執。", "煩公揮蝟湏，談笑安晉室。", "暮年淝水師，逆虜甚窘急。", "幅巾棋局間，百萬一戰襲。", "功名亦餘事，聊爲兒輩立。", "平時誚虚曠，聞此自羞澀。", "萬古終悠悠，客意頗蕭瑟。", "忍看西州門，更作羊曇泣。"]'),
('b92d010c-8fd8-482f-b04f-6409d300f557','卞公祠','周紫芝','宋','宋诗','song-poetry','','[]','卞公古剛者，直莭不可挫。',144,'全唐诗/poet.song.86000.json','["卞公古剛者，直莭不可挫。", "巖巖六龍子，矯矯中興佐。", "可憐謝幼輿，梭飛齒還墮。", "志懐不事事，見面輒欲唾。", "非關執鄙吝，要欲激疲愞。", "茂弘豈駑駘，廟社因遷播。", "維公抗劇賊，嬰此不測禍。", "平生忠義氣，臨絕不自奈。", "憤心握兩拳，爪甲穿掌過。", "英風渺何之，末路悲坎軻。", "高堂風入帷，壞壁塵生坐。", "清魂不可招，聊爲歌楚些。"]'),
('0c3fe1ec-e7fb-4341-8b94-c44bc2c6c720','遊定林','周紫芝','宋','宋诗','song-poetry','','[]','青山繞招提，危磴迎屐齒。',144,'全唐诗/poet.song.86000.json','["青山繞招提，危磴迎屐齒。", "泉聲去悠悠，秀色來亹亹。", "定林得幽處，勝踐發新喜。", "當年手種樹，來禽雜青李。", "横斜照壁詩，平淡如止水。", "尚想扶風帳，横經多士子。", "奈此後學徒，發冢用詩禮。", "朝回丹青像，暮撤配食簋。", "空餘古祠荒，老木寒籐委。", "遺像猶便便，念往悲復起。", "舉似與山僧，山僧豈知此。", "日暮歸去來，林深足荆杞。"]'),
('f3e8688f-6867-46b5-bb3c-8ab6fc06c23b','采石道中示伯尹','周紫芝','宋','宋诗','song-poetry','','[]','飛盡楊花京洛春，又将一舸到江濱。',64,'全唐诗/poet.song.86000.json','["飛盡楊花京洛春，又将一舸到江濱。", "聊憑淺碧浮烟水，爲洗軟紅隨馬塵。", "紫蟹黄雞秋漸近，東阡北陌酒將醇。", "只今我與君同夢，他日君容我卜鄰。"]'),
('5e92208f-1890-474c-9f06-db3962d4c118','伯瞻作酒官植竹局中見索鄙句','周紫芝','宋','宋诗','song-poetry','','[]','虞郎種粟秋不收，一生坎軻多窮愁。',176,'全唐诗/poet.song.86000.json','["虞郎種粟秋不收，一生坎軻多窮愁。", "有才無命百寮底，人笑獼猴騎土牛。", "蚤時脫身隱吴市，晚歲作吏分糟丘。", "貴人官高印如斗，君獨雞栖馬如狗。", "騎曹只可呼馬曹，漫仕何人知漫叟。", "平生好竹心未闌，小分雲嶺青檀欒。", "横窗尚恐翠露薄，得雨便作秋聲寒。", "向來麴糵一掃盡，風月已足供蹣跚。", "吾門如市心若水，箕坐不知身是官。", "念我平生絕韻友，相從久結無情歡。", "君當下榻我亦往，風雨對眠聽夢殘。"]'),
('961da057-b76f-4a17-b6a2-23664c07c591','次韻次卿寄李姑谿時欲問舎宛陵','周紫芝','宋','宋诗','song-poetry','','[]','我亦平生願執鞭，拜公眉宇記當年。',64,'全唐诗/poet.song.86000.json','["我亦平生願執鞭，拜公眉宇記當年。", "泰和人物真圖畫，李白風流是列仙。", "雪裏已無回棹意，文中新有卜居篇。", "幅巾還作溪堂夢，何日相從句水邊。"]'),
('baa14781-c382-4a46-a6dd-3945b2cfe654','河魨三絕  其一','周紫芝','宋','宋诗','song-poetry','','[]','水没春江不見沙，河魨吹絮荻生芽。',32,'全唐诗/poet.song.86000.json','["水没春江不見沙，河魨吹絮荻生芽。", "平生所欠但一死，可更杯中論鏌邪。"]'),
('2461ee60-21bb-490a-b68f-e03e36c6f883','河魨三絕  其二','周紫芝','宋','宋诗','song-poetry','','[]','釣蓑常恨此盟寒，兩歲珍庖屢入盤。',32,'全唐诗/poet.song.86000.json','["釣蓑常恨此盟寒，兩歲珍庖屢入盤。", "細雨春江從此逝，不應猶棄季鷹官。"]'),
('e2585532-72e2-48fb-8df6-3a6999bf5910','河魨三絕  其三','周紫芝','宋','宋诗','song-poetry','','[]','一飽欣然下箸餘，庾郎鮭菜復何須。',32,'全唐诗/poet.song.87000.json','["一飽欣然下箸餘，庾郎鮭菜復何須。", "當時獻納堪憐許，只解區區說䱥魚。"]'),
('db8863a6-ec7e-4b96-a125-6f728217fdd2','戲蛙','周紫芝','宋','宋诗','song-poetry','','[]','夢回閑看繞燈蛾，窗外蛙聲兩更多。',32,'全唐诗/poet.song.87000.json','["夢回閑看繞燈蛾，窗外蛙聲兩更多。", "莫遣盤中種鮭菜，要留水底作笙歌。"]'),
('c670ba45-65b6-4e7d-9aa7-b42e23a40543','爲蛙答','周紫芝','宋','宋诗','song-poetry','','[]','偶作長吟君莫嗔，一泓聊占小池春。',32,'全唐诗/poet.song.87000.json','["偶作長吟君莫嗔，一泓聊占小池春。", "斗升雖未分公廩，青紫猶堪作賣人。"]'),
('2a9be138-d90a-4644-b76d-1cea67beba4c','次韻李子澤過次卿谿堂二首  其一','周紫芝','宋','宋诗','song-poetry','','[]','溪雨廉纖作晚晴，斜川風物喚淵明。',32,'全唐诗/poet.song.87000.json','["溪雨廉纖作晚晴，斜川風物喚淵明。", "歸來定自有新句，醉著烏巾一幅輕。"]'),
('34b265e0-8b2e-4f89-ace6-4941bf1356b7','次韻李子澤過次卿谿堂二首  其二','周紫芝','宋','宋诗','song-poetry','','[]','時人但數李北海，惡客遠過元次山。',32,'全唐诗/poet.song.87000.json','["時人但數李北海，惡客遠過元次山。", "笑我不能同一醉，也來谿上看烟鬟。"]'),
('58255229-13d7-487a-82a3-81cbd6fb4e27','次韻次卿穿池得古研','周紫芝','宋','宋诗','song-poetry','','[]','功名到手莫嫌遲，妙琢先分紫玉池。',64,'全唐诗/poet.song.87000.json','["功名到手莫嫌遲，妙琢先分紫玉池。", "他日北門當視草，只今南澗且題詩。", "人間未忍終埋没，神力應先作護持。", "好替青氈成舊物，知君家有寧馨兒。"]'),
('09edd585-946d-48b6-b3f0-04b01cd402e3','次韻次卿鳴琴終日二絕  其一','周紫芝','宋','宋诗','song-poetry','','[]','大音固自元無曲，綠綺何勞更著絃。',32,'全唐诗/poet.song.87000.json','["大音固自元無曲，綠綺何勞更著絃。", "此調最高人不會，未知今復爲誰傳。"]'),
('cd4959ff-3120-43c0-ab18-14fcef3e7e19','次韻次卿鳴琴終日二絕  其二','周紫芝','宋','宋诗','song-poetry','','[]','平生有味在朱絃，想得清風入指寒。',32,'全唐诗/poet.song.87000.json','["平生有味在朱絃，想得清風入指寒。", "小閣香消簾不捲，知君不爲俗人彈。"]'),
('551f6365-5ec9-433a-8391-8679f8b282c5','代人贈别二首  其一','周紫芝','宋','宋诗','song-poetry','','[]','縷金歌裏越姬羞，紅蠟光中翠黛愁。',32,'全唐诗/poet.song.87000.json','["縷金歌裏越姬羞，紅蠟光中翠黛愁。", "貪向樽前話離别，不知郎酒十分流。"]'),
('97b3e0cf-34fe-43df-b53f-1ff33c2d824c','代人贈别二首  其二','周紫芝','宋','宋诗','song-poetry','','[]','越奴年紀似羅敷，年紀無多情有餘。',32,'全唐诗/poet.song.87000.json','["越奴年紀似羅敷，年紀無多情有餘。", "别後此情能記否，好憑北雁寄南書。"]'),
('f3872786-9940-4539-9d48-aa0374860f87','端午日小雨已而復晴','周紫芝','宋','宋诗','song-poetry','','[]','斷雲飛雨過平川，吹作團欒碧玉天。',64,'全唐诗/poet.song.87000.json','["斷雲飛雨過平川，吹作團欒碧玉天。", "酒綠强能開病眼，絛長那解繫流年。", "閑收艾葉晴窗外，忍對榴花白髮邊。", "細葛香羅天上有，烏紗白簟北窗眠。"]'),
('d917f799-0a49-43b4-8201-99520cd0b114','五月七日南堂見楊花','周紫芝','宋','宋诗','song-poetry','','[]','柳深何處可藏鴉，窗繞長廊綠暗紗。',32,'全唐诗/poet.song.87000.json','["柳深何處可藏鴉，窗繞長廊綠暗紗。", "造物惜春知有意，薫風時一度楊花。"]'),
('8b8340e0-6936-4daa-8e6c-88f468ab88f2','五月八夜月色明甚望麻姑昭亭二山','周紫芝','宋','宋诗','song-poetry','','[]','天高月白夜漫漫，倚杖來看月下山。',64,'全唐诗/poet.song.87000.json','["天高月白夜漫漫，倚杖來看月下山。", "老眼直窮烟靄外，諸峰渾在有無間。", "翰林耽酒今何處，仙女乘鸞去不還。", "天恐兩山看未足，故飛明鏡照孱顔。"]'),
('02386fa6-e4e5-4983-a008-44f1b41f09bd','讀林和靖集書其尾','周紫芝','宋','宋诗','song-poetry','','[]','泉石膏肓挽不回，笑看嵩少仕塗開。',64,'全唐诗/poet.song.87000.json','["泉石膏肓挽不回，笑看嵩少仕塗開。", "暮年封禪無遺藁，平日江湖只釣臺。", "月自黄昏人已老，鶴無消息客誰來。", "吴兒不解高人意，秋菊何當薦一杯。"]'),
('9ff0fecf-8aab-452a-906f-3b486008a78b','六月四日大水','周紫芝','宋','宋诗','song-poetry','','[]','夜雨聲喧萬壑雷，奔流明日自天來。',64,'全唐诗/poet.song.87000.json','["夜雨聲喧萬壑雷，奔流明日自天來。", "深疑瓠子河初决，復訝浮山堰始摧。", "水涸成梁真漫爾，山行乘橇信悠哉。", "望中何物關詩眼，銀海光中碧玉堆。"]'),
('78fb967a-3d58-4b7b-a165-6ccf06c42e4a','潘擇之惠合谿蘆菔種','周紫芝','宋','宋诗','song-poetry','','[]','庾郎鮭菜只春蔬，新向金城得上酥。',32,'全唐诗/poet.song.87000.json','["庾郎鮭菜只春蔬，新向金城得上酥。", "會見銀絲堆細縷，酒香橙熟鱠江鱸。"]'),
('0e2a267a-2605-4871-80f8-d6aa863a49ec','忻師開小軒秋霜之側范龍閣名以絕塵要予作詩','周紫芝','宋','宋诗','song-poetry','','[]','虎谿大士軒雖小，龍閣老翁詩更新。',64,'全唐诗/poet.song.87000.json','["虎谿大士軒雖小，龍閣老翁詩更新。", "積翠但令常到眼，軟紅元不解隨人。", "抗容俗裏自得計，望拜馬頭渠豈嗔。", "只好與君供一笑，世間何事可關身。"]'),
('d37a7459-0363-4b69-b5ad-2ee970ed4748','次韵劉元亢讀白樂天與劉夢得書','周紫芝','宋','宋诗','song-poetry','','[]','香山天下士，直道可事君。',144,'全唐诗/poet.song.87000.json','["香山天下士，直道可事君。", "口語作奇禍，後來成積薪。", "巨棟雖已捐，白璧原自珍。", "百年付春夢，千載期斯人。", "可憐肉食子，議者空反唇。", "文華一照耀，今古無搢紳。", "才高固不世，盛德終少鄰。", "鹿鹿數餘子，瑣瑣非公倫。", "豐盈與名譽，詎可鍾一身。", "暮年林壑意，觴咏全天真。", "君子與小人，兩者自此分。", "寄言顔巷徒，勿語傷哉貧。"]'),
('822371a5-e3a2-4d18-87c1-7ce9ca6e8ac8','五月二十四日避暑東寺折簡邀子容不至','周紫芝','宋','宋诗','song-poetry','','[]','凉飈呼不來，惡熱苦難避。',84,'全唐诗/poet.song.87000.json','["凉飈呼不來，惡熱苦難避。", "城南有佳人，相望隔秋水。", "願言倚瓊瑤，相攜謝簪履。", "花木通禪房，茶瓜供幽事。", "君方從簿書，相仍日填委。", "咫尺如參商，况乃在千里。", "日暮殊未來，清風爲誰起。"]'),
('932d3443-ca2a-41fb-b25a-c974e0a9a12e','次韻元亢見貽','周紫芝','宋','宋诗','song-poetry','','[]','人生如浮雲，夢境無真樂。',96,'全唐诗/poet.song.87000.json','["人生如浮雲，夢境無真樂。", "功名繞床盧，聚散合錢醵。", "可憐燈火讀，聖處恨未博。", "我非金閨彦，敢靜玉關柝。", "衰年未免俗，萬事隨獵較。", "安得共芳洲，相期採蘭若。", "眷言平生歡，寧負歲寒約。", "唾手可書紳，君意良不薄。"]'),
('dc1372d5-32df-4868-9578-9c08cbb9cad5','次韻元亢雨中見寄','周紫芝','宋','宋诗','song-poetry','','[]','窮巷結蝸廬，僅有一席廣。',72,'全唐诗/poet.song.87000.json','["窮巷結蝸廬，僅有一席廣。", "風雨不出門，山林負清賞。", "悵懷念幽人，道阻不得往。", "瀰漫隔江漢，契闊異霄壤。", "清風吹句來，念我作技癢。", "安得從君遊，此意良惘惘。"]'),
('7d5e4ee2-8317-4e2d-a586-68e6af044907','酌明寂泉','周紫芝','宋','宋诗','song-poetry','','[]','脩途繚重岡，病足倦遊歷。',132,'全唐诗/poet.song.87000.json','["脩途繚重岡，病足倦遊歷。", "山根得蒙泉，石盎貯深碧。", "亭虚繞朱欄，綠淨明水色。", "老禪黄蘗米，棄置久復憶。", "振策望青雲，清泉裂崖壁。", "至今一掬甘，長飲山中客。", "金鼎候松風，蒼龍破圓璧。", "醉腹澆彭亨，真味付泯默。", "何當謀挈瓶，徙倚終日夕。", "清甘不可嗽，猿鳥與同喫。", "洗我兩月塵，爛煮南山石。"]'),
('ad3ae527-2140-46e1-80f1-c2801c373937','題王定父淑問堂','周紫芝','宋','宋诗','song-poetry','','[]','平生心笑伯州犁，羅織雖工不當威。',64,'全唐诗/poet.song.87000.json','["平生心笑伯州犁，羅織雖工不當威。", "莫採黄金鑄刑鼎，要令青草入圜扉。", "于張必大君須記，六蓼先亡事恐非。", "聞說堂成已無訟，臥看庭樹轉斜暉。"]'),
('e87b6188-ae1d-4067-9d62-06f7e3258ce4','次韻元素登城暮歸二首  其一','周紫芝','宋','宋诗','song-poetry','','[]','天遣劉郎又白頭，少年文學似求由。',64,'全唐诗/poet.song.87000.json','["天遣劉郎又白頭，少年文學似求由。", "朱門華轂聊安命，藜杖芒鞋可散憂。", "大隱未成聊小隱，濁流誰得寘清流。", "賦成凖擬吾先讀，王粲秋來正倚樓。"]'),
('860726d2-4ebc-43f3-8dd1-e79e6682866d','次韻元素登城暮歸二首  其二','周紫芝','宋','宋诗','song-poetry','','[]','晚來飛鞚上城頭，欲躡華鑣苦末由。',64,'全唐诗/poet.song.87000.json','["晚來飛鞚上城頭，欲躡華鑣苦末由。", "醉裏有鄉須着屐，人間無地可埋憂。", "功名于我真聊爾，人物似君無此流。", "想對青天回白鳥，半鈎斜月掛江樓。"]'),
('afccc6cb-0de1-4eea-9bdd-2563f8924792','中秋月下作','周紫芝','宋','宋诗','song-poetry','','["\u957f\u6c5f"]','去年城南作中秋，江雲遮月爛不收。',144,'全唐诗/poet.song.87000.json','["去年城南作中秋，江雲遮月爛不收。", "幽人獨對秋風立，姮娥似隔重雲羞。", "更長忽聽曉鼓急，夢去只有殘燈留。", "今歲不知身在此，門枕長江風自起。", "樽中有酒坐有客，江面如天月如水。", "秋風滿樹凉葉飛，新歡欲盡還成悲。", "身其餘幾事不偶，老之將至吾今衰。", "人生閱世自有數，萬事反覆難預知。", "何當舉酒一再拜，與月更作明年期。"]'),
('9d2146df-e056-4a86-8d1a-0cec917a3940','宿蔣山','周紫芝','宋','宋诗','song-poetry','','[]','薄遊踐初心，寓宿便晚靜。',144,'全唐诗/poet.song.87000.json','["薄遊踐初心，寓宿便晚靜。", "山空秋有聲，人寂夜更永。", "華鯨催曉色，有客動深省。", "焚香禮大士，杖策上危嶺。", "黄金明窣堵，妙音生佛境。", "眼窮天無盡，地轉江萬頃。", "緬懷梁武帝，問法昔造請。", "識師鳥巢中，道契言自領。", "會令天龍宫，金碧粲絕頂。", "我來脩法供，汲水具乳茗。", "願同桑下留，覧勝畢餘景。", "還從天際歸，悠然理烟艇。"]'),
('51f6e5f8-a9b2-4820-92e3-f6ef6d1f4006','九日登鳳凰臺','周紫芝','宋','宋诗','song-poetry','','[]','落木驚高秋，旅食念行役。',144,'全唐诗/poet.song.87000.json','["落木驚高秋，旅食念行役。", "含羞古祠花，青蘂未堪摘。", "雲山不着脚，佳節似可惜。", "一嘯百尺臺，往趁凌風翮。", "羣山如玉玞，千古圍故國。", "孤城打寒潮，往事誰記憶。", "玉樹那得花，金蓮去無跡。", "興亡更六朝，濺血幾飛鏑。", "重瞳飛上天，毰毸避矰弋。", "何年覧德輝，古榜猶可識。", "父老無由詢，殘碑少遺刻。", "空餘弔古涕，自對斜陽滴。"]'),
('58072bd8-0ed0-44ca-bdcd-c9359966e915','次韻元中芭蕉軒','周紫芝','宋','宋诗','song-poetry','','[]','道人悟無生，開軒有深意。',96,'全唐诗/poet.song.87000.json','["道人悟無生，開軒有深意。", "是身如芭蕉，妙語良默契。", "婆娑坐芳藂，聊復此遊戲。", "秋風鳴環佩，曉露濕蒼翠。", "閉窗得陰多，凉簟驚雨細。", "索句清夢餘，時能助幽思。", "我亦箇中人，平生會佳致。", "此樂倘見分，杖策時一至。"]'),
('991a2c15-a1b7-4f3b-bedb-1e6d95116484','符川逢次卿遂約同舟','周紫芝','宋','宋诗','song-poetry','','[]','被褐念遊客，落帆逢故人。',144,'全唐诗/poet.song.87000.json','["被褐念遊客，落帆逢故人。", "晚歲風露寒，一笑樽俎春。", "餘子豈不佳，數面聊成親。", "平生不漫與，知君意良真。", "少日共林壑，劇談唾冠巾。", "皎然兩玉壺，不受一點塵。", "各以口腹累，老大成參辰。", "政坐造物兒，有意相怒嗔。", "荏苒時不再，俛仰迹遂陳。", "秋風吹前谿，搖蕩生碧鱗。", "不如載扁舟，相視聊飲醇。", "醉聽篷底語，共臥南谿垠。"]'),
('5f692963-f612-4a4c-8370-ae8bb9d182d1','次韻國師對月見懷','周紫芝','宋','宋诗','song-poetry','','[]','老子關門不著書，奄奄真復似曹蜍。',64,'全唐诗/poet.song.87000.json','["老子關門不著書，奄奄真復似曹蜍。", "月來林下苦相憶，詩落眼前歡有餘。", "滿挹清光歸酒面，小分秋色到吾廬。", "胸中拍塞愁千斛，特地煩君一掃除。"]'),
('58b7356c-b8f3-42f1-938f-6119b4c1d6c8','寄徐季長','周紫芝','宋','宋诗','song-poetry','','[]','念昔桃始華，别君漳水頭。',144,'全唐诗/poet.song.87000.json','["念昔桃始華，别君漳水頭。", "相别幾何時，天事司蓐收。", "闕月六度圓，相見間何闊。", "百年飛電中，能得幾回别。", "别君幾何時，憶君如饑渇。", "饑渇良有時，思君無時節。", "野人苦幽獨，相值誰與親。", "流落在蒼莽，坎軻一傷神。", "相望參與商，相隔雲與泥。", "草木忝臭味，笑談極相思。", "相思一何久，行行重回首。", "回首征雁行，中有來書否。"]'),
('cd974f40-f3a4-40e7-8362-0b58ce6531be','送王天民歸雙泉','周紫芝','宋','宋诗','song-poetry','','[]','舊聞雙泉居，縹渺在寥廓。',120,'全唐诗/poet.song.87000.json','["舊聞雙泉居，縹渺在寥廓。", "仙人上叢霄，遺甃結飛閣。", "廣庭三百步，一木可四角。", "刀圭分蒼虬，鱗鬛自皴錯。", "至今風雨枝，疑有孤栖鶴。", "王郎吹玉簫，飛鳧下雙屩。", "時乘三峰雲，來繞月城脚。", "人生多乖離，未踐繡水約。", "知心念獨君，時來慰牢落。", "我欲從之遊，何當解羈縛。"]'),
('c0ed0ca4-4e25-43ba-bba1-a5df10183e10','圩氓歎','周紫芝','宋','宋诗','song-poetry','','[]','圩氓築敗圩，飽腹無粟菽。',156,'全唐诗/poet.song.87000.json','["圩氓築敗圩，飽腹無粟菽。", "强扶南畝犁，辛苦望一熟。", "插秧在中田，秋來半黄綠。", "白雨忽翻盆，積潦囓圩腹。", "波頭卷春雷，洶涌裂坤軸。", "倉皇未出門，白水已半屋。", "攀椽栖木杪，寢飯雜鵝鶩。", "客行艤孤舟，繫纜怯水宿。", "叩門乞燈火，父老迎我哭。", "我亦一酸鼻，軟語聊撫祝。", "老稚且相收，慎勿輒棄逐。", "行看散陳紅，官倉有餘粟。", "救爾無遠謀，每飯慚食肉。"]'),
('d1369350-1369-404e-8a18-39d5362d5d9e','八月二十日種竹八本','周紫芝','宋','宋诗','song-poetry','','[]','東岡新種八龍孫，北嶺清陰肯見分。',32,'全唐诗/poet.song.87000.json','["東岡新種八龍孫，北嶺清陰肯見分。", "留取一林聽夜雨，莫教千畝僣封君。"]'),
('6f77b5e9-6a1d-418d-940d-66ec495217cb','次韻次卿中秋月下書所見','周紫芝','宋','宋诗','song-poetry','','[]','三載彭門夢，新年故國秋。',48,'全唐诗/poet.song.87000.json','["三載彭門夢，新年故國秋。", "月當千里共，酒要十分酬。", "翠幕知誰卷，雙鬟不奈羞。", "寒螿莫相惱，啼作晚窗愁。"]'),
('95d6a554-cc54-4bb7-acdb-d81a07281041','題大着肚并引  其一','周紫芝','宋','宋诗','song-poetry','','[]','金陵朱世英官長沙，或有畫箕踞而坐者號大着肚。',78,'全唐诗/poet.song.87000.json','["金陵朱世英官長沙，或有畫箕踞而坐者號大着肚。", "舊有贊頌皆鄙語，朱爲題小詩其上以易之。", "其尾云“但将貯酒三千鍾，莫話容卿數百輩。", "”余愛其語有味，更作此詩以廣其意。"]'),
('ce24298c-a4ea-47cc-9cfd-0d7a101d4a3d','題大着肚并引  其二','周紫芝','宋','宋诗','song-poetry','','[]','平生頗笑王會稽，坦腹驚動郗家兒。',160,'全唐诗/poet.song.87000.json','["平生頗笑王會稽，坦腹驚動郗家兒。", "暮年羞澁爲懷祖，計較毫末如兒癡。", "嶔𡼭更誚周郎鄙，自說空洞終何爲。", "達人大觀無不可，無鹽未必非西施。", "了知倚杖清言者，外示夷曠中難窺。", "不如此老身如寄，萬事模稜真得計。", "掉臂行歌眼看天，擁膝長吟腹垂地。", "羞遣家奴捧玉環，肯爲門生作經笥。", "白肥如瓠君莫輕，終年貯酒真酒甖。", "結喉道士倘復見，敢託石鼎譏彭亨。"]'),
('8d729357-96e5-41f4-add8-89c41dbfef24','次韻元傑病中書懷','周紫芝','宋','宋诗','song-poetry','','[]','本來無病是維摩，人說烟霞久臥疴。',64,'全唐诗/poet.song.87000.json','["本來無病是維摩，人說烟霞久臥疴。", "獨閉衡門春尚在，却攜藜杖句還多。", "已將名字傳三語，懶作悲凄和九歌。", "止酒淵明今復飲，便須俗客到無何。"]'),
('d73831c4-a7a4-49c7-86d4-5f3789cfda70','次韻幾聖見貽二首  其一','周紫芝','宋','宋诗','song-poetry','','[]','梅花雪後有殘枝，留與幽人照夕暉。',64,'全唐诗/poet.song.87000.json','["梅花雪後有殘枝，留與幽人照夕暉。", "已借水光浮淨几，更將山翠染春衣。", "回中漫叟移舟去，月下淵明種豆歸。", "知我短坡無客到，肯攜長麈爲翁揮。"]'),
('ef9563be-aeca-4864-9f96-97183544f91f','次韻幾聖見貽二首  其二','周紫芝','宋','宋诗','song-poetry','','[]','坎止流行念已輕，常關雖設是吾扃。',64,'全唐诗/poet.song.87000.json','["坎止流行念已輕，常關雖設是吾扃。", "事如痛定何堪說，出爲饑驅豈有情。", "滿座自傾鸜鵒舞，半巖擬作鳳凰聲。", "醉中深意知誰解，付與前身阮步兵。"]'),
('63ec0dbd-7206-417b-b51f-1ade3327545f','李似表雪中置酒席上次韵','周紫芝','宋','宋诗','song-poetry','','[]','東風吹玉塵，十指寒欲墮。',84,'全唐诗/poet.song.87000.json','["東風吹玉塵，十指寒欲墮。", "西齋借微温，妙語驚咳唾。", "詩成酒行間，一掃飛電過。", "坐令止酒陶，酒戒爲君破。", "但愁飛絮零，似我霜鬢鬌。", "他年玉堂人，伴直誰對臥。", "恨無屈宋才，共續離騷些。"]'),
('7f31aba4-d626-46d1-84ec-5cb685e5b384','次韵元素對雪十韵','周紫芝','宋','宋诗','song-poetry','','[]','雲凍風仍急，天低雪未收。',120,'全唐诗/poet.song.87000.json','["雲凍風仍急，天低雪未收。", "山寒飛鳥絕，江晚一蓑幽。", "曉樹梅初放，風簾絮自投。", "孤鶱迷遠鶴，痴立看饑鷗。", "櫪馬歸鞍速，韝鷹獵羽遒。", "連城理睥睨，千騎冷貔貅。", "何處回蘭棹，誰人擁釣裘。", "閉門憐我病，得句付君搜。", "上瑞書三白，登年在九秋。", "何當明月夜，同作廣寒遊。"]'),
('f88c8290-9fd5-4111-bbc1-722fe9d85d89','甘菊數本舊植之地沮洳湫隘頗有悴色十一月二十三日移植牆下明日小雨數刻欣然便有生意','周紫芝','宋','宋诗','song-poetry','','[]','小草偷微生，崛强沮洳間。',156,'全唐诗/poet.song.87000.json','["小草偷微生，崛强沮洳間。", "託根倘失所，憔悴無好顔。", "嗟哉一大地，寧無尺寸閑。", "造物惜不與，無乃亦太慳。", "櫟社豈不惡，盤錯未易栞。", "下可百牛蔽，上可星斗干。", "此物有遠韵，何人憫清孱。", "我移東籬栽，往近九畹蘭。", "天心固有在，生理似可還。", "小雨喜霡霂，低枝濕斕斑。", "春苗已足採，落英行可餐。", "爲我制頹齡，使我昇飛仙。", "物微自有知，報君以長年。"]'),
('5e779c1b-dbb7-41b3-b3cc-0ec558aaa87f','蠟梅六言三首  其一','周紫芝','宋','宋诗','song-poetry','','[]','剪蠟枝横隴月，釀花蜜滿蜂房。',28,'全唐诗/poet.song.87000.json','["剪蠟枝横隴月，釀花蜜滿蜂房。", "誰遣凌寒枝上，中含百和花香。"]'),
('0ed3dd4f-a462-4edf-8fac-c7e658e4a98b','蠟梅六言三首  其二','周紫芝','宋','宋诗','song-poetry','','[]','雲珮風侵玉冷，仙裳霧卷羅黄。',28,'全唐诗/poet.song.87000.json','["雲珮風侵玉冷，仙裳霧卷羅黄。", "家在蘂珠宫裏，衣薫鵲尾爐香。"]'),
('d6ef9b03-d8f0-423d-8f49-8148b3dae47f','蠟梅六言三首  其三','周紫芝','宋','宋诗','song-poetry','','[]','桃花占上林簿，蘭芷擅離騷經。',28,'全唐诗/poet.song.87000.json','["桃花占上林簿，蘭芷擅離騷經。", "欲吊花中遺逸，聊尋世外林坰。"]'),
('5592bebc-cbbc-4bb8-b382-482b0f042fa6','再賦三首  其一','周紫芝','宋','宋诗','song-poetry','','[]','孤根雅宜幽處，空明宛似僧房。',28,'全唐诗/poet.song.87000.json','["孤根雅宜幽處，空明宛似僧房。", "我作蒲團燕坐，時參鼻觀清香。"]'),
('23214b5b-4ffd-41e2-84d9-850a2d7be065','再賦三首  其二','周紫芝','宋','宋诗','song-poetry','','[]','淺俗微嫌菊陋，麤粗不愛葵黄。',28,'全唐诗/poet.song.87000.json','["淺俗微嫌菊陋，麤粗不愛葵黄。", "花裏誰方高韵，人中可比黄香。"]'),
('10da531b-8a7e-4ee0-9c51-91b8fb69413f','再賦三首  其三','周紫芝','宋','宋诗','song-poetry','','[]','移種定從天上，世間那有此香。',28,'全唐诗/poet.song.87000.json','["移種定從天上，世間那有此香。", "白髪人應羞看，鵝兒酒可爭嘗。"]'),
('bd27f268-0ff1-45fa-960c-adeceada137c','送詹伯尹之大梁','周紫芝','宋','宋诗','song-poetry','','[]','寒風轉平林，密雪吹重裘。',120,'全唐诗/poet.song.87000.json','["寒風轉平林，密雪吹重裘。", "遊子當北征，朝曦趣行輈。", "人生會有别，一訣寧復愁。", "念君最少孤，束髮勤清脩。", "壽母豈不力，白髮今滿頭。", "功名唾手事，歲月逝欲流。", "長安小車兒，哆口笑土牛。", "君才豈不高，逸氣横九州。", "弊帚已千金，白璧價未酬。", "願言慎行李，去去君勿留。"]'),
('2ff5587e-e147-4aa3-8285-f185686f2a6c','次韵何師與梅花二絕示劉凝遠  其一','周紫芝','宋','宋诗','song-poetry','','[]','月姊宫前玉樹春，杏花菖葉不同村。',32,'全唐诗/poet.song.87000.json','["月姊宫前玉樹春，杏花菖葉不同村。", "多情誰道天無意，先與梅花雨露恩。"]'),
('edb178dd-49c6-4917-8272-4c4ecc70b746','次韵何師與梅花二絕示劉凝遠  其二','周紫芝','宋','宋诗','song-poetry','','[]','何人急遣蓬萊使，喚得春回江上村。',32,'全唐诗/poet.song.87000.json','["何人急遣蓬萊使，喚得春回江上村。", "誰信廣平心已冷，老於花似太無恩。"]'),
('485ea173-b6a8-4407-9126-7c58ab7a0455','文殊老人寄和張宰共賦堂詩要余同作','周紫芝','宋','宋诗','song-poetry','','[]','世無陳太丘，民隱念誰訴。',288,'全唐诗/poet.song.87000.json','["世無陳太丘，民隱念誰訴。", "兒饑不肯乳，咿嚶復誰慕。", "殖禄膏妻孥，居官付羈旅。", "何心書下考，絕意躡高步。", "張侯名家郎，作吏得奇趣。", "提攜念疲勞，憂勤急朝暮。", "散作千家春，一洗五里霧。", "簪纓被餘輝，草木飽朝露。", "官閑理朱絲，雲靜落飛屨。", "當期卓子康，揚鑣各分路。", "飛書恐到來，築屋寧久住。", "詩成梯幾間，酬酢語交互。", "酒杯方流行，喜甚捷官渡。", "歌詩載懽謠，鞭箠息嗔怒。", "翰墨良從容，流冗自奔赴。", "聲今詫父老，名亦借童孺。", "觴豆落明珠，萬壑疾東注。", "賓從俱鄒枚，含毫各驚顧。", "戰須老將鏖，兵思勍敵遇。", "主人方燕喜，飲至非草具。", "人生俟河清，俯仰有新故。", "寄言三不欺，令尹勿輕忤。", "民今知己疲，着艾豈勝炷。", "鋒傳固應須，軺車少當駐。"]'),
('61eb4627-0a83-4b7f-bf9f-d2bcf7dcb624','讀涪翁黔南詩作','周紫芝','宋','宋诗','song-poetry','','[]','阿香名字本無雙，流落真成竄夜郎。',64,'全唐诗/poet.song.87000.json','["阿香名字本無雙，流落真成竄夜郎。", "蚤歲浪言腸是錦，只今空復鬢成霜。", "名傳故國猶驚座，詩入浯川尚滿囊。", "天爲少陵增秀句，故教遷客上瞿塘。"]'),
('32991897-bb28-482c-9adc-1ef2a5b0996d','次韵元亢和邦師喜其歸自錢塘','周紫芝','宋','宋诗','song-poetry','','[]','道人青眼爲君開，前度劉郎今又來。',64,'全唐诗/poet.song.87000.json','["道人青眼爲君開，前度劉郎今又來。", "白雨飽催湖上句，紅粧誰把醉時杯。", "籬邊採菊山千疊，渡口呼船谿九回。", "便恐横翔到蓬閣，試尋林下小徘徊。"]'),
('c10c140c-8589-4aeb-bd59-f2cd097fa3c5','送吕霞卿吕當世棄官而出家今爲道士','周紫芝','宋','宋诗','song-poetry','','[]','得錢夢穢官夢屍，等爲臭腐焉用爲。',144,'全唐诗/poet.song.87000.json','["得錢夢穢官夢屍，等爲臭腐焉用爲。", "世人愛官如愛命，君獨棄官如棄泥。", "道人胸中少荆棘，一色但種棗與梨。", "華名自毁不足取，高位疾顛無乃危。", "魚須忽復入君手，三命循牆急須走。", "朝持玉磬誦琅函，夜着黄冠朝北斗。", "天上雲車久未來，壺中日月空長久。", "吳山楚澤兩西東，與子一笑殊匆匆。", "會當握手五百載，摩挲金狄還相逢。"]'),
('44650c97-cb76-4072-9e9e-1f6a63d4e25b','趙丞家野堂','周紫芝','宋','宋诗','song-poetry','','[]','近喜崔斯立，新成背郭堂。',96,'全唐诗/poet.song.87000.json','["近喜崔斯立，新成背郭堂。", "傍崖深置屋，喚客小飛觴。", "稍遣花經眼，頻移竹過牆。", "官清公事少，夢熟鳥聲長。", "藤倚樛枝瘦，芸翻亂葉香。", "騎曹休問馬，聱叟漫爲郎。", "丘壑胸中事，乾坤醉處鄉。", "人間一遊戲，出處兩俱忘。"]'),
('01120cfd-7bf9-4e03-9ac2-ea9a28f9d2e0','元夕睡起','周紫芝','宋','宋诗','song-poetry','','[]','元夕不復飲，夜寒誰與娛。',48,'全唐诗/poet.song.87000.json','["元夕不復飲，夜寒誰與娛。", "人隨千騎出，自對一燈孤。", "有夢須黄妳，無情問紫姑。", "鼇山在天上，回望隔中區。"]'),
('670747aa-a634-45b9-a06b-2f1bd36bde63','次韻元素野步','周紫芝','宋','宋诗','song-poetry','','[]','金隄不復上蹣跚，矍鑠何勞强據鞍。',64,'全唐诗/poet.song.87000.json','["金隄不復上蹣跚，矍鑠何勞强據鞍。", "從我泥中甘蠖屈，看他高處作鵬摶。", "錦江春色能供醉，濠上遊魚亦可觀。", "聞有平沙邀晚步，定隨明月下林端。"]'),
('07eb7415-999d-4f32-b44e-aaa07ca344a4','姑谿書報録近作因寄宣毫越簡','周紫芝','宋','宋诗','song-poetry','','[]','五雲書札何時得，古錦詩囊久未傾。',64,'全唐诗/poet.song.87000.json','["五雲書札何時得，古錦詩囊久未傾。", "急遣能言管城子，仍煩解事楮先生。", "飽霜穴兔秋方健，照雪溪藤搗更精。", "南雁去時人尚遠，雙魚欲到眼先明。"]'),
('4b3ed777-78d6-4555-aa16-5304c5825e58','次韵王次卿喜劉元亢登第','周紫芝','宋','宋诗','song-poetry','','[]','劉郎才思似春閑，文在阿房季孟間。',64,'全唐诗/poet.song.87000.json','["劉郎才思似春閑，文在阿房季孟間。", "盡把胸中着雲夢，還從筆底看波瀾。", "我無富貴詢唐舉，人說科名汙次山。", "馳馬行看歸舊物，舞衣先喜慰親顔。"]'),
('b78cf852-d497-48fb-855c-aec3b2192835','奉酬韋深道見寄詩','周紫芝','宋','宋诗','song-poetry','','[]','蓋世功名豈不佳，韋郎心事本烟霞。',64,'全唐诗/poet.song.87000.json','["蓋世功名豈不佳，韋郎心事本烟霞。", "秋風自老千章木，春雨誰分一部蛙。", "夜鶴政愁雲出岫，鱸魚會遣客思家。", "從君細意論幽恨，準擬應須到落花。"]'),
('ff98043a-57f4-4cc1-94ef-ffed528241e5','韋深道和詩且以書堅扁舟之約僕以禁烟歸掃邱墓未暇先寄此詩','周紫芝','宋','宋诗','song-poetry','','[]','闕然不見十年餘，借屋新來共一湖。',64,'全唐诗/poet.song.87000.json','["闕然不見十年餘，借屋新來共一湖。", "已向雙魚逢尺素，更因五字得明珠。", "子猷心欲隨烟棹，摩詰居應似畫圖。", "會待龐公歸上塚，便求奴飯馬青芻。"]'),
('18e5a01b-bd74-4c1f-a426-03c8123d946a','次韵邦伯達春寒','周紫芝','宋','宋诗','song-poetry','','[]','嶺外梅花使已來，江南正月未春回。',64,'全唐诗/poet.song.87000.json','["嶺外梅花使已來，江南正月未春回。", "頑雲放日歸蓬牖，殘雪將寒入酒杯。", "便有社風催燕到，何須羯鼓打花開。", "老于春事渾無意，睡起羣書正作堆。"]'),
('cec89780-a211-47bd-a00c-195f4917f7d7','高公墓','周紫芝','宋','宋诗','song-poetry','','[]','高公古遺直，三年立螭頭。',120,'全唐诗/poet.song.87000.json','["高公古遺直，三年立螭頭。", "載筆有公言，高論肅冕旒。", "少年取巍科，妙學窮九流。", "晚窺青囊書，穴地生公侯。", "當時千載人，繼出歐與劉。", "如何百年後，零落歸山丘。", "墓門梗荒棘，長松泣高秋。", "佳城定天與，政自非人謀。", "我來倚墓木，伴客聊遨遊。", "斗酒與隻雞，誰爲橋公羞。"]'),
('a5a956e8-b799-42fb-8e06-5cdd64844cff','次韵章季常題石魚研屏','周紫芝','宋','宋诗','song-poetry','','[]','蒼崖百丈懸江濱，江潭下躍吞舟鱗。',182,'全唐诗/poet.song.87000.json','["蒼崖百丈懸江濱，江潭下躍吞舟鱗。", "戲將雙影倒掛崖石上，妙絕始信陽侯神。", "短屏誰爲琢山骨，與君一障西風塵。", "世間百怪那可解，清詩宛轉聊窮因。", "問誰幻出水底石，掉尾鼓鬛波粼粼。", "固應鳳咮與龍尾，明窗淨几長相親。", "君家機雲好兄弟，玉山對峙高嶙峋。", "爲貧聊試漆園吏，手板拄頰心看雲。", "要收江湖入几席，釣竿拂水垂風綸。", "誰當爲我語石魚，莫愛浪翻月白千頃江鎔銀。", "但願玉堂常伴直，對此風流千載人。"]'),
('4add5783-4969-4013-bea2-39cb715154ff','次韵何丈即席','周紫芝','宋','宋诗','song-poetry','','[]','春風無力柳嫣然，花欲爭春作意妍。',64,'全唐诗/poet.song.87000.json','["春風無力柳嫣然，花欲爭春作意妍。", "坐上詩成雲態度，樽前人鬬玉嬋娟。", "鳳簫初暖參差竹，檀板還催大小絃。", "惡客正應妨作樂，主人渾似孟公賢。"]'),
('a7b89373-b597-48f3-9bcc-a1721be1961b','次韵子容池亭晚思二首  其一','周紫芝','宋','宋诗','song-poetry','','[]','便到青雲尚黑頭，有亭莫賦二宜休。',32,'全唐诗/poet.song.87000.json','["便到青雲尚黑頭，有亭莫賦二宜休。", "如君豈是池中物，要趁官閑作浪遊。"]'),
('cc4754cc-5caf-4206-9ab1-b44c14a93912','次韵子容池亭晚思二首  其二','周紫芝','宋','宋诗','song-poetry','','[]','漫叟江湖閑日月，輞川圖畫小池亭。',32,'全唐诗/poet.song.87000.json','["漫叟江湖閑日月，輞川圖畫小池亭。", "謝郎春草有新句，付與老人雙眼青。"]'),
('8865b50a-2272-4b8f-a884-4f0c899d22c8','次韵次卿林下行，歌十首  其一','周紫芝','宋','宋诗','song-poetry','','[]','風吹蘇小門前柳，雨暗羅敷陌上桑。',32,'全唐诗/poet.song.87000.json','["風吹蘇小門前柳，雨暗羅敷陌上桑。", "遙想錦江春色暖，被花惱得少陵狂。"]'),
('f997b42f-7ea1-498e-b6c2-e6062481bc94','次韵次卿林下行，歌十首  其二','周紫芝','宋','宋诗','song-poetry','','[]','聞道全家隱鹿門，竹籬茅屋寄江村。',32,'全唐诗/poet.song.87000.json','["聞道全家隱鹿門，竹籬茅屋寄江村。", "龐公事業無多子，只有平安遺子孫。"]'),
('fe429e31-158d-4d61-b884-3553d53ebad2','次韵次卿林下行，歌十首  其三','周紫芝','宋','宋诗','song-poetry','','[]','事向閑中種種休，春來林下興還幽。',32,'全唐诗/poet.song.87000.json','["事向閑中種種休，春來林下興還幽。", "上山雙屐與誰着，掛杖百錢時獨遊。"]'),
('2f13ddfc-c19d-40ba-8fc2-fcec3f33de47','次韵次卿林下行，歌十首  其四','周紫芝','宋','宋诗','song-poetry','','[]','郡郭東邊是草堂，巖花時雜澗花香。',32,'全唐诗/poet.song.87000.json','["郡郭東邊是草堂，巖花時雜澗花香。", "愁從把酒杯中少，日向讀書窗下長。"]'),
('8c275373-af35-4e78-ab7a-1a562e2ca690','次韵次卿林下行，歌十首  其五','周紫芝','宋','宋诗','song-poetry','','[]','愁多應怪獨醒人，心事全憑麴米春。',32,'全唐诗/poet.song.87000.json','["愁多應怪獨醒人，心事全憑麴米春。", "醉後逢花堪一笑，狂來曳杖却成真。"]'),
('2c9abf01-3496-458c-8050-e8c7f7a567fe','次韵次卿林下行，歌十首  其六','周紫芝','宋','宋诗','song-poetry','','[]','身世無營策最良，年來幽事不多忙。',32,'全唐诗/poet.song.87000.json','["身世無營策最良，年來幽事不多忙。", "飰牛欲起方朝露，種豆纔歸又夕陽。"]'),
('a4ac9c24-7d52-4831-9b07-ac0d157043ef','次韵次卿林下行，歌十首  其七','周紫芝','宋','宋诗','song-poetry','','[]','賣酒罾魚只數家，卜鄰元在水之涯。',32,'全唐诗/poet.song.87000.json','["賣酒罾魚只數家，卜鄰元在水之涯。", "扁舟定自桃源去，斜日紅飛兩岸花。"]'),
('ee07fa34-9763-49a9-b40c-32cd87339adb','次韵次卿林下行，歌十首  其八','周紫芝','宋','宋诗','song-poetry','','[]','人情危甚劍頭炊，未可雲鵬笑一枝。',32,'全唐诗/poet.song.87000.json','["人情危甚劍頭炊，未可雲鵬笑一枝。", "冠冕窟中元不到，雲山堆裏復誰知。"]'),
('dd87f2e2-c850-49fb-bf21-70ef657299de','次韵次卿林下行，歌十首  其九','周紫芝','宋','宋诗','song-poetry','','[]','得酒固應聊復飲，有田何苦不親耡。',32,'全唐诗/poet.song.87000.json','["得酒固應聊復飲，有田何苦不親耡。", "客來深巷聞雞犬，便是淵明歸後居。"]'),
('c1314e2a-8df8-4157-9d55-e1e8a5cfa298','次韵次卿林下行，歌十首  其一○','周紫芝','宋','宋诗','song-poetry','','[]','勃窣蹣跚不上堤，却來林下小徘徊。',32,'全唐诗/poet.song.87000.json','["勃窣蹣跚不上堤，却來林下小徘徊。", "已知脩竹有千畝，更爲桃花求百栽。"]'),
('2362dcdf-fadd-4c1e-873b-b62ba57e5e2b','聞蛙','周紫芝','宋','宋诗','song-poetry','','[]','草合平溝漲綠醅，亂蛙聲在古城隈。',32,'全唐诗/poet.song.87000.json','["草合平溝漲綠醅，亂蛙聲在古城隈。", "何時細雨春風夜，還我西池鼓吹來。"]'),
('68c37123-74ca-424f-a70f-b70a2cbedff7','次韵趙鈐飲次卿家時牡丹盛開而僕不及見','周紫芝','宋','宋诗','song-poetry','','[]','揚子草玄仍有居，河間好事復多書。',64,'全唐诗/poet.song.87000.json','["揚子草玄仍有居，河間好事復多書。", "獨來林下相尋處，醉倒花間得句初。", "人去不知紅爛熳，春殘忍看綠扶疏。", "明年許作樽前客，準擬籃輿喚阿舒。"]'),
('221f40e0-2340-4174-af9f-4e4789677483','林間燒笋戲作','周紫芝','宋','宋诗','song-poetry','','[]','滿山稚子欲翻籬，莫管春風上番時。',32,'全唐诗/poet.song.87000.json','["滿山稚子欲翻籬，莫管春風上番時。", "來伴野僧參玉版，不知今日已茶毗。"]'),
('1d4d0ce7-1cce-413d-8c36-3d88a98ec636','夜讀艾子書其尾','周紫芝','宋','宋诗','song-poetry','','[]','萬里投荒海一隅，八年蜑子與同居。',64,'全唐诗/poet.song.87000.json','["萬里投荒海一隅，八年蜑子與同居。", "可憐金殿鑾坡日，渾在蠻烟瘴雨餘。", "奇怪誰書方朔傳，滑稽空著子長書。", "不知平日經綸意，晚作兒曹一笑娛。"]'),
('1654ece6-d6ef-4d4a-b82b-5cb87930705b','雨意甚濃方起而止','周紫芝','宋','宋诗','song-poetry','','[]','欲成凍雨又吹殘，香稻垂垂不救乾。',64,'全唐诗/poet.song.87000.json','["欲成凍雨又吹殘，香稻垂垂不救乾。", "謾對醨雲訟風伯，還將火傘付炎官。", "未容漲綠浮烟艇，且看晴雲轉玉盤。", "誰與天工論赤地，盡傾銀漢作波瀾。"]'),
('9dabf187-a57e-4f22-a7b1-a7a0b6fe4f37','次韵趙明叔喜雨不寐','周紫芝','宋','宋诗','song-poetry','','[]','雲忽油然雨沛然，黄童白叟盡成顛。',64,'全唐诗/poet.song.87000.json','["雲忽油然雨沛然，黄童白叟盡成顛。", "喚晴鳩婦鳴屋角，飽水秧孫明稻田。", "御史平冤魂亦喜，弘羊言利死誰憐。", "草玄窗下子揚子，凉入孤燈夜不眠。"]'),
('203fe9b0-8edd-44e0-8d66-f217320ace96','送强幼安','周紫芝','宋','宋诗','song-poetry','','[]','慈固必能勇，剛亦能近仁。',228,'全唐诗/poet.song.87000.json','["慈固必能勇，剛亦能近仁。", "內荏色徒厲，定知非仁人。", "强公本仁者，笑語生陽春。", "散爲三年澤，不及千里民。", "庬恩出豈弟，雅量含清醇。", "應容盗取氈，肯叱吏吐茵。", "誰知乃中剛，臨難氣益振。", "前年攝虎符，折衝如有神。", "鄰封墮賊手，齒寒已亡唇。", "孤城危纍卵，夜臥寄積薪。", "清詩見横槊，高會開重闉。", "羣奔竄狐鼠，萬刃抗一身。", "豈但虎渡河，遂使盗入秦。", "至今忠義士，不數遠與巡。", "嗟我挾策子，繆作升堂賓。", "忠風激中腸，别語聊重陳。", "公議誰能掩，偉績終難湮。", "陰功及黎庶，天語形絲綸。", "富貴當自兹，照眼功名新。"]'),
('638b7b53-ac25-4409-9221-91804464ff05','東坡老人居儋耳嘗獨遊城北過谿觀閔客草舍偶得一蒻笠戴歸婦女小兒皆笑邑犬皆吠吠所怪也六月六日惡熱如墮甑中散髮南軒偶誦其語忽大風自北來驟雨彌刻','周紫芝','宋','宋诗','song-poetry','','[]','持節休誇海上蘇，前身便是牧羊奴。',64,'全唐诗/poet.song.87000.json','["持節休誇海上蘇，前身便是牧羊奴。", "應嫌朱紱當年夢，故作黄冠一笑娛。", "遺跡與公歸物外，清風爲我襲庭隅。", "憑誰喚起王摩詰，畫作東坡戴笠圖。"]'),
('362e9e75-23da-4a6d-b8e9-5e1524906d39','婁黥庵納凉','周紫芝','宋','宋诗','song-poetry','','[]','婁黥無骨可封王，生事全憑藥一囊。',64,'全唐诗/poet.song.87000.json','["婁黥無骨可封王，生事全憑藥一囊。", "閉户翻經頭已白，開門延客酒初嘗。", "竹從春後知無數，花自山來别有香。", "未有數椽容我老，聊分一榻借君凉。"]'),
('684e17e2-adec-4f94-8b56-88473fed14a6','晚浴崇教寺','周紫芝','宋','宋诗','song-poetry','','[]','閑居誰與遊，幸此招提鄰。',180,'全唐诗/poet.song.87000.json','["閑居誰與遊，幸此招提鄰。", "時乘下澤車，訪我物外人。", "往往聽魚鼓，相隨作朝昬。", "齋得飽佛飯，暮浴霑僧巾。", "情熟自不厭，無求亦何嗔。", "我生束世故，欲解未有因。", "願丏一滴甘，爲洗千刼塵。", "無冠顧安整，有衣聊自振。", "道人小軒窗，池凈花色新。", "芭蕉過微雨，蒼翠爭藂筠。", "勁節秋益好，柔葩委菅榛。", "豈但娛老眼，亦足觀是身。", "欹眠寄靜榻，小休只逡巡。", "茶甘猶在口，龕燈已前陳。", "日暮行當歸，擊柝催重闉。"]'),
('9c1d7a3c-7310-4ee2-9449-46d55b59d260','次韵元傑暑中書事','周紫芝','宋','宋诗','song-poetry','','[]','劉郎家世盡名卿，晚歲憐君尚带經。',64,'全唐诗/poet.song.87000.json','["劉郎家世盡名卿，晚歲憐君尚带經。", "道在莫嫌榆歷歷，詩高何媿草青青。", "杜門不出人應笑，與世相違我獨醒。", "誰與林塘共清夜，綠荷時照兩三螢。"]'),
('c91cb3ac-0ae7-4580-a66b-d274286d8398','次韵李子澤中秋無月','周紫芝','宋','宋诗','song-poetry','','[]','月在愁雲黯淡中，綠樽誰與共秋風。',32,'全唐诗/poet.song.87000.json','["月在愁雲黯淡中，綠樽誰與共秋風。", "君家自有人如玉，嫋嫋停停似楚宫。"]'),
('5111d03e-18a5-4b6e-a53b-7782302b1422','次韵春卿遊黄蘖道場','周紫芝','宋','宋诗','song-poetry','','[]','長安多貴人，被服縈寶带。',168,'全唐诗/poet.song.87000.json','["長安多貴人，被服縈寶带。", "名字垂鼎彛，功勳壓崧岱。", "一懷上蔡悲，樂事鍾我輩。", "知君汗漫遊，食蛤據龜背。", "若若笑痴兒，洋洋飛大蓋。", "梯空瞰千山，閱此烟雨態。", "小閣亦何有，長松颯微籟。", "聊將身世夢，淨洗佛祖戒。", "行樂要及時，幸此無籍在。", "只今况豐年，禾黍已旆旆。", "狂風不鳴條，積雨不破塊。", "賞心失幽期，噬臍有餘悔。", "曉猿倘未驚，斯遊君勿怪。", "便當買薄田，往抱躬耕耒。"]'),
('9d28ca00-3c25-4caf-ae77-11d18e20ad1b','八月二十一日大熱夜半微凉','周紫芝','宋','宋诗','song-poetry','','[]','八月大地千里赤，蓐收權輕苦無力。',64,'全唐诗/poet.song.87000.json','["八月大地千里赤，蓐收權輕苦無力。", "未許寒蟬飽風露，聊爲秋蚊增羽翼。", "蒲葵呼扇腕欲搖，絺綌捐衣汗猶滴。", "誰遣秋風半夜來，先向高梧寄消息。"]'),
('d42f8e56-20c5-4651-84c6-67f7189b7e1c','和李似表丞廳梅發用胡士曹韵','周紫芝','宋','宋诗','song-poetry','','["\u897f\u6e56"]','江頭雪屋知誰家，雪中冷艶空争華。',144,'全唐诗/poet.song.87000.json','["江頭雪屋知誰家，雪中冷艶空争華。", "不知何郎閉東閣，坐看江梅初着花。", "谷底春回猶未透，天寒袖薄姿微瘦。", "黄昏有月誰復知，舉世無花出君右。", "人生一月幾胡盧，枝猶在手霜滿鬚。", "湖邊孤坐不飲酒，西湖處士空清臞。", "知君不學崔斯立，幅巾漫對枯松株。", "鉄心雖冷白自勝，金縷醉歌歡豈無。", "明朝花在有新句，詩成阿買還當書。"]'),
('91200a9e-5763-4c45-b519-c60b5b1fb260','次韵次卿約尋梅二絕  其一','周紫芝','宋','宋诗','song-poetry','','[]','擬摘寒梢一點春，佩囊無句久生塵。',32,'全唐诗/poet.song.87000.json','["擬摘寒梢一點春，佩囊無句久生塵。", "尋花會得王郎意，應爲江梅似玉人。"]'),
('32bb37c2-4c30-4974-affc-e2f6c967d799','次韵次卿約尋梅二絕  其二','周紫芝','宋','宋诗','song-poetry','','[]','想得瑤林玉樹春，高標元自出風塵。',32,'全唐诗/poet.song.87000.json','["想得瑤林玉樹春，高標元自出風塵。", "殷勤欲共梅花笑，却恐梅花解笑人。"]'),
('44c78953-d057-44e9-a6dc-ad4694a8165e','寄題折將軍家忠勇堂','周紫芝','宋','宋诗','song-poetry','','[]','折侯古將家，雄筭讋邊土。',144,'全唐诗/poet.song.87000.json','["折侯古將家，雄筭讋邊土。", "將軍最晚出，驍勇不媚嫵。", "十年守雁門，飛矢射猛虎。", "平生程不識，不作一錢數。", "誓言月支胡，唾手端可取。", "夜半奏捷書，歡聲曉飛舞。", "雲旗塗黄金，彩錯映寰宇。", "談笑開華堂，忠勇掲天語。", "功成倘堅壁，鎮靜古所與。", "何當使敵人，開户玩處女。", "置酒日高會，緩带擊歌鼓。", "要令無智名，折衝在樽俎。"]'),
('133980a4-de92-4acd-9cc6-5c2de93ea8b1','東牆橘將熟催以長句','周紫芝','宋','宋诗','song-poetry','','[]','木奴嫋嫋半垂牆，故惱幽人苦未忙。',64,'全唐诗/poet.song.87000.json','["木奴嫋嫋半垂牆，故惱幽人苦未忙。", "雨細不妨無賴綠，簾疏時與可憐香。", "誰將磊落黄金顆，爲賦甘酸白雪囊。", "只有天公真解事，便須先借滿林霜。"]'),
('9341a415-9feb-456d-9012-78184a4f5859','夜宿東寺雪作寒甚','周紫芝','宋','宋诗','song-poetry','','[]','古寺初投箠，荒陴已授更。',48,'全唐诗/poet.song.87000.json','["古寺初投箠，荒陴已授更。", "雪飛穿幕片，風作撼窗聲。", "今日招提境，當年敵騎營。", "可憐王處仲，江上築孤城。"]'),
('9bf6a1a7-1dcc-43cf-a45b-561269d0a22e','哭普兒','周紫芝','宋','宋诗','song-poetry','','[]','胸中欠梨棗，種此無明根。',144,'全唐诗/poet.song.87000.json','["胸中欠梨棗，種此無明根。", "造物初戲劇，憂傷裂心肝。", "奪我破殻雛，長鳴猶未翰。", "况乃渥洼種，墮地已足觀。", "此理竟莫曉，老淚空闌干。", "端如卜子夏，淚盡雙眼眢。", "母哭不忍聽，聽之鼻辛酸。", "人言有子爾，欲遣吾心寛。", "有生無短長，視死同一歎。", "曉人當如是，自曉終爲難。", "究竟無奈何，哀哉亦何言。", "安得大靈龜，騎雲款天門。"]'),
('e33134fe-fd66-489f-92f0-0af9e306831e','次韵答子容三首  其一','周紫芝','宋','宋诗','song-poetry','','[]','載酒念疇昔，幽寻日相過。',72,'全唐诗/poet.song.87000.json','["載酒念疇昔，幽寻日相過。", "十年登鬼録，奄冉今已多。", "舊盟難重尋，俗子終殊科。", "只今驚大巫，爲我驅妖魔。", "但恐費推挽，勞君戒蹉跎。", "願隨翩翩子，徙倚南山阿。"]'),
('b35f0458-b3f5-4373-88d0-c24b59c5605d','次韵答子容三首  其二','周紫芝','宋','宋诗','song-poetry','','[]','老懶不出門，泯默抱窮獨。',72,'全唐诗/poet.song.87000.json','["老懶不出門，泯默抱窮獨。", "賴此千載人，洗我雙病目。", "公思如懸河，傾瀉歸四凟。", "我如眢井泉，鑿地日不足。", "幸分一滴甘，濡此將槁木。", "行當奉周旋，歸囊粲珠玉。"]'),
('0bb60b46-9948-482d-b99e-f5a7f8375403','次韵答子容三首  其三','周紫芝','宋','宋诗','song-poetry','','[]','故交天一涯，塗路困脩阻。',72,'全唐诗/poet.song.87000.json','["故交天一涯，塗路困脩阻。", "新交同一邦，對面日晤語。", "知君相知心，政在亹亹處。", "朝屐窮幽深，夜床同曉雨。", "似聞跫然音，振翮便輕舉。", "俗物多敗人，公其勿輕許。"]'),
('136eb614-e0da-48ca-9db5-058f8fd56c7c','次韵蘇如圭乞貓','周紫芝','宋','宋诗','song-poetry','','[]','蘇侯家四壁，每飯歌權輿。',132,'全唐诗/poet.song.87000.json','["蘇侯家四壁，每飯歌權輿。", "庾郎鮭菜盤，三韭羅春蔬。", "饑鼠竄旁舍，不復勞驅除。", "何爲走老黥，貫魚乞狸奴。", "頗知紅錦囊，萬卷家多書。", "我時醉着帽，過子城南居。", "手擎烏絲欄，棐几自卷舒。", "寒具久不設，躉尾亦足娛。", "猶恐遭咬囓，備豫須不虞。", "狸奴當努力，鼠輩勤誅鋤。", "無爲幸一飽，高臥依寒壚。"]'),
('6a5e3763-a78a-4381-8c15-7c6b611e0c81','食蛤蜊一首','周紫芝','宋','宋诗','song-poetry','','[]','舊聞若士昇中天，俗眼未識烏鳶肩。',144,'全唐诗/poet.song.87000.json','["舊聞若士昇中天，俗眼未識烏鳶肩。", "據龜食蛤結汗漫，盧敖尚肯遊人間。", "高談謾罵沈昭略，坐視元長嗤稚弱。", "更言且共食蛤蜊，忿氣難平兩譏謔。", "下臨無地高無天，更作兒女爭媸妍。", "平生我亦笑二子，豈知真味含芳鮮。", "何如結屋清江曲，風雨關門酒初熟。", "自烹折鼎吹濕薪，笑倚胡床摩醉腹。", "但願年年對蛤蜊，一杯薦我梨花玉。"]'),
('9515bada-15e0-4872-82e2-be52d24201e4','演師跳珠泉','周紫芝','宋','宋诗','song-poetry','','[]','阿𡡉事窮奢，供億在寰宇。',120,'全唐诗/poet.song.87000.json','["阿𡡉事窮奢，供億在寰宇。", "雲錦張風帆，明珠濺飛雨。", "須臾就變滅，慶弔只仰俯。", "何如西山泉，迸石互吞吐。", "尋源上層巓，流脉下深塢。", "散作跳空珠，纍纍不堪數。", "雖無千金賞，玉漱羅堂廡。", "道人得摩尼，夜光還合浦。", "不知方外士，得失兩安取。", "此意誰復知，寒流自千古。"]'),
('0e7b2d8f-4fcf-4ab1-985f-fb5ca62bdcc2','瓊師蒼筤軒','周紫芝','宋','宋诗','song-poetry','','[]','絕境渺天末，招提入雲端。',120,'全唐诗/poet.song.87000.json','["絕境渺天末，招提入雲端。", "汪灣一溪水，似與山屈盤。", "僧房各上下，處處聞驚湍。", "道人更幽獨，開窗對檀欒。", "細雨洗輕碧，微風生暮寒。", "雲梢自裊裊，玉佩時珊珊。", "繄我絕韵友，久結無情歡。", "相逢如故人，棄置良獨難。", "婆娑弄清影，夕陽殊未殘。", "何當分清陰，與子同考槃。"]'),
('09e12973-4f46-438d-9310-86c568649389','蠟梅一首','周紫芝','宋','宋诗','song-poetry','','[]','彼美青樓倡，顔色豈不好。',132,'全唐诗/poet.song.87000.json','["彼美青樓倡，顔色豈不好。", "春風桃李花，過雨堪一掃。", "粲粲星冠女，雲宫在三島。", "霧帔卷黄羅，披風出雲表。", "焚香禮夜壇，香霧生杳渺。", "恨無脂粉顔，千金聘嫋嫋。", "劉郎竟不來，含嚬弄清曉。", "誰憐傲霜枝，照眼自明瞭。", "永懷蕊宫姿，微黄淡飛標。", "清蟾耿寒枝，與月自相惱。", "真賞久未逢，殘英惜空老。"]'),
('6030f4eb-24bc-461a-b7bb-112d0ad1a0af','次韵雷飛卿雪中掉小舟見過','周紫芝','宋','宋诗','song-poetry','','[]','别時江上草離離，相見寒枝欲放梅。',64,'全唐诗/poet.song.87000.json','["别時江上草離離，相見寒枝欲放梅。", "目送征鴻天外去，夢驚烟棹雪中來。", "青雲誰料未十里，白髮政須同一杯。", "老日相逢能有幾，春花欲動莫先回。"]'),
('679ce947-c291-403b-bc84-dbc71be6ef56','次韵似表謝胡士曹分梅花','周紫芝','宋','宋诗','song-poetry','','[]','李侯自以詩名家，詩成與月爭霜華。',144,'全唐诗/poet.song.87000.json','["李侯自以詩名家，詩成與月爭霜華。", "誰將尤物調韵語，拄笏騎曹分好花。", "花寒力淺香微透，惱亂詩翁作詩瘦。", "對花欲作楚狂顛，草賦誰居廣平右。", "但愁急管吹羌胡，便應買酒煩長鬚。", "參横想見綠衣舞，月中笑語花微臞。", "天香艷艷與誰好，君家兄弟元三株。", "明日新詩入花蕚，人間此事應久無。", "可憐多病閉門叟，對月痴坐空中書。"]'),
('3252070d-53b1-482b-ad58-da21939a2a3b','雪中過慶老方丈','周紫芝','宋','宋诗','song-poetry','','[]','雲滿江天雪意酣，擁爐聊復聽巴談。',64,'全唐诗/poet.song.87000.json','["雲滿江天雪意酣，擁爐聊復聽巴談。", "老人不出真藏六，來客何勞說後三。", "已借團蒲搖短夢，更澆春餅薦餘甘。", "此生試向閑中看，何止人間七不堪。"]'),
('47f3c315-f5ba-4f22-bc6c-d1fbe023fbac','次韵答春卿尋梅','周紫芝','宋','宋诗','song-poetry','','[]','霜梅槁立清江濆，誰當爲挽歸來魂。',128,'全唐诗/poet.song.87000.json','["霜梅槁立清江濆，誰當爲挽歸來魂。", "青鞋醉踏江沙路，玉蕤簪帽驚王孫。", "臨風想見花有語，此郎詞賦如文園。", "花開無情落亦易，聞香當款知誰門。", "怕看落地白雪滿，便恐綴枝青子繁。", "温風明月不易得，繞樹莫放花黄昏。", "知君共醉有佳客，此意歸來誰與論。", "煩君與問花無恙，尚堪一笑同清樽。"]'),
('4812db86-9faf-474d-94c2-03e0b1c481c0','飲沈都曹家梅花下','周紫芝','宋','宋诗','song-poetry','','[]','去年夜走山百盤，山中飛雪朝漫漫。',128,'全唐诗/poet.song.87000.json','["去年夜走山百盤，山中飛雪朝漫漫。", "不知春向夢中盡，更有梅花醉後看。", "今年冬温寒力軟，春入梅梢已堪剪。", "插花重飲故人樽，猶得一枝供細撚。", "豈知藂棘避戈鋋，還對粉香驚婉孌。", "花前楚客狂欲顛，月下吳牛空自喘。", "明年尚恐賊連營，零落肯教花滿眼。", "只今猶可醉餘香，杯行到君莫嫌滿。"]'),
('cabda65e-7e49-4ee6-958c-b3ec2f8b12a8','次韵舒天用元夕觀燈喜甚成詩二首  其一','周紫芝','宋','宋诗','song-poetry','','[]','河陜妖氛漸欲平，不應戎馬尚連營。',64,'全唐诗/poet.song.87000.json','["河陜妖氛漸欲平，不應戎馬尚連營。", "聲傳萬井燈花麗，月到中天夜氣清。", "爛醉且須遊閬苑，論功終合擬長城。", "歸來袖手無人識，喚作風流阮步兵。"]'),
('d9c62570-217b-4517-a75c-64d5f11999af','次韵舒天用元夕觀燈喜甚成詩二首  其二','周紫芝','宋','宋诗','song-poetry','','[]','樂事悠悠不繫情，生涯狗苟復蠅營。',64,'全唐诗/poet.song.87000.json','["樂事悠悠不繫情，生涯狗苟復蠅營。", "嫌渠燈燭紅紗亂，爲我歌詞白雪清。", "豈料脫身歸故國，可憐行樂記王城。", "開元盛事元如許，何日中原不用兵。"]'),
('d9ea5a3c-54f9-421e-acbc-23c80d0ef3c2','次韵元司理元夜三絕  其一','周紫芝','宋','宋诗','song-poetry','','[]','火龍衘燭御城遊，喜入昇平四百州。',32,'全唐诗/poet.song.87000.json','["火龍衘燭御城遊，喜入昇平四百州。", "惆悵長安今夜月，爲誰重上漢宫樓。"]'),
('0e996976-4624-4c2e-9790-3f2b8f45af0d','次韵元司理元夜三絕  其二','周紫芝','宋','宋诗','song-poetry','','[]','憶得葆真池上春，水晶簾底看燈人。',32,'全唐诗/poet.song.87000.json','["憶得葆真池上春，水晶簾底看燈人。", "當年京洛隨車客，今夜江湖臥病身。"]'),
('440294d4-e5d6-492f-bb27-ddc493b83f43','次韵元司理元夜三絕  其三','周紫芝','宋','宋诗','song-poetry','','[]','花落殘缸睡味酣，九霄誰正夢傳柑。',32,'全唐诗/poet.song.87000.json','["花落殘缸睡味酣，九霄誰正夢傳柑。", "百千燈滿虚空界，半夜回光獨閉庵。"]'),
('cba5c407-fa79-4a4d-b948-a6e0ca91a301','次韵同舒天用和元侯三絕  其一','周紫芝','宋','宋诗','song-poetry','','[]','舒郎人物是清流，不解蒲萄得一州。',32,'全唐诗/poet.song.87000.json','["舒郎人物是清流，不解蒲萄得一州。", "郡守無燈亦行樂，也隨賓客上江樓。"]'),
('ba22e925-68b8-4de0-b8d1-cfde92e04a6d','次韵同舒天用和元侯三絕  其二','周紫芝','宋','宋诗','song-poetry','','[]','亂離燈火不成春，月下歸時有幾人。',32,'全唐诗/poet.song.87000.json','["亂離燈火不成春，月下歸時有幾人。", "我老尚堪陪一笑，世間無似此閑身。"]'),
('838618a4-5d40-48ee-b423-626e82dcb5c0','次韵同舒天用和元侯三絕  其三','周紫芝','宋','宋诗','song-poetry','','[]','遊騎歸來尚半酣，一杯誰與瓮頭柑。',32,'全唐诗/poet.song.87000.json','["遊騎歸來尚半酣，一杯誰與瓮頭柑。", "小窗夢斷龕燈在，影落疏梅月上庵。"]'),
('f38a65de-fcc5-4bc8-9753-7bca6bbd635d','菖蒲山子歌','周紫芝','宋','宋诗','song-poetry','','["\u534e\u5c71", "\u592a\u6e56"]','南人生長在山間，家家有窗窗有山。',231,'全唐诗/poet.song.87000.json','["南人生長在山間，家家有窗窗有山。", "吳峰楚嶠不知數，但見雲埋雨洗堆烟鬟。", "誰知長安綺紈子，一拳何處鑱雲根。", "陽侯疏鑿出巖穴，上有斕斑皺蘚紋。", "下有千歲不死瑤草蒼鬚繁，痴兒持此矜王孫。", "朝攜磈礧登朱門，暮擁紅旌辭帝閽。", "開元承平二十年，四邊無警不控弦。", "綉衣半是花鳥使，達官避路誰敢言。", "大艑岢峨春浪碧，處處爭看太湖石。", "天心不肯乾太湖，八州萬口空嗟吁。", "纍石作山齊華嶽，千峰萬巒撐碧落。", "樛龍夭矯攬雲雨，彷彿去天無一握。", "錦帆東下飛龍舟，咸陽苑籞空蕭索。", "杜陵野老哀江頭，菖蒲之山兮誰爾留。"]'),
('c677c154-812c-4411-8033-0bb9face9448','次韵羅仲共山村題咏十首  其一','周紫芝','宋','宋诗','song-poetry','','[]','晏坐銷長日，禪心薫妙香。',24,'全唐诗/poet.song.87000.json','["晏坐銷長日，禪心薫妙香。", "已成三折臂，安用九迴腸。"]'),
('3fb3d40f-3c70-441e-be2e-5f43c41b98c2','次韵羅仲共山村題咏十首  其二','周紫芝','宋','宋诗','song-poetry','','[]','花片風前落，江流雨後渾。',24,'全唐诗/poet.song.87000.json','["花片風前落，江流雨後渾。", "少陵新得句，應似浣花村。"]'),
('2dd83b77-a601-4d35-9c0d-cb0c65c07b79','次韵羅仲共山村題咏十首  其三','周紫芝','宋','宋诗','song-poetry','','[]','喪亂何時定，江村愁殺人。',24,'全唐诗/poet.song.87000.json','["喪亂何時定，江村愁殺人。", "日長空有睡，花在不成春。"]'),
('b1e7f7e6-477b-4c5c-a651-23f17e32158a','次韵羅仲共山村題咏十首  其四','周紫芝','宋','宋诗','song-poetry','','[]','老去家無定，名高席未前。',24,'全唐诗/poet.song.87000.json','["老去家無定，名高席未前。", "如君尚窮約，誰與問蒼天。"]'),
('bb1601d6-35e3-4fde-869d-6fb9b05a8296','次韵羅仲共山村題咏十首  其五','周紫芝','宋','宋诗','song-poetry','','[]','避地成真隱，依山結草廬。',24,'全唐诗/poet.song.87000.json','["避地成真隱，依山結草廬。", "此身無籍在，隨寓即成居。"]'),
('6072cccd-cfcf-45b9-b80d-04d4651bbb88','次韵羅仲共山村題咏十首  其六','周紫芝','宋','宋诗','song-poetry','','[]','北闕書難上，南方賊未誅。',24,'全唐诗/poet.song.87000.json','["北闕書難上，南方賊未誅。", "諸公在廊廟，誰與問唐虞。"]'),
('bd364c84-026d-43d5-a6ec-f72c159071a4','次韵羅仲共山村題咏十首  其七','周紫芝','宋','宋诗','song-poetry','','[]','欲問濯潭路，懸知隔數村。',24,'全唐诗/poet.song.87000.json','["欲問濯潭路，懸知隔數村。", "曉來茅屋夢，相對飽朝暄。"]'),
('3838e576-6a81-495f-8fc6-51a7de4e417e','次韵羅仲共山村題咏十首  其八','周紫芝','宋','宋诗','song-poetry','','[]','有醉銷千日，無詩學四愁。',24,'全唐诗/poet.song.87000.json','["有醉銷千日，無詩學四愁。", "幾因君得句，技癢不能休。"]'),
('72a1c880-a331-457c-a935-40bea9faad1c','次韵羅仲共山村題咏十首  其九','周紫芝','宋','宋诗','song-poetry','','[]','塞北兵戈滿，竹西歌吹空。',24,'全唐诗/poet.song.87000.json','["塞北兵戈滿，竹西歌吹空。", "何堪故鄉夢，真在白頭中。"]'),
('266f89b3-676c-4661-840a-c1ba20587a1d','次韵羅仲共山村題咏十首  其一○','周紫芝','宋','宋诗','song-poetry','','[]','兩國兵難解，三春花自飛。',24,'全唐诗/poet.song.87000.json','["兩國兵難解，三春花自飛。", "愁因春鳥喚，心逐暮鴻歸。"]'),
('26f365f4-a289-40bf-a131-a0a22ce06a79','次韵草堂主人雨中十首  其一','周紫芝','宋','宋诗','song-poetry','','[]','反鎖衡門誰復開，草堂殊不見兵埃。',32,'全唐诗/poet.song.87000.json','["反鎖衡門誰復開，草堂殊不見兵埃。", "雄風斜卷雲頭去，雌霓横遮雨脚回。"]'),
('183310f1-fe28-47e6-935a-08d9f02d814f','次韵草堂主人雨中十首  其二','周紫芝','宋','宋诗','song-poetry','','[]','有家憐我無鄉地，好事知君不世情。',32,'全唐诗/poet.song.87000.json','["有家憐我無鄉地，好事知君不世情。", "借得小窗安淨榻，臥聽風雨入荷聲。"]'),
('1b0185b2-7657-4b45-a5b8-29fa03f727a3','次韵草堂主人雨中十首  其三','周紫芝','宋','宋诗','song-poetry','','[]','虎頭山下元無路，龍骨溪邊尚有窗。',32,'全唐诗/poet.song.87000.json','["虎頭山下元無路，龍骨溪邊尚有窗。", "風裏荷花吹不倒，雨中鸂鶒自成雙。"]'),
('52aaf1da-9646-4915-acdd-5b3f881a5f1d','次韵草堂主人雨中十首  其四','周紫芝','宋','宋诗','song-poetry','','[]','少年結客不思家，酒涴春衫白苧麻。',32,'全唐诗/poet.song.87000.json','["少年結客不思家，酒涴春衫白苧麻。", "今日江村烟雨裏，兵戈滿地鬢雙華。"]'),
('27283d02-4a3e-4a95-9b6d-4c1eec85ad02','次韵草堂主人雨中十首  其五','周紫芝','宋','宋诗','song-poetry','','[]','滿谿烟雨濕芙蕖，綠葉紅花錦不殊。',32,'全唐诗/poet.song.87000.json','["滿谿烟雨濕芙蕖，綠葉紅花錦不殊。", "聞說宛西橋畔宅，小園無地不荒蕪。"]'),
('994925de-6fe3-4917-8c5d-0a128025f471','次韵草堂主人雨中十首  其六','周紫芝','宋','宋诗','song-poetry','','[]','醉裏青春挽不留，眼前戈甲幾時休。',32,'全唐诗/poet.song.87000.json','["醉裏青春挽不留，眼前戈甲幾時休。", "溪邊雨細花吹盡，隴上風寒麥又秋。"]'),
('3a085592-9e0f-4784-bdab-bc7dcc5f89b0','次韵草堂主人雨中十首  其七','周紫芝','宋','宋诗','song-poetry','','[]','亂來歲月總如流，頭白江村不奈愁。',32,'全唐诗/poet.song.87000.json','["亂來歲月總如流，頭白江村不奈愁。", "老罷此身何處着，尚堪同倚雨中樓。"]'),
('728ab0d0-1aac-4a57-927f-0a8cb486b3a2','次韵草堂主人雨中十首  其八','周紫芝','宋','宋诗','song-poetry','','[]','含桃熟後鶯還語，柳絮飛時燕亦忙。',32,'全唐诗/poet.song.87000.json','["含桃熟後鶯還語，柳絮飛時燕亦忙。", "風物但隨時節好，不知人意自凄凉。"]'),
('436bb062-ef9a-404b-84e3-66cf9161f30e','次韵草堂主人雨中十首  其九','周紫芝','宋','宋诗','song-poetry','','[]','浴鳧飛鷺下横塘，花過鶯歸草自長。',32,'全唐诗/poet.song.87000.json','["浴鳧飛鷺下横塘，花過鶯歸草自長。", "恰似碧雞坊口望，浣花谿上一茅堂。"]'),
('c28eb62b-c288-40e3-af81-ca590928f08d','次韵草堂主人雨中十首  其一○','周紫芝','宋','宋诗','song-poetry','','[]','避地偷生只閉門，不堪搔首對醨尊。',32,'全唐诗/poet.song.87000.json','["避地偷生只閉門，不堪搔首對醨尊。", "行歌野哭江頭路，雨葉風花總斷魂。"]'),
('dc1f3bdb-cd28-4cf9-82da-280d3cec587c','避兵遣懷六首  其一','周紫芝','宋','宋诗','song-poetry','','[]','鳥噪烏江渡，鯨吞白下州。',48,'全唐诗/poet.song.87000.json','["鳥噪烏江渡，鯨吞白下州。", "地分元帥重，聲入賊營愁。", "近磔巡江尉，將俘北闕頭。", "兵行速如鬼，高鼻半氈裘。"]'),
('0bd0e72a-711f-4b6e-93ad-92bacc91114d','避兵遣懷六首  其二','周紫芝','宋','宋诗','song-poetry','','[]','江闊烽烟冷，城危戰騎驍。',48,'全唐诗/poet.song.87000.json','["江闊烽烟冷，城危戰騎驍。", "虜從諸道入，將擁潰兵驕。", "萬國晝多壘，三軍夜擊刁。", "干戈空滿眼，蛇豕不勝梟。"]'),
('5fa82ed0-eaa7-4ece-b3a4-0c8a57ac27ae','避兵遣懷六首  其三','周紫芝','宋','宋诗','song-poetry','','[]','避地蒼黄夜，悲涼郡郭西。',48,'全唐诗/poet.song.87000.json','["避地蒼黄夜，悲涼郡郭西。", "捫蘿危絕磴，杖策困深泥。", "掩面憐痴女，回頭愧老妻。", "驚魂猶未定，胡馬莫頻嘶。"]'),
('d4eba083-32b4-4b6a-a4ec-36f00e63d5f8','避兵遣懷六首  其四','周紫芝','宋','宋诗','song-poetry','','[]','野宿寧堪度，風餐寔自憐。',48,'全唐诗/poet.song.87000.json','["野宿寧堪度，風餐寔自憐。", "妻孥渾在眼，戈甲暗凋年。", "夜月翻驚鵲，炎天看跕鳶。", "射敵無一矢，南渡幾樓船。"]'),
('67a3fa76-c010-4270-851a-210a3f2d0554','避兵遣懷六首  其五','周紫芝','宋','宋诗','song-poetry','','[]','心折來時路，身行亂後村。',48,'全唐诗/poet.song.87000.json','["心折來時路，身行亂後村。", "土兵呵白晝，野婦哭黄昏。", "賊去烟留屋，人歸日在門。", "舂陵四萬户，今日幾家存。"]'),
('b71fca91-f53d-4d76-9128-19d9a38542d8','避兵遣懷六首  其六','周紫芝','宋','宋诗','song-poetry','','[]','閶闔乾坤大，封疆四百州。',48,'全唐诗/poet.song.87000.json','["閶闔乾坤大，封疆四百州。", "蒙塵二聖哲，伐叛六春秋。", "地入强胡闊，官封悍將優。", "奉天哀詔下，感泣萬方愁。"]'),
('da701901-e714-496a-bd3b-bc3237f1563d','次韵常元明西坑見寄二首  其一','周紫芝','宋','宋诗','song-poetry','','[]','西坑只在亂山間，尋得仇池十九泉。',32,'全唐诗/poet.song.87000.json','["西坑只在亂山間，尋得仇池十九泉。", "有句能催千嶂雨，無人共釣一川烟。"]'),
('aa37b87f-2087-4b17-8ccd-1425166451ee','次韵常元明西坑見寄二首  其二','周紫芝','宋','宋诗','song-poetry','','[]','南來賊騎欲凌川，北嶺人家自燒原。',32,'全唐诗/poet.song.87000.json','["南來賊騎欲凌川，北嶺人家自燒原。", "聞道西坑堪避地，擬尋雞犬問桃源。"]'),
('b4ed8ab6-7772-410f-a88a-e34bfb16affa','寒食雜興三首  其一','周紫芝','宋','宋诗','song-poetry','','[]','寒食只數日，天氣殊未佳。',108,'全唐诗/poet.song.87000.json','["寒食只數日，天氣殊未佳。", "輕雲澹微茫，細雨吹横斜。", "青春似無情，不到愁人家。", "霽色忽浩蕩，平原繡芳華。", "走馬惡少年，挾矢射戟牙。", "白羽叫餓鴟，舉網連五豝。", "會當斬長鯨，封侯鳴鼓笳。", "時危何不有，寒士空泥沙。", "凜凜羞俠氣，悠悠但咨嗟。"]'),
('144d8af9-4dd1-46a8-aaf4-ad398d69ea96','寒食雜興三首  其二','周紫芝','宋','宋诗','song-poetry','','[]','憶昔在京華，醉踏長安市。',120,'全唐诗/poet.song.87000.json','["憶昔在京華，醉踏長安市。", "長安白面郎，快馬如流水。", "羅襦照暮春，鬬草攜佳麗。", "就中五侯家，雲幄耀金翠。", "九陌過香軿，都人拾遺珥。", "歌喧樂佳節，日暮多沉醉。", "榮華一消歇，禍亂蒼黄起。", "北狩隨兩宫，血屬六萬指。", "征車去悠悠，河水日瀰瀰。", "浩歌哀江頭，老淚不可止。"]'),
('ba014bd7-7df7-416c-b64d-9dd300a0e058','寒食雜興三首  其三','周紫芝','宋','宋诗','song-poetry','','[]','北邙何巍巍，高冢如魚鱗。',120,'全唐诗/poet.song.87000.json','["北邙何巍巍，高冢如魚鱗。", "慨彼墓中士，中朝稱貴人。", "萬金樹豐碑，千金琢麒麟。", "自從胡騎入，亂離隔中原。", "生者各奔竄，死者啣長冤。", "子孫無奠享，白楊悲餒魂。", "峨峨纓冠子，往往無丘墳。", "舉酒西北向，野哭望白雲。", "我今上先隴，覆杯松下根。", "時危不自保，念之殊酸辛。"]'),
('a9527f52-ea37-468f-a7a3-0533419239b1','寒食夜月下作','周紫芝','宋','宋诗','song-poetry','','[]','一百五夜對明月，二十七種無蔬柈。',64,'全唐诗/poet.song.87000.json','["一百五夜對明月，二十七種無蔬柈。", "莫嫌萬點飛花恨，且結三人對影歡。", "流落忽成身老大，亂離誰不涕闌干。", "顛狂自笑那能寐，立盡春風午夜寒。"]'),
('bdd0690d-faf0-4689-871c-f418117ebb4c','送詹伯尹丞涇邑','周紫芝','宋','宋诗','song-poetry','','[]','西溪寒食柳花飛，正是琴高欲到時。',64,'全唐诗/poet.song.87000.json','["西溪寒食柳花飛，正是琴高欲到時。", "薄禄僅酬三釡志，新篇莫負兩松詩。", "催科未辦何妨拙，作吏能清不用知。", "高論平生期活國，一方疲瘵看君醫。"]'),
('20951a27-8412-42a6-afcd-340266acfabf','題馮尉綠浄堂','周紫芝','宋','宋诗','song-poetry','','[]','不種平池玉井蓮，卷簾堂下水如煙。',64,'全唐诗/poet.song.87000.json','["不種平池玉井蓮，卷簾堂下水如煙。", "溶溶自漲晴江綠，脈脈還通暗谷泉。", "誰道馮唐今白首，始知梅福是真仙。", "客來莫吐青銅面，要看蟾宫上下天。"]'),
('9d348918-5cad-4910-b82d-ea37737424aa','野飯','周紫芝','宋','宋诗','song-poetry','','[]','野飯聊娛老，登盤春物佳。',48,'全唐诗/poet.song.87000.json','["野飯聊娛老，登盤春物佳。", "芼羮横荻笋，煮餅荐槐芽。", "魚尾初垂劍，臺苗未着花。", "誰言庾郎瘦，蔬腹漸禁茶。"]'),
('5cd710c5-7d1c-4729-ab1f-f50c31b9fa4b','明皇羯鼓圖','周紫芝','宋','宋诗','song-poetry','','[]','禁籞鶯聲外，天袍擁御黄。',48,'全唐诗/poet.song.87000.json','["禁籞鶯聲外，天袍擁御黄。", "曲名翻荔子，春苑繞沉香。", "白雨花奴手，風鬉舞馬床。", "向來歌吹地，何處是漁陽。"]'),
('4d6a56fc-ce4f-42d3-b5d9-943cfef1bfd4','送智上人','周紫芝','宋','宋诗','song-poetry','','[]','道人飲山流，顔色頗秀整。',120,'全唐诗/poet.song.87000.json','["道人飲山流，顔色頗秀整。", "經營一庵足，偃蹇萬事屏。", "忽隨銅峰雲，飛下銅峰頂。", "欲了一大緣，此意極勇猛。", "白晝多豺狼，横塗半坑穽。", "爲言尸陁林，誰能保腰領。", "要憑降魔力，化作清淨境。", "師亦初無言，薄俗時自警。", "盡洗歷劫冤，願力周涬溟。", "瘦藤行可支，慎勿厭馳騁。"]'),
('1f63121c-1f8f-4daf-87f7-b20c9b69daf1','張載揚言揚州燕子無屋可居即船爲巢命黄叔魚賦詩今年春余始見叔魚詩于宣城遂同賦','周紫芝','宋','宋诗','song-poetry','','[]','塞北胡兒歸去日，揚州燕子却來時。',64,'全唐诗/poet.song.87000.json','["塞北胡兒歸去日，揚州燕子却來時。", "空尋畫舸藏風雨，更爲傍人話别離。", "回首凄迷春水路，傷心零落舊巢泥。", "斜陽不見烏衣巷，一讀君詩淚欲垂。"]'),
('f213dac3-740d-40b2-a539-1f6aae1fb491','送吕右丞罷鎮宛陵','周紫芝','宋','宋诗','song-poetry','','[]','漢室承平久，侯邦拱衛尊。',288,'全唐诗/poet.song.87000.json','["漢室承平久，侯邦拱衛尊。", "勳華垂日月，展錯動乾坤。", "開闢規模大，紛更制作繁。", "民勞箕斂日，虜痛鑿空痕。", "鳴鏑侵榆塞，穹廬指鳯閽。", "羽書飛始急，魚鼎沸初渾。", "內禪皇圖遠，春宫曉日暾。", "羣妖悉葅醢，黄髪半騰鶱。", "公入登丞轄，忠稱自諌垣。", "論思知蹇蹇，屬意本元元。", "蠖濩資扶掖，奇庬力引援。", "犬羊盟易失，虎兕敵仍存。", "轉戰知何已，風塵忽再昏。", "倉皇趨帳殿，奔北弃弓鞬。", "傾日心應折，瞻天眼欲眢。", "徽音求太姒，基命本姜嫄。", "大物歸明辟，蒼生荷國恩。", "推符迎代邸，結綬擁堯軒。", "灞上真人出，塗山萬國奔。", "回天功不世，徙突事堪論。", "已復安西土，猶煩護北門。", "要須調鼎手，爲洗泣隅冤。", "萬杵堅城壘，千兵列戍屯。", "賊鋒憂寇鈔，原燎畏燒燔。"]'),
('bac59bf8-10b4-40ae-8e5d-e71ba4476e25','元素僻在草野羣盗縱横久不得問新作鼎來喜次其韻三首  其一','周紫芝','宋','宋诗','song-poetry','','[]','兵氣纒滄海，斜陽入暮林。',48,'全唐诗/poet.song.87000.json','["兵氣纒滄海，斜陽入暮林。", "魂傷春落絮，淚濕晚啼禽。", "只有衣成結，渾無髪受簪。", "殘生已飄泊，老日更侵尋。"]'),
('2f2df566-5727-4b49-b439-9397742bbe39','元素僻在草野羣盗縱横久不得問新作鼎來喜次其韻三首  其二','周紫芝','宋','宋诗','song-poetry','','[]','自失雲橋路，空傷烟樹林。',48,'全唐诗/poet.song.87000.json','["自失雲橋路，空傷烟樹林。", "天驕猶射月，青犢未成禽。", "尚怯矛頭米，空横柱後簪。", "春光無賴好，花落共誰尋。"]'),
('5e74722e-c2b2-4ee9-b091-8b7d53a01e7d','元素僻在草野羣盗縱横久不得問新作鼎來喜次其韻三首  其三','周紫芝','宋','宋诗','song-poetry','','[]','近聞君隱處，茅屋带平林。',48,'全唐诗/poet.song.87000.json','["近聞君隱處，茅屋带平林。", "但可占鳴犢，誰能黜展禽。", "書應藂浄几，塵已暗横簪。", "杖策終隨子，雲山上百尋。"]'),
('6a96d134-8955-4e46-89ba-07beb7185581','同仲共兄弟訪趙行可行可置酒二首  其一','周紫芝','宋','宋诗','song-poetry','','[]','倚杖山頭寺，維舟柳下堤。',48,'全唐诗/poet.song.87000.json','["倚杖山頭寺，維舟柳下堤。", "莫催金騕褭，且醉玉東西。", "亂後兵猶滿，風驚鳥未栖。", "看君飛動意，兩目在鯨鯢。"]'),
('57da37cf-15df-450d-8ec2-8c8957d9f53b','同仲共兄弟訪趙行可行可置酒二首  其二','周紫芝','宋','宋诗','song-poetry','','[]','坐客三珠秀，王孫玉樹高。',48,'全唐诗/poet.song.87000.json','["坐客三珠秀，王孫玉樹高。", "酒寧關爾軰，山合對吾曹。", "遊子家何定，將軍戰未鏖。", "相逢莫相失，羣盜正如毛。"]'),
('ce73f915-e16d-4b76-9420-4244acd3a079','讀陳公葆真宫詩有感而作','周紫芝','宋','宋诗','song-poetry','','[]','念昔全盛日，天子方祈年。',120,'全唐诗/poet.song.87000.json','["念昔全盛日，天子方祈年。", "崆峒擬問道，桂館延列仙。", "葆真號上宫，柳色參雲烟。", "方池下見底，上映壺中天。", "長安二三月，遊女飛朱軿。", "蹣跚步金堤，依約遺翠鈿。", "芙蕖倚紅粧，弄影秋江邊。", "我亦時結客，曵杖相周旋。", "不知客中人，有此稀世賢。", "臨老誦公詩，撫卷徒惘然。"]'),
('94f71c01-6976-41ee-b85a-94e3cc0377e8','初夏','周紫芝','宋','宋诗','song-poetry','','[]','絮飛長陌又春餘，綠滿菖蒲夏已初。',64,'全唐诗/poet.song.87000.json','["絮飛長陌又春餘，綠滿菖蒲夏已初。", "雙蝶不來花蔌蔌，一鶯時到樹疏疏。", "平生懶作折楊曲，萬事可占長柳書。", "只有故山真耐久，伴人閑處作踟蹰。"]'),
('69bc8088-bdd7-4984-8374-0490bdf1024e','賊退後經舊居','周紫芝','宋','宋诗','song-poetry','','[]','反側虞戈兵，流離厭山谷。',216,'全唐诗/poet.song.87000.json','["反側虞戈兵，流離厭山谷。", "師興解重圍，亂定出荼毒。", "提攜望郷關，老稚甘趼足。", "故里成丘墟，門巷亡詰曲。", "大木亦已薪，蔓草行可束。", "東鄰殺翁媪，禍難云最酷。", "白骨在草間，零落不相屬。", "西家各奔竄，係擄及僮僕。", "當時黄金囊，掉頭不肯贖。", "新交半亡沒，變故誰記録。", "舉家竟何歸，寄食歎局促。", "凶年大軍後，旱氣日熇熇。", "涸井不供炊，垢膩那得浴。", "不知病瘦軀，何以度蒸溽。", "自從關陜亂，威弧殊未韣。", "十人九無家，蕩析豈所欲。", "微生何足論，主食久不玉。", "但願早休兵，四海各安俗。"]'),
('01a340d4-c3e3-4c63-b0dc-e56597b679b0','憫雨歎','周紫芝','宋','宋诗','song-poetry','','[]','南方久不雨，旱氣日益酷。',144,'全唐诗/poet.song.87000.json','["南方久不雨，旱氣日益酷。", "起視夜何其，星斗燦滿目。", "朝雲藹空濛，暮雨思霢霂。", "雷師方鞭車，風伯忽舞纛。", "百神各顛倒，誰爲調玉燭。", "兩宫方蒙塵，百執被驅逐。", "萬里沙漠行，長征犯三伏。", "懸知臣子心，北望眢兩目。", "願興膚寸雲，朝隮暮滲漉。", "天公倘悔禍，何止望一熟。", "皇輿既言歸，壤地亦旋復。", "誰當挽天河，下洗憂憤辱。"]'),
('cb39af1a-250e-4fbe-bbb3-de4ef5d61675','和人題徐獻可倅廳池蓮二首  其一','周紫芝','宋','宋诗','song-poetry','','[]','風流别乘水中仙，百丈新移玉井蓮。',32,'全唐诗/poet.song.87000.json','["風流别乘水中仙，百丈新移玉井蓮。", "試掉小舟花裏去，便如苕霅雨中眠。"]'),
('0f08ceba-15e1-4c2c-b488-a4f30250de89','和人題徐獻可倅廳池蓮二首  其二','周紫芝','宋','宋诗','song-poetry','','[]','西風吹雨綠楊灣，香滿紅粧一水間。',32,'全唐诗/poet.song.87000.json','["西風吹雨綠楊灣，香滿紅粧一水間。", "不把監州比螃蟹，看花誰似兩公閑。"]'),
('15360acc-73f0-4fe3-bcc2-90b1e32c78ad','毅果出示次卿詩編中有彭門見寄之作乃追和元韵','周紫芝','宋','宋诗','song-poetry','','[]','往憶烏衣郎，北走彭門道。',216,'全唐诗/poet.song.87000.json','["往憶烏衣郎，北走彭門道。", "六年隔音容，萬事掛懷抱。", "相思枉停雲，尺紙開小草。", "爲言清夜夢，莞爾同一笑。", "黄樓渺天末，路遠何由到。", "我亦仰屋梁，恍若落月照。", "神交見顔色，此理固良妙。", "撫事思少年，相期在嵩少。", "是時海內安，王師未征討。", "尚有丘壑姿，可寄沮溺傲。", "一從胡鶵驕，斯民困征調。", "一死抗賊徒，奇禍發詞藻。", "造物苦見憎，與俗坐殊好。", "微軀此棲遲，長夜悲靜悄。", "蒼狗變浮雲，世事那可料。", "傷心埋白玉，急景轉飛鳥。", "幸此好事人，遺編爲傾倒。", "老眼倏巳明，權門益慵掃。"]'),
('391464bb-5c22-429d-bc5c-339495092797','毅師以次卿詩編見示以二詩還之  其一','周紫芝','宋','宋诗','song-poetry','','[]','雲錦當年事，傷心不忍思。',48,'全唐诗/poet.song.87000.json','["雲錦當年事，傷心不忍思。", "江寒收骨後，山晚斷魂時。", "直節君何恨，天心我獨疑。", "老懷無處著，更復把君詩。"]'),
('96725917-b791-4cd9-b2fe-d1aec02ac0c6','毅師以次卿詩編見示以二詩還之  其二','周紫芝','宋','宋诗','song-poetry','','[]','人物忽掃地，風流誰復知。',48,'全唐诗/poet.song.87000.json','["人物忽掃地，風流誰復知。", "子猷心愛竹，摩詰少能詩。", "疇昔山林意，殘年喪亂悲。", "明珠在滄海，好句莫多遺。"]'),
('55729bf4-f95e-478d-8ab2-6c09b028d1cd','蔡生縛氈根毛筆戲書小詩','周紫芝','宋','宋诗','song-poetry','','[]','臥沙細肋策勳餘，點鼠何勞强挽鬚。',32,'全唐诗/poet.song.87000.json','["臥沙細肋策勳餘，點鼠何勞强挽鬚。", "毛穎典型空復在，髯郎今巳號中書。"]'),
('efb8faff-64eb-4165-89c5-32bb5f1b6d28','九日度折嶺','周紫芝','宋','宋诗','song-poetry','','[]','脩途苦悠悠，行邁日靡靡。',156,'全唐诗/poet.song.87000.json','["脩途苦悠悠，行邁日靡靡。", "間道避羣兇，弛擔倦行李。", "重岡頗峻極，一上三十里。", "荆榛塞舊蹊，設險防賊軌。", "鑿空破狼石，猿徑僅容趾。", "俯身視懸崖，駭汗如流水。", "回首問僕夫，倉皇謀進止。", "鄧公固忠臣，王陽真孝子。", "經營能幾何，蹈歷乃至爾。", "佳晨懷故鄉，絕頂步屐齒。", "醉帽落清樽，浮香嚼金蕊。", "歲事行晏陰，四郊復多壘。", "浩歌歸去來，吾行且安竢。"]'),
('b02c7d87-80bf-48cb-96b1-5c44dec0c5f3','宿靈河寺','周紫芝','宋','宋诗','song-poetry','','[]','風餐倚虚壑，險步躋雲梯。',120,'全唐诗/poet.song.87000.json','["風餐倚虚壑，險步躋雲梯。", "驚魂棲客枕，夜宿投招提。", "殷勤入簷月，肯爲幽人低。", "滄海念横流，萬方喧鼓鼙。", "胡爲困行役，竄伏隨麕麑。", "南枝越鳥巢，北風胡馬嘶。", "耿耿念徒旅，依依懷故谿。", "脂車待明發，胡爲尚栖栖。", "人生如醵飲，暫聚還復暌。", "百年能幾何，行樂戒噬臍。"]'),
('7bd0b307-dc18-4e69-99f2-8db9a912e49a','秋霖歎','周紫芝','宋','宋诗','song-poetry','','[]','去年陰山雪，平地三尺餘。',180,'全唐诗/poet.song.87000.json','["去年陰山雪，平地三尺餘。", "人言土中蝗，入土不用驅。", "今年歲枯旱，野食無豆蔬。", "西來三尺蝗，舊歲雪不如。", "秋田有遺秉，未足飽一夫。", "細雨生穀芽，屯雲幾時舒。", "群兇劇豺虎，諸將勞驅除。", "横尸作京觀，流血如决渠。", "高穹厭殺氣，荆棘滿郊墟。", "尚復此恒雨，未知當何如。", "豈欲令斯民，竟死不少紓。", "天亦念赤子，理豈有是歟。", "會當開晴雲，却返羲和車。", "我廩雖巳殫，我地尚可鋤。", "庶用種宿麥，更作來歲儲。"]'),
('afd123e1-f1f5-4553-b760-d1ee455f9249','次韵趙鵬翔秋夜歎','周紫芝','宋','宋诗','song-poetry','','[]','朝彈雍門琴，暮歌梁父吟。',132,'全唐诗/poet.song.87000.json','["朝彈雍門琴，暮歌梁父吟。", "秋容日欲老，客愁秋更深。", "問言愁何許，萬里懷歸心。", "昔在洛陽日，頗遭胡騎侵。", "骨肉盡奔迸，歲月良侵尋。", "譬如痛定人，當痛難重任。", "辭親就薄禄，夜寢無完衾。", "家亡河間書，囊鮮鴻寶金。", "誰能援一臂，使子無陸沉。", "老驥得平坂，驚鳯翔長林。", "佳名一朝白，高義千古欽。"]'),
('50ea6d85-99a9-45bc-b003-c02d87d54002','山谷先生弔秦少游詩云少游醉臥古藤下誰與愁眉唱一杯解道樽前斷腸句江南唯有賀方回此以言語文字知少游者也余鄉人有官藤州者謂藤人爲余言少游既病洗沐步上光華亭手持白玉杯命取江水立酌一杯而逝嗚呼此豈徒然者哉東坡題少游自作挽詞以爲能一死生齊物我是真知少游者也','周紫芝','宋','宋诗','song-poetry','','[]','古藤陰下偶婆娑，南北隨緣意若何。',64,'全唐诗/poet.song.87000.json','["古藤陰下偶婆娑，南北隨緣意若何。", "白玉杯寒亭上月，縷金衣斷醉時歌。", "還將萬里澄江水，盡洗平生綺語魔。", "能道秦郎解忘物，嶺南唯有雪堂坡。"]'),
('0720994c-b8a0-41ac-aeb6-1b26840f21b9','歲杪雨雪連日悶題六絕  其一','周紫芝','宋','宋诗','song-poetry','','[]','春前舊雪連新雪，雨後春寒带臘寒。',32,'全唐诗/poet.song.87000.json','["春前舊雪連新雪，雨後春寒带臘寒。", "殘日送年能幾許，一番風雨歲將闌。"]'),
('4663850f-e4ae-460c-8813-bf51c87bd9f8','歲杪雨雪連日悶題六絕  其二','周紫芝','宋','宋诗','song-poetry','','[]','樹頭雪過梅猶在，地上春回柳未知。',32,'全唐诗/poet.song.87000.json','["樹頭雪過梅猶在，地上春回柳未知。", "舊歲新年渾似夢，凍雲寒雨不勝悲。"]'),
('d3e646b1-134e-421c-acbe-b1f35601640d','歲杪雨雪連日悶題六絕  其三','周紫芝','宋','宋诗','song-poetry','','[]','春回九地初頒歷，人傍千門復看儺。',32,'全唐诗/poet.song.87000.json','["春回九地初頒歷，人傍千門復看儺。", "盡是漢家無事日，白頭扶杖意如何。"]'),
('cb9fd559-8bd8-4800-bbd8-7ae3c14c3b5b','歲杪雨雪連日悶題六絕  其四','周紫芝','宋','宋诗','song-poetry','','[]','去年胡代馬渡淮流，江北江南處處愁。',33,'全唐诗/poet.song.87000.json','["去年胡代馬渡淮流，江北江南處處愁。", "破虜只今猶遣將，富民何日定封侯。"]'),
('65e6bbc6-66f4-4e6c-bad4-58ebb26592be','歲杪雨雪連日悶題六絕  其五','周紫芝','宋','宋诗','song-poetry','','[]','鞭牛迎得春來了，爆竹催將歲欲徂。',32,'全唐诗/poet.song.87000.json','["鞭牛迎得春來了，爆竹催將歲欲徂。", "莫把流年作悲喜，人間萬事有乘除。"]'),
('f4115e00-a9e0-4e5e-a180-733382502ca0','歲杪雨雪連日悶題六絕  其六','周紫芝','宋','宋诗','song-poetry','','[]','大雪今宵一尺餘，王春明日歲云初。',32,'全唐诗/poet.song.87000.json','["大雪今宵一尺餘，王春明日歲云初。", "豐年已識天公意，上瑞仍煩太史書。"]'),
('0bd6573a-7e13-473a-b006-3dd8780d4c5a','凌歊晚眺','周紫芝','宋','宋诗','song-poetry','','[]','故鄉南望幾時回，落日登臨眼自開。',64,'全唐诗/poet.song.87000.json','["故鄉南望幾時回，落日登臨眼自開。", "倚杖獨看飛鳥去，開窗忽擁大江來。", "傷心不見姑溪老，抱病聊尋宋武臺。", "歲晚無人弔遺跡，壁間詩在半灰埃。"]'),
('27112d69-e72d-46b4-9c1a-441cd7d0e800','次韵伯尹登嚴子陵釣臺','周紫芝','宋','宋诗','song-poetry','','[]','明光宫中梟夜鳴，漢鼎何人窺重輕。',176,'全唐诗/poet.song.87000.json','["明光宫中梟夜鳴，漢鼎何人窺重輕。", "老髗未汙屬鏤血，四海掩鼻愁羶腥。", "當時避地豈得已，巖棲水宿俱非情。", "誰知舉世無真隱，此意獨高嚴子陵。", "一鈎明月滿蓑雨，桃花水漲春江平。", "生涯頗似玄真子，端欲釣魚非釣名。", "故人巳作飛龍起，猶着羊裘釣烟水。", "異時侯霸豈其儔，未可輕將袞衣比。", "心知不爲世人屈，無故不作三公耳。", "富貴浮雲只眼前，執戟長憐子揚子。", "丈夫名節倘未立，安用區區識奇字。"]'),
('333b3827-9db1-4dcd-9a84-fdd2e221dde8','環翠亭','周紫芝','宋','宋诗','song-poetry','','[]','客意長隨倦鳥還，翠屏空夢小孱顔。',64,'全唐诗/poet.song.87000.json','["客意長隨倦鳥還，翠屏空夢小孱顔。", "更將臨老雙愁眼，來看平生未見山。", "西子爲誰顰遠黛，湘娥何事髻烟鬟。", "千巖萬壑無人處，便是輞川圖畫間。"]'),
('ec8e216f-3a03-4065-a792-39d7da5ea41b','種德亭','周紫芝','宋','宋诗','song-poetry','','[]','萬緣宜作夢時看，只有情田種德難。',64,'全唐诗/poet.song.87000.json','["萬緣宜作夢時看，只有情田種德難。", "但把胸中着梨棗，不愁庭下欠芝蘭。", "倡條冶葉渾無賴，錯節盤根頗耐寒。", "莫笑襄陽龐老子，全家長享鹿門安。"]'),
('cdd8892c-f271-4cd6-8455-7a94c29fbd00','蔡澄源録三家詩見借各題一詩以還之  其一','周紫芝','宋','宋诗','song-poetry','','[]','翰林才大今師伯，目短曹劉數仭牆。',32,'全唐诗/poet.song.87000.json','["翰林才大今師伯，目短曹劉數仭牆。", "我亦當年曾問字，雲泥無路可升堂。"]'),
('9f0ecb14-4fb9-4906-ad45-b866e8209a9b','蔡澄源録三家詩見借各題一詩以還之  其二','周紫芝','宋','宋诗','song-poetry','','[]','早時得句唾成珠，晚歲分符雪似須。',32,'全唐诗/poet.song.87000.json','["早時得句唾成珠，晚歲分符雪似須。", "聊復把公詩過日，何心賦我食無餘。"]'),
('93346710-bb26-4ffd-9242-5e38e487d11a','蔡澄源録三家詩見借各題一詩以還之  其三','周紫芝','宋','宋诗','song-poetry','','[]','少年湖海識元龍，老去功名事已空。',32,'全唐诗/poet.song.87000.json','["少年湖海識元龍，老去功名事已空。", "筆陣舊知無與敵，詩城今復有誰攻。"]'),
('ffb87e8b-e12b-427f-951e-4020007a04a4','睡起有感','周紫芝','宋','宋诗','song-poetry','','[]','日長誰復款幽扉，睡到斜陽恰盡時。',64,'全唐诗/poet.song.87000.json','["日長誰復款幽扉，睡到斜陽恰盡時。", "缺月要圓雲未肯，青春欲老絮先知。", "天扵我輩元無分，夢比人間更不疑。", "門外故人千嶂遠，燈前華髪萬絲垂。"]'),
('a46f4f56-671a-4ac8-91f2-e2355d3f31e5','次韻伯遠春雪','周紫芝','宋','宋诗','song-poetry','','[]','風寒欲下欺春雪，天近先垂壓地雲。',64,'全唐诗/poet.song.87000.json','["風寒欲下欺春雪，天近先垂壓地雲。", "堆得樓頭成玉色，吹來酒面作波紋。", "憑陵暖日竟何事，調護新花誰解紛。", "温詔始聞如挾纊，九重應復念三軍。"]'),
('503694ab-3f1b-4fbd-8aad-2179713a2100','光武二十八年五溪蠻反馬文淵年六十三矣踴躍請行卒致困敗班定遠久在絕域上疏請歸詞甚切至其略曰臣不敢望至酒泉郡但願生入玉門關遂老中朝辛亥季春三日燈下讀此二傳感而賦詩','周紫芝','宋','宋诗','song-poetry','','[]','平生長歎馬文淵，功業遨遊二帝間。',64,'全唐诗/poet.song.87000.json','["平生長歎馬文淵，功業遨遊二帝間。", "洛社龍飛初有意，嶠南鳶墮不知還。", "雖迷槃瓠壺頭路，肯愧祈連冢上山。", "政坐不如班定遠，乞身生入玉門關。"]'),
('0d897291-0c97-412d-b9de-9d313e15cf7a','題趙周賓家夜獵圖','周紫芝','宋','宋诗','song-poetry','','[]','翰林作醉石，偶似蒼於菟。',189,'全唐诗/poet.song.87000.json','["翰林作醉石，偶似蒼於菟。", "龍眠見之笑，爲作匹馬彎彫弧。", "云是將軍出夜獵，上有仇池行草書。", "雲沙蒼茫日欲下，道逢伏虎南山隅。", "心知是虎不是石，雙弦急控皆盧胡。", "明朝白羽飲頑石，摩挲欲盡金僕姑。", "君不見賜累千金新垣平，連佩六印欒將軍。", "致君大略豈在爾，封侯細事不到君。", "先生言語妙天下，瘴海七年皮肉皴。", "邂逅英物數蘇李，曹蜍如生亦如死。", "龍眠有眼識天人，異世同成一奇事。", "君當什襲勿漫摹，此人此畫人間無。"]'),
('8009582e-fea2-45a0-be67-680dc4fbff9e','五禽言','周紫芝','宋','宋诗','song-poetry','','[]','余避賊山中，婆娑巖壑間。',51,'全唐诗/poet.song.87000.json','["余避賊山中，婆娑巖壑間。", "終日寂然不聞人聲，惟春禽嘲哳不絕于耳。", "乃用其語效昔人爲五禽言，亦山中一戲事也。"]'),
('7d3e16c7-2a8c-4b38-ae39-8b4f3278eb42','婆餅焦','周紫芝','宋','宋诗','song-poetry','','[]','雲穰穰，麥穗黄，婆餅欲焦新麥香。',40,'全唐诗/poet.song.87000.json','["雲穰穰，麥穗黄，婆餅欲焦新麥香。", "今年麥熟不敢嘗，斗量車載傾囷倉，化作三軍馬上糧。"]'),
('259bfaf2-58d1-4f73-a15f-1efea681637a','泥滑滑','周紫芝','宋','宋诗','song-poetry','','[]','山中流水聲聒聒，春禽說雨春泥滑。',46,'全唐诗/poet.song.87000.json','["山中流水聲聒聒，春禽說雨春泥滑。", "誰爲春禽語，莫報幽人明日雨。", "幽人明日欲上山，山頭雨足花斕斑。"]'),
('c554e366-432f-43cb-a8f2-42a20622a8f9','提壺盧','周紫芝','宋','宋诗','song-poetry','','[]','提壺盧，樹頭勸酒聲相呼，勸人沽酒無處沽。',52,'全唐诗/poet.song.87000.json','["提壺盧，樹頭勸酒聲相呼，勸人沽酒無處沽。", "太歲何年當在酉，敲門問漿還得酒。", "田中黍穗處處黄，瓮頭新綠家家有。"]'),
('14b006ed-7547-4cfb-94e3-9c2536302381','思歸樂','周紫芝','宋','宋诗','song-poetry','','[]','山花冥冥山欲雨，杜鵑聲酸客無語。',68,'全唐诗/poet.song.87000.json','["山花冥冥山欲雨，杜鵑聲酸客無語。", "客欲去山邊，賊營夜鳴鼓。", "誰言杜鵑歸去樂，歸來處處無城郭。", "春日暖，春雲薄。", "飛來日落還未落，春山相呼亦不惡。"]'),
('4bf43efc-f6f2-4f08-b63c-094f4d62803b','布穀','周紫芝','宋','宋诗','song-poetry','','[]','田中水涓涓，布穀催種田，賊今在邑農在山。',52,'全唐诗/poet.song.87000.json','["田中水涓涓，布穀催種田，賊今在邑農在山。", "但願今年賊去早，春田處處無荒草。", "農夫呼婦出山來，深種春秧答飛鳥。"]'),
('a999ffbc-39a2-45e5-baa8-6f219a60b91a','水西壁間見吕居仁絕句次其韻','周紫芝','宋','宋诗','song-poetry','','[]','秋霜落後題詩處，醉墨淋漓苦未乾。',32,'全唐诗/poet.song.87000.json','["秋霜落後題詩處，醉墨淋漓苦未乾。", "不見窮愁孟東野，亂峰空鎖一溪寒。"]'),
('4d5ab557-27b8-4412-9576-ecfde6e3db23','題聖龍泉時方避賊山中','周紫芝','宋','宋诗','song-poetry','','[]','泉聲來自古龍湫，山底驚雷萬壑秋。',32,'全唐诗/poet.song.87000.json','["泉聲來自古龍湫，山底驚雷萬壑秋。", "濺雹打窗空破夢，飛流無盡不湔愁。"]'),
('404df22e-2916-4d2f-b99e-8678552a67b0','次韻伯尹食糟民示趙鵬翔','周紫芝','宋','宋诗','song-poetry','','[]','十年用兵九不熟，人家有田不種穀。',208,'全唐诗/poet.song.87000.json','["十年用兵九不熟，人家有田不種穀。", "盡枯膏血作軍儲，却買官糟貯饑腹。", "富者鬻田貧鬻妻，夜困桁楊曉敲朴。", "長腰一粒不下咽，輸入官倉常滿屋。", "昔年貫朽內府錢，諸公何苦開漢邊。", "自從胡馬飲江水，便恐黔首流饑涎。", "黄塵白骨尚滿眼，錦裘繡帽誰當前。", "烹羊炰羔固不惡，饑民食糟真可憐。", "元侯幕下短主簿，肯與斯民作調護。", "不愁吏考拙催科，寧脫青衫賦歸去。", "詹侯老文稱大手，樂府詩高古無有。", "安得狂歌徹聖明，便叱風雷清九有。", "却驅羣賊作良農，還我昭陵舊丁口。"]'),
('d6824135-55f2-4f82-acd4-9bb27c862756','山中避盗後十首  其一','周紫芝','宋','宋诗','song-poetry','','[]','喪亂今猶爾，安危了未分。',48,'全唐诗/poet.song.87000.json','["喪亂今猶爾，安危了未分。", "叛羌初射月，羣盗忽如雲。", "妙略歸諸將，深憂軫聖君。", "灞陵逢醉尉，應有故將軍。"]'),
('69d83bef-18fc-42cb-8e5a-e10bea297fea','山中避盗後十首  其二','周紫芝','宋','宋诗','song-poetry','','[]','避地今猶雪，移家春復深。',48,'全唐诗/poet.song.87000.json','["避地今猶雪，移家春復深。", "豈無花到眼，可奈鳥驚心。", "茶動容時摘，蘭香得細尋。", "山中有幽事，青犢未成禽。"]'),
('cca5d63a-e777-463e-a701-ce633ab4822b','山中避盗後十首  其三','周紫芝','宋','宋诗','song-poetry','','[]','浩蕩奔流急，倉黄突騎來。',48,'全唐诗/poet.song.87000.json','["浩蕩奔流急，倉黄突騎來。", "擁旌方滿目，縱炬巳成灰。", "去踏青山道，歸看白骨堆。", "須煩郭中令，一爲洗胡埃。"]'),
('cdd40c6a-6d9e-4a28-b793-ecddb3cea9e8','山中避盗後十首  其四','周紫芝','宋','宋诗','song-poetry','','[]','横道俱蛇豕，親交信絕疏。',48,'全唐诗/poet.song.87000.json','["横道俱蛇豕，親交信絕疏。", "别來應隔歲，亂定始收書。", "轉徙移家後，存亡雪涕餘。", "微生一螻蟻，播越念皇輿。"]'),
('2b4839ee-6385-44db-8632-75a417a36c91','山中避盗後十首  其五','周紫芝','宋','宋诗','song-poetry','','[]','夜燧餘三月，新愁有百端。',48,'全唐诗/poet.song.87000.json','["夜燧餘三月，新愁有百端。", "驚魂頻雨泣，枵腹任風餐。", "射雉山居險，薫狐穴處難。", "胡來猶可爾，寇至不勝殘。"]'),
('0e37a464-ab54-4ed2-b399-ddcd9d6e802f','山中避盗後十首  其六','周紫芝','宋','宋诗','song-poetry','','[]','黯慘春歸日，荒凉賊後村。',48,'全唐诗/poet.song.87000.json','["黯慘春歸日，荒凉賊後村。", "鼓猶聞去寨，火未息平原。", "不恨室廬盡，重欣老稚存。", "此方惟是姥，亦復飯王孫。"]'),
('61d943c0-291c-4037-8e62-c3dcf5087c89','山中避盗後十首  其七','周紫芝','宋','宋诗','song-poetry','','[]','今日報賊去，下山猶復遲。',48,'全唐诗/poet.song.87000.json','["今日報賊去，下山猶復遲。", "羣兒收淚笑，老眼顧人疑。", "夢入鄉關屢，魂應軀幹離。", "一春三避賊，十事九成悲。"]'),
('4d60e74c-4f72-46f4-9e43-9331ecd6429f','山中避盗後十首  其八','周紫芝','宋','宋诗','song-poetry','','[]','翠巘幾曲折，往來三數家。',48,'全唐诗/poet.song.87000.json','["翠巘幾曲折，往來三數家。", "搗皮催作紙，擁焙看烘茶。", "山盡始見日，溪晴時露沙。", "武陵知便是，隔岸有桃花。"]'),
('c81b163c-fe5a-413d-be3b-19eea68e6464','山中避盗後十首  其九','周紫芝','宋','宋诗','song-poetry','','[]','賊去方燒縣，兵來復打城。',48,'全唐诗/poet.song.87000.json','["賊去方燒縣，兵來復打城。", "艱難唯有骨，生死兩無情。", "欲住家何有，謀歸計未成。", "人言李御史，滿腹是精神。"]'),
('c678f794-0825-4c29-b1e3-3e2977306579','山中避盗後十首  其一○','周紫芝','宋','宋诗','song-poetry','','[]','可怪子劉子，全家肯見存。',48,'全唐诗/poet.song.87000.json','["可怪子劉子，全家肯見存。", "長分夜雨榻，復共草堂樽。", "磊落吾何取，笑言君益温。", "它時此心在，結草報深恩。"]'),
('ad9b2379-3e0a-4b06-b17f-6a0b4d4ff16d','侯元進賦待鳯堂佳句見邀同作','周紫芝','宋','宋诗','song-poetry','','[]','見說封君竹，風枝飽歲寒。',48,'全唐诗/poet.song.87000.json','["見說封君竹，風枝飽歲寒。", "會看雙鸑鷟，飛下碧琅玕。", "惡鳥良復厭，閑花吹自殘。", "絕知門可款，夢對小檀欒。"]'),
('52c16f90-dc9a-4edd-9075-7532787f95fd','題趙鈐家墨牛圖','周紫芝','宋','宋诗','song-poetry','','[]','昔我築室花姑川，短蓑青帽耕春田。',192,'全唐诗/poet.song.87000.json','["昔我築室花姑川，短蓑青帽耕春田。", "一犁落盡菖葉雨，雙犢自分春草眠。", "向晚歸來臥牛背，小巷疏林日猶在。", "繫牛柳下門未關，鄰翁攜酒牛邊醉。", "回頭往事無十年，田入富家牛賣錢。", "草荒春隴賊燒屋，十口有家無一椽。", "眼昏頭禿不如意，此畫一見心惘然。", "河間豈是田家子，書多自可天禄比。", "平生眼厭玉驊騮，水牯作圖聊復爾。", "北陌東阡喚未歸，空遣農人告春事。", "田間望月看吳牛，老子從來乃如此。", "便當火急解龍泉，換取四蹄耕雨水。"]'),
('c57d1408-24aa-4504-9c85-e9fafc3ee907','賊後收拾殘書作','周紫芝','宋','宋诗','song-poetry','','[]','此生空作短檠痴，老去猶慚閱市資。',64,'全唐诗/poet.song.87000.json','["此生空作短檠痴，老去猶慚閱市資。", "豈有鄴書猶插架，更無班史可充饑。", "今朝過眼亡三篋，它日還君欠一瓻。", "亂葉紛披在懸磬，春風可是故相欺。"]'),
('c527b9d3-41ee-418e-b776-7a341f9314be','燕欲來巢','周紫芝','宋','宋诗','song-poetry','','[]','亂後烏衣巷欲空，擬尋茅舍伴蓑翁。',64,'全唐诗/poet.song.87000.json','["亂後烏衣巷欲空，擬尋茅舍伴蓑翁。", "戲將鶵去春風裏，銜得泥歸暮雨中。", "炙手不嫌門户冷，傍人如獻語言工。", "明年記取來時節，應是桃花滿院紅。"]'),
('4dfd9fad-79c7-41c3-8d1c-d1118f15ce7f','三月三夜得梅花數枝燈下作','周紫芝','宋','宋诗','song-poetry','','[]','故人遠客天一涯，寄我萬里風前枝。',176,'全唐诗/poet.song.87000.json','["故人遠客天一涯，寄我萬里風前枝。", "方壺含澌不受汙，可着玉樹瑤林姿。", "孤芳妙質不可說，天香肯復須人知。", "老人不作世間夢，但見玉友如兒時。", "急張青燈當明月，要看疏影横屏幃。", "花寒不睡斗欲落，笑語似與人追隨。", "持杯未怪此宵樂，論情忍負平生期。", "回頭却憶青山道，處處相逢花不老。", "短籬飛雪山更寒，古木啼烏月催曉。", "清魂屢往途路遙，故人久别相知少。", "只今如此邂逅何，莫厭詩成苦相惱。"]'),
('5b329903-a618-40f0-bb10-67d7b699575b','桓公祠','周紫芝','宋','宋诗','song-poetry','','[]','蘇峻兵方急，桓公氣未平。',48,'全唐诗/poet.song.87000.json','["蘇峻兵方急，桓公氣未平。", "一身唯死節，四海但孤城。", "歲月人間夢，功勳紙上名。", "可憐山下老，澆酒問陰晴。"]'),
('df268f52-2e85-4a84-8ba5-fcb5d36fcf9a','次韵元進寒食感事','周紫芝','宋','宋诗','song-poetry','','[]','寒食江天雨弄晴，夕陽花草一川明。',64,'全唐诗/poet.song.87000.json','["寒食江天雨弄晴，夕陽花草一川明。", "持盃欲下它鄉淚，上冢寧無故國情。", "漸喜三春逢禁火，會須五斗解朝酲。", "知君屢作東萊夢，我亦飄零歎此生。"]'),
('9d938352-95df-43ed-95d9-b3494414e83a','次韻元進再示','周紫芝','宋','宋诗','song-poetry','','[]','屋角鳴鳩喚晚晴，眼驚新火一番明。',64,'全唐诗/poet.song.87000.json','["屋角鳴鳩喚晚晴，眼驚新火一番明。", "兵戈處處傷時事，花柳村村惱客情。", "無復御廊分冷食，只將蹋鞠醒春酲。", "德公上冢知何日，滿眼春愁太瘦生。"]'),
('b617aac0-8ecd-4b54-805b-6e1075715beb','雨後過琴高巖','周紫芝','宋','宋诗','song-poetry','','[]','夜雨喧旅枕，曉徑深春泥。',156,'全唐诗/poet.song.87000.json','["夜雨喧旅枕，曉徑深春泥。", "奔流自山來，轉眼忽渺瀰。", "微生抱羈蹇，老病凌欹危。", "青山岌當前，客意恍若遺。", "空崖倚天立，怪石從雲垂。", "雲間笙簫聲，隱約天風吹。", "斯人已仙去，孤蹤邈何之。", "釣石屹中流，誰來把綸絲。", "一水繞山麓，淺碧涵漣漪。", "長年抗塵容，照水羞華髭。", "羡門不可遇，惜哉吾巳衰。", "人生不學仙，萬冢空纍纍。", "于今豈未可，撫事聊歔欷。"]'),
('4f1324e8-17e8-4ad8-9d44-6192f99a0e54','讀樞密張公梅雪二詩公諱叔夜','周紫芝','宋','宋诗','song-poetry','','[]','禁中頗牧誰最良，上前論事張子房。',208,'全唐诗/poet.song.87000.json','["禁中頗牧誰最良，上前論事張子房。", "張公九尺鬚眉蒼，談兵說劍眼爲方。", "金城有策若未試，便恐談笑無戎羌。", "時平不用臨邊手，乞得南州作醉郷。", "黄堂酒盡客未起，清畎風多禾自長。", "只今白雪醉中句，猶带東閣官梅香。", "胡狂敢挽射日弩，當年誰上東封章。", "王城三月斷信息，賊軍螘附方跳梁。", "白頭侍郎最先至，擁兵直入趨咸陽。", "中人傳詔天爲喜，戎師夜遁軍威張。", "太宰官高亦動色，毬路带禠腰金黄。", "功名無成落邊土，此老此功誰更數。", "想得韋韝毳幕寒，夜聽邊聲淚如雨。"]'),
('b800b231-1679-40b3-b751-669ccef34f0b','次韻元進以長句見勉','周紫芝','宋','宋诗','song-poetry','','[]','一雨俱回草木春，槁枝着葉定何因。',64,'全唐诗/poet.song.87000.json','["一雨俱回草木春，槁枝着葉定何因。", "煩君筆底三昧句，洗我胸中千斛塵。", "憂患此生真已了，風烟萬里正愁人。", "白頭攘臂干戈裏，欲遣何人喚孔賓。"]'),
('b2b275f4-592d-4be9-90f2-df8c0829d1b6','次韻元進病中書懷','周紫芝','宋','宋诗','song-poetry','','[]','一竿烟雨釣羊裘，稍負初心只自羞。',64,'全唐诗/poet.song.87000.json','["一竿烟雨釣羊裘，稍負初心只自羞。", "擬學倦飛雙去鳥，可憐無定一虚舟。", "未成大隱定小隱，爲用人謀更鬼謀。", "君有胸中經濟策，不須猶說二宜休。"]'),
('4ec8ef2b-b2a0-4748-8e15-62f0ae87a369','次韻元進書事','周紫芝','宋','宋诗','song-poetry','','[]','七尺看君玉作山，倦遊莫賦鳥知還。',64,'全唐诗/poet.song.87000.json','["七尺看君玉作山，倦遊莫賦鳥知還。", "大椿本自八千歲，天馬終縻十二閑。", "笑我生涯真草草，如公人物未班班。", "他時一枕江南夢，猶記相從水石間。"]'),
('20d7f84c-7ea6-40ad-b9be-8254e59309cd','次韻元素見寄','周紫芝','宋','宋诗','song-poetry','','[]','吾曹心事寄微言，此意難從世俗論。',64,'全唐诗/poet.song.87000.json','["吾曹心事寄微言，此意難從世俗論。", "妙句已先醒醉夢，尺書何止到寒温。", "因緣只睡心情懶，習氣唯書眼力昬。", "知有草廬能避地，滿村烟雨一柴門。"]'),
('0c80ea13-0d8c-4505-b0b6-5ff86e89308d','次韻奉答馮遠猷','周紫芝','宋','宋诗','song-poetry','','[]','翩翩綺紈子，粲粲潔衣服。',120,'全唐诗/poet.song.87000.json','["翩翩綺紈子，粲粲潔衣服。", "朱門酒肉臭，不飽膏粱腹。", "凄迷百草中，得比蘭與玉。", "手持白瑤琴，欲鼓朱絃曲。", "閟兹清廟音，未易可流俗。", "名家千里駒，歷塊步巳獨。", "妙年振華鑣，肯折鹽車軸。", "中原暗風塵，國步日窘促。", "勒銘樹高勳，要是一夔足。", "期君乃如此，使我安小築。"]'),
('370854cc-3e69-4a5d-82a1-e551d11e20fe','劉將軍寶刀歌','周紫芝','宋','宋诗','song-poetry','','[]','將軍寶刀玉三尺，夜半有光如日赤。',140,'全唐诗/poet.song.87000.json','["將軍寶刀玉三尺，夜半有光如日赤。", "蒼水使者誰敢捫，蓬頭劍士眼不識。", "鸊鵜膏瑩秋水光，切玉如泥不動芒。", "秋風夜作蛟龍吼，人言乃是真干將。", "知君老將家有種，談兵論事書撐腸。", "不願君持此刀日解三千牛，願刳月支作飲器，却纒錦絛朝未央。", "妖腰亂領不自保，豐狐老猘誰跳梁。", "酒酣起舞爲君語，時危此劍知難藏。"]'),
('fb30faf5-ea48-4ad0-a411-81a418af8301','雨過','周紫芝','宋','宋诗','song-poetry','','[]','池面過小雨，樹腰生夕陽。',48,'全唐诗/poet.song.87000.json','["池面過小雨，樹腰生夕陽。", "雲分一山翠，風與數荷香。", "素月自有約，綠瓜初可嘗。", "鸕鷀莫飛去，留此伴新凉。"]'),
('4f2623d8-ddb9-4b45-87a9-3d81a4080213','五月十八日魏宗明官舍作','周紫芝','宋','宋诗','song-poetry','','[]','黄塵白骨已無人，青谷朱樓尚有村。',32,'全唐诗/poet.song.87000.json','["黄塵白骨已無人，青谷朱樓尚有村。", "今夜三更山吐月，共傾雙淚看金盆。"]'),
('bf1b2194-3caf-4ef2-b6c3-ac3d1e980634','蔡長源以老馬見借駑甚戲作','周紫芝','宋','宋诗','song-poetry','','[]','羸驂已老莫嗔渠，涉世迂疏我自愚。',32,'全唐诗/poet.song.87000.json','["羸驂已老莫嗔渠，涉世迂疏我自愚。", "馬不能言當臆對，未知吾孰與君駑。"]'),
('e18a5602-83dd-4c55-bc3d-c73c0f662bf6','吳思道示藏海小集','周紫芝','宋','宋诗','song-poetry','','[]','文物風流數建安，此生猶及見波瀾。',64,'全唐诗/poet.song.87000.json','["文物風流數建安，此生猶及見波瀾。", "清詩更遣何人到，餘子懸知一笑看。", "猶恐向來無鮑謝，謾勞當日話吳韓。", "知君有意分膏馥，老眼空驚白雪寒。"]'),
('8751d323-55ea-46bb-ad96-915ef1feb33b','讀鄭公奉使録  其一','周紫芝','宋','宋诗','song-poetry','','[]','黠虜難交玉帛歡，只因獻納是爭端。',32,'全唐诗/poet.song.87000.json','["黠虜難交玉帛歡，只因獻納是爭端。", "鄭公不請長纓去，有口真堪伐可汗。"]'),
('2ea099d9-ed5f-4e20-abfc-aff23453d905','讀鄭公奉使録  其二','周紫芝','宋','宋诗','song-poetry','','[]','諸公有意勒燕然，不道昭陵閉玉關。',32,'全唐诗/poet.song.87000.json','["諸公有意勒燕然，不道昭陵閉玉關。", "却遣氈裘窺漢鼎，拜公遺像獨何顔。"]'),
('e5bd003e-86e8-46b2-8f19-2bb02b4a8eca','小蔡許借徐詩未至','周紫芝','宋','宋诗','song-poetry','','[]','馬中未必無驊騮，人中豈可無曺劉。',160,'全唐诗/poet.song.87000.json','["馬中未必無驊騮，人中豈可無曺劉。", "龍媒西來幾萬里，異士一出三千秋。", "李白坐詩竄夜郎，退之論佛流潮州。", "天公可笑無老眼，兩翁憔悴令人愁。", "平生四海黄太史，長庚配月何曾死。", "西江自是南國紀，公有高名政如此。", "人言此老酷似舅，坐上拈花獨公喜。", "分得西江一派流，萬古正須公一洗。", "我老耽詩空瘠臞，起死鍼盲正要渠。", "子豈有意能起予，書來并寄囊中珠。"]'),
('2d7a532a-c27c-4b7d-8a8f-e00169237252','次韻費茂和風月亭新成','周紫芝','宋','宋诗','song-poetry','','[]','十室煕煕俗自恬，令君豈弟不多嚴。',64,'全唐诗/poet.song.87000.json','["十室煕煕俗自恬，令君豈弟不多嚴。", "簿書遣吏且堆案，風月撩人時到簷。", "賸種幽花無限好，滿傾春酒十分甜。", "何勞結屋深防客，清節如君有底嫌。"]'),
('26667dca-9bb4-432a-92d2-fdb8186543a9','孫耘老酒間出麻姑像要余作詩','周紫芝','宋','宋诗','song-poetry','','[]','青絲一尺高蓬鬆，玉顔微駐丹砂紅。',64,'全唐诗/poet.song.87000.json','["青絲一尺高蓬鬆，玉顔微駐丹砂紅。", "雲軿飛來自何許，滿山落葉元無蹤。", "長天如烟月如霧，便恐乘鸞月邊去。", "煩君急與問中郎，從此更誰知癢處。"]'),
('6c091092-21a7-4432-a5a3-f6f6b45191fe','夏熱歎','周紫芝','宋','宋诗','song-poetry','','[]','祝融當權不可奪，海水欲沸山欲裂。',192,'全唐诗/poet.song.87000.json','["祝融當權不可奪，海水欲沸山欲裂。", "黄頭父老見事多，謂有此身無此熱。", "老人何得怨天公，山堂日日多南風。", "烏紗欹帽剪雲葉，白鬢吹雪飛蓬鬆。", "已挹蔗漿澆熱惱，更注井花回睡容。", "人生如此亦不惡，飽食安坐初何功。", "蒙塵况駐奉天輦，避暑望幸驪山宫。", "蕃兵入漢作巢窟，戰騎横戈歲馳突。", "旌旗耀日紅蔽天，鐵甲烘雲氣銷骨。", "安得壯士如惡來，上訴帝閽關鑰開。", "盡瀉天河作飛雨，四海八方無一埃。", "秋禾不槁敵不來，我亦高枕喧春雷。"]'),
('c8bc602d-44e5-4b5c-8508-707ef934b656','送許體之守貴州','周紫芝','宋','宋诗','song-poetry','','[]','人物久衰謝，斯文寄渺茫。',144,'全唐诗/poet.song.87000.json','["人物久衰謝，斯文寄渺茫。", "先生推老成，詞采今擅場。", "交遊數輩行，猶及晁與張。", "大坡渺雲漢，小坡與相羊。", "豈兹絲綸手，不入鵷鷺行。", "爾來南中守，雨露新漢章。", "南中俱樂土，佩带安農桑。", "銅花秀鎧甲，芝菌生桁楊。", "霜林荔子熟，釀瓮千家香。", "使君嘯鈴閣，賓客醉高堂。", "古來多循吏，治行何曾彰。", "願公飲無何，坐使斯民康。"]'),
('1e1e29ad-179e-43b6-a976-d9682c5c0902','許貴州出蘇叔黨樹石','周紫芝','宋','宋诗','song-poetry','','[]','老坡騎鯨上天去，小坡落筆如風雨。',64,'全唐诗/poet.song.87000.json','["老坡騎鯨上天去，小坡落筆如風雨。", "能添老樹着巖間，爲石傳神自翁語。", "兩坡俱死真可惜，君有一拳何處得。", "誰向九原呼此翁，爲我五日畫一石。"]'),
('4fb85e3f-8aba-4ce1-b308-cfd4e25a23e4','立秋前三日夜雨','周紫芝','宋','宋诗','song-poetry','','[]','殘漏催燈暗，風梧带雨鳴。',48,'全唐诗/poet.song.87000.json','["殘漏催燈暗，風梧带雨鳴。", "細聽驚夢點，渾作斷腸聲。", "乍冷秋應近，無眠句又成。", "愁多推不去，頭白更憂兵。"]'),
('f9b825b8-684a-4ab8-ab9e-11bf95c9f6ed','亂後併得陶杜二集','周紫芝','宋','宋诗','song-poetry','','["\u957f\u6c5f"]','少陵有句皆憂國，陶令無詩不說歸。',64,'全唐诗/poet.song.87000.json','["少陵有句皆憂國，陶令無詩不說歸。", "常恨兩翁埋槁壤，頓驚雙璧墮窮扉。", "風催錦里花枝少，草長江南豆葉稀。", "自古高才多寂寞，遺編讀盡淚頻揮。"]'),
('61366eb7-8dc6-414a-9b9e-b31b2b753905','讀徐伯遠書外家遺事作二絕句以紀之并序','周紫芝','宋','宋诗','song-poetry','','[]','就死由來不自疑，玉顔那爲賊鋒低。',64,'全唐诗/poet.song.87000.json','["就死由來不自疑，玉顔那爲賊鋒低。", "了知今日投淵婦，猶勝當年斷臂妻。", "殺氣駸駸戰艦驕，春江漫漫濕金翹。", "但將紅袖供歌舞，却爲周郎笑二喬。"]'),
('4d35aad3-8094-49d9-bac9-ca35c67e38fe','秋旱既久巳而大雨','周紫芝','宋','宋诗','song-poetry','','[]','霜旱憂千里，靈湫臥蟄龍。',48,'全唐诗/poet.song.87000.json','["霜旱憂千里，靈湫臥蟄龍。", "叢祠亦何力，女覡遂論功。", "凍雨雲霓過，秋田寇盗空。", "饑腸蒙一飽，歡甚雪髯翁。"]'),
('eb1b0748-d4e2-40d1-9883-4c495cbeff57','夜雨不寐','周紫芝','宋','宋诗','song-poetry','','[]','歲已隨流水，身猶轉斷蓬。',48,'全唐诗/poet.song.87000.json','["歲已隨流水，身猶轉斷蓬。", "秋風雙鬢短，夜雨一燈紅。", "衰病無多力，窮愁莫漫攻。", "殘年消底物，溪外兩三峰。"]'),
('5e81f697-5808-4783-9b59-1423cc507c19','次韻羅叔共紀事見寄','周紫芝','宋','宋诗','song-poetry','','[]','中原困胡虜，此事昔固聞。',288,'全唐诗/poet.song.87000.json','["中原困胡虜，此事昔固聞。", "何嘗大江南，犬羊動成群。", "踴躍萬騎入，蒼黄兩龍奔。", "五年三避狄，十室九見焚。", "相公既降虜，盗賊俱官軍。", "遂令江以南，填山滿屯營。", "老稚五六輩，相呼走荒村。", "君昔東道主，竄身亦荆榛。", "兩家三十口，既死驚復存。", "共求草中生，有似麞與麕。", "平時巳蹭蹬，老恨有此身。", "湛湛兩玉壺，炯炯無一塵。", "猶喜垂盡中，得此千載人。", "珠璣皎在前，自然洗妖氛。", "恨君濟時策，百未有一伸。", "半通猶綰戾，兩肘空懸鶉。", "無人作游揚，恐得按劍嗔。", "濃雲卷膚寸，未許膏斯民。", "念昔仲夏夜，赤氣騰天曛。", "雨足下垂地，誅斬當奸臣。", "敵將果夜遁，王師策殊勳。", "班荆記是夕，同我二三君。", "君歌獨慷慨，淚下霑衣巾。", "願言補周袞，八表均堯仁。"]'),
('4d445e59-ce54-44e8-9dec-33b88e20a886','七月十八日夜獨坐靜寄月出麻姑背開户徜徉夜久不寐','周紫芝','宋','宋诗','song-poetry','','[]','秋日忽復翳，暮色横陂陁。',144,'全唐诗/poet.song.87000.json','["秋日忽復翳，暮色横陂陁。", "黯黯窗户暗，森森修竹多。", "我懶不點燈，枯藤與婆娑。", "青山忽吐月，隔竹翻金波。", "須臾滿幽林，欸乃被巖阿。", "開門望天漢，星宿方森羅。", "秋風入梧楸，白露霑芰荷。", "夜寒有驚鵲，飛鳴繞南柯。", "蒼生願安枕，壯士方横戈。", "誰能請纓劍，故地收關河。", "我意忽不愜，鄰鷄復當歌。", "詩成月巳落，奈此老狂何。"]'),
('ae78b7c2-cdd6-4d53-bbb1-6d7698b28533','次韻魏宗明攜酒小集','周紫芝','宋','宋诗','song-poetry','','[]','山翁爛醉習家池，碎剪黄花點玉巵。',64,'全唐诗/poet.song.87000.json','["山翁爛醉習家池，碎剪黄花點玉巵。", "亹亹聽君真有味，皇皇憐我欲何之。", "難陪痛飲心先醉，强作朱顔老昜衰。", "明日囊中有新句，尚堪醉墨寫淋漓。"]'),
('5472f37b-0fd8-4d5e-b4df-21716b4bb04b','次韻吕居仁詩尾見及四絕  其一','周紫芝','宋','宋诗','song-poetry','','[]','詩成邂逅得窮愁，眼見郎潛又白頭。',32,'全唐诗/poet.song.87000.json','["詩成邂逅得窮愁，眼見郎潛又白頭。", "人物向來山吏部，篇章今日謝宣州。"]'),
('53dc5519-6db0-4876-be77-e323832ff2b5','次韻吕居仁詩尾見及四絕  其二','周紫芝','宋','宋诗','song-poetry','','[]','狗監連衡苦未平，秋成戈甲尚乘城。',32,'全唐诗/poet.song.87000.json','["狗監連衡苦未平，秋成戈甲尚乘城。", "夢魂幾欲隨公去，爲問高安路幾程。"]'),
('279d86b1-ee1a-436d-929b-88ad9c9d65e7','次韻吕居仁詩尾見及四絕  其三','周紫芝','宋','宋诗','song-poetry','','[]','樓上看山酒一巵，人間此樂豈兒知。',32,'全唐诗/poet.song.87000.json','["樓上看山酒一巵，人間此樂豈兒知。", "秋風吹落霜前雁，寄得西來别後詩。"]'),
('bf05ccfc-95b2-4668-8c16-a00ee781fa08','次韻吕居仁詩尾見及四絕  其四','周紫芝','宋','宋诗','song-poetry','','[]','白髪書生誰復論，蕭然深閉一蓬門。',32,'全唐诗/poet.song.87000.json','["白髪書生誰復論，蕭然深閉一蓬門。", "自知赤壁功名晚，羞與周郎作耳孫。"]'),
('0198efcc-f633-4074-8927-35f36aae6c79','題裴晉公畫像二絕  其一','周紫芝','宋','宋诗','song-poetry','','[]','朝論當年洶洶時，此翁奇事少人知。',32,'全唐诗/poet.song.87000.json','["朝論當年洶洶時，此翁奇事少人知。", "夢中縛得吳元濟，猶說緋衣是小兒。"]'),
('fb081111-f7ec-46c8-aeba-0f85c17d4bd9','題裴晉公畫像二絕  其二','周紫芝','宋','宋诗','song-poetry','','[]','瘦着輕裘似不勝，書生事業復誰能。',32,'全唐诗/poet.song.87000.json','["瘦着輕裘似不勝，書生事業復誰能。", "莫嗔小鴨可禽兔，真有禪師解放鷹。"]'),
('3f014f04-bd07-48c8-9226-f014b2c8f5b8','玉友初成戲作二首  其一','周紫芝','宋','宋诗','song-poetry','','[]','小瓮鵝黄撥不開，晚風吹螘轉荷杯。',64,'全唐诗/poet.song.87000.json','["小瓮鵝黄撥不開，晚風吹螘轉荷杯。", "燈前細酌情何限，病後朱顔老却回。", "我亦平生笑餘耳，人今何處有陳雷。", "方從歡伯作幽事，莫喚酪奴相繼來。"]'),
('2c93dda6-f679-4c5c-8675-9da4bf73f63b','玉友初成戲作二首  其二','周紫芝','宋','宋诗','song-poetry','','[]','舊交誰復可相忘，晚向林中得此郎。',64,'全唐诗/poet.song.87000.json','["舊交誰復可相忘，晚向林中得此郎。", "政恐大兒妨笑語，頻呼小友共回翔。", "坐來烏有聊爲客，醉後無何即是鄉。", "多謝故人分玉粒，夜燈和雨搗新香。"]'),
('291263b2-8136-40d2-ab7c-b27ee81930be','撿故書得舊寫真戲書','周紫芝','宋','宋诗','song-poetry','','[]','楊柳春風濯濯枝，深慚張緒少年時。',64,'全唐诗/poet.song.87000.json','["楊柳春風濯濯枝，深慚張緒少年時。", "期期尚有胸中意，種種真成鬢上悲。", "暮四朝三心巳了，年頭月尾老俱遺。", "此中空洞今何有，曲盡周郎更不知。"]'),
('718a6a02-fc36-4d58-b44c-9ae12e75e7fa','八月三日早起','周紫芝','宋','宋诗','song-poetry','','[]','金樞壞殘月，暘谷賓朝曦。',204,'全唐诗/poet.song.87000.json','["金樞壞殘月，暘谷賓朝曦。", "九日浴滄海，一日騰上枝。", "上枝邈何許，但隱山半規。", "須臾掛銅鉦，飛上天一涯。", "光景被草木，曄曄含幽姿。", "微暾入圓吭，飛鳴各嚶咿。", "物意自欣悅，人情傷歲時。", "卷我東窗簾，羣山抺脩眉。", "炙背翻故書，搜腸出新詩。", "俟河幾時清，種豆落爲萁。", "人生行樂耳，富貴終何爲。", "丈夫風雲會，事業肩臯夔。", "時哉不我與，浩歌君勿疑。", "紉蘭可爲佩，製荷可爲衣。", "駕以白玉虬，驂以蒼精螭。", "翩翩八荒外，渺渺天風吹。", "世俗付一笑，造化真小兒。"]'),
('7653c7fd-9250-4576-8fcd-3065098bbaaa','雨作留水西溪漲不可復歸','周紫芝','宋','宋诗','song-poetry','','[]','東谿打槳過西溪，南嶺雲飛北嶺時。',64,'全唐诗/poet.song.87000.json','["東谿打槳過西溪，南嶺雲飛北嶺時。", "鳥語屢呼人載酒，山行不厭雨催詩。", "靜中秋色人間少，客裏泉聲夜半知。", "老去隨緣皆可耳，愁霖未用苦相欺。"]'),
('c02d6624-7deb-44d4-8cd7-b44d50883ef8','病中王邦憲見過以詩爲謝因以當别','周紫芝','宋','宋诗','song-poetry','','[]','别後衡門久不開，壯心消盡已成灰。',64,'全唐诗/poet.song.87000.json','["别後衡門久不開，壯心消盡已成灰。", "白頭羈客病中老，青眼故人天外來。", "相見有時那昜得，語離終在莫頻催。", "山城歸路應殘臘，早寄春風嶺上梅。"]'),
('6a7c5ef6-399e-4443-8a9c-81a8a4754345','病起負暄菊籬一首','周紫芝','宋','宋诗','song-poetry','','[]','臥疴初肅霜，小間倏玄冬。',156,'全唐诗/poet.song.87000.json','["臥疴初肅霜，小間倏玄冬。", "老境知幾何，半落呻吟中。", "醫師固楚産，砭灼矜神功。", "巫師雜荒怪，呼吸生雷風。", "江鄉鬰毒霧，禦濕無鞠藭。", "况復窘行役，六月傷藴隆。", "寒熱遂百戰，藥石徒屢攻。", "槁項與黄馘，苶然非昔容。", "逮兹脫九死，更生本蒼穹。", "今晨頗欣悅，步我菊籬東。", "無誰與共語，梵誦庶可終。", "憂樂有乘除，涉世殊窮通。", "幸兹未暝間，有樂聊復從。"]'),
('7a9777f2-e76d-49f3-804b-bbb1d0edeb92','送詹伯尹赴三衢酒官','周紫芝','宋','宋诗','song-poetry','','[]','東觀誰臨未見書，起居君不解何如。',64,'全唐诗/poet.song.87000.json','["東觀誰臨未見書，起居君不解何如。", "懶從瓜隴耕春雨，聊聽糟床滴夜渠。", "滿世棘荆渾未定，白頭書尺莫全疏。", "官曹有禄仍無事，看着斑衣從版輿。"]'),
('84a282e4-890a-49a4-8c64-e5e667b3ec0a','辛亥冬無雪天氣妍暖如禁烟時書所感三絕句  其一','周紫芝','宋','宋诗','song-poetry','','[]','夕陽微傍小窗明，便遣飛蟲作意鳴。',32,'全唐诗/poet.song.87000.json','["夕陽微傍小窗明，便遣飛蟲作意鳴。", "天共梅花元有約，誰教草色上荒城。"]'),
('551ea032-34f9-459b-af3a-5550e3cbdbc4','辛亥冬無雪天氣妍暖如禁烟時書所感三絕句  其二','周紫芝','宋','宋诗','song-poetry','','[]','當年白雨打凉州，春色還催禁籞遊。',32,'全唐诗/poet.song.87000.json','["當年白雨打凉州，春色還催禁籞遊。", "記得端門迎輦路，輕冰一夜綠楊溝。"]'),
('57ac6578-fc48-47da-b15c-c4bb638fcf64','辛亥冬無雪天氣妍暖如禁烟時書所感三絕句  其三','周紫芝','宋','宋诗','song-poetry','','[]','去年和雪臥榛叢，雪裏旌旗分外紅。',32,'全唐诗/poet.song.87000.json','["去年和雪臥榛叢，雪裏旌旗分外紅。", "江上只今無盗賊，樓頭昨夜已春風。"]'),
('3302110a-9d4e-4e4e-b3a0-30e9885bcbd2','仁宗皇帝飛白歌','周紫芝','宋','宋诗','song-poetry','','[]','八神警蹕羣靈趨，風師雨伯當前驅。',242,'全唐诗/poet.song.87000.json','["八神警蹕羣靈趨，風師雨伯當前驅。", "漢家四葉聖主出，共扶日御升天衢。", "當時農桑三萬里，地上錢流已如水。", "左有稷契右皋夔，四嶽九官真濟濟。", "太師當國天下安，貂蟬繡袞身如山。", "范公特節下金鑾，名落百蠻毛髪寒。", "鄭公有口伐可汗，可使一言無契丹。", "太平天子坐垂拱，蟬蜵蠖濩朝千官。", "侍臣愕立蓬萊殿，看草宸奎麗雲漢。", "中人傳賜宣口勅，雨露恩光極昭煥。", "公家什襲宫錦囊，五彩屬天驚夜光。", "試從父老說嘉祐，百年厚德知難忘。", "自從喪亂雙眼暗，猶喜人間得時見。", "小臣拜舞喜欲顛，安得身隨千官朝九天。", "眼見萬騎無控弦，四海復似昭陵年。"]'),
('131f9f07-3245-456d-8800-c3953cc33b1e','雪中睡起書北窗二首  其一','周紫芝','宋','宋诗','song-poetry','','[]','斷雲疏雨暗樓臺，春在寒空不肯回。',64,'全唐诗/poet.song.87000.json','["斷雲疏雨暗樓臺，春在寒空不肯回。", "梅亦羞人花未笑，柳知何事眼慵開。", "久拚雙鬢緣詩老，忍放痴愁入酒來。", "猶有暮年文字業，睡餘重秩亂書堆。"]'),
('90b03c91-3365-4599-8c51-d5c6fe21091b','雪中睡起書北窗二首  其二','周紫芝','宋','宋诗','song-poetry','','[]','窗下梅花凍玉壺，夢回閑聽雪跳珠。',64,'全唐诗/poet.song.87000.json','["窗下梅花凍玉壺，夢回閑聽雪跳珠。", "樽中酒盡何由得，枕上詩成可自娛。", "身世固應渾是夢，功名知巳不成盧。", "明朝醉倒春風路，試問黄公覓舊壚。"]'),
('531173e3-9f8e-42fb-b8bc-e80216c8950d','次韻元素自東皋寄新詩賊退猶未久  其一','周紫芝','宋','宋诗','song-poetry','','[]','北風胡馬自長鳴，月到南枝鳥共驚。',64,'全唐诗/poet.song.87000.json','["北風胡馬自長鳴，月到南枝鳥共驚。", "留我小溪回短棹，看渠紅旆作長城。", "人思龐老皆知隱，賊說康成亦畏名。", "亂後欲從君一笑，滿林荆棘未堪行。"]'),
('aafd502e-4b1d-428a-bff7-94d68e0c4884','次韻元素自東皋寄新詩賊退猶未久  其二','周紫芝','宋','宋诗','song-poetry','','[]','先生老去以詩鳴，亂定詩來眼倍驚。',64,'全唐诗/poet.song.87000.json','["先生老去以詩鳴，亂定詩來眼倍驚。", "但把明珠照兼乘，未須白璧換連城。", "人言陶令嘗耽酒，我識玄真不釣名。", "晚日追隨嘆才盡，始知天馬足能行。"]'),
('73814079-e2f8-48a9-b2fb-b706422810dd','奉聖山中邂逅忻師相與話十年舊事爲之惘然二十一日同遊陳侍講附子園偶作此篇','周紫芝','宋','宋诗','song-poetry','','[]','不見跳珠巳十年，舊遊重說固依然。',64,'全唐诗/poet.song.87000.json','["不見跳珠巳十年，舊遊重說固依然。", "此生如我豈非夢，到處逢師真是緣。", "倦客來看栽藥圃，先生昔侍講經筵。", "人間作計無多子，也合歸耕種穀田。"]'),
('c6cf6bc9-f6eb-40d0-9a78-53a605424426','過石壁','周紫芝','宋','宋诗','song-poetry','','[]','兩峰夾天高，一水繞山麓。',144,'全唐诗/poet.song.87000.json','["兩峰夾天高，一水繞山麓。", "鳥道盤山腰，下臨千仭谷。", "仰視寸草青，千章羅巨木。", "轉峽瀉哀湍，驚雷裂坤軸。", "日月所隱庇，光景不到目。", "道險當捨車，重趼摩兩足。", "不知誰鑿空，穿穴入山腹。", "平生蜀道難，耳目聞見熟。", "兹山亦尤物，初未掛史牘。", "了知天宇間，萬險自重複。", "窮人重錙銖，凌冒取危辱。", "歲晏霜雪多，歸途戒當速。"]'),
('e3cc0656-2a2b-4032-aca7-8f21fa3aa782','出石壁','周紫芝','宋','宋诗','song-poetry','','[]','倚空山嶄巖，平地石齟齬。',144,'全唐诗/poet.song.87000.json','["倚空山嶄巖，平地石齟齬。", "脩途繞危磴，千里無寸土。", "山高不見日，霧重自成雨。", "入壁天始明，出壁日過午。", "青蒼斷崖谷，開豁見天宇。", "稻田棋局方，梯山種禾黍。", "道傍兩三家，稍稍聞笑語。", "始知在人寰，邂逅得徒旅。", "倦僕饑欲啼，遊子歡自許。", "攜孥老一廛，白髪無處所。", "何當把春犁，望月耕隴畝。", "閉門了殘年，危磴不復取。"]'),
('69cec911-cc5c-4b43-83ec-6c723048b2ad','徽州道中觀山二首  其一','周紫芝','宋','宋诗','song-poetry','','[]','老去心安一味閑，江南江北飽看山。',32,'全唐诗/poet.song.87000.json','["老去心安一味閑，江南江北飽看山。", "不知今日徽州路，始落千巖萬壑間。"]'),
('02f110ab-bc30-4220-a846-20a985fa0872','徽州道中觀山二首  其二','周紫芝','宋','宋诗','song-poetry','','[]','暖日巖花上翠藤，半巖松桂聳亭亭。',32,'全唐诗/poet.song.87000.json','["暖日巖花上翠藤，半巖松桂聳亭亭。", "南來到處無山似，喚作東川小錦屏。"]'),
('cead6437-7754-447f-a094-193895f9a1e5','上饒道中望月巖','周紫芝','宋','宋诗','song-poetry','','[]','瘦馬度莽蒼，悠悠忽長年。',168,'全唐诗/poet.song.87000.json','["瘦馬度莽蒼，悠悠忽長年。", "群山不知數，袞袞來眼前。", "忽逢天上月，下掛蒼崖巔。", "炯如碧玉玦，中空竇雲天。", "巖柯亦薄相，爲作蟾桂圓。", "陰晴無顯晦，千古長嬋娟。", "坐令馬上夢，憶我江南川。", "江空月自吐，萬頃含風烟。", "静聞欸乃聲，入我獨宿船。", "誤從塵網中，見似喜欲顛。", "何當追昔遊，擺脫區中緣。", "買地結茅屋，攀雲躡飛仙。", "朝吸白露光，暮飲山根泉。", "清歡倘可結，浩歌與周旋。"]'),
('f6c9cb76-b719-4dae-88c7-4295ac9c9624','於潛道中戲作','周紫芝','宋','宋诗','song-poetry','','[]','徐娘雖老風流在，學得啼眉時世粧。',32,'全唐诗/poet.song.87000.json','["徐娘雖老風流在，學得啼眉時世粧。", "只有於潛舊家女，但攜篷沓嫁新郎。"]'),
('cc9fc0f2-21d2-4af9-baae-fdba9db489e6','收伯尹三衢書','周紫芝','宋','宋诗','song-poetry','','[]','近有南州使，雙持赤鯉魚。',48,'全唐诗/poet.song.87000.json','["近有南州使，雙持赤鯉魚。", "花時孤客淚，亂後故人書。", "一别真如許，三年少定居。", "時危消息好，老去莫情疏。"]'),
('a615f25e-4b96-4900-b4ef-20b9592540c7','正月十日雪','周紫芝','宋','宋诗','song-poetry','','[]','維時孟春月，歲事司勾芒。',204,'全唐诗/poet.song.87000.json','["維時孟春月，歲事司勾芒。", "微陽力猶弱，未足扶百昌。", "風伯偶偃旆，電師亦潛光。", "堅冰頓欲解，蟄户不肯藏。", "群陰勢未屈，寒飈忽飛翔。", "積陰既得泄，雪意亦異常。", "痴雲迷澒洞，烟水俱蒼茫。", "行人有墮指，裹足畏前岡。", "疏梅強解事，一笑矜芳香。", "誰憐百草死，萬木寒仍僵。", "東君始用事，抗此凛冽剛。", "那知假微暾，乃復爲此祥。", "幽人解春衣，酒券僅可償。", "倚此數日暖，蒼黄索衣裳。", "萬事多反覆，天心難重量。", "賴我有殘榼，聊足資清狂。", "此意誰復論，醉眼空望羊。"]'),
('36100a21-57e5-4859-b231-c9a0b2535a56','銅爵研','周紫芝','宋','宋诗','song-poetry','','[]','藁街夜腹空燃脂，可憐漢祚終陵夷。',128,'全唐诗/poet.song.87000.json','["藁街夜腹空燃脂，可憐漢祚終陵夷。", "老瞞自在作家主，欺它寡婦并孤兒。", "洛陽宫殿皆頹圯，更作高臺半天起。", "臺上吹香十里聞，臺下洗粧漳水渾。", "當時歌管一消歇，回望西陵空斷魂。", "百年歲月空中鳥，花不長妍人易老。", "臺傾人去不復存，碧瓦澄泥爲誰好。", "那知流落向寒窗，乞與詩人賦花草。"]'),
('f2619a64-a9fd-488a-80da-3a97effd1f55','次韻伯尹見寄二首  其一','周紫芝','宋','宋诗','song-poetry','','[]','種種星星苦見侵，已無心作四愁吟。',64,'全唐诗/poet.song.87000.json','["種種星星苦見侵，已無心作四愁吟。", "三秋令我頻成夢，一月勞君幾嗣音。", "臭味每嗟無草木，因緣已定只山林。", "此心耿耿從誰語，遺恨依然淚滿襟。"]'),
('cb67bbe6-7db0-40fe-b7de-d880d582dd8b','次韻伯尹見寄二首  其二','周紫芝','宋','宋诗','song-poetry','','[]','從古何人解識真，夜光欲到了無因。',64,'全唐诗/poet.song.87000.json','["從古何人解識真，夜光欲到了無因。", "只今懷璧還歸趙，它日揮毫有過秦。", "餘子不應霑厚禄，此郎寧合坐長貧。", "白衣蒼狗俱成夢，富貴功名不在人。"]'),
('848b17cc-a210-499e-9dd6-1169aa6f5e50','次韻常元明寄侯元進','周紫芝','宋','宋诗','song-poetry','','[]','丞哉風味似崔侯，松下行吟萬事休。',64,'全唐诗/poet.song.87000.json','["丞哉風味似崔侯，松下行吟萬事休。", "亂後只應堪一笑，官閑如此復何求。", "看花欲下春衫淚，射月先憂塞草秋。", "賴有道人三昧句，爲君一洗向來愁。"]'),
('c0902019-187b-45db-be74-5d66a0e8e132','和趙鵬翔贈李生','周紫芝','宋','宋诗','song-poetry','','[]','人間作畫如作詩，妙由心得非人爲。',206,'全唐诗/poet.song.87000.json','["人間作畫如作詩，妙由心得非人爲。", "五日一石十日水，此事無乃亦可期。", "向來郭恕先，妙手真復奇。", "經年不肯下一筆，胸中丘壑誰當知。", "忽然有興不可遏，寫作槎枒風雨枝。", "回頭却笑閻立本，緩急與人爲畫師。", "李生聞是成遠後，一生落魄唯飲酒。", "貴人金多不可呼，閒日爲多畫日偶。", "心知公子非俗人，平生筆底波瀾翻。", "故作滄江與巨石，要看萬里風濤相吐吞。", "誰知此老不足數，自笑一生常苦辛。", "桃花水暖小艇窄，十年辜負江邊春。", "時危力小去未得，畫圖入眼空傷神。"]'),
('514fb654-f396-4abd-afb2-92c7477363bd','次韻韋深道哭陳諫議','周紫芝','宋','宋诗','song-poetry','','[]','自是羣姦誤聖君，初心豈願作忠臣。',64,'全唐诗/poet.song.87000.json','["自是羣姦誤聖君，初心豈願作忠臣。", "平生勁氣埋黄壤，當日嘉言在紫宸。", "諌議裂麻方伏閤，諸公鳴玉自垂紳。", "向來六子俱誅滅，此道于誰較屈伸。"]'),
('507bfb7a-b4f8-440a-b8bd-4e4bcd2ea68c','叔達許分萱柳二栽作二絕  其一','周紫芝','宋','宋诗','song-poetry','','[]','華顛老去幾霜秋，知處元應不奈愁。',32,'全唐诗/poet.song.87000.json','["華顛老去幾霜秋，知處元應不奈愁。", "但得稍分花到眼，誰能更覓地埋憂。"]'),
('f2fb6871-80da-4a2f-8e53-615d53e190e8','叔達許分萱柳二栽作二絕  其二','周紫芝','宋','宋诗','song-poetry','','[]','鋤荒巳出牆根路，剪綠仍分雪後栽。',32,'全唐诗/poet.song.87000.json','["鋤荒巳出牆根路，剪綠仍分雪後栽。", "便與數椽容我老，當留一徑待君來。"]'),
('0dd8d3f9-d462-4a74-8579-48ebc9daf7bc','謝元不伐寄靈巖七詩用梅聖俞韻','周紫芝','宋','宋诗','song-poetry','','[]','靈巖勝絕天下稀，開鑿乃自太古出。',160,'全唐诗/poet.song.87000.json','["靈巖勝絕天下稀，開鑿乃自太古出。", "山名初豈有顯晦，勝處要須詩黼黻。", "自從梅老登列仙，尤物誰憐久埋没。", "具茨筆力扛九鼎，坐遣清詩入山骨。", "據龜食蛤誰與遊，絳節雲車到仙窟。", "雲間招手疑有無，月下吹簫真仿彿。", "飛雲杳藹風吹香，翠潤空濛雨垂濕。", "誰從洞口看金書，想對神清時獨立。", "我家靈巖山脚底，識面何由恍如失。", "雖無幽夢到三山，尚有明珠容什襲。"]'),
('c170d84c-df4c-47af-bfbe-cc2d32ecb799','送别徐南美','周紫芝','宋','宋诗','song-poetry','','[]','謀臣如雲將如雨，欲剪天驕奉明主。',160,'全唐诗/poet.song.87000.json','["謀臣如雲將如雨，欲剪天驕奉明主。", "御營飛詔肅虎貔，妙略縱横自神武。", "誰騎駁馬蹄雙朱，夢從璜溪親帝輿。", "手提大鉞殺兩將，日御少却公重扶。", "此公堂堂出當國，羣盗相看少顔色。", "江上鯨鯢盡掃除，草中狐兔無窠窟。", "折衝自可銷戈兵，寸地尺天歸聖明。", "帳下偏禆何足數，幕中賓客公獨稱。", "願資碩畫戡禍亂，坐遣四海歌昇平。", "書生白首亦安用，尚可平戎作短行。"]'),
('d095a7fe-1754-4941-a131-1f8f1cdbf790','送侯元進罷涇溪丞','周紫芝','宋','宋诗','song-poetry','','["\u957f\u6c5f"]','胡雛飲馬窺長江，巨鼎一沸俱倉黄。',192,'全唐诗/poet.song.87000.json','["胡雛飲馬窺長江，巨鼎一沸俱倉黄。", "我攜老稚不知處，流離夜竄涇山陽。", "山中小邑真蕞爾，井邑無聲但流水。", "亂石巉崢虎看人，賈客稀疏市爭米。", "憶昔相逢羣盗中，過我天宫寶坊裏。", "人言覓句崔立之，恐是前身侯叔起。", "當官論事嚼寒冰，醉後詩成只彈指。", "三年兵火夢中遊，别去何堪日千里。", "人生直氣忌太高，論少卑之亦聊爾。", "功名唾手良偶然，邂逅庸奴亦如此。", "如公人物自有餘，似我蒼華真老矣。", "只今滿世尚干戈，應念相思遣雙鯉。"]'),
('1f54c6c4-3509-40ef-9d9c-51892ec253e9','李使君示開化諸詩','周紫芝','宋','宋诗','song-poetry','','[]','使君一出承明廬，當年兩佩龜峰魚。',176,'全唐诗/poet.song.87000.json','["使君一出承明廬，當年兩佩龜峰魚。", "龜峰小兒騎竹馬，笑挽朱轓歸故閭。", "門外春風吹畫戟，小閣香濃綺疏碧。", "蘇州五字老更奇，東陽八詠人誰敵。", "山堂聞說公自開，烟雨遙供翠鬟色。", "更向招提山窟中，竹杖穿雲飽經歷。", "夜上孤峰看明月，曉趁鐘魚着僧屐。", "詩成知復幾牛腰，倒廩傾囷公不惜。", "他人舉似與何人，知我耽詩老成僻。", "平日看囊止一錢，驚見縱横着圭璧。", "當遣兒童勿浪傳，按劍從來少人識。"]'),
('006f7bee-6ef9-4c5d-ac80-d4ca1d15d0c9','贈元具茨二首  其一','周紫芝','宋','宋诗','song-poetry','','[]','平生結客少年塲，人物如君見未嘗。',64,'全唐诗/poet.song.87000.json','["平生結客少年塲，人物如君見未嘗。", "早歲風流知漫叟，一時師友是黄香。", "相從便作雙鳧去，欲見應須一葦航。", "只恐涪翁門下士，九重應合奉清光。"]'),
('0b9308f6-6bd3-4cf0-8076-54e90ffd8928','贈元具茨二首  其二','周紫芝','宋','宋诗','song-poetry','','[]','名在金華季孟間，流傳佳句落人寰。',64,'全唐诗/poet.song.87000.json','["名在金華季孟間，流傳佳句落人寰。", "異時文采今何在，掃地風流喚欲還。", "賸馥見分雖有意，小巫自顧獨何顔。", "源明不恨生衰俗，尚喜人中識魯山。"]'),
('83a51ed0-8b47-4999-a8e5-90d376a21692','羅仲共兄弟文集爲賊所殘','周紫芝','宋','宋诗','song-poetry','','[]','照眼明珠兩陸離，機雲兄弟似當時。',64,'全唐诗/poet.song.87000.json','["照眼明珠兩陸離，機雲兄弟似當時。", "文章未許輕霑丏，神物何爲欠護持。", "白璧懸知從間道，青氈亦復付偷兒。", "誰言舉世無蘇暐，收得香奩第一詩。"]'),
('2e989a9f-ecbf-4c67-9c14-834dd3ef1517','何元靜以詩索花次韻詩尾致剪花之約','周紫芝','宋','宋诗','song-poetry','','[]','城南有客身倦遊，飯無脫粟衣無裘。',176,'全唐诗/poet.song.87000.json','["城南有客身倦遊，飯無脫粟衣無裘。", "短牆雨濕花木晚，窮巷草深籬落秋。", "心常自許玉川輩，人言恐是原憲流。", "千奴安得封君禄，偶有一花聊可目。", "綵椽作架恐未暇，春到聽花飛上屋。", "衡門無酒客不知，寒谷少春花更遲。", "慇勤未足供一笑，慚愧煩君作好詩。", "誰遣春風吹急雨，枝頭會見花無数。", "夜窗月白得暗香，曉枕風微戰輕素。", "已辦并州快剪刀，爲剪長條送春去。", "君當釀酒買肥羔，莫倚匆匆陳草具。"]'),
('532dddb5-6285-43d0-8265-b7c8fd7db3fe','後數日以詩償剪花之約','周紫芝','宋','宋诗','song-poetry','','[]','春風吹雲不成雨，暖日將春到花塢。',160,'全唐诗/poet.song.87000.json','["春風吹雲不成雨，暖日將春到花塢。", "知君不羡鶴林神，但將詩作催花鼓。", "饕風虐雨一掃空，國艶天香爲君吐。", "金刀盟在不敢寒，急走送君花滿盤。", "何郎要將湯餅試，不放枝頭朝露乾。", "樽雖有酒莫謾把，客未可人誰共看。", "想當風暖月更白，流蘇帳掛香團欒。", "應笑老翁門寂寂，咫尺誰來草玄宅。", "暗香和月與誰同，芳條委地無人摘。", "春與幽姿似少情，雨打風翻漫狼藉。"]'),
('7376de96-a315-470d-ba63-df26166923e6','送舒永豐','周紫芝','宋','宋诗','song-poetry','','[]','斯民如草木，九聖含春温。',180,'全唐诗/poet.song.87000.json','["斯民如草木，九聖含春温。", "秋風一披拂，零落難重陳。", "嗣皇回日御，杲杲昇朝暾。", "誰令天驕子，欲肆長鯨吞。", "王師一倡亂，諸將皆星奔。", "可憐爾羣蒼，終不負漢恩。", "固亦念顛仆，所喜邦本存。", "舒侯名家郎，翔鸞未鶱騰。", "稍分民社寄，似欲親撥煩。", "盍敷寛大詔，力補瘡痍痕。", "勿謂蕞爾邑，安能著華軒。", "妙割俱有用，雞牛無足言。", "君看密縣宰，視民真子孫。", "汗馬無寸勞，太傅豈不尊。", "扶衰其有意，願復矜元元。"]'),
('3756c3d8-bc43-46c9-9e67-580490b5aa32','次韻何君與晚晴','周紫芝','宋','宋诗','song-poetry','','[]','花深雨過一鳩鳴，喚起何郎對晚晴。',64,'全唐诗/poet.song.87000.json','["花深雨過一鳩鳴，喚起何郎對晚晴。", "暮靄連山明白鷺，夕陽回處带啼鶯。", "浮生可笑能幾屐，萬事政須論一枰。", "想得追隨共飛蓋，玉觴零亂酒催行。"]'),
('9e4d24df-3996-48ec-8561-d825ca1cac7e','次韻劉元素暮春書懷','周紫芝','宋','宋诗','song-poetry','','[]','斷腸風雨落花時，空遣劉郎賦柳枝。',64,'全唐诗/poet.song.87000.json','["斷腸風雨落花時，空遣劉郎賦柳枝。", "涉世功名真螘穴，送春歌吹只蛙池。", "尚堪短策時乘興，猶有寒杯可共持。", "更願餘生似東野，雲龍無地不相隨。"]'),
('94bc0f0d-ed89-465d-b63d-e90976415e51','次韻元素再用前作','周紫芝','宋','宋诗','song-poetry','','[]','春晴無復少年時，那作驚烏夜繞枝。',64,'全唐诗/poet.song.87000.json','["春晴無復少年時，那作驚烏夜繞枝。", "願與君遊雲夢澤，不愁人奪鳯凰池。", "北窗付我常高臥，手板看渠自倒持。", "擬伴遺民釣烟水，蕭規真欲效曹隨。"]'),
('b19a29ef-aa85-455f-8552-ad773e2086cf','元素將與余别再賦前篇因以留之','周紫芝','宋','宋诗','song-poetry','','[]','江頭雲雁欲飛時，倦翮依然在一枝。',64,'全唐诗/poet.song.87000.json','["江頭雲雁欲飛時，倦翮依然在一枝。", "少竚晚潮青版舫，共聽朝雨綠荷池。", "伯生醉熟慚空洞，夢得詩高有護持。", "南浦分襟定何日，懸知清夢與君隨。"]'),
('837cc761-99ab-42bd-af44-c22d26672f3a','送元素','周紫芝','宋','宋诗','song-poetry','','[]','重來樽酒定何時，藜杖同誰把一枝。',64,'全唐诗/poet.song.87000.json','["重來樽酒定何時，藜杖同誰把一枝。", "雅量久知吞夢澤，高飛猶恨隔天池。", "凌烟事業歸驃騎，樂府歌行付總持。", "自載筆床茶竈去，喜君風味似天隨。"]'),
('36161e1b-b5fb-4fae-a679-83801757f38b','次韻元不伐暮春再遊俞氏園期任道卿劉長孺不至','周紫芝','宋','宋诗','song-poetry','','[]','素心失前期，幽事縈老念。',120,'全唐诗/poet.song.87000.json','["素心失前期，幽事縈老念。", "小築猶未成，殘年作逋欠。", "五字俯見投，光芒肯收斂。", "遐想徒意消，從遊知禮僭。", "流離兵盗餘，有籍猶未占。", "尚想南岡花，依依弄殘艶。", "棲遲倘會意，往返殊未厭。", "如何兩公子，盟寒久無驗。", "我語良可刪，公當爲磨玷。", "載酒苦未能，兹焉負深歉。"]'),
('9fbf4659-c2e4-4337-ab47-6fd598011c97','春晚絕句二首  其一','周紫芝','宋','宋诗','song-poetry','','[]','春來白水欲平田，未拆鞦韆已禁烟。',32,'全唐诗/poet.song.87000.json','["春來白水欲平田，未拆鞦韆已禁烟。", "傷雨落花空着地，倚風輕絮解漫天。"]'),
('c59fa0a1-cdf5-45e4-ab53-50c011c3afe6','春晚絕句二首  其二','周紫芝','宋','宋诗','song-poetry','','[]','鳥聲時向靜中聞，盡日陰晴漫不分。',32,'全唐诗/poet.song.87000.json','["鳥聲時向靜中聞，盡日陰晴漫不分。", "庭下落花如落絮，眼前春思似春雲。"]'),
('b7dbe216-34dc-448a-8dc3-6d59810a5df9','訪張元明山齋','周紫芝','宋','宋诗','song-poetry','','[]','張侯詩似嶺雲閑，飛鳥何心只願還。',64,'全唐诗/poet.song.87000.json','["張侯詩似嶺雲閑，飛鳥何心只願還。", "醉裏有官如物外，眼前無客似山間。", "來聽春枕連宵雨，看畫秋屏着色山。", "老去此身無處用，固應容我作躋攀。"]'),
('c43d02b7-8fa1-4ecc-8c61-00cadc682d9f','次韻張元明書劉氏草堂','周紫芝','宋','宋诗','song-poetry','','[]','草堂聞出碧雞西，一色桃花去路迷。',64,'全唐诗/poet.song.87000.json','["草堂聞出碧雞西，一色桃花去路迷。", "有眼固應元自白，無腰略可爲人低。", "池塘看浴雙鳧雨，簾幙時銜燕子泥。", "想得君家舊蓑笠，依然猶在太真谿。"]'),
('1be7e28e-0709-48c4-b268-554b5cb63c82','四月二十八日江元楷置酒坐客皆醉臥已而主人亦就睡戲作數語以紀其事','周紫芝','宋','宋诗','song-poetry','','[]','西園春事闌，歌管罷絲竹。',144,'全唐诗/poet.song.87000.json','["西園春事闌，歌管罷絲竹。", "青錢落高榆，幽鳥囀空谷。", "江侯不能閑，折簡到吾屬。", "凈掃南窗塵，共把一樽玉。", "重觴各頹然，睡味久乃熟。", "齁齁兩鼻雷，艶艶當筵燭。", "因知歡有餘，誰謂飲不足。", "偉哉三玉人，曾不愧坦腹。", "應憐俗子陋，禮法困窘束。", "坐中飲濕生，起舞自成曲。", "主人亦忘客，去留隨所欲。", "可笑陶淵明，欲睡客須逐。"]'),
('4e8b1f1a-c903-4ecf-a0f7-817b720217e7','題張元眀四鬼捕懶龍圖','周紫芝','宋','宋诗','song-poetry','','[]','五月江南地無黍，帝遣雷師下行雨。',160,'全唐诗/poet.song.87000.json','["五月江南地無黍，帝遣雷師下行雨。", "百神受職羣龍奔，一龍藏頭翳玄雲。", "雷師奮虬叱四鬼，拽取老龍朝帝閽。", "張侯直氣不可屈，雲間睥睨旁怒嗔。", "歸來面壁聊一吐，畫作新圖走兒女。", "潛虬怕死不肯行，夜叉飛天髪毛豎。", "人間空笑虎頭痴，筆底風雲遽如許。", "今年雨足年亦豐，蜥蜴蝘蜓俱論功。", "龍方下避千里赤，疾雷破柱頌天公。", "天公有令那得爾，寄語痴龍莫辭死。"]'),
('440c1fc0-daa0-43a6-977b-71c50066fa00','次韻趙伯武病中即事五首  其一','周紫芝','宋','宋诗','song-poetry','','[]','臥疴念經時，勿藥有新喜。',48,'全唐诗/poet.song.87000.json','["臥疴念經時，勿藥有新喜。", "便應走駸駸，誰復稱起起。", "嘯歌理壺觴，婆娑在窗几。", "想當呼濁醪，與客談妙理。"]'),
('eb12f833-582a-4382-a7bd-58f24440be75','次韻趙伯武病中即事五首  其二','周紫芝','宋','宋诗','song-poetry','','[]','趙侯佳公子，妙伎數三絕。',48,'全唐诗/poet.song.87000.json','["趙侯佳公子，妙伎數三絕。", "對君如春水，熇熇消內熱。", "一爲藥石誤，良會能契闊。", "便當亟相過，共此良夜月。"]'),
('6180d8a7-c8bc-485f-bba6-c2c45ed3d964','次韻趙伯武病中即事五首  其三','周紫芝','宋','宋诗','song-poetry','','[]','愛酒知有癖，耽書久成痴。',48,'全唐诗/poet.song.87000.json','["愛酒知有癖，耽書久成痴。", "官曹足餘暇，幽策約屢枝。", "但恐蒹葭陋，繆倚瓊玉姿。", "况無彈丸手，突過黄初詩。"]'),
('e2d05c76-9397-4e15-84fe-897a69a4792a','次韻趙伯武病中即事五首  其四','周紫芝','宋','宋诗','song-poetry','','[]','病餘春巳歸，飛花滿空堂。',48,'全唐诗/poet.song.87000.json','["病餘春巳歸，飛花滿空堂。", "萱草欲成窠，戎葵粲微黄。", "高門有賀客，新篘怯初嘗。", "人生貴強健，餘事亦渺茫。"]'),
('a5069d1d-7ec2-4b57-90d9-dbf768c1d60f','次韻趙伯武病中即事五首  其五','周紫芝','宋','宋诗','song-poetry','','[]','平生沈東陽，鶴骨儼如故。',48,'全唐诗/poet.song.87000.json','["平生沈東陽，鶴骨儼如故。", "朝來聞巾車，載酒定何處。", "暮歸坐東軒，翰墨有佳趣。", "當持烏絲欄，爲乞錦囊句。"]'),
('a2b58ed4-a085-4fa8-a1a2-ee28393dd2cf','送費茂和二首  其一','周紫芝','宋','宋诗','song-poetry','','[]','誰言令尹拙催科，鞭朴當如豈弟何。',64,'全唐诗/poet.song.87000.json','["誰言令尹拙催科，鞭朴當如豈弟何。", "樓下久傳于蔿曲，人間方唱紇那歌。", "虎知低首須應殺，雉已將雛不可羅。", "太史若書神爵傳，慈祥未愧昔人多。"]'),
('bdf39201-2053-460e-b867-cdfe5bb4aa96','送費茂和二首  其二','周紫芝','宋','宋诗','song-poetry','','[]','前賢零落謾知名，後輩何由識老成。',64,'全唐诗/poet.song.87000.json','["前賢零落謾知名，後輩何由識老成。", "誰遣斯民俱臥轍，因知循吏本無聲。", "眼前公事何時了，月下清樽且復傾。", "想得新栽池上柳，送君歸棹亦多情。"]'),
('72c46ec2-f4a2-4843-9c7d-4cd524a2dd56','汪才任寺簿得劉遺民釣臺于涇水之上將作小亭而未暇有詩次其韻','周紫芝','宋','宋诗','song-poetry','','[]','眼前時事只紛紛，林下誰來弔逸民。',64,'全唐诗/poet.song.87000.json','["眼前時事只紛紛，林下誰來弔逸民。", "斷石至今留故物，赤欄何日照江濵。", "飄流歲月人空遠，料理風烟意轉新。", "擬借一椽垂短釣，此生真欲繼前塵。"]'),
('1b3602d7-8d3f-4829-aa5d-469663b5df86','秋暑臥病示莊簿','周紫芝','宋','宋诗','song-poetry','','[]','老火倏巳盡，金行殊未剛。',168,'全唐诗/poet.song.87000.json','["老火倏巳盡，金行殊未剛。", "弱棗漸可剝，七月猶驕陽。", "赤日不可嚮，白汗驚流漿。", "誰將窮谷冰，爲我濡枯腸。", "况兹老病軀，息偃真在床。", "敲秋賴風玉，微飈襲衣裳。", "言念北征士，萬里方拓疆。", "秋雲靜邊日，光耀劍戟場。", "君今飽韜略，論事時抗章。", "諸公頗動色，有策云甚良。", "何當給鋒車，結佩朝明光。", "一鼓收關河，再鼓擒戎王。", "兵戈既靜洗，不復腥犬羊。", "萬夫各解甲，四海均清凉。"]'),
('dea08857-16ee-4bae-b0bb-17255e8c7c6b','雨後微凉再示莊簿','周紫芝','宋','宋诗','song-poetry','','[]','蓐收始用事，健行肅乾剛。',168,'全唐诗/poet.song.87000.json','["蓐收始用事，健行肅乾剛。", "微飈生淅瀝，一雨洗亢陽。", "香羅阨團扇，玉椀辭蔗漿。", "况蒙慷慨詞，猶激卑懦膓。", "當食忽亡匕，起立遂失床。", "鷄鳴中夜興，呼燈攬冠裳。", "自從羯胡亂，四海失故疆。", "向來桑麻區，半作荆棘場。", "黔首未安堵，皂囊思獻章。", "聞有圯上書，今代誰張良。", "風雲須嘉會，日月依末光。", "當宁方側席，誰能薦吾王。", "鷙鳥尚垂翅，老眼空望羊。", "秋風一夕起，撫事增悲涼。"]'),
('90857532-c847-4051-8602-e3b30f241bb3','觀大閲','周紫芝','宋','宋诗','song-poetry','','[]','落日鳴笳鼓，西風卷旆旌。',48,'全唐诗/poet.song.87000.json','["落日鳴笳鼓，西風卷旆旌。", "熊羆千騎肅，錦繡一川明。", "猛士方投石，將軍未請纓。", "不須誇劍舞，卻縠是書生。"]'),
('36e00147-088b-4185-86be-754f469adcb4','復愁二首  其一','周紫芝','宋','宋诗','song-poetry','','[]','秋風嫋嫋秋雲愁，寒日耿耿還西流。',64,'全唐诗/poet.song.87000.json','["秋風嫋嫋秋雲愁，寒日耿耿還西流。", "昬鴉接翅带遠水，暮雨滿山昏北樓。", "微凉漸欲入枕簟，白露復恐霑梧楸。", "横戈壯士半茅土，雲壑布衣悲素秋。"]'),
('aa2eb5f4-ef0d-49f1-82f4-28e1661588a8','復愁二首  其二','周紫芝','宋','宋诗','song-poetry','','[]','江南郡邑半成灰，江北諸藩信不來。',64,'全唐诗/poet.song.87000.json','["江南郡邑半成灰，江北諸藩信不來。", "此日兵連殊未解，向來邊釁復誰開。", "三關故地何時得，二帝征鑾幾日回。", "白髪草萊無遠策，時垂雙泪只興哀。"]'),
('ec17b137-aca2-4b2f-8fbf-f0a9b56e697c','次韻馮遠猷夜雨屋漏有作','周紫芝','宋','宋诗','song-poetry','','[]','我昔在田間，秋霖傷歲熟。',144,'全唐诗/poet.song.87000.json','["我昔在田間，秋霖傷歲熟。", "常憂床床雨，夜下東屯屋。", "飯牛起晨耕，短蓑聊櫛沐。", "違濕因五遷，勞形真僕僕。", "坐歌南山粲，那惜清夜促。", "平生小馮君，秀齒粲冰玉。", "生餘華屋姿，豈識霑濡辱。", "誰知折角巾，肯念滹沱軸。", "會將秋雨謠，寫入朱弦曲。", "知君有過秦，妙畫行見録。", "袞衣坐法宮，當宁調玉燭。", "吾廬雖獨破，受凍死亦足。"]'),
('4a61e8f6-418e-489c-9dca-5eacc93357c4','飲魏宗明家分韻得酒字','周紫芝','宋','宋诗','song-poetry','','[]','閉門苦秋炎，散髪臥北牖。',132,'全唐诗/poet.song.87000.json','["閉門苦秋炎，散髪臥北牖。", "小雨度微凉，西風颯衰柳。", "起邀馬服君，步過雲中守。", "雲中雅好事，酌我玉巵酒。", "諸公飲方豪，何曾問升斗。", "而我纔飲濕，已復困濡首。", "臭味本自同，初何間能否。", "不然瓊瑤林，何以着老叟。", "歡同一笑間，義重千載後。", "脫彈無新詩，刻燭愧敏手。", "詩成慎勿再，坐客驚欲走。"]'),
('0ab30652-fe1f-4f83-bcf3-f131500d6f91','感韓碑用李義山韻','周紫芝','宋','宋诗','song-poetry','','[]','長蛇封豕矜雄姿，弄兵三世窺皇羲。',387,'全唐诗/poet.song.87000.json','["長蛇封豕矜雄姿，弄兵三世窺皇羲。", "自從胡騎入中土，僥倖歲月寛誅夷。", "錦纒紅帕五十載，肯輸赤豹兼黄羆。", "憲皇神算本天授，指顧不勞戈一揮。", "元和上相拜元帥，黄金鑄印手自持。", "三軍踏雪砍墉入，夜摩賊壘朝搴旗。", "侍中西平老將種，屬鞬拜舞行相隨。", "緋衣小兒却健武，未怕賊首如虎貔。", "功垂竹帛不可掩，名在萬古誰能訾。", "行軍司馬號大手，蒼珉承詔鑱瑰詞。", "平生直筆有公議，從人乞米知羞爲。", "狗功須賴發縱者，盡勒殊勳歸鼎司。", "宮中小女强解事，歛祍雪涕垂豐頤。", "絺章繪句隨斷裂，厖恩下沛驚淋漓。", "空餘大雅配吉甫，春秋廟享存歌詩。", "當時左右無諌者，應慚鳴佩趨龍墀。", "襄陽太守獨何事，殷勤自刻平吳碑。", "將軍更勒燕然石，蠻風瘴雨侵蟠螭。", "張功耀武示萬世，二子無乃爲已私。", "晉公純德古未有，彊藩悍將親平治。", "羣奸聞風膽爲落，自奮老拳擒宛脾。", "都人尚想白羽扇，野蔓已理黄絹詞。", "唐家晚歲事如此，誰令舉世躋純煕。", "君不見鄭公之死肉未冷，停婚碎石恩還追。"]'),
('795deaa4-afe4-489d-ba21-07201d3e2953','寄題元具茨雙梅庵','周紫芝','宋','宋诗','song-poetry','','[]','高節知公冠九州，梅花却對令君羞。',64,'全唐诗/poet.song.87000.json','["高節知公冠九州，梅花却對令君羞。", "詩如往日陶彭澤，人是只今陳太邱。", "挽得繁枝供宴坐，小分疏影入清流。", "簿書堆裏渾無事，玉雪香中醉即休。"]'),
('6d21de5a-17ad-4816-9de6-358287568513','讀東坡儋耳新詩','周紫芝','宋','宋诗','song-poetry','','[]','先生流落久居夷，屬國前身事巳非。',64,'全唐诗/poet.song.87000.json','["先生流落久居夷，屬國前身事巳非。", "萬里岷峨空入夢，七年海嶠不思歸。", "桄榔葉暗蠻村雨，荔子紅垂瘴嶺扉。", "政坐詩窮關底事，雲鵬誰道總卑飛。"]'),
('7b869da6-c1c8-4653-9933-24882cab9912','次韻時然惠徽州近作','周紫芝','宋','宋诗','song-poetry','','[]','莊侯四海習鑿齒，鸞栖一枝亦聊爾。',192,'全唐诗/poet.song.87000.json','["莊侯四海習鑿齒，鸞栖一枝亦聊爾。", "沸鑊那尋袁處州，獨跨羸驂度徽水。", "羊腸路繞十八坡，危磴天懸三十里。", "捫參歷井不復休，一握去天真有此。", "軍符夜下星火急，吏習文書日填委。", "青山倥傯未可厭，方外周旋人有幾。", "坐看雲生拄頰間，便恐詩成横槊裏。", "萬壑千巖入句來，天遣江山助奇偉。", "我昔經行五嶺頭，芙蓉峰高天正秋。", "凄音怨曲不成調，細雨寒烟空復愁。", "曉得新詩驚欲倒，句似當年山色好。", "一生忍淚泣秋風，可笑區區郊與島。"]'),
('0a61fb55-33d2-4828-85a9-3d3a6de2f128','題吕節夫園亭十一首 雲林堂','周紫芝','宋','宋诗','song-poetry','','[]','高情惡喧囂，結屋傍空曠。',48,'全唐诗/poet.song.87000.json','["高情惡喧囂，結屋傍空曠。", "草堂寄雲林，遠目聊自放。", "偃蹇良不疑，世情真可抗。", "不知堂中人，誰同倚藤杖。"]'),
('a6ff8a40-f746-4343-af48-1f323ae03196','題吕節夫園亭十一首 半隱寮','周紫芝','宋','宋诗','song-poetry','','[]','顯晦固有時，出處本同致。',48,'全唐诗/poet.song.87000.json','["顯晦固有時，出處本同致。", "乘流與遇坎，等是一戲事。", "真隱了無心，寧須論朝市。", "君看半隱名，是中有深意。"]'),
('05fc94d9-6871-46ea-890c-9756d4a29168','題吕節夫園亭十一首 歲寒披','周紫芝','宋','宋诗','song-poetry','','[]','山中與誰語，俗士不我過。',48,'全唐诗/poet.song.87000.json','["山中與誰語，俗士不我過。", "時攜登山屐，閑上歲寒坡。", "不知青女威，奈此蒼官何。", "從今桃李花，漫漫空復多。"]'),
('2b33f198-54bb-4d26-9e85-dc3f7ea7c6f0','題吕節夫園亭十一首 朝陽臺','周紫芝','宋','宋诗','song-poetry','','[]','殘月壞金樞，朝曦吐暘谷。',48,'全唐诗/poet.song.87000.json','["殘月壞金樞，朝曦吐暘谷。", "南臺凌日觀，杲杲明萬木。", "白露亦巳晞，桐陰轉簷曲。", "危坐讀黄庭，想像巾一幅。"]'),
('fd6b4836-ab6e-4fff-91dc-45fe525b19a8','題吕節夫園亭十一首 衆芳閣','周紫芝','宋','宋诗','song-poetry','','[]','草木有盛德，俗眼未易觀。',48,'全唐诗/poet.song.87000.json','["草木有盛德，俗眼未易觀。", "幽姿不可見，微香在林間。", "植我東籬菊，藝此九畹蘭。", "芳意似有知，爲君笑朱欄。"]'),
('41e0b74b-b438-4b27-bfe3-f776c852af4e','題吕節夫園亭十一首 藤洞','周紫芝','宋','宋诗','song-poetry','','[]','雲山渺無何，地勝餘草木。',48,'全唐诗/poet.song.87000.json','["雲山渺無何，地勝餘草木。", "蒼藤飽風霜，夭矯作巖谷。", "幽香出空洞，清樾交翠麓。", "想時攜客來，班荆對棋局。"]'),
('c0dfccff-f143-4620-9301-9afa6db5eb61','題吕節夫園亭十一首 學圃亭','周紫芝','宋','宋诗','song-poetry','','[]','疏泉灌空畦，折柳樊小圃。',48,'全唐诗/poet.song.87000.json','["疏泉灌空畦，折柳樊小圃。", "關心有幽事，寄意在衡宇。", "但恐經綸人，兹焉忽高舉。", "慎勿厭荷鋤，烟蓑濕春雨。"]'),
('2f1d2031-e531-499b-81ac-a91ffd52dc65','題吕節夫園亭十一首 卷書閣','周紫芝','宋','宋诗','song-poetry','','[]','機雲佳兄弟，胸中幾石渠。',48,'全唐诗/poet.song.87000.json','["機雲佳兄弟，胸中幾石渠。", "萬事資不理，三篋補有餘。", "它時策高勳，已復得異書。", "安用結飛樓，傍架時卷舒。"]'),
('1e756e36-3b38-401c-8e2a-69e18c2ec5ba','題吕節夫園亭十一首 舒嘯軒','周紫芝','宋','宋诗','song-poetry','','[]','淵明磊落人，啾唧倦吟諷。',48,'全唐诗/poet.song.87000.json','["淵明磊落人，啾唧倦吟諷。", "聊將舒歗聲，一爲洗喧閧。", "寄言梟獍徒，請勿恣嘲哢。", "君看半嶺間，依稀有鳴鳯。"]'),
('89dd5b42-9bfd-4808-85ec-bed0fecf682d','題吕節夫園亭十一首 越香堂','周紫芝','宋','宋诗','song-poetry','','[]','佳木寄深塢，自與春有期。',48,'全唐诗/poet.song.87000.json','["佳木寄深塢，自與春有期。", "幽姿誰復省，軒軒頗矜持。", "真賞倘已逢，清香襲人衣。", "士爲知己死，此語良不欺。"]'),
('05b76461-1f0d-494b-ab64-6366e4818c30','題吕節夫園亭十一首 容安軒','周紫芝','宋','宋诗','song-poetry','','[]','生理須幾何，安分一枝足。',48,'全唐诗/poet.song.87000.json','["生理須幾何，安分一枝足。", "向來高明中，百鬼作禍福。", "何如此衡茅，長年樂幽獨。", "慎勿將蝸牛，輕比蠻與觸。"]'),
('f659dc62-967e-4e73-8acc-7f29d82aa5ab','金華老人分老潘點漆墨十月二十三日久雨新霽弄筆北窗戲作此語華嚴經云須彌山筆大海聚墨不能書寫一字法門','周紫芝','宋','宋诗','song-poetry','','[]','老來窗几漫塵埃，誰與潘郎點漆煤。',32,'全唐诗/poet.song.87000.json','["老來窗几漫塵埃，誰與潘郎點漆煤。", "一字法門書不得，又撩風月作詩媒。"]'),
('d3c06085-d291-4682-a160-c28b2223a17e','東窗對雪六言四首  其一','周紫芝','宋','宋诗','song-poetry','','[]','月觀雲臺何處，瑤林玉樹誰家。',28,'全唐诗/poet.song.87000.json','["月觀雲臺何處，瑤林玉樹誰家。", "幻成銀色世界，雨此天女寶花。"]'),
('61e4181e-f5d2-4b6f-ab5b-6fca13f432d2','東窗對雪六言四首  其二','周紫芝','宋','宋诗','song-poetry','','[]','天淨銀潢渺渺，林寒玉珮珊珊。',28,'全唐诗/poet.song.87000.json','["天淨銀潢渺渺，林寒玉珮珊珊。", "有月時翻瑤草，無人來踏瓊田。"]'),
('54ea595a-0778-419c-a2ab-884eaf3aad07','東窗對雪六言四首  其三','周紫芝','宋','宋诗','song-poetry','','[]','擁鼻駝裘不暖，澆腸蟻榼還空。',28,'全唐诗/poet.song.87000.json','["擁鼻駝裘不暖，澆腸蟻榼還空。", "助我茶甌玉雪，煎成石鼎松風。"]'),
('7ea4b493-67da-48ac-97be-ac954e48c798','東窗對雪六言四首  其四','周紫芝','宋','宋诗','song-poetry','','[]','睡起山驚堆玉，詩成研欲敲冰。',28,'全唐诗/poet.song.87000.json','["睡起山驚堆玉，詩成研欲敲冰。", "飄瓦莫嫌碎點，打窗留伴寒燈。"]'),
('56084254-a723-4753-94a9-322e09c73b30','聞雪二首  其一','周紫芝','宋','宋诗','song-poetry','','[]','黄昏雪意未全成，寒入重衾曉更清。',32,'全唐诗/poet.song.87000.json','["黄昏雪意未全成，寒入重衾曉更清。", "風裏未看穿幕片，夢中先聽打窗聲。"]'),
('37736f78-f82d-4dc8-a6dd-6ccc7c920783','聞雪二首  其二','周紫芝','宋','宋诗','song-poetry','','[]','朔風初喚夢魂回，曉枕時聞急雪來。',32,'全唐诗/poet.song.87000.json','["朔風初喚夢魂回，曉枕時聞急雪來。", "未有春衣堪換酒，明朝誰辦送寒杯。"]'),
('89481c38-f867-4923-a47e-2200d594dd2b','次韻莊簿對雪','周紫芝','宋','宋诗','song-poetry','','[]','月姊雲冠玉作膚，白鸞飛鞚下天衢。',64,'全唐诗/poet.song.87000.json','["月姊雲冠玉作膚，白鸞飛鞚下天衢。", "欲酬平地雪三尺，正要澆愁酒一壺。", "林下閉門須好句，廟堂調燭費嘉謨。", "它時瓊佩朝銀闕，共醉寒江記老夫。"]'),
('04419df5-1e56-47d0-a054-93cc45a3697f','讀外舅高晉翁詩集','周紫芝','宋','宋诗','song-poetry','','[]','結髪論人物，傾心慕老成。',144,'全唐诗/poet.song.87000.json','["結髪論人物，傾心慕老成。", "掃門嗟齒暮，洗眼失冰清。", "心苦彈冠懶，名應脱屨輕。", "眼高空爾輩，醉熟自平生。", "長嘯蘇門冷，微顰下蔡傾。", "千兵森武庫，五字築詩城。", "鮑謝篇章麗，陰何句法精。", "聱牙徒自放，貞耀復誰旌。", "草露功名薄，春雲歲月更。", "鴨頭江自綠，馬鬛墓還平。", "蹤跡荆襄在，文華劍佩榮。", "塵編愁獨把，清淚一縱横。"]'),
('d6a08e06-9e83-4680-bb3e-deb4a1af6dd6','吳幾聖許分蠟梅栽二首  其一','周紫芝','宋','宋诗','song-poetry','','[]','林下幽姿惱殺人，書來分我月黄昏。',32,'全唐诗/poet.song.87000.json','["林下幽姿惱殺人，書來分我月黄昏。", "杜陵老子堪憐許，枉乞桃栽一百根。"]'),
('1f71038a-cc6c-40e4-87a5-7f2c84833814','吳幾聖許分蠟梅栽二首  其二','周紫芝','宋','宋诗','song-poetry','','[]','越羅新學染宮黄，不著紅藍一點粧。',32,'全唐诗/poet.song.87000.json','["越羅新學染宮黄，不著紅藍一點粧。", "移取綵衣歌舞樹，莫教曉夢怨餘香。"]'),
('c49dfa38-11cc-4c36-97ff-51ea06c5dd18','幾聖以三詩寄蠟梅栽次韻  其一','周紫芝','宋','宋诗','song-poetry','','[]','寄將琢玉風前句，剪送和香雪後枝。',32,'全唐诗/poet.song.87000.json','["寄將琢玉風前句，剪送和香雪後枝。", "要識此花真面目，細看無色畫中詩。"]'),
('695409bc-e1f0-4ee4-a36c-cb2c2a55cca9','幾聖以三詩寄蠟梅栽次韻  其二','周紫芝','宋','宋诗','song-poetry','','[]','釀蜜成花此似難，移根深恨老來看。',32,'全唐诗/poet.song.87000.json','["釀蜜成花此似難，移根深恨老來看。", "豐肌弱骨須調護，可怕寒梢白露團。"]'),
('15e55c5f-fb69-47fc-94d2-189b249f9e62','幾聖以三詩寄蠟梅栽次韻  其三','周紫芝','宋','宋诗','song-poetry','','[]','慣見江邊雪様梅，此根常恐自天來。',32,'全唐诗/poet.song.87000.json','["慣見江邊雪様梅，此根常恐自天來。", "懸知老去醉中眼，便是姚黄花懶開。"]'),
('165f0a78-afec-4752-8e4e-7dd7a50959ec','次韻沈給事對雪長句二首  其一','周紫芝','宋','宋诗','song-poetry','','[]','灑天飛雪被長巒，落絮縈風醉後觀。',64,'全唐诗/poet.song.87000.json','["灑天飛雪被長巒，落絮縈風醉後觀。", "塞上餐氈公獨記，月中回棹我知寒。", "已書上瑞歸天闕，又挽豐年到筆端。", "懸瓠功名知有意，微生底處更求安。"]'),
('6af5cf95-1f04-4f8d-a027-a76802dcd9fd','次韻沈給事對雪長句二首  其二','周紫芝','宋','宋诗','song-poetry','','[]','翠失千峰與萬巒，爛銀宮闕縱奇觀。',64,'全唐诗/poet.song.87000.json','["翠失千峰與萬巒，爛銀宮闕縱奇觀。", "樓空翠濕衣裘重，詩就風生齒頰寒。", "聊與江山分絕致，浪陪樽俎問更端。", "莫嗔郢曲無人和，七子風流負建安。"]'),
('deebddd5-a188-4a6c-927a-a8319e5d8d27','韻莊時然徽州山下見梅三絕  其一','周紫芝','宋','宋诗','song-poetry','','[]','凍蘂寒梢也自芳，斷橋深塢獨聞香。',32,'全唐诗/poet.song.87000.json','["凍蘂寒梢也自芳，斷橋深塢獨聞香。", "山中行處花吹面，馬上歸時詩滿囊。"]'),
('1bc535e5-1f89-4145-820d-00292eac7b4f','韻莊時然徽州山下見梅三絕  其二','周紫芝','宋','宋诗','song-poetry','','[]','雪後花開人未歸，津亭誰共把寒杯。',32,'全唐诗/poet.song.87000.json','["雪後花開人未歸，津亭誰共把寒杯。", "句中解道梅如雪，夢裏可無人似梅。"]'),
('a823a9e3-d938-4cf8-be5e-b4151093e430','韻莊時然徽州山下見梅三絕  其三','周紫芝','宋','宋诗','song-poetry','','[]','春到梅梢雪作堆，庾郎愁眼爲誰開。',32,'全唐诗/poet.song.87000.json','["春到梅梢雪作堆，庾郎愁眼爲誰開。", "白龜城裏未曾見，徽嶺句中渾寄來。"]'),
('394703fa-6854-470a-ba7e-ae3e078d580a','雪將晴聞梅已有開者','周紫芝','宋','宋诗','song-poetry','','[]','臘雪自知春欲回，凍雲元不耐朝暉。',32,'全唐诗/poet.song.87000.json','["臘雪自知春欲回，凍雲元不耐朝暉。", "便須急買尋山屐，莫放梅花一片飛。"]'),
('7c2d30f7-73a2-4cc0-8ec0-4a6e5dc20893','題雪堂大研一首','周紫芝','宋','宋诗','song-poetry','','[]','河間多書人共知，未見紫巖方玉池。',144,'全唐诗/poet.song.87000.json','["河間多書人共知，未見紫巖方玉池。", "東坡老人上天去，流落人間君得之。", "寶匣初開眼光眩，相約君家與同看。", "麝煤霮䨴雲滿天，尺璧堅温玉微汗。", "峨眉山高兩蘇出，自是斯文有秦漢。", "先生著書書滿家，晚得窮愁坐城旦。", "只今蠆尾人爭傳，異時龜趺不須斷。", "百年榮辱一夢餘，空與高人作奇玩。", "安得大手揭陽君，爲我銘此元賓研。"]'),
('9c72f05f-06d1-4649-a546-c9d53730828a','次韻具茨老人觀臘月十五日按兵','周紫芝','宋','宋诗','song-poetry','','[]','六花陣合紅滿川，鼓鼙聲喧旌暗天。',208,'全唐诗/poet.song.87000.json','["六花陣合紅滿川，鼓鼙聲喧旌暗天。", "錦裘繡帽不動鞭，腰鞬兩弓誰更先。", "城狐社鼠空百千，一呼辟易投戈鋋。", "霹靂晝射蛟螭淵，妖星夜落蚩尤躔。", "穀城老父書誰傳，可爲帝師策萬全。", "脱兔一出忽復旋，風聲鶴唳驚虚弦。", "常山蛇勢孰後前，四頭八尾屢變遷。", "何止內政分軌連，部伍聊足相糾聯。", "勢如漂石奔流泉，蒙衝未數浮江船。", "三軍不用呼飛燕，功成唾手豈待年。", "長安賊平不改廛，萬里玉關沉夕烟。", "降王曳組未解纒，白麻曉下彤庭宣。", "兵雄澤潞非公賢，談笑自足空戎邊。"]'),
('5c6d5c54-d945-4a2a-ac61-3398a384cd49','沈元用太守和具茨詩張元明兩用其韻見邀同賦','周紫芝','宋','宋诗','song-poetry','','[]','漢陽胡騎嘶秦川，六龍御日升中天。',208,'全唐诗/poet.song.87000.json','["漢陽胡騎嘶秦川，六龍御日升中天。", "翠鑾親巡耀寶鞭，神武自作諸將先。", "子陽盗據衆萬千，井中蛙腹不受鋋。", "虎頭誰敢當文淵，一洗萬古空英躔。", "風威巳落諸蕃傳，上兵伐謀軍貴全。", "固應玉陛當周旋，朱幡猶此閲望弦。", "安危以身誰肯前，願扶國步整播遷。", "勁兵出塞鏖祁連，長纓曳首來翩聯。", "盡驅酋長朝甘泉，未慚驃騎羞戈船。", "先聲旋下齊與燕，稱觴拜舞呼萬年。", "黄童佩犢無征廛，農桑萬里通人烟。", "蓬頭舞劍空腰纒，要分頗牧來藩宣。", "古來千里制一賢，長城未必能防邊。"]'),
('ce222bf5-31cf-42f4-943f-9a2935d60493','横谿小市再宿慨然有感','周紫芝','宋','宋诗','song-poetry','','[]','小市人烟南北頭，清江賈客去來舟。',64,'全唐诗/poet.song.87000.json','["小市人烟南北頭，清江賈客去來舟。", "兒時風物依然在，老去光陰不奈愁。", "可憐白髪無好意，更對故城思舊遊。", "烟塵蓬勃兵火急，歲晚棹歌歸去休。"]'),
('28f79ca2-fa0a-434d-880e-a2389e81bcee','夜宿長林明日遊仙壇宮','周紫芝','宋','宋诗','song-poetry','','[]','麻川過長林，路轉無百里。',144,'全唐诗/poet.song.87000.json','["麻川過長林，路轉無百里。", "積雨斷津梁，日亂十六水。", "忽從岡阜間，稍得千家市。", "凌晨上仙祠，遂作折屐喜。", "水流自汪灣，山亦甚雄偉。", "小邑頗下臨，擾擾屯聚蟻。", "一笑相與言，黄冠有仙子。", "爲言庭前菊，霜餘爛黄蘂。", "採之制頹齡，可以堅髪齒。", "不須事虚曠，至道亦良邇。", "神仙固可學，吐納乃餘事。", "斯言雖甚簡，中亦含妙理。"]'),
('112fdee7-fa57-4a4f-aa98-d182361ca58e','星源逢仲共兄弟别後道中奉寄二首  其一','周紫芝','宋','宋诗','song-poetry','','[]','曉色凄迷客夢長，賈胡留滯更他鄉。',64,'全唐诗/poet.song.87000.json','["曉色凄迷客夢長，賈胡留滯更他鄉。", "自隨匹馬家千里，眼見故人天一方。", "霜落駝裘朝着帽，雨來山驛夜分床。", "與君相别無多日，已聽鳴鴻欲斷腸。"]'),
('4b99aaac-0eeb-42b0-bb3f-6fcc0604dcb7','星源逢仲共兄弟别後道中奉寄二首  其二','周紫芝','宋','宋诗','song-poetry','','[]','十年四海不解甲，一日三秋更憶君。',64,'全唐诗/poet.song.87000.json','["十年四海不解甲，一日三秋更憶君。", "别後光陰逐流水，老來蹤跡似浮雲。", "心懷丘壑情雖在，眼暗風塵首重分。", "滿眼尚添新戰骨，何年真起故將軍。"]'),
('470945cc-0e33-4b7f-b46e-74af019b5590','苦寒二首  其一','周紫芝','宋','宋诗','song-poetry','','[]','朔風吹雪天漫漫，厚地欲裂江水乾。',64,'全唐诗/poet.song.87000.json','["朔風吹雪天漫漫，厚地欲裂江水乾。", "懸知北客未省見，太古以來無此寒。", "冰簷垂筍風撼屋，布衣生稜體生粟。", "老翁炙手厭朱門，明朝晨暾更堪曝。"]'),
('84f698c1-0c27-4cbf-b31e-2f0ce283ab9e','苦寒二首  其二','周紫芝','宋','宋诗','song-poetry','','[]','天容黯慘悲風吹，寒日欲出寒雲垂。',64,'全唐诗/poet.song.87000.json','["天容黯慘悲風吹，寒日欲出寒雲垂。", "千門晝閉人跡絕，萬里長空鳥不飛。", "豺虎號寒聲怒急，行人指墮毛爲立。", "易水風高燕地寒，白頭書生望雲泣。"]'),
('0f11bcba-2346-4afb-8999-3f3f31503397','具茨老人讀書寮','周紫芝','宋','宋诗','song-poetry','','[]','具茨四壁無斗儲，載行書多常滿廬。',192,'全唐诗/poet.song.87000.json','["具茨四壁無斗儲，載行書多常滿廬。", "胸中嵬壘幾石渠，三篋補亡無復餘。", "起居誰不解何如，校書著作虚詔除。", "元元本本窮古初，雌黄付與金銀車。", "朅來窮山歲三徂，催科政拙民力蘇。", "黄童佩犢耕菑畬，戴白未見空欷歔。", "焚香晏坐臨綺疏，三年不識園中蔬。", "邇來結屋聊卷舒，手抄平生未見書。", "曼倩兩目如懸珠，四十四萬何多歟。", "較公所得無錙銖，門生校讎誰與居。", "我欲從公路鬱迃，著鞭何時跨蹇驢。", "不求奴飯馬青芻，得公奇字歸自娛。"]'),
('52e3efde-3d3d-4045-b814-683450caa068','送元具茨歸黄山','周紫芝','宋','宋诗','song-poetry','','[]','元祐宗師數聖朝，兩公分路久揚鑣。',64,'全唐诗/poet.song.87000.json','["元祐宗師數聖朝，兩公分路久揚鑣。", "具茨人物真奇偉，雙井風流未寂寥。", "可怪魯山猶簿領，不應聱叟是漁樵。", "何時收拾江湖句，歸作歌詩補舜韶。"]'),
('b9e3d533-2748-4604-a6ac-3b0a99e7b57b','乞蠟梅  其一','周紫芝','宋','宋诗','song-poetry','','[]','老翁真是可憐人，却覓花醫病眼昏。',32,'全唐诗/poet.song.87000.json','["老翁真是可憐人，却覓花醫病眼昏。", "乞取疏枝更疏蘂，莫論桃葉又桃根。"]'),
('4aa7a1cc-596a-4d56-a41e-af1c60ee0d7d','乞蠟梅  其二','周紫芝','宋','宋诗','song-poetry','','[]','臘盡冰消未見時，春風應入近南枝。',32,'全唐诗/poet.song.87000.json','["臘盡冰消未見時，春風應入近南枝。", "懸知老樹開花早，苦恨幽人得句遲。"]'),
('ba06be54-f1f4-427d-afb8-96be271024c5','秀淮亭晚眺','周紫芝','宋','宋诗','song-poetry','','[]','未得三吳去，東來且過淮。',48,'全唐诗/poet.song.87000.json','["未得三吳去，東來且過淮。", "要須煩曉浪，聊爲洗風霾。", "飄泊從人笑，窮愁費力排。", "平生臨水意，老去若爲懷。"]'),
('8f97c5ab-54ac-4001-a4d0-8a4eb2720166','次韻趙師是題烏江連雲觀二絕  其一','周紫芝','宋','宋诗','song-poetry','','["\u957f\u6c5f"]','項王才器固無雙，秦鼎雖輕可獨扛。',32,'全唐诗/poet.song.87000.json','["項王才器固無雙，秦鼎雖輕可獨扛。", "豐沛故人如不用，濟師猶得問長江。"]'),
('3bbfe0f4-58b4-4532-8872-5dfabc2d8854','次韻趙師是題烏江連雲觀二絕  其二','周紫芝','宋','宋诗','song-poetry','','[]','連雲臺上倚闌干，着眼何妨盡日閑。',32,'全唐诗/poet.song.87000.json','["連雲臺上倚闌干，着眼何妨盡日閑。", "公子胸中有雲夢，更須爲助借江山。"]'),
('0498846a-e97a-40bd-986e-b7856b371af9','送潘擇之尉南巢','周紫芝','宋','宋诗','song-poetry','','[]','潘郎胸中有文藝，白髪青衫初試吏。',64,'全唐诗/poet.song.87000.json','["潘郎胸中有文藝，白髪青衫初試吏。", "少年欲射漢庭策，晚乃去作南巢尉。", "寒廳結屋八九椽，導騎挽弓三數輩。", "但願君如梅子真，人物風流亦何愧。"]'),
('395fe5ed-76d8-4800-a434-00080e3dca4a','題善應師毋我庵','周紫芝','宋','宋诗','song-poetry','','[]','今君無我亦無人，誰識毗邪妙悟身。',64,'全唐诗/poet.song.87000.json','["今君無我亦無人，誰識毗邪妙悟身。", "宴坐只應山是伴，夜禪唯與月相親。", "支郎好馬元成癖，懶瓚垂洟却是真。", "更待衆生總無病，萬金良藥不妨神。"]'),
('2f5ed186-277e-46c3-a5e6-d62d8edb18a2','元夕訪忍毋我已睡復起','周紫芝','宋','宋诗','song-poetry','','[]','殘缸零落數枝紅，春在空濛薄霧中。',64,'全唐诗/poet.song.87000.json','["殘缸零落數枝紅，春在空濛薄霧中。", "月似冰輪人似玉，車如流水馬如龍。", "山僧睡起三更後，遊客閑來一笑同。", "明暗短檠君莫厭，此燈無盡法無窮。"]'),
('414f0649-e773-4c44-b9c0-3fd7361e4410','次韻忍毋我春日三絕句  其一','周紫芝','宋','宋诗','song-poetry','','[]','暖入平林囀鳥鶵，日烘花氣滿庭隅。',32,'全唐诗/poet.song.87000.json','["暖入平林囀鳥鶵，日烘花氣滿庭隅。", "道人元不關春事，肯把新晴餉客無。"]'),
('a6173087-2f42-4a4a-a97d-223f8f16b609','次韻忍毋我春日三絕句  其二','周紫芝','宋','宋诗','song-poetry','','[]','雨餘繞屋一渠水，日落滿簾何處山。',32,'全唐诗/poet.song.87000.json','["雨餘繞屋一渠水，日落滿簾何處山。", "我亦時來開病眼，怕將春色照愁顔。"]'),
('3760b41e-d4bf-407f-8f18-fcfb77c329f3','次韻忍毋我春日三絕句  其三','周紫芝','宋','宋诗','song-poetry','','[]','春意全灰病後心，粥魚齋鼓聽禪林。',32,'全唐诗/poet.song.87000.json','["春意全灰病後心，粥魚齋鼓聽禪林。", "鳥啼南嶺夢初斷，花發故園人懶尋。"]'),
('cab6fd9a-054e-4094-917d-44b8a85f17bb','燈下讀韓致光外集','周紫芝','宋','宋诗','song-poetry','','[]','吳宮花草弄纖柔，西子粧成特地羞。',64,'全唐诗/poet.song.87000.json','["吳宮花草弄纖柔，西子粧成特地羞。", "笑我老情難娬媚，愛渠好句儘風流。", "香奩詩在人何處，斷腕名高事已休。", "更欲與誰論此恨，遺編讀罷一燈留。"]'),
('6b440e1e-1d37-4962-944e-a861f01c1ac3','春寒','周紫芝','宋','宋诗','song-poetry','','[]','寒意苦未解，春陰連晝霾。',48,'全唐诗/poet.song.87000.json','["寒意苦未解，春陰連晝霾。", "文書堆午枕，風雨閉寒齋。", "花落空驚眼，愁多欲滿懷。", "客情須一醉，安得酒如淮。"]'),
('eb01d838-89bb-4829-aec9-44b05696fe1e','試湖陰徐道久筆','周紫芝','宋','宋诗','song-poetry','','[]','山中三窟遭蕩焚，十年遺種無礽雲。',144,'全唐诗/poet.song.87000.json','["山中三窟遭蕩焚，十年遺種無礽雲。", "管城已老既謝事，柔毛遂出收微勳。", "騷人手握奴隸管，人間自此無蕕薫。", "徐生晚出頗自喜，妙伎天與人皆聞。", "羝羊退舍栗尾避，族非東郭不肯論。", "往歲江南說諸葛，至今有口皆能言。", "眼前厚利聊取足，身後典刑寧復存。", "騂牲自是犁牛出，忠臣豈但孝子門。", "古來取士貴閥閲，未必元成俱有孫。"]'),
('7ef566ef-e2be-4343-bad6-0a69aa913e9f','送孫秀才兼寄達道人','周紫芝','宋','宋诗','song-poetry','','[]','當年御史凛霜風，見說金狨玉面驄。',64,'全唐诗/poet.song.87000.json','["當年御史凛霜風，見說金狨玉面驄。", "汗簡有名知不朽，皂囊無稾豈非忠。", "夢思故國兵猶滿，身落它鄉路更窮。", "只有老禪真具眼，識君應在典型中。"]'),
('db1b5b64-94c7-4893-955a-e6cfaf1323d4','鰔鮓','周紫芝','宋','宋诗','song-poetry','','[]','放筯朝盤空，食指昨夜動。',48,'全唐诗/poet.song.87000.json','["放筯朝盤空，食指昨夜動。", "軟玉開香包，桃花點春瓮。", "平生江瑤柱，異名寔同用。", "何當登禹書，永作淮海貢。"]'),
('d09cc35c-c866-429f-ad35-f00708bde44e','淮寇及境而退喜甚成詩','周紫芝','宋','宋诗','song-poetry','','[]','近喜横戈寇，南來偃旆旌。',48,'全唐诗/poet.song.87000.json','["近喜横戈寇，南來偃旆旌。", "瀕江猶樹柵，带甲謾持兵。", "夜柝初寒枕，春田已趣耕。", "使君今尚父，應便是長城。"]'),
('71638c66-d776-4b86-b87b-cac2d8deab44','題米元章祠堂','周紫芝','宋','宋诗','song-poetry','','[]','繡谿遺跡巳茫茫，父老時能說漫郎。',64,'全唐诗/poet.song.87000.json','["繡谿遺跡巳茫茫，父老時能說漫郎。", "蒼碣尚餘唐翰墨，古祠猶是晉衣裳。", "旌旗還向江湖老，簷廡空悲草木長。", "我亦敢持寒具手，爲公來炷影前香。"]'),
('99bdf23c-ba58-468b-8b4c-40b3d3b287dc','次韻魏定甫早春題咏五首  其一','周紫芝','宋','宋诗','song-poetry','','[]','臘雪初晴梅欲花，有人聞說鬢如鴉。',32,'全唐诗/poet.song.87000.json','["臘雪初晴梅欲花，有人聞說鬢如鴉。", "清詩勾引江南夢，應向今宵還到家。"]'),
('b87731e6-2da3-45ad-9643-93cdf37d71b3','次韻魏定甫早春題咏五首  其二','周紫芝','宋','宋诗','song-poetry','','[]','三十六番風未回，微紅難倩剪刀裁。',32,'全唐诗/poet.song.87000.json','["三十六番風未回，微紅難倩剪刀裁。", "魏侯句裏有春色，不打凉州花自開。"]'),
('7b941a1e-5396-44a4-a3a3-a60551d48040','次韻魏定甫早春題咏五首  其三','周紫芝','宋','宋诗','song-poetry','','[]','雨後桃花可意紅，一川楊柳醉春風。',32,'全唐诗/poet.song.87000.json','["雨後桃花可意紅，一川楊柳醉春風。", "舞衣歌扇重撩理，百尺朱樓烟樹中。"]'),
('41b7c7d8-923b-4589-a625-e40bd540f446','次韻魏定甫早春題咏五首  其四','周紫芝','宋','宋诗','song-poetry','','[]','白頭憔悴未歸身，羞作須江入社人。',32,'全唐诗/poet.song.87000.json','["白頭憔悴未歸身，羞作須江入社人。", "自是愁多無好句，不關詩瘦與傷春。"]'),
('ed21eb9a-6b8e-4c41-b273-a98615da8239','次韻魏定甫早春題咏五首  其五','周紫芝','宋','宋诗','song-poetry','','[]','柴扉春亦借融和，客少高軒誰肯過。',32,'全唐诗/poet.song.87000.json','["柴扉春亦借融和，客少高軒誰肯過。", "醉裏我應慚畢阮，詩中君合是陰何。"]'),
('57cf3ef3-d305-4943-9e1f-1f3c9170c8d9','正月十八日謁客意甚不樂已而過正師猶未起書小詩窗間而已','周紫芝','宋','宋诗','song-poetry','','[]','玉壺花暖日烘窗，奪我寒衾曉夢長。',32,'全唐诗/poet.song.87000.json','["玉壺花暖日烘窗，奪我寒衾曉夢長。", "慚愧高人方擁鼻，小爐沉水宿殘香。"]'),
('12c02460-1b51-45f2-af6d-9e12d64049bf','張老借東軒晝睡','周紫芝','宋','宋诗','song-poetry','','[]','誰言知處是閑愁，一入華胥萬事休。',32,'全唐诗/poet.song.87000.json','["誰言知處是閑愁，一入華胥萬事休。", "借得東軒還宿願，何須雲夢澤南州。"]'),
('816bdfa3-ea29-4c50-aa18-0b3056d8dc80','畦蔬一首','周紫芝','宋','宋诗','song-poetry','','["\u957f\u6c5f"]','猗嗟老人，如水中槎。',190,'全唐诗/poet.song.87000.json','["猗嗟老人，如水中槎。", "攜壺挈榼，泛宅浮家。", "飄然北來，寓此一蝸。", "食無畎畝，衣無桑麻。", "藜莧滿腹，雜以蜆蝦。", "以鼓我腹，妻孥笑譁。", "旅人之食，豈曰不腆。", "不足則求，我顔亦靦。", "乃即舍隅，蒿萊是剪。", "藝此春蔬，侵畦覆畹。", "雨葉風枝，忽其滿眼。", "擷之掇之，以芼以烹。", "聊以當肉，亦足彭亨。", "搖喉澤吻，茹葅啜羮。", "如天酥酡，飯在家僧。", "彼哉膏粱，孰爲重輕。", "安得長江，載揚我舲。", "買地五畝，抱甕躬耕。", "駕言聿歸，以畢餘生。"]'),
('e11d4b77-2998-451d-8f61-29be95a3b3c8','解人敦武郎富君爲余言解池廣二百里其利不貲又有六小池官雖置戍以爲厲禁而民寔擅其利或悉以屬縣官則鹽不復成其事頗怪作小詩以紀之','周紫芝','宋','宋诗','song-poetry','','[]','天意懸知損有餘，小池分水計非疏。',32,'全唐诗/poet.song.87000.json','["天意懸知損有餘，小池分水計非疏。", "誰知當日蕭丞相，亦解區區說海魚。"]'),
('c2d06951-136b-4584-952f-642499849d04','春日小詩三首  其一','周紫芝','宋','宋诗','song-poetry','','[]','亂離回首又春風，江上人家一半空。',32,'全唐诗/poet.song.87000.json','["亂離回首又春風，江上人家一半空。", "燕子多情依舊舞，桃花無語可憐紅。"]'),
('27fc6963-2eb7-48b9-a157-721dbd9d3b82','春日小詩三首  其二','周紫芝','宋','宋诗','song-poetry','','[]','烏鳶啣紙欲成窠，寒食羈愁不奈多。',32,'全唐诗/poet.song.87000.json','["烏鳶啣紙欲成窠，寒食羈愁不奈多。", "夢到鹿門親上冢，花前老淚欲懸河。"]'),
('2e8d29bd-0746-40e0-b849-85f765f47ff0','春日小詩三首  其三','周紫芝','宋','宋诗','song-poetry','','[]','兵戈無地可窺臨，風物依然惱客心。',32,'全唐诗/poet.song.87000.json','["兵戈無地可窺臨，風物依然惱客心。", "未有鶯時春欲盡，已無花處綠成陰。"]'),
('7f6b1f0c-6372-4d35-ad26-b775fd5984a0','抄宛邱先生集見和許貴州詩因以悼之','周紫芝','宋','宋诗','song-poetry','','[]','臺閣諸公盡要途，一麾新拜嶺南除。',64,'全唐诗/poet.song.87000.json','["臺閣諸公盡要途，一麾新拜嶺南除。", "當時爲我歌新句，别後何人哭訃書。", "夢斷世間青瑣闥，醉傾天上碧琳腴。", "平生交舊晁張輩，餘子紛紛可作奴。"]'),
('f2122738-607e-49ab-a855-ceafa50ec396','米元章爲須江太守聞有怪石在河壖莫知其所自來人以爲異而不敢取公命移置州沼爲燕遊之玩石至而驚遽命設席拜於庭下曰吾欲見石兄二十年矣聞者以爲言坐是罷去余遊濡須而石猶在詢之邦人信然乃作此詩','周紫芝','宋','宋诗','song-poetry','','["\u957f\u6c5f"]','漫郎與世苦不偶，俶儻如公世安有。',176,'全唐诗/poet.song.87000.json','["漫郎與世苦不偶，俶儻如公世安有。", "平生學書筆似錐，晚歲得州大如斗。", "淮西道院長江邊，天公付與公高眠。", "使君閉閣作奇字，門前白浪春風顛。", "人言異石天所出，三十六峰如洞天。", "亟呼我兄更再拜，俗眼相看頗驚怪。", "喚錢作兄真可憐，喚石作兄無乃賢。", "望塵羅拜良可笑，米公拜石不同調。", "愚智相懸乃如此，何啻人間三十里。", "是非從古無公論，彼此相笑何時巳。", "巉巖對客初不言，堯桀紛紛渠自爾。"]'),
('214be5f2-9257-4b62-ae1d-db59c0fd673d','芍藥今歲着三花','周紫芝','宋','宋诗','song-poetry','','[]','春歸那肯爲儂留，尚有三花慰客愁。',32,'全唐诗/poet.song.87000.json','["春歸那肯爲儂留，尚有三花慰客愁。", "十里紅樓卷珠箔，不知誰在古揚州。"]'),
('2dc65c34-17ed-4354-94f2-bb4eff0cb168','羣山臺暮雨','周紫芝','宋','宋诗','song-poetry','','[]','傑觀凌寒江，朱欄俯平野。',156,'全唐诗/poet.song.87000.json','["傑觀凌寒江，朱欄俯平野。", "羣峰江上來，屹立羅萬馬。", "山容多態度，顯晦入模寫。", "朝雲結烟鬟，翠色遠相射。", "夜月横脩眉，娟娟亦閑雅。", "天生此尤物，政復爲閑者。", "馮夷翻怒濤，汹汹激風榭。", "神女亦將雲，時從楚臺下。", "造物出奇傑，娛客助揮灑。", "時方苦積潦，百里無十舍。", "我雖非官曹，對酒那忍把。", "人生急行樂，有味如啖蔗。", "悲喜有乘除，歸愁耿長夜。"]'),
('db8caac5-de03-4a30-8a8c-3e63b128b5ff','須江暮春雜題三首  其一','周紫芝','宋','宋诗','song-poetry','','[]','三月陰晴江上天，江花落盡水平川。',64,'全唐诗/poet.song.87000.json','["三月陰晴江上天，江花落盡水平川。", "紅蠶老去桑垂椹，黄鳥飛來柳撲綿。", "千里心常懸夢裏，十分春總在愁邊。", "時時更謝蘇司業，乞與杖頭沽酒錢。"]'),
('9a290d7e-0edd-4f9d-9fce-626b40a52669','須江暮春雜題三首  其二','周紫芝','宋','宋诗','song-poetry','','[]','須江舊事與誰論，萬古悠悠入夕曛。',64,'全唐诗/poet.song.87000.json','["須江舊事與誰論，萬古悠悠入夕曛。", "楚子名今推伍伯，阿瞞功獨蓋三分。", "空埋冶父山邊骨，已散濡須塢口軍。", "欲爲英雄弔遺跡，筆頭無古戰場文。"]'),
('a5a574e5-609c-4a62-9d49-b5a440226a6f','須江暮春雜題三首  其三','周紫芝','宋','宋诗','song-poetry','','[]','淮上風埃滿客衣，二年樓閣送斜暉。',64,'全唐诗/poet.song.87000.json','["淮上風埃滿客衣，二年樓閣送斜暉。", "心如落絮隨風去，春與殘花作伴歸。", "塞外夕烽悲鼓角，江邊飛雨濕旌旗。", "只今便覓東皋路，巳失南山種豆期。"]'),
('9e238063-4f25-42a2-a6ad-1e44700796e0','寓舍雜題三首  其一','周紫芝','宋','宋诗','song-poetry','','[]','久作乘風去，重尋聽雨眠。',48,'全唐诗/poet.song.87000.json','["久作乘風去，重尋聽雨眠。", "更無輕絮落，又見小荷圓。", "芍藥何人種，茂葵一笑妍。", "亂離歸未得，且復此經年。"]'),
('dfd3af54-b908-4481-957d-db26c8a22d37','寓舍雜題三首  其二','周紫芝','宋','宋诗','song-poetry','','[]','老去書中得，心因病後衰。',48,'全唐诗/poet.song.87000.json','["老去書中得，心因病後衰。", "栖栖身是夢，種種鬢成絲。", "鳥自知時節，人猶說亂離。", "倚樓天萬里，無地置吾錐。"]'),
('84b5c1c2-c4d5-40da-91a3-7f0db1ad6476','寓舍雜題三首  其三','周紫芝','宋','宋诗','song-poetry','','[]','客路猶飄泊，江山未定居。',48,'全唐诗/poet.song.87000.json','["客路猶飄泊，江山未定居。", "賣刀安得犢，彈鋏竟無魚。", "一飽非難事，平生不願餘。", "但能休旅枕，便可稅征車。"]'),
('e6d346c0-de18-4e65-894f-3f64ed1bf771','客舍有井極深而寒今歲大暑日汲以供盥濯喜甚賦此','周紫芝','宋','宋诗','song-poetry','','[]','重廊陰陰與天隔，下有井泉餘百尺。',208,'全唐诗/poet.song.87000.json','["重廊陰陰與天隔，下有井泉餘百尺。", "乍垂修綆已復寒，深注花甆不勝白。", "山城夏旱百井眢，盥濯從誰問涓滴。", "暮年來此看老黥，日倚銀床卷深碧。", "炎官火傘空自張，玉川清風已生腋。", "翰林醉熟呼不醒，宮中誰賦花娉婷。", "中人傳詔玉起立，井花吹面詩還成。", "詩成白雪真同調，咫尺回姿妃子笑。", "此郎自是醉謫仙，肯作官家詩待詔。", "北窗老子貪晝眠，蓬頭突鬢良可憐。", "但將飽睡答長健，安得新詩追昔年。", "我生無譽亦無毁，老去功名薄如紙。", "日向山堂洗睡容，空費君家一壺水。"]'),
('4790c5e9-c205-4ab0-9221-a7600d69ffcf','六月十二日過笑庵道人頗出近詩二首  其一','周紫芝','宋','宋诗','song-poetry','','[]','無人與作繡川遊，共看荷花一雨秋。',32,'全唐诗/poet.song.87000.json','["無人與作繡川遊，共看荷花一雨秋。", "乞得道人三昧句，破除千斛庾郎愁。"]'),
('1d077c1c-6ed1-4e6d-87c2-c3c3d876ae9f','六月十二日過笑庵道人頗出近詩二首  其二','周紫芝','宋','宋诗','song-poetry','','[]','來尋午枕林間夢，分得羲皇窗底風。',32,'全唐诗/poet.song.87000.json','["來尋午枕林間夢，分得羲皇窗底風。", "且與笑庵同一笑，不知家在大江東。"]'),
('ba88db8b-20b3-4f54-bfd9-8d9798ce7563','笑庵兩和前韻復作二絕  其一','周紫芝','宋','宋诗','song-poetry','','[]','莫把須江作浪遊，笑庵如水氣如秋。',32,'全唐诗/poet.song.87000.json','["莫把須江作浪遊，笑庵如水氣如秋。", "但知有道能忘我，便恐無天可寄愁。"]'),
('e50a0b1c-e616-45cd-b887-2811138e146c','笑庵兩和前韻復作二絕  其二','周紫芝','宋','宋诗','song-poetry','','[]','新詩時出笑談中，清似松江夜雨風。',32,'全唐诗/poet.song.87000.json','["新詩時出笑談中，清似松江夜雨風。", "邂逅碧雲來入句，老夫真欲愧遼東。"]'),
('9d06e3e7-a3e8-4d29-84d5-c1753f9559f9','徐使君送冰','周紫芝','宋','宋诗','song-poetry','','[]','江南地暖不藏雪，六月無冰破煩熱。',160,'全唐诗/poet.song.87000.json','["江南地暖不藏雪，六月無冰破煩熱。", "俱在炎官火傘中，暍死行人不堪說。", "今年渡江當入淮，淮人蔭子恰復開。", "眼明一見玉壺面，仿彿肺腑無塵埃。", "使君忽遣鈴下走，金盆分似來鈴齋。", "方圭圓璧不可數，玉峰中立高崔嵬。", "蔗漿退舍不入口，井花避席當停盃。", "我生坐甑安得此，借以清風亦聊爾。", "明年公復侍甘泉，御府分光照窗几。", "却憶敲冰餉野人，回望江城在千里。"]'),
('9bcb661d-ca16-4e94-94fc-89d1ab359e07','寓秀師房','周紫芝','宋','宋诗','song-poetry','','[]','寂寂疏窗秋更催，班班菊蘂爲誰開。',64,'全唐诗/poet.song.87000.json','["寂寂疏窗秋更催，班班菊蘂爲誰開。", "山曾有約終相負，鳥解嘲人怪復來。", "閱世了知心是夢，倒床須放鼻如雷。", "又從白足西庵老，共試齋餘雙井杯。"]'),
('056dff5e-07e8-45ad-9727-1e4f5784ce33','雨過凉甚','周紫芝','宋','宋诗','song-poetry','','[]','龍脚蜿蜒苦未收，亂雲攜雨過西州。',64,'全唐诗/poet.song.87000.json','["龍脚蜿蜒苦未收，亂雲攜雨過西州。", "倚欄斜日到烟樹，回首數星横夕樓。", "樂歲豈關羈客事，好風聊爲老人留。", "今宵枕簟凉如水，又向華胥作爛遊。"]'),
('263d10f6-a214-4b37-8b5e-474fa4dc042e','望黄山','周紫芝','宋','宋诗','song-poetry','','[]','宿雲忽解駁，曉色明朝暾。',180,'全唐诗/poet.song.87000.json','["宿雲忽解駁，曉色明朝暾。", "高秋寓遠目，萬象秋毫分。", "羣峰雜遝來，突騎從横奔。", "驊騮獨驤首，迥出凢馬羣。", "嵩高實維嶽，羅列如兒孫。", "玉京與金闕，亭亭在雲巒。", "羣仙驂蒼虬，冠珮朝至尊。", "往者風露夕，妙奏聞清圓。", "名理以絃歌，異事父老傳。", "丹成已仙去，流脈在山根。", "至今茲山下，幽泉湛餘温。", "安得從浴沂，聊以濯我冠。", "一沐去塵土，再沐生羽翰。", "朝遊參安期，暮躅追羡門。", "振足八荒外，垂手青雲端。"]'),
('a641da4c-ba3d-4395-b8e2-0185addb20f3','次韻鄭使君白菊','周紫芝','宋','宋诗','song-poetry','','[]','平生鄭康成，不種花嬋娟。',240,'全唐诗/poet.song.87000.json','["平生鄭康成，不種花嬋娟。", "但聞書带草，羅生滿堂前。", "佳菊苦解事，殷勤爲公妍。", "紅油護霜日，一笑真嫣然。", "秋風轉寒枝，束素爭回旋。", "團欒立芳砌，皎若璧月圓。", "使君頗牧手，年來出臨邊。", "燕衎自折衝，賓從時招延。", "苦愛白玉姿，臨風嗅芳鮮。", "揚州東閣梅，自此復誰憐。", "安得白雲詞，寫入朱絲絃。", "淵明眼獨醒，載酒知誰先。", "騷人茹精蘂，世塵聊自蠲。", "幽姿倏已空，二士窮益堅。", "人生五馬貴，行樂須何年。", "絕勝杜陵老，江花惱成顛。", "才名與富貴，似公真兩全。", "新詩如脫彈，一出萬口傳。", "鋒車行復來，琬琰殊未鐫。", "且當對香雪，燕寢凝沉箋。"]'),
('9b8b60f8-3f4c-4dc1-99ea-5182b2fe76fd','次韻遠猷旅夕二首  其一','周紫芝','宋','宋诗','song-poetry','','[]','西風滿眼莫登樓，回望鄉關去末由。',64,'全唐诗/poet.song.87000.json','["西風滿眼莫登樓，回望鄉關去末由。", "晚色不催金絡馬，夜燈空夢玉搔頭。", "梁王行識相如賦，楚國方悲宋玉秋。", "萬里長途知不晚，一杯聊爲老人留。"]'),
('debca870-20ef-4404-9aeb-008b84b2358d','次韻遠猷旅夕二首  其二','周紫芝','宋','宋诗','song-poetry','','[]','久占無何作醉鄉，人間萬事只逢場。',64,'全唐诗/poet.song.87000.json','["久占無何作醉鄉，人間萬事只逢場。", "潘郎已老謾華髪，夢得多情還斷腸。", "政恐新愁無處着，不知清夜爲誰長。", "煩君試草思歸曲，付與蛾眉小抑揚。"]'),
('745ad7fc-b6c8-4fe3-9673-1c61ff02e62d','王將軍以李伯時二馬遺張天民','周紫芝','宋','宋诗','song-poetry','','[]','龍眠筆意天與妙，尺素幻出雙驊騮。',156,'全唐诗/poet.song.87000.json','["龍眠筆意天與妙，尺素幻出雙驊騮。", "一馬不動尾，四蹄踣鐵邊風秋。", "一馬爭前趨，平坡欲下方回頭。", "兩馬交頸萬里愁，龍媒未免羈長秋。", "風鬃霧鬛不受囚，錦韀坐遣駑駘羞。", "將軍六郡良家子，卷送歸君深有意。", "蹶如歷塊一過都，使恐談笑無狂胡。", "人間豈有渥洼足，不與天驥爭長途。", "草黄沙晚天欲黑，縱有權奇少人識。", "眼中千里不易得，時危願爾一努力。"]'),
('90a7538f-1e23-409d-904b-044cc5d14285','須江雨中','周紫芝','宋','宋诗','song-poetry','','[]','須江樓上倚秋風，草樹荒凉故壘空。',32,'全唐诗/poet.song.87000.json','["須江樓上倚秋風，草樹荒凉故壘空。", "吹盡角聲人不見，畫橋和雨繫艨艟。"]'),
('e66e59f9-88d5-4610-9c1c-ef91d784b0f1','擇之得鹿割鮮見餉以詩爲謝','周紫芝','宋','宋诗','song-poetry','','[]','潘郎尉居巢，月止萬錢俸。',144,'全唐诗/poet.song.87000.json','["潘郎尉居巢，月止萬錢俸。", "遙憐寒孟郊，午食勤夜誦。", "空庖無雞豚，敢設亞父供。", "如何得伊尼，割鮮勤遠送。", "老夫極驚喜，兒曹亦嘲諷。", "憫我太常齋，此意君良重。", "饑腸罄一飽，狀若蹲鴟凍。", "茅簷坐局促，山禽聽曉哢。", "安得隨少年，短衣飛挽鞚。", "燒野得驚麋，即之那忍縱。", "呦呦寒聲微，麌麌一矢中。", "聊復從左盂，獵我江南夢。"]'),
('bceb36c9-5156-4958-940a-fa73ae5ac9ad','秋意三首  其一','周紫芝','宋','宋诗','song-poetry','','[]','雨細方淋露，雲疏欲護霜。',48,'全唐诗/poet.song.87000.json','["雨細方淋露，雲疏欲護霜。", "老情常落莫，秋物半青黄。", "榆塞弓窺月，天田馬犯疆。", "防城江上急，時節近重陽。"]'),
('9ab42f9c-4046-4345-bedd-b4237c19de66','秋意三首  其二','周紫芝','宋','宋诗','song-poetry','','[]','老去何曾健，秋來白髪新。',48,'全唐诗/poet.song.87000.json','["老去何曾健，秋來白髪新。", "萬方多難日，四海獨愁人。", "論愧傾三耳，年今已六身。", "太平猶眼見，知復幾青春。"]'),
('a9c6ffc3-5bc7-4447-99a8-ff1d9853d544','秋意三首  其三','周紫芝','宋','宋诗','song-poetry','','[]','病骨駸駸老，清愁日日深。',48,'全唐诗/poet.song.87000.json','["病骨駸駸老，清愁日日深。", "寒添青士節，霜與木奴金。", "跡共雲無定，愁隨月滿林。", "幽蟲泣床下，可是不知心。"]'),
('5c75b28c-5666-4897-b56b-87af9831c2be','次韻遠猷東池晚思','周紫芝','宋','宋诗','song-poetry','','[]','多事馮公子，含情不奈秋。',48,'全唐诗/poet.song.87000.json','["多事馮公子，含情不奈秋。", "東池寄飄泊，畫舫信夷猶。", "烽尚連三月，詩應擬四愁。", "且須傾酒椀，未可喚歸舟。"]'),
('e2dcc591-c88a-4586-b866-18f529b7f256','次韻元素見寄二首  其一','周紫芝','宋','宋诗','song-poetry','','[]','秋來烹鯉得明珠，頗勝當年獲異書。',64,'全唐诗/poet.song.87000.json','["秋來烹鯉得明珠，頗勝當年獲異書。", "里社相從真是伴，江湖作計未全疏。", "愁須强把樽中蟻，老亦寧思組上魚。", "回望花姑溪北墅，可能無路到華胥。"]'),
('c09585b8-2c3e-4819-9c0f-143a644d5f10','次韻元素見寄二首  其二','周紫芝','宋','宋诗','song-poetry','','[]','人間何處不蘧廬，匹馬來遊偶束書。',64,'全唐诗/poet.song.87000.json','["人間何處不蘧廬，匹馬來遊偶束書。", "晚歲光陰頻入夢，雁來消息莫相疏。", "淮南乘興非關米，筯下烹鮮喜有魚。", "避地偷生落閑處，功名無復似包胥。"]'),
('9e9b76f2-1445-4ed1-a669-a64dc3366ecb','次韻王彦猷參謀避胡山中寄茶字韻詩卷二首  其一','周紫芝','宋','宋诗','song-poetry','','[]','詩如摩詰自名家，未數劉顛賦雪車。',64,'全唐诗/poet.song.87000.json','["詩如摩詰自名家，未數劉顛賦雪車。", "問字誰攜子雲酒，敲門擬送玉川茶。", "回頭拾得風前句，掃地先除眼界花。", "老去無緣渾似夢，相隨真欲問毗邪。"]'),
('1cec5156-e56b-4d0b-9047-5d37133cb866','次韻王彦猷參謀避胡山中寄茶字韻詩卷二首  其二','周紫芝','宋','宋诗','song-poetry','','[]','扁舟流浪作浮家，病齒凋零脫左車。',64,'全唐诗/poet.song.87000.json','["扁舟流浪作浮家，病齒凋零脫左車。", "千里歸心秋後燕，一年春事雨前茶。", "它時我自開三徑，此去君當判六花。", "相見已還平日願，豚蹄何用祝汙邪。"]'),
('fa11e97f-f601-43e7-9cf5-f5b64a0e8851','繡溪秋晚二首  其一','周紫芝','宋','宋诗','song-poetry','','[]','羈客三年別，風裘九月寒。',48,'全唐诗/poet.song.87000.json','["羈客三年別，風裘九月寒。", "暮鴉啼日落，紅葉墜霜乾。", "地接淮山遠，天浮楚服寛。", "須江無父老，舊事說曹瞞。"]'),
('36108e0a-6ae7-4384-a217-192c8bd0cc34','繡溪秋晚二首  其二','周紫芝','宋','宋诗','song-poetry','','[]','不作黄花夢，空悲紫塞秋。',48,'全唐诗/poet.song.87000.json','["不作黄花夢，空悲紫塞秋。", "淚懸江上點，心結雨邊愁。", "久客猶千里，殘年念一邱。", "倚欄多少恨，暝色滿江樓。"]'),
('b2b6d5d4-0dbc-4c55-8a5c-ee79607c4f21','歷陽道中二絕  其一','周紫芝','宋','宋诗','song-poetry','','[]','斜照孤村一水閑，維舟盡日柳陰間。',32,'全唐诗/poet.song.87000.json','["斜照孤村一水閑，維舟盡日柳陰間。", "此生已作淮西夢，更看江南隔岸山。"]'),
('a89c412b-2163-4efb-8001-fb4322114339','歷陽道中二絕  其二','周紫芝','宋','宋诗','song-poetry','','[]','江邊孤壘古濡須，憔悴斯民百戰餘。',32,'全唐诗/poet.song.87000.json','["江邊孤壘古濡須，憔悴斯民百戰餘。", "賴有豐年慰羈客，軟炊雲子薦鱸魚。"]'),
('63b9726c-d897-4c52-a364-f90937a83ec4','將别須江作','周紫芝','宋','宋诗','song-poetry','','[]','落葉江頭楓樹枝，秋風又入去年衣。',64,'全唐诗/poet.song.87000.json','["落葉江頭楓樹枝，秋風又入去年衣。", "淮南米賤聊乘興，笠澤魚肥却念歸。", "老境但知隨物化，幽期常恐與心違。", "羣山堂下山干點，不見祠雲作雨飛。"]'),
('be0ec6be-0b88-49f2-8dfb-cdcead3e2c99','九日郡樓獨坐','周紫芝','宋','宋诗','song-poetry','','[]','西風斜日可憐秋，已作重陽更上樓。',64,'全唐诗/poet.song.87000.json','["西風斜日可憐秋，已作重陽更上樓。", "門外白衣來獨晚，坐中司馬醉應休。", "茱茰香在人何處，黄菊花開淚欲流。", "山意娛人不勝好，苦無佳句若爲酬。"]'),
('c16c36e4-9203-4e25-be0b-6d7c0fd7da02','過雨二首  其一','周紫芝','宋','宋诗','song-poetry','','[]','短日收殘雨，西風送夕陽。',48,'全唐诗/poet.song.87000.json','["短日收殘雨，西風送夕陽。", "時光雙去鳥，世事一炊粱。", "卷箔山堆案，翻書月滿囊。", "諸君方給札，不擬獻長楊。"]'),
('57fe5fdc-4044-40b7-b1fc-470e0a963836','過雨二首  其二','周紫芝','宋','宋诗','song-poetry','','[]','自落山邊日，孤飛雨後雲。',48,'全唐诗/poet.song.87000.json','["自落山邊日，孤飛雨後雲。", "樹將風報客，天遣月爭曛。", "詩苦窮堪忍，胡强老怕聞。", "殘更隨夢盡，長日與愁分。"]'),
('7961989e-bd8a-4ddb-b793-fb8e3c57b948','次韻黄子才野步飯懷禪師道場','周紫芝','宋','宋诗','song-poetry','','[]','聞說尋山屐，閑穿近郭村。',156,'全唐诗/poet.song.87000.json','["聞說尋山屐，閑穿近郭村。", "眼明山淨綠，心愛水清喧。", "幽事付餘日，狂歌終放言。", "地經殊代遠，名爲老僧存。", "境勝醒朝梵，蔬甘飽夕飱。", "僧應只靈運，客或是文園。", "覓句聞吳詠，投文弔楚魂。", "夢時驚遠籟，背喜曝微暾。", "歷井窺雲窟，窮山繞石根。", "蹇驢當復跨，促席未容温。", "兒輩休嗤點，吾曹自引援。", "濁醪聊共把，蠧簡付重論。", "歸和山中句，挑燈老眼昏。"]'),
('0a190309-82f3-4009-b473-82fb0cb18724','十六夜月色甚明與客棹舟至普寧寺','周紫芝','宋','宋诗','song-poetry','','[]','昨宵明月共千里，今夕極天無一雲。',160,'全唐诗/poet.song.87000.json','["昨宵明月共千里，今夕極天無一雲。", "不知誰令太虚空，着此皎皎白玉盆。", "長空與月慰愁眼，良夜得酒含微醺。", "天公有約不可負，急蕩兩槳凌江濆。", "更攜江上滿船月，來打寺下三更門。", "脩廊夜寂風葉亂，古佛不語殘膏存。", "老禪今夕但拍手，狂客數輩空餘樽。", "高談劇語天亦怒，白璧故遣雲相吞。", "人言禍福真倚伏，歡常有餘飲不足。", "篙師促客歸去來，夜半風顛浪如屋。"]'),
('7e5ef712-485f-495f-8c7e-2ce0835550b6','朝盤二首  其一','周紫芝','宋','宋诗','song-poetry','','[]','郭索何人捕草泥，朝盤新見玉團臍。',32,'全唐诗/poet.song.87000.json','["郭索何人捕草泥，朝盤新見玉團臍。", "却思烟雨江南夜，紅火青蓑入稻畦。"]'),
('c340ebc1-a433-4cea-9e95-665d3c2a5017','朝盤二首  其二','周紫芝','宋','宋诗','song-poetry','','[]','江近秋深足鱠材，半青橙子带香開。',32,'全唐诗/poet.song.87000.json','["江近秋深足鱠材，半青橙子带香開。", "黄金鱗鬛丹砂尾，落紙看成白雪堆。"]'),
('ff4d9b53-5621-4534-9121-8c24c08ffd3b','磚爐','周紫芝','宋','宋诗','song-poetry','','[]','秋風吹孤鴻，浩蕩去鄉國。',120,'全唐诗/poet.song.87000.json','["秋風吹孤鴻，浩蕩去鄉國。", "心悲淮山秋，家近楚江側。", "囊無狐白裘，奈此風雨夕。", "經營尺寸地，便可寄幽寂。", "磚爐規舊製，蒲團買新織。", "雖無琢獸紅，可醉珠履客。", "會當與狸奴，曲肱分坐席。", "急雪度寒飇，夜窗鳴淅瀝。", "詩成几醉夢，殘缸耿虚壁。", "何必遊八關，吾手自可炙。"]'),
('12300f4f-11f8-42f5-958e-2380b5b6afa3','山鬼行','周紫芝','宋','宋诗','song-poetry','','[]','黑風夜度鶖鶬高，黄狐出窟山鬼號。',64,'全唐诗/poet.song.87000.json','["黑風夜度鶖鶬高，黄狐出窟山鬼號。", "江空人靜雪飛急，城頭擊柝催鳴刁。", "老翁愁寒小兒哭，薪如黄金米如玉。", "將軍半醉獵城南，鐵馬敲冰響山谷。"]'),
('f5ddbc13-df39-4653-b67a-cd6008a83e71','次韻明叔九日見懷','周紫芝','宋','宋诗','song-poetry','','[]','準擬重陽共一杯，幅巾臨水復登臺。',64,'全唐诗/poet.song.87000.json','["準擬重陽共一杯，幅巾臨水復登臺。", "飛花撲面君相送，落葉滿山人未回。", "故國只憑幽夢到，斷腸頻寄尺書來。", "此生終向江湖老，黄菊紅茰笑謾催。"]'),
('3540a198-7264-4609-ab49-07b978b8a00b','十月十九日江晴放舟','周紫芝','宋','宋诗','song-poetry','','[]','雲静天無滓，霜晴日乍暄。',48,'全唐诗/poet.song.87000.json','["雲静天無滓，霜晴日乍暄。", "風平初放纜，江穩自流船。", "賈客眠吹笛，篙工坐意錢。", "吾行聊爾爾，百丈莫頻牽。"]'),
('2fdf6d7c-078f-4973-81dc-9c8fbca7e945','雪後殊未有梅頗懷故山二首  其一','周紫芝','宋','宋诗','song-poetry','','[]','淮山落莫水蒼茫，雪在梅梢冷欲僵。',32,'全唐诗/poet.song.87000.json','["淮山落莫水蒼茫，雪在梅梢冷欲僵。", "要與玉奴蘇凍骨，不知誰有反魂香。"]'),
('07e086fe-8619-4769-8eb9-b35e30b38fcf','雪後殊未有梅頗懷故山二首  其二','周紫芝','宋','宋诗','song-poetry','','[]','真色生香無世塵，參横猶記夢回人。',32,'全唐诗/poet.song.87000.json','["真色生香無世塵，參横猶記夢回人。", "風前懊惱梅花使，不寄江南一點春。"]'),
('6beb5f96-05a9-40e3-bea8-952ce4cba823','王靜翁言客有賦食虎肉詩者詞甚壯要余同作','周紫芝','宋','宋诗','song-poetry','','[]','六郡良家家好武，相試翹關來征虜。',128,'全唐诗/poet.song.87000.json','["六郡良家家好武，相試翹關來征虜。", "夜從惡少數十輩，醉上南山縛驍虎。", "短衣匹馬不挽强，虎而有翼誰敢當。", "旁觀睥睨方縮手，一臠割鮮君巳嘗。", "平生飲血如甘露，羞作車中三日婦。", "但當一飽不搖喉，誰說萬錢難下箸。", "寝皮食肉君勿嗔，虎爲人害當復去。", "可笑長楊射獵兒，日暮歸來數狐兔。"]'),
('e0e9891c-a4a8-4fa9-95e6-6fa089b575c6','次韻黄子才冬至日醉臥王丞家夢還家如平時','周紫芝','宋','宋诗','song-poetry','','[]','黄郎本天才，驥足尚少屈。',180,'全唐诗/poet.song.87000.json','["黄郎本天才，驥足尚少屈。", "平生嗜烟霞，投老成痼疾。", "乞食方叩門，攜幼未入室。", "何爲作斯遊，瘦馬醉自兀。", "朝饑乃見驅，妙思何由逸。", "誦君思歸吟，感我羈旅日。", "道塗頗風埃，歲月苦飄忽。", "尚須營一飽，不愁屈兩膝。", "可憐蓬閣姿，未珥螭頭筆。", "丞哉苦風流，威令寛且栗。", "懸知千里駒，肯爲牢之出。", "胡爲倚寒窗，清夢恍若失。", "但愁一線紅，又過白駒隙。", "婦眉誰與畫，旅髪歸亦櫛。", "吚嚶兒女歡，餘事聽造物。"]'),
('c06b9dbb-f346-440a-9ffa-b90a66e63b2d','次韻趙茂卿書事','周紫芝','宋','宋诗','song-poetry','','[]','自昔人高馬服名，胸中有策似金城。',64,'全唐诗/poet.song.87000.json','["自昔人高馬服名，胸中有策似金城。", "玉階方寸何由借，榆塞風塵幾日清。", "萬里有家無夢到，一樽和淚與誰傾。", "竹西回首揚州路，腸斷故園春草生。"]'),
('625cdd94-8ec0-4a68-ac02-282738013582','王彦猷用色字韻見貽和答','周紫芝','宋','宋诗','song-poetry','','[]','人生殊用舍，初不繫失得。',96,'全唐诗/poet.song.87000.json','["人生殊用舍，初不繫失得。", "念君垂天鵬，未作六月息。", "佳人絕代姿，蛾眉本傾國。", "人皆倚市門，孰乃有國色。", "風雲倘復遇，富貴或見逼。", "一朝得天驥，遂可空冀北。", "况今登俊良，百吏歸黜陟。", "洗眼看横飛，故山勿輕憶。"]'),
('f2f717c4-fc8d-4535-9b73-e8c217b8c092','冶父寺','周紫芝','宋','宋诗','song-poetry','','[]','楚俗樂戰鬬，征誅專莫敖。',168,'全唐诗/poet.song.87000.json','["楚俗樂戰鬬，征誅專莫敖。", "蛇豕肆吞噬，一舉夷蒲騷。", "小器良易盈，舉趾凌雲霄。", "輕敵取敗衂，縊死由矜驕。", "淺識恥鄧曼，安在誇雄豪。", "至今冶父山，遺跡真寥寥。", "何年化龍宮，金碧爭岧嶤。", "耽耽羣於菟，跪伏尾自搖。", "乃知道力妙，智數何能高。", "曩者羅與楚，蟻忿較一朝。", "慈哀洗萬劫，自足消兵刀。", "道人結界地，遠引離喧囂。", "欲禮大士塔，恨無野僧包。", "臨風一悵望，短髪空爬搔。"]'),
('d1897be0-63e3-4f85-978e-aa7921c868b0','賈主簿家蠟梅','周紫芝','宋','宋诗','song-poetry','','[]','臘月邊城風雨沙，带香誰剪蠟梅花。',32,'全唐诗/poet.song.87000.json','["臘月邊城風雨沙，带香誰剪蠟梅花。", "寒燈枉作江南夢，春在牆東主簿家。"]'),
('a62d702a-18e3-4fb9-8f18-e851c8bbd070','僕將南歸笑庵以詩見留次韻','周紫芝','宋','宋诗','song-poetry','','[]','思家一日似三秋，病眼凄然怯上樓。',64,'全唐诗/poet.song.87000.json','["思家一日似三秋，病眼凄然怯上樓。", "十幅風蒲催我去，數枝烟竹爲君留。", "還將曉枕燈前句，分作孤蓬雨後愁。", "便合北來尋老伴，人間何處有湯休。"]'),
('2ecd7556-4498-4340-aead-2f57775093ed','掛席','周紫芝','宋','宋诗','song-poetry','','[]','掛席下晴江，歸從我北窗。',48,'全唐诗/poet.song.87000.json','["掛席下晴江，歸從我北窗。", "年今真晼晚，事亦付奇厖。", "酒可澆腸飲，胡誰緩頰降。", "買田如有路，誓欲老吾邦。"]'),
('ccc90507-d230-4c65-9d2d-0b8e7b1ce5ce','歸自須江泊舟于湖舟中書事','周紫芝','宋','宋诗','song-poetry','','[]','一自胡塵起，飄零十載過。',216,'全唐诗/poet.song.87000.json','["一自胡塵起，飄零十載過。", "危情窘荆棘，老眼暗干戈。", "草草真聊爾，栖栖可奈何。", "功名麟閣晚，興在鹿門多。", "避地依淮浦，傷心聽楚歌。", "邊烽明夕嶠，戍鼓擊寒波。", "江控曹公塢，山連冶父坡。", "憑高懷更遠，弔古事應訛。", "久客横歸棹，長年着短蓑。", "風高飽帆腹，潮稳轉山阿。", "漸喜鄉音似，還成醉臉酡。", "凄凉想茅屋，留滯厭江沱。", "井邑疏星火，津亭長薜蘿。", "連檣自來往，壞壁本嵳峨。", "蜂目今何在，黄鬚跡巳磨。", "餘生能幾屐，急景付飛梭。", "歲熟如堪隱，詩成可自哦。", "平生南畝願，無地與婆娑。"]'),
('5fec8e81-4f3a-4d0c-8382-aca0ce82c60d','復故廬一首','周紫芝','宋','宋诗','song-poetry','','[]','我卜我居，於城之隅。',170,'全唐诗/poet.song.87000.json','["我卜我居，於城之隅。", "繚以羣山，带以清渠。", "日出扶桑，月翳金樞。", "朝雲夕烟，變滅卷舒。", "喬木豐草，蔚其周廬。", "羣書在床，濁酒在壺。", "蹣跚簪裾，亦復晏如。", "淮水之遊，誰脂我車。", "逮其歸而，四壁其徒。", "柔柯既剪，稚竹日疏。", "山爲改容，木爲槁枯。", "吾亦浩然，言念歸與。", "今我來思，爲之躊躇。", "扊扅在門，鞿靮在塗。", "駕言曷歸，杜門寔娛。", "寒止皸瘃，饑止瘠臞。", "人誰不死，焉識其餘。"]'),
('b595335f-e2d3-4393-a84b-4920b712dbca','雪後留報恩方丈三絕  其一','周紫芝','宋','宋诗','song-poetry','','[]','文脊坊邊雪作堆，報恩溪上凍全開。',32,'全唐诗/poet.song.87000.json','["文脊坊邊雪作堆，報恩溪上凍全開。", "一天雲葉卷風去，四面玉峰攢馬來。"]'),
('3423f542-7b22-42e5-9778-d70d9493d497','雪後留報恩方丈三絕  其二','周紫芝','宋','宋诗','song-poetry','','[]','澆睡莫教茶乳薄，留香不放畫簾開。',32,'全唐诗/poet.song.87000.json','["澆睡莫教茶乳薄，留香不放畫簾開。", "道人知我無餘事，特爲尋詩借榻來。"]'),
('cb4ea21e-1491-4eee-877d-2fecb95b49f3','雪後留報恩方丈三絕  其三','周紫芝','宋','宋诗','song-poetry','','[]','老禪心地已如灰，愁眼能令一笑開。',32,'全唐诗/poet.song.87000.json','["老禪心地已如灰，愁眼能令一笑開。", "落日無情且歸去，梅花若在却須來。"]'),
('ffa2c147-1b38-42cc-8c8b-ab52c68373d2','張元明羅仲共賦郡池白蓮僕時在淮西十二月中休方德脩始出巨軸追和','周紫芝','宋','宋诗','song-poetry','','["\u5e90\u5c71"]','花似當時傅粉郎，不須湯餅試新粧。',64,'全唐诗/poet.song.87000.json','["花似當時傅粉郎，不須湯餅試新粧。", "固知桃李無國色，猶恐蘭蓀是俗香。", "人在匡廬新結社，詩傳淮楚夢還鄉。", "波沉不見香羅襪，空向牛腰得夜光。"]'),
('53dc09b4-1117-4df5-8a0c-ca005475f660','送舜卿遊建昌','周紫芝','宋','宋诗','song-poetry','','[]','并門當日倚長城，笑遣妖兇卷旆旌。',64,'全唐诗/poet.song.87000.json','["并門當日倚長城，笑遣妖兇卷旆旌。", "江上長鯨知巳滅，草中封豕不勞平。", "十年當念瘡痍苦，此日寧論戰伐名。", "虎帳夜談資婉畫，爲言奇策是休兵。"]'),
('448eeac3-da9d-4717-96a5-fa5c94ce83c9','官軍屢捷淮寇漸平五首  其一','周紫芝','宋','宋诗','song-poetry','','[]','北來驍虜盡成禽，九廟行聞奏凱音。',32,'全唐诗/poet.song.87000.json','["北來驍虜盡成禽，九廟行聞奏凱音。", "從此燕齊如振槁，將軍勳業似淮陰。"]'),
('fa2db579-fa62-45f8-bca9-b8fabde34dd7','官軍屢捷淮寇漸平五首  其二','周紫芝','宋','宋诗','song-poetry','','[]','擁道行人撥不開，檻車行看縛戎魁。',32,'全唐诗/poet.song.87000.json','["擁道行人撥不開，檻車行看縛戎魁。", "羽書便恐椎門入，知是淮陰露布來。"]'),
('bcbfd290-157d-48db-b227-614c8fdfc2d9','官軍屢捷淮寇漸平五首  其三','周紫芝','宋','宋诗','song-poetry','','[]','風聲鶴唳是王師，大似秦苻欲破時。',32,'全唐诗/poet.song.87000.json','["風聲鶴唳是王師，大似秦苻欲破時。", "黄屋乍聞天一笑，此歡應有近臣知。"]'),
('dcf0b23e-d5a9-4dc7-90fb-18a635f9bc7b','官軍屢捷淮寇漸平五首  其四','周紫芝','宋','宋诗','song-poetry','','[]','棗熟梨黄河朔秋，頗聞箕斂不勝愁。',32,'全唐诗/poet.song.87000.json','["棗熟梨黄河朔秋，頗聞箕斂不勝愁。", "迎師已欲攜簞食，臠炙何勞費萬牛。"]'),
('7f8a5da0-901f-4ebd-9100-7592e4f33b06','官軍屢捷淮寇漸平五首  其五','周紫芝','宋','宋诗','song-poetry','','[]','新得降番壤地開，玉觴爭奉萬年杯。',32,'全唐诗/poet.song.87000.json','["新得降番壤地開，玉觴爭奉萬年杯。", "明年御棗紅千顆，又見青徐入貢來。"]'),
('2029a562-4285-46aa-9bb7-dc55204fbb89','立春日聞捷','周紫芝','宋','宋诗','song-poetry','','[]','未獻椒花頌，先頒鳳曆春。',48,'全唐诗/poet.song.87000.json','["未獻椒花頌，先頒鳳曆春。", "亞釵雙燕小，垂鬢綵幡勻。", "兵已知胡遠，歡應與歲新。", "遙聞漢天子，喜色動中宸。"]'),
('8fcdfea9-3522-49f8-b680-a2320c303f6c','題李彦恢家龍眠七馬圖','周紫芝','宋','宋诗','song-poetry','','[]','古來畫馬知幾人，當時只數曹將軍。',176,'全唐诗/poet.song.87000.json','["古來畫馬知幾人，當時只數曹將軍。", "龍媒貎得照夜白，七十萬匹空雲屯。", "但令韓幹作弟子，未許韋偃窺藩垣。", "風流掃地五百載，始得龍眠空馬羣。", "龍眠自是天下士，胸中元有真騏驎。", "寧王玉面久不見，風騣霧鬛驚猶存。", "四蹄翻風不受縶，意在萬里絕馳奔。", "安能局促鹽車下，更與蹇驢分短轅。", "先生既老誰入室，後來只數城南孫。", "孫郎繼死骨又朽，人間此馬如浮雲。", "勸君掩卷勿浪出，世無九方誰與論。"]'),
('93adb0b2-643b-43b7-b656-f302a4dfe7da','題彦恢家仇池四石刻','周紫芝','宋','宋诗','song-poetry','','[]','伏波南來自交趾，可笑汗牛推薏苡。',179,'全唐诗/poet.song.87000.json','["伏波南來自交趾，可笑汗牛推薏苡。", "人言包裹足珠犀，誰識閑身謝簪履。", "如何當年元相國，胸中飽飲貪泉水。", "胡椒八百亦安用，坐此殺生真可鄙。", "龍眠主簿亦兒嬉，銀鈎蠆尾搜遺奇。", "三年獨有一錢在，歸來清節人皆知。", "囊空安得紫絲帳，車重只餘黄絹碑。", "自言所至輒寓目，窮搜屋壁翻階墀。", "不嫌尤物觸時禁，恍然入手心驚疑。", "君不見嶧山篆刻焚野火，磨崖萬仞高崔嵬。", "何如四石横棐几，左提右挈行相隨。"]'),
('1e3241b8-75fe-4bdf-98ec-28dd3f34d7ad','正月十五日同圓明老師渡谿西雨作不可回三絕  其一','周紫芝','宋','宋诗','song-poetry','','[]','伴師同拄一枝藤，野岸凌兢踏斷冰。',32,'全唐诗/poet.song.87000.json','["伴師同拄一枝藤，野岸凌兢踏斷冰。", "老去莫辜元夜眼，試憑江閣看漁燈。"]'),
('eb9e54b6-d767-4656-ac9a-7eaab77decd6','正月十五日同圓明老師渡谿西雨作不可回三絕  其二','周紫芝','宋','宋诗','song-poetry','','[]','舊時好客孔文舉，無事長隨支道林。',32,'全唐诗/poet.song.87000.json','["舊時好客孔文舉，無事長隨支道林。", "燈夜羞歸對妻子，傳柑知我已無心。"]'),
('09c8c618-a748-44a9-92cf-16bbdd7a941c','正月十五日同圓明老師渡谿西雨作不可回三絕  其三','周紫芝','宋','宋诗','song-poetry','','[]','一别風塵客恨長，鳯城燈燭記微茫。',32,'全唐诗/poet.song.87000.json','["一别風塵客恨長，鳯城燈燭記微茫。", "人生相見知何定，夜雨重來此對床。"]'),
('c579f23d-65f4-48e0-ba3f-c16e45a47606','次韻和答圓明老師二首  其一','周紫芝','宋','宋诗','song-poetry','','[]','平生作劇謾逢場，枘鑿由來苦未當。',64,'全唐诗/poet.song.87000.json','["平生作劇謾逢場，枘鑿由來苦未當。", "笑我彈冠方適越，看誰紉佩獨沉湘。", "捧心政恐元非病，怒臂前知不自量。", "它日小松山下路，合分風月與徜徉。"]'),
('e5a9e209-12ac-4102-afb5-3bcac2c64781','次韻和答圓明老師二首  其二','周紫芝','宋','宋诗','song-poetry','','[]','回首雲庵日又低，孤帆欲渡晚風吹。',64,'全唐诗/poet.song.87000.json','["回首雲庵日又低，孤帆欲渡晚風吹。", "桃花水暖拍隄去，蓮葉舟輕隨棹移。", "老罷轉知身是夢，愁來只有鬢成絲。", "人間無地安雙足，萬事從頭愧老師。"]'),
('203f6f3d-a466-49a8-9e40-41bf6a813ec6','次韻元素賦余新居','周紫芝','宋','宋诗','song-poetry','','[]','一樽能此共窺臨，草色凄迷步履深。',64,'全唐诗/poet.song.87000.json','["一樽能此共窺臨，草色凄迷步履深。", "黄帽青鞋聊偃蹇，白衣蒼狗自浮沉。", "瓮頭酒熟須同把，窗下詩成亦共吟。", "待得吾廬真可愛，更須繞屋樹成陰。"]'),
('72e1670b-6d86-486d-af4d-fb954a81f1e0','元素再邀同賦','周紫芝','宋','宋诗','song-poetry','','[]','載酒何人肯見臨，情於老伴莫嫌深。',64,'全唐诗/poet.song.87000.json','["載酒何人肯見臨，情於老伴莫嫌深。", "誦君詞賦疑仙去，笑我功名付陸沉。", "且可閉門留客飲，不知擁膝是誰吟。", "幅巾趁取春猶在，來聽黄鸝喚午陰。"]'),
('de4be53f-5022-44fb-82b6-982e9f308ff4','元素再邀同賦','周紫芝','宋','宋诗','song-poetry','','[]','家住三峰頗下臨，畏人小築不辭深。',64,'全唐诗/poet.song.87000.json','["家住三峰頗下臨，畏人小築不辭深。", "南齊謝老樓空在，東海麻姑信已沉。", "恨子不當青瑣闥，伴人猶作白頭吟。", "我窮無物能娛客，只有蒼梧滿地陰。"]'),
('cc63fc6d-9e7b-4a88-80fe-e99e36d6cb10','望故廬一首','周紫芝','宋','宋诗','song-poetry','','[]','龜城去江，邈在一隅。',170,'全唐诗/poet.song.87000.json','["龜城去江，邈在一隅。", "我家龜舫，亦足軒渠。", "草耕木茹，瓮牖蓬樞。", "有客二人，寔邀望舒。", "長鬚之奴，玉川之廬。", "何必仙去，方丈蓬壺。", "何必校書，起居何如。", "無禍爲福，徐行當車。", "我乎誰交，誰乎我徒。", "春蛙嘈雜，夏木扶疏。", "大盗遽起，山摧海枯。", "我焚其巢，將焉適歟。", "善刀而藏，爲之踟蹰。", "望我故處，宛其在塗。", "我友云亡，云誰與娛。", "願洗甲兵，肉四海臞。", "奠我新宅，以飽三餘。"]'),
('1f31da8d-ee25-4d66-b828-931fe2d7fbd0','次韻趙戒叔燈下見榴花明日重午','周紫芝','宋','宋诗','song-poetry','','[]','醉帽風前著，榴花燭下看。',48,'全唐诗/poet.song.87000.json','["醉帽風前著，榴花燭下看。", "嫣妍爲誰好，流落未妨歡。", "故國應千里，歸塗夢百盤。", "明朝是重午，努力願加餐。"]'),
('d8e44ff3-a2a1-47e2-aee0-c9660bd1ced9','次韻戒叔增明閣晚眺','周紫芝','宋','宋诗','song-poetry','','[]','朱閣瞰流水，曲欄横晚天。',48,'全唐诗/poet.song.87000.json','["朱閣瞰流水，曲欄横晚天。", "薄雲初過雨，高柳却鳴蟬。", "杖履且終日，風塵今幾年。", "莫將懐遠句，重說舊林泉。"]'),
('9adc542e-f31b-4fb6-8661-890188160657','劉公祠','周紫芝','宋','宋诗','song-poetry','','[]','昔歲金胡始南渡，官軍夜遁如脫兔。',112,'全唐诗/poet.song.87000.json','["昔歲金胡始南渡，官軍夜遁如脫兔。", "孤城何啻累卵危，賊至不殊羣蟻附。", "夜提王師來解圍，燕中老將如猛虎。", "平明横槊屬兩鞬，疋馬馳從賊營去。", "崢嶸但見虜可擒，倉卒不知身已仆。", "平生三箭得天山，白骨看成一丘土。", "馬前班劍不動塵，猶勝車中三日婦。"]'),
('563ca4e3-dd3f-476c-ac33-8512a999f107','送江子','周紫芝','宋','宋诗','song-poetry','','[]','六朝固陵夷，佳士亦間出。',156,'全唐诗/poet.song.87000.json','["六朝固陵夷，佳士亦間出。", "風流數後來，諸江有人物。", "總持偉文采，文通頗超越。", "清忠若休映，對賊能抵突。", "定知蘇屬國，不爲延明屈。", "斯人黄卷中，願見未可必。", "誰知有來雲，遂入諸子室。", "相從忽三年，不見無十日。", "人生會相别，此别殊慘慄。", "相望渺江湖，時危盗如櫛。", "願言加餐飯，栖遲且蓬蓽。", "時來亦騰騫，安用苦密勿。", "尺素倘可通，公當念伊鬰。"]'),
('a5334841-8597-4c64-a154-1f41fc37a55f','次韻聖謨見寄二首  其一','周紫芝','宋','宋诗','song-poetry','','[]','十年悲兩京，萬騎開幕府。',60,'全唐诗/poet.song.87000.json','["十年悲兩京，萬騎開幕府。", "誰知鹿門翁，遠引脫罪罟。", "吾衰固安用，文字考前古。", "尚煩金蘭交，弔此饑寒苦。", "龐公不可見，賤子何足取。"]'),
('6b9a6074-2546-4ba5-ba03-196cf260b3a7','次韻聖謨見寄二首  其二','周紫芝','宋','宋诗','song-poetry','','[]','青衫幾痴兒，歛版上公府。',60,'全唐诗/poet.song.87000.json','["青衫幾痴兒，歛版上公府。", "固應横海鯨，不可汙池罟。", "高才乏近用，初不異今古。", "功名亦偶然，慘戚良自苦。", "富貴如公等，唾手自可取。"]'),
('deeb9bae-5d04-4f07-98ba-2123fbfa738b','次韻木南稀見贈','周紫芝','宋','宋诗','song-poetry','','[]','上章分得鑑湖春，賀老前身恐是君。',64,'全唐诗/poet.song.87000.json','["上章分得鑑湖春，賀老前身恐是君。", "常病薫蕕難共器，豈容雞鶩可同羣。", "已無若若纍纍意，頗坐奇奇怪怪文。", "稍許白頭親杖履，少年功業付終軍。"]'),
('508f5c56-ce8f-40b3-832e-fbfbc5464826','蠧魚','周紫芝','宋','宋诗','song-poetry','','[]','山堂夜雨如決渠，黄梅半熟書生魚。',130,'全唐诗/poet.song.87000.json','["山堂夜雨如決渠，黄梅半熟書生魚。", "樹頭朝日忽復出，聊向空階翻故書。", "老人耕鑿無膏腴，緗囊細字時相娛。", "自欣引睡得黄嬭，便恐無意呼青奴。", "讀書本不求甚解，姓名足記知有餘。", "此蟲何乃徒飽腹，死葬書葉真痴愚。", "不如化作石帆山下蠒，織成吳綾光滿眼。", "乞與袁娘作舞衣，常把花枝侍君輦。"]'),
('3020fe7b-c539-4ad5-ae33-b94726283846','西齋聞禽','周紫芝','宋','宋诗','song-poetry','','[]','西齋草樹頗蒙密，竹暗城頭不通日。',160,'全唐诗/poet.song.87000.json','["西齋草樹頗蒙密，竹暗城頭不通日。", "風晴高柳恰飛綿，花盡黄蜂未成蜜。", "北窗也復可憐人，亂離十載空傷神。", "病對青山疑是夢，眼驚新綠已無春。", "羈懷有句喑不吐，終日無言聞鳥語。", "寒窗窈窕不嫌風，晚色溟濛却宜雨。", "穿條隔葉止復啼，白粉畫眉金作羽。", "應爲山翁久慣聽，聽久不知心轉苦。", "廟堂何日議銷兵，攜手尚堪歸樂土。", "還我花姑溪上椽，臥聽春禽囀桃塢。"]'),
('bb0aa58f-e808-4396-a8ab-7ed23e3c6535','五月二十九日對雨懷舊','周紫芝','宋','宋诗','song-poetry','','[]','危坐東窗日自長，幽人不出雨何妨。',64,'全唐诗/poet.song.87000.json','["危坐東窗日自長，幽人不出雨何妨。", "未論飽飯三秋樂，且說高眠一枕凉。", "晴後却疑猶點滴，夜深應是更淋浪。", "此聲有味知誰解，安得君來與對床。"]'),
('a958dbd4-75a4-47c3-a6a1-c8cd1af543c8','余既作前詩已而復晴客有誦余舊詩者其略云開門更待西南月無客來分上下牀聞之恍然如夢中語漫不省記爲何詩也乃和前篇以足之','周紫芝','宋','宋诗','song-poetry','','[]','貧共閑身味轉長，雨随農事不相妨。',64,'全唐诗/poet.song.87000.json','["貧共閑身味轉長，雨随農事不相妨。", "莫嫌旅枕喧朝夢，要與書檠作夜涼。", "黄犢催耕思莽蒼，短蓑垂釣念滄浪。", "開門更待西南月，無客來分上下床。"]'),
('64994ec5-7a46-4b9d-b140-fbe5bb2dfe85','後二日望東南大雨久之白龍翔於雲間掉尾而上老農云白龍見則旱祥也','周紫芝','宋','宋诗','song-poetry','','[]','白晝鈎簾望處長，初於眼界了無妨。',64,'全唐诗/poet.song.87000.json','["白晝鈎簾望處長，初於眼界了無妨。", "坐看雲嶺埋烟雨，聊借西軒作晚凉。", "卷水翔龍方矯矯，轉山飛瀑更浪浪。", "豐凶許事誰能問，獨對殘書月滿床。"]'),
('8d909175-86c8-4d75-b8c3-7c580db60cab','旅夕','周紫芝','宋','宋诗','song-poetry','','[]','秋雲翳長空，微雨餞殘暑。',120,'全唐诗/poet.song.87000.json','["秋雲翳長空，微雨餞殘暑。", "新凉入郊墟，中田熟禾黍。", "秋蟲自知時，入我床下語。", "西風幾何時，秋意遽如許。", "曉色催鳴鷄，孤砧急寒杵。", "遊子未得歸，留滯在江浦。", "生理思田園，饑寒念兒女。", "持此兩鬢霜，世路復焉取。", "起視夜何其，江月方欲吐。", "便當隨孤鴻，雲霄肅雙羽。"]'),
('331711f5-0f79-46db-af70-42076b16f0d1','次韻章季常見予所賦彦恢家七馬四石二詩','周紫芝','宋','宋诗','song-poetry','','[]','灞陵老將身未侯，連城價重誰當酬。',176,'全唐诗/poet.song.87000.json','["灞陵老將身未侯，連城價重誰當酬。", "龍眠三歲亦何有，滿載緗囊歸汗牛。", "蒼珉照眼裂躉尾，尺素抹電飛驊騮。", "春風吹晴作妍暖，棊窗剝啄驚紋楸。", "慇懃喚客出奇玩，一笑終日君家留。", "此郎胸中有奇策，未能竟借前箸籌。", "波瀾收歛入詩律，報章還得明珠投。", "九重真龍想天驥，入木八法餘銀鈎。", "只今尤物不到手，空花老日生雙眸。", "章侯嘆息恨未見，但聽寒雀空嘲啁。", "平生欸乃不成曲，無聲可和綿駒謳。"]'),
('12ef667e-769a-4853-bc31-efba4c6fd44b','次韻季常疊前作見寄','周紫芝','宋','宋诗','song-poetry','','[]','人生富貴如五侯，祿豐位大功不酬。',176,'全唐诗/poet.song.87000.json','["人生富貴如五侯，祿豐位大功不酬。", "朱輪華屋令人羞，一蓑不如歸飯牛。", "自駕款叚馬少遊，勝驟玉腕尚書騮。", "少年蹭蹬在丘壑，晚歲風雨悲梧楸。", "江邊短艇苦喚我，此心勇往誰能留。", "幽期正怨齒髪悞，事定不須龜筴籌。", "言雖太漫君莫笑，與語俗人真暗投。", "香秔炊熟碧鱸美，横江已辦秋風鈎。", "胸中它日幾雲夢，四海不勞圍寸眸。", "肯聽兒女昵昵語，秋蟲悲笑徒啾啁。", "陽春白雪一落耳，竹枝凄怨慚蠻謳。"]'),
('4b1a031f-8237-4a98-bede-c5627f0ac591','次韻馮遠猷觀水','周紫芝','宋','宋诗','song-poetry','','[]','带雨山雲晚尚繁，黄流先已漲江干。',64,'全唐诗/poet.song.87000.json','["带雨山雲晚尚繁，黄流先已漲江干。", "海邊鷗鳥恐不下，濠上遊魚誰肯觀。", "錦里十家俱半壁，龍門八節定無灘。", "早知四載歸神禹，疏鑿誰能泄浩漫。"]'),
('11a07dec-a931-4455-aaa4-50e2cf19237f','次韻子雍同達書記遊安林','周紫芝','宋','宋诗','song-poetry','','[]','江湖流落一烏巾，同障西風滿扇塵。',64,'全唐诗/poet.song.87000.json','["江湖流落一烏巾，同障西風滿扇塵。", "試爲支郎吐幽句，了知長吉是前身。", "欲寛江上三年夢，更碾禪房一掬春。", "不爲相逢苦相挽，行吟應在楚江濱。"]'),
('78fb8e77-2c5c-4820-bc1c-d2a15db3ba63','遠猷家高麗松扇','周紫芝','宋','宋诗','song-poetry','','[]','三韓使者身堂堂，手持漢節歸明光。',64,'全唐诗/poet.song.87000.json','["三韓使者身堂堂，手持漢節歸明光。", "寶刀不受戎王燕，便面空含風露香。", "雙鸞織花大如月，凛凜猶餘歲寒節。", "莫將七寶畫團欒，乞與誰家小桃葉。"]'),
('cc49abad-8a3c-4098-977e-1921287fcb3e','西齋金鳯花開百餘日相繼不絕難其能久而惜羣芳之不留也','周紫芝','宋','宋诗','song-poetry','','[]','昨日晴天花滿樹，今日風前已飛絮。',128,'全唐诗/poet.song.87000.json','["昨日晴天花滿樹，今日風前已飛絮。", "閑花可是天與紅，着意東風吹不去。", "偶然乘此花樹空，遂擥春暉學飛翥。", "人間此鳥久不出，擬欲高翔入鵷鷺。", "凌傲風光不自羞，狼藉空庭復誰覷。", "自應斂衽避芳塵，一笑非關迫遲暮。", "可憐開謝百日中，浪遣花神費調護。", "嶺梅何事挽不留，零落風枝怨寒沍。"]'),
('d7214d3f-08a9-45ad-957a-ce3cd52f963f','贈别木南稀','周紫芝','宋','宋诗','song-poetry','','[]','月下吹簫王子晉，醉中騎馬賀知章。',64,'全唐诗/poet.song.87000.json','["月下吹簫王子晉，醉中騎馬賀知章。", "無家只賣文爲活，有酒聊憑醉作鄉。", "夜雨對床驚客枕，秋風無淚把離觴。", "閬州此去如天上，說着城南只斷膓。"]'),
('bfeacc54-5a8d-45e7-b44b-1e24ae37ca25','徐使君新作採菊亭','周紫芝','宋','宋诗','song-poetry','','[]','使君占吏師，老手便治劇。',120,'全唐诗/poet.song.87000.json','["使君占吏師，老手便治劇。", "論功飲無何，課最上殊勣。", "人言神爵中，有此二千石。", "擁麾幾何時，千里靜森戟。", "遂移佳菊苗，步着東籬屐。", "南山忽當眼，淨几分晚碧。", "黄花行欲開，吹帽盡佳客。", "豐年公事少，閑日頗自適。", "便恐趣公歸，翺翔步丹極。", "曉枕夢催班，朦朧想山色。"]'),
('e9ed62fe-e6ce-4467-910d-2c6006660572','陪徐使君登秋浦樓','周紫芝','宋','宋诗','song-poetry','','[]','白髪衰顔已倦遊，倚樓端爲使君留。',64,'全唐诗/poet.song.87000.json','["白髪衰顔已倦遊，倚樓端爲使君留。", "天連遠嶠雲埋樹，波撼孤城水繞樓。", "有客自傷愁外眼，何人解寫雨中秋。", "世間無此登臨勝，休把城南說閬州。"]'),
('59bc1159-33b9-4014-b564-6b8f83ac7c35','二十三日雨霽再陪徐使君登秋浦樓','周紫芝','宋','宋诗','song-poetry','','[]','細雨愁雲特地晴，重來水秀復山明。',64,'全唐诗/poet.song.87000.json','["細雨愁雲特地晴，重來水秀復山明。", "江風吹面滄波動，嵐氣侵衣翠潤生。", "南浦落帆催畫角，麗譙殘照滿雙旌。", "未知九日齊山會，樽酒何人與共傾。"]'),
('dbe4f1db-91ba-4fdb-a677-adb91b32aacb','睡起題西齋壁','周紫芝','宋','宋诗','song-poetry','','[]','熟睡閑欹一幅紗，夢殘庭樹落疏花。',32,'全唐诗/poet.song.87000.json','["熟睡閑欹一幅紗，夢殘庭樹落疏花。", "屋頭正喜鳩喚婦，牆下忽聞蜂打衙。"]'),
('daa55f29-b2bc-418b-9e5a-80eb3fe2778a','題劉生畫王子猷嚴子陵二圖  其一','周紫芝','宋','宋诗','song-poetry','','[]','人生不相知，相視粤與秦。',48,'全唐诗/poet.song.87000.json','["人生不相知，相視粤與秦。", "臭味倘復同，萬里心相親。", "何必兒女曹，爾汝相怨恩。", "浩歌反歸航，詎識此意申。"]'),
('54f1478b-5d05-499f-834e-4d0e8ed01783','題劉生畫王子猷嚴子陵二圖  其二','周紫芝','宋','宋诗','song-poetry','','[]','四皓挽復來，子陵呼不起。',48,'全唐诗/poet.song.87000.json','["四皓挽復來，子陵呼不起。", "天下復歸心，兩京同一軌。", "義重勢乃輕，理自固應爾。", "賣菜苦求益，可笑真俗子。"]'),
('109e5d42-37a2-4ab9-af7e-3a168f2aaa39','登杜牧之翠微亭故基','周紫芝','宋','宋诗','song-poetry','','[]','秋草無情上舞臺，清江猶抱故山回。',32,'全唐诗/poet.song.87000.json','["秋草無情上舞臺，清江猶抱故山回。", "紫微郎爲誰攜酒，斜日西風菊自開。"]'),
('a44b805f-76a2-41b3-a04e-abc49f47159a','中秋大晴採菊亭對月','周紫芝','宋','宋诗','song-poetry','','[]','風與秋容一様清，雲隨風盡十分晴。',64,'全唐诗/poet.song.87000.json','["風與秋容一様清，雲隨風盡十分晴。", "江從採菊亭前過，月到雙梧頂上明。", "塞草又黄人亦老，霜鬚渾白酒還傾。", "不應造物知愁極，故着玉蟾娛老情。"]'),
('25d71ebb-0061-42c6-a1f2-a770c560c863','秋蝗歎','周紫芝','宋','宋诗','song-poetry','','[]','驅車入秋原，懞懞盡禾黍。',180,'全唐诗/poet.song.87000.json','["驅車入秋原，懞懞盡禾黍。", "田父刈且歌，笑言雜兒女。", "路傍騎馬翁，下與田父語。", "問言田家勞，云何樂如許。", "父老仰天歎，懇款話心膂。", "今年遭歲凶，夏旱連秋暑。", "誰知勤餉婦，社甕蒭綠醑。", "君看西來蝗，落地輒盖土。", "入境不入田，食草不食秬。", "老農亦何幸，此樂詎天與。", "爲言相君賢，爲惠寔在汝。", "羣兇滿江淮，殺氣自消阻。", "微蟲初何知，仁者亦復與。", "知公意在民，有穀寧忍咀。", "勸爾但自歡，蝗來不須禦。"]'),
('8a94540c-bdd3-44b2-8e31-a94c367671d4','謁昭明祠','周紫芝','宋','宋诗','song-poetry','','[]','歷年有攸歸，脩短良亦異。',120,'全唐诗/poet.song.87000.json','["歷年有攸歸，脩短良亦異。", "天乎不祚梁，斯人乃即世。", "於皇元良資，盛德真豈弟。", "高文貫百家，妙學窮六藝。", "悠悠悲徂年，凛凜尚生氣。", "偉哉千載人，享此百世祀。", "金朱煥靈宮，奔走恭祀事。", "遐瞻儼森寒，神雨倏復至。", "傴僂奠椒漿，悲風肅蘭佩。", "想像折芳馨，茲焉獨長喟。"]'),
('f45c8509-9e6f-437f-9c37-6fe79c8586e1','次韻元傑聽谿亭見寄','周紫芝','宋','宋诗','song-poetry','','[]','貧病相牽各異鄉，心隨南雁與翺翔。',64,'全唐诗/poet.song.87000.json','["貧病相牽各異鄉，心隨南雁與翺翔。", "感君三絕出妙手，慰我九回縈别腸。", "山色爲人分淺黛，泉聲何事碎鳴璫。", "千巖萬壑山陰路，誰與臨流共一觴。"]'),
('db615612-fe0f-4458-bd8b-8cb1029a8254','清樾晚雨效韓偓三絕  其一','周紫芝','宋','宋诗','song-poetry','','[]','池上風荷香撲衣，紅粧鏡裏雨如絲。',32,'全唐诗/poet.song.87000.json','["池上風荷香撲衣，紅粧鏡裏雨如絲。", "試呼小艇尋烟去，便是苕溪五月時。"]'),
('c88d67cd-1204-465b-bfed-60556f21757a','清樾晚雨效韓偓三絕  其二','周紫芝','宋','宋诗','song-poetry','','[]','白鷺一雙飛暮靄，亂鴉無數立官樓。',32,'全唐诗/poet.song.87000.json','["白鷺一雙飛暮靄，亂鴉無數立官樓。", "角聲吹盡欄猶倚，雨落黄昏人白頭。"]'),
('fa0753be-4c1c-4bb9-b9c4-c3ed2a07303b','清樾晚雨效韓偓三絕  其三','周紫芝','宋','宋诗','song-poetry','','[]','黄昏簾幙人誰卷，暮雨闌干客自憑。',32,'全唐诗/poet.song.87000.json','["黄昏簾幙人誰卷，暮雨闌干客自憑。", "獨自不知多少恨，一池荷葉碎秋聲。"]'),
('ff51e0c2-4d39-4942-9ffc-6e7ff88cbda1','齊山有巖穴宛轉山間秀色可喜號小九華','周紫芝','宋','宋诗','song-poetry','','[]','衰容迫遲暮，驅車厭行役。',156,'全唐诗/poet.song.87000.json','["衰容迫遲暮，驅車厭行役。", "路逢玉孱顔，庻用慰愁寂。", "誰知九鳯羣，夐與秋水隔。", "落日自凄迷，轉盼失虗碧。", "幸茲登臨間，會遇晚乃獲。", "玲瓏八九峰，模寫在尋尺。", "欎雲開層巔，飛瀑掛蒼壁。", "凜然削寒玉，秀色粲可摘。", "緬懷融結初，岌嶪自開闢。", "懸知孤客恨，爲了愛山癖。", "聊將小巖巒，入我尋山屐。", "何時解塵鞿，卜築在泉石。", "遂當挹諸峰，羅列歸几席。"]'),
('60c95245-e49e-4540-9100-21592fd4b85a','齊山依小巖作觀音閣','周紫芝','宋','宋诗','song-poetry','','[]','亂山空洞自成龕，十里秋風響檜杉。',32,'全唐诗/poet.song.87000.json','["亂山空洞自成龕，十里秋風響檜杉。", "我亦來脩香火供，便疑身在普陁巖。"]'),
('4ed82db9-2757-445f-91b8-e3871ab1e5b5','池口觀樓船','周紫芝','宋','宋诗','song-poetry','','[]','湘水妖氛靜，樓船盡日横。',48,'全唐诗/poet.song.87000.json','["湘水妖氛靜，樓船盡日横。", "風濤心自恐，舟楫眼初驚。", "伏莽膏金鉞，將軍駕木城。", "太平無此物，指日望銷兵。"]'),
('d37df208-6931-4161-a36b-ae325324b306','飲酒三首  其一','周紫芝','宋','宋诗','song-poetry','','[]','高皇掃強秦，縱横成妙略。',108,'全唐诗/poet.song.87000.json','["高皇掃強秦，縱横成妙略。", "三傑豈不雄，曾不出籠絡。", "曹參晚爲相，痛飲事杯酌。", "當知清淨化，寓意在酬酢。", "魏武獨何爲，屢下禁酒約。", "兵戈纒九州，猜忌恣暴虐。", "堂堂孔北海，醉語雜諧謔。", "斯人猶殺之，四海何由廓。", "古來成敗事，紛紛真一噱。"]'),
('3ad981ca-f1c9-428e-bee7-d92d367df7ba','飲酒三首  其二','周紫芝','宋','宋诗','song-poetry','','[]','昔我在田畝，薄言事耘薅。',120,'全唐诗/poet.song.87000.json','["昔我在田畝，薄言事耘薅。", "種秔亦種秫，可食兼可醪。", "清香滿寒甕，夜滴喧春槽。", "洗我玉花甆，酌此鵝黄膏。", "閱歲更閹茂，下田但藜蒿。", "里胥厭追索，縣籍書逋逃。", "邇來兵火急，斗粟千錢高。", "不飲動逾月，憔悴成楚騷。", "丈夫命運薄，困阨例所遭。", "究竟無如何，隨緣且陶陶。"]'),
('4abc980f-8b48-44f9-9c6c-92f2654a1791','飲酒三首  其三','周紫芝','宋','宋诗','song-poetry','','[]','濁醪有何好，所貴資清歡。',96,'全唐诗/poet.song.87000.json','["濁醪有何好，所貴資清歡。", "如何畢阮輩，頭没杯案間。", "我飲但涓滴，而作飲酒篇。", "兒曹見之笑，謂我狂且顛。", "政應坐自失，說夢痴人前。", "一酌憂已亡，再酌當陶然。", "此意但自得，此理詎可言。", "萬古一淵明，何由與之論。"]'),
('71bda296-360b-40f7-a9b5-856ea4b824d1','秋晚念歸','周紫芝','宋','宋诗','song-poetry','','[]','風寒黄葉未全落，露重流螢巳不飛。',32,'全唐诗/poet.song.87000.json','["風寒黄葉未全落，露重流螢巳不飛。", "胡馬又肥秋欲老，旅巢無定客思歸。"]'),
('72c7696f-b3c9-46f4-a9c8-b403e99da5a6','親征詔下朝野歡呼六首  其一','周紫芝','宋','宋诗','song-poetry','','[]','茫茫禹迹混殊方，誰遣中華識犬羊。',32,'全唐诗/poet.song.87000.json','["茫茫禹迹混殊方，誰遣中華識犬羊。", "今日澶淵尋舊役，會看一矢殪戎王。"]'),
('ee8d982f-c444-4470-b2fa-a611b7f943c0','親征詔下朝野歡呼六首  其二','周紫芝','宋','宋诗','song-poetry','','[]','天戈未指敵先摧，掩耳誰能及迅雷。',32,'全唐诗/poet.song.87000.json','["天戈未指敵先摧，掩耳誰能及迅雷。", "便遣風師清輦路，奉迎北狩兩宮回。"]'),
('54573cd6-cd7a-4a4b-b146-04fbde883438','親征詔下朝野歡呼六首  其三','周紫芝','宋','宋诗','song-poetry','','[]','誰信妖兇膽自驚，君王親駕六騑行。',32,'全唐诗/poet.song.87000.json','["誰信妖兇膽自驚，君王親駕六騑行。", "江邊紅日三更出，怪得欃槍夜不明。"]'),
('da1e29d5-083b-414a-a7ab-c5e62b5a08ed','親征詔下朝野歡呼六首  其四','周紫芝','宋','宋诗','song-poetry','','[]','漢業當於馬上成，謾勞諸將久經營。',32,'全唐诗/poet.song.87000.json','["漢業當於馬上成，謾勞諸將久經營。", "廟堂早扈南陽駕，已爲蒼生洗甲兵。"]'),
('c17ba800-1550-4026-a698-dbba00618e8e','親征詔下朝野歡呼六首  其五','周紫芝','宋','宋诗','song-poetry','','[]','雉扇遙聞擁翠鑾，遠方耕鑿尚偷安。',32,'全唐诗/poet.song.87000.json','["雉扇遙聞擁翠鑾，遠方耕鑿尚偷安。", "誰知黄鉞臨戎地，江上秋風玉帳寒。"]'),
('3f09363c-24ce-41f7-9ed2-b140463774e1','親征詔下朝野歡呼六首  其六','周紫芝','宋','宋诗','song-poetry','','[]','請看介子請長纓，白髪書生百不能。',32,'全唐诗/poet.song.87000.json','["請看介子請長纓，白髪書生百不能。", "誰掃浯溪題歲月，漫郎端欲頌中興。"]'),
('294042ee-7c6a-47a1-9cc7-f20e6481cdc1','青陽道中望九華諸峰作','周紫芝','宋','宋诗','song-poetry','','[]','平生愛山意，瞑目想奇崛。',120,'全唐诗/poet.song.87000.json','["平生愛山意，瞑目想奇崛。", "東南號多山，萬嶺空峍屼。", "不知罏錘工，鑄此一尤物。", "峰巒與天近，紫翠爭日出。", "何年飛三山，此事亦恍惚。", "要欲移嵌巖，下作仙聖窟。", "我願從之遊，飛昇蛻塵骨。", "山行尚悠悠，客意殊忽忽。", "弱水不可渡，瘦馬聊自兀。", "落日回寸眸，飛鳥但滅没。"]'),
('2c9c93b7-33bb-4918-8f4d-7a4dd7963c1a','次韻吕仁父教授題余秋浦詩卷  其一','周紫芝','宋','宋诗','song-poetry','','[]','病客還隨倦鳥翰，霜風猶带客衣寒。',32,'全唐诗/poet.song.87000.json','["病客還隨倦鳥翰，霜風猶带客衣寒。", "誰持馬上歸來句，換得天孫雲錦端。"]'),
('b1adc086-ff05-4007-a0ed-97399a3a3749','次韻吕仁父教授題余秋浦詩卷  其二','周紫芝','宋','宋诗','song-poetry','','[]','汗漫誰從食蛤遊，歲窮真似賈胡留。',32,'全唐诗/poet.song.87000.json','["汗漫誰從食蛤遊，歲窮真似賈胡留。", "恨無摩詰丹青手，貌得瀟湘兩岸秋。"]'),
('b075d2c3-712b-4f06-9595-edd34662e9f9','次韻吕仁父教授題余秋浦詩卷  其三','周紫芝','宋','宋诗','song-poetry','','["\u957f\u6c5f"]','試從秋浦望長江，猶有遺蹤在渺茫。',32,'全唐诗/poet.song.87000.json','["試從秋浦望長江，猶有遺蹤在渺茫。", "滿地黄花秋日晚，傷心不見紫微郎。"]'),
('588c126c-7400-43f7-933e-fb53d7d8e702','燒芋','周紫芝','宋','宋诗','song-poetry','','[]','幽人日晏方索米，朱門醉頭扶未起。',144,'全唐诗/poet.song.87000.json','["幽人日晏方索米，朱門醉頭扶未起。", "人微何敢望一囷，鮒死知誰濡斗水。", "糞火撥灰聊效顰，玉糝誇羮未須爾。", "紫團包玉不洗泥，火候初匀香透紙。", "從來真味貴天全，大羮不致名太始。", "饞涎爲止翁欲顛，饑膓不鳴兒更喜。", "口腹爲災莫漫誇，五畝應須急料理。", "但托長鑱仍短鑱，誰能畏首復畏尾。", "未知春雨荷鋤歸，空羡吾家燒芋美。"]'),
('af1651f3-6641-4d1c-9125-9b4c78b3abe5','十二月二十九日雪中煮茗','周紫芝','宋','宋诗','song-poetry','','[]','旋掃飛花煮玉塵，一杯聊餉作詩人。',32,'全唐诗/poet.song.87000.json','["旋掃飛花煮玉塵，一杯聊餉作詩人。", "未知折脚鐺中雪，何似浮蛆瓮裏春。"]'),
('4eeec397-1132-491b-9fe5-f9b341d2d575','小兒漬蜜雪見餉用前韻','周紫芝','宋','宋诗','song-poetry','','[]','黄蜜香和糝徑塵，紫蘭兒餉白頭人。',32,'全唐诗/poet.song.87000.json','["黄蜜香和糝徑塵，紫蘭兒餉白頭人。", "誰知茅屋三冬雪，中有蜂房一掬春。"]'),
('6c348b9c-1250-4643-bf46-dc316f0cc994','雪後小霽擷菊苗薦茗','周紫芝','宋','宋诗','song-poetry','','[]','短窗烘日見深明，牆角泥乾路欲成。',64,'全唐诗/poet.song.87000.json','["短窗烘日見深明，牆角泥乾路欲成。", "槐葉索淘春漸近，菊苗薦茗雪初晴。", "寒叢且對天隨子，大白誰浮阮步兵。", "願借芳香明老眼，要翻書葉送餘生。"]'),
('0a903d80-35de-418d-9280-e638a219f1d1','雪後北牆','周紫芝','宋','宋诗','song-poetry','','[]','攜兒聊作北牆行，泥雪初乾杖履輕。',64,'全唐诗/poet.song.87000.json','["攜兒聊作北牆行，泥雪初乾杖履輕。", "病後茶槍渾不要，眼前蔬甲喜全生。", "鳥聲漸軟春應近，梅萼催香日自晴。", "忽憶讀殘書未了，却須歸趁小窗明。"]'),
('cc8aa184-a72e-44bc-b5a1-681157174848','冬至前七日極暖','周紫芝','宋','宋诗','song-poetry','','[]','風日炎洲似，暄妍趣歲華。',48,'全唐诗/poet.song.87000.json','["風日炎洲似，暄妍趣歲華。", "三冬開蟄户，十月見梅花。", "翠管書雲近，黄羊賽臘賖。", "却愁遲暮雪，隨意作横斜。"]'),
('2bc58386-323c-4110-8f2a-b92615c995d6','冬至日晚晴可喜','周紫芝','宋','宋诗','song-poetry','','[]','雲物纔書雪未稀，樓臺忽復带斜暉。',64,'全唐诗/poet.song.87000.json','["雲物纔書雪未稀，樓臺忽復带斜暉。", "日從銀色界中出，鳥向瑤池影外飛。", "可忍便教烟欲瞑，會須更待月同歸。", "羣山即是三山頂，八極聊將寸目圍。"]'),
('1279d6ea-24b4-450b-b6fc-2f8206ce7837','送黄子才還姑蘇用陶淵明王撫軍座送客詩韻','周紫芝','宋','宋诗','song-poetry','','[]','歲事忽已晏，行邁良亦腓。',96,'全唐诗/poet.song.87000.json','["歲事忽已晏，行邁良亦腓。", "誰知出岫雲，意作無心歸。", "嗟我寡徒旅，隻影夐無依。", "况乃遠離别，與子千里違。", "中原念亂久，意緒轉愁悲。", "迢迢兩溪水，淡淡浮斜暉。", "豈無雙頳尾，尺素不可遲。", "慎勿不相念，棄置忽如遺。"]'),
('4da8a25d-1a20-42d3-8c28-dfddf946c1b3','奉寄黄端冕用送子才韻','周紫芝','宋','宋诗','song-poetry','','[]','至言如秋霜，既肅百草腓。',96,'全唐诗/poet.song.87000.json','["至言如秋霜，既肅百草腓。", "諂諛忘中正，千古良同歸。", "倘無骾槩士，舉世將疇依。", "袞職或可補，鼎鑊安得違。", "所以長沙傅，慟哭爲時悲。", "讜語數十上，子今有餘暉。", "我欲從之遊，周道苦倭遲。", "倭遲不足惜，子言願無遺。"]'),
('f24f0a47-4cf2-4fbb-a838-93ae76abf9c4','陳公園梅極盛頃嘗與客遊觀花下兵盗十年今復過之追念存殁愴然有感三絕  其一','周紫芝','宋','宋诗','song-poetry','','[]','忽憶梅花空斷膓，十年依約夢中香。',32,'全唐诗/poet.song.87000.json','["忽憶梅花空斷膓，十年依約夢中香。", "如今濯錦江邊路，不見栽花黄四娘。"]'),
('900a4dc9-fd5d-4385-8f0b-77e797c74a4a','陳公園梅極盛頃嘗與客遊觀花下兵盗十年今復過之追念存殁愴然有感三絕  其二','周紫芝','宋','宋诗','song-poetry','','[]','玉雪驚看亂後枝，梅花雖在鬢成絲。',32,'全唐诗/poet.song.87000.json','["玉雪驚看亂後枝，梅花雖在鬢成絲。", "當時一醉還如夢，今日嫣然復爲誰。"]'),
('8eaea358-db93-4036-93b4-2448c87a02d8','陳公園梅極盛頃嘗與客遊觀花下兵盗十年今復過之追念存殁愴然有感三絕  其三','周紫芝','宋','宋诗','song-poetry','','[]','溪上長眠雙玉瓶，只今誰在復誰傾。',32,'全唐诗/poet.song.87000.json','["溪上長眠雙玉瓶，只今誰在復誰傾。", "花知何事遽如許，人亦看花太瘦生。"]'),
('45d394ae-8319-43c7-9adb-58cd858c655e','紙閣初成','周紫芝','宋','宋诗','song-poetry','','[]','小閣春温借隙光，風簾不掛最宜香。',32,'全唐诗/poet.song.87000.json','["小閣春温借隙光，風簾不掛最宜香。", "窗前睡鴨吹雲縷，聊與幽人度日長。"]'),
('241dc7e2-2df0-4475-b872-f6cfbce3a30c','除夜雜興三首  其一','周紫芝','宋','宋诗','song-poetry','','[]','華髪日就槁，萎萎如秋草。',96,'全唐诗/poet.song.87000.json','["華髪日就槁，萎萎如秋草。", "秋草剪復生，髪禿不再好。", "雅意憐兒童，軟語媚翁媪。", "鑷白挽流光，持盃錫難老。", "我老不足惜，汝生念不早。", "兵戈常在眼，流離猶滿道。", "且當篘殘缸，瓶空莫辭倒。", "醒視夜何其，東行日杲杲。"]'),
('721f96cb-f004-4889-be1f-1695050b170d','除夜雜興三首  其二','周紫芝','宋','宋诗','song-poetry','','[]','憶昔元會日，漢家全盛時。',84,'全唐诗/poet.song.87000.json','["憶昔元會日，漢家全盛時。", "奉隨觀國賓，得見漢官儀。", "中郎授國璽，屬國朝遠夷。", "萬邦瞻咫尺，龍姿喜元知。", "皇天厭久治，夜見蚩尤旗。", "微生脫九死，飲此除夜巵。", "河陽狩未還，螻蟻何足悲。"]'),
('7db93e3c-91dc-444d-a956-bdd1c6a2e809','除夜雜興三首  其三','周紫芝','宋','宋诗','song-poetry','','[]','昔年避羣盗，夜竄蒼山阿。',84,'全唐诗/poet.song.87000.json','["昔年避羣盗，夜竄蒼山阿。", "偷生歲忽杪，妻孥共婆娑。", "村醪薄如水，我顔安得酡。", "夜半黑風起，撾門驚荷戈。", "今夕復何夕，奈此歡樂何。", "人生不自保，聚散如羣儺。", "更當增蘭膏，照此盃中波。"]'),
('92d2d6b3-8242-49b5-86a3-afe3f8006644','立春日雨中三絕  其一','周紫芝','宋','宋诗','song-poetry','','[]','滿天雲物正垂垂，何處青春欲到時。',32,'全唐诗/poet.song.87000.json','["滿天雲物正垂垂，何處青春欲到時。", "花信未從風裏得，豐年先自雨中知。"]'),
('1b13c891-4cd3-4519-af42-9cbee64ebc61','立春日雨中三絕  其二','周紫芝','宋','宋诗','song-poetry','','[]','先自逢春老倍傷，兩簷疏雨更淋浪。',32,'全唐诗/poet.song.87000.json','["先自逢春老倍傷，兩簷疏雨更淋浪。", "眼前無復新幡勝，只有寒葅照庾郎。"]'),
('e71cda4d-7e4c-41c3-928d-d2a3607d2ffc','立春日雨中三絕  其三','周紫芝','宋','宋诗','song-poetry','','[]','春光先已到誰家，風裏釵頭小燕斜。',32,'全唐诗/poet.song.87000.json','["春光先已到誰家，風裏釵頭小燕斜。", "只有幽人了無事，臥看疏雨濕梅花。"]'),
('a10993fb-5d55-48ff-97f9-dcba42111ef1','張載楊示元道州詩卷羅仲共有詩在卷尾次其韻','周紫芝','宋','宋诗','song-poetry','','[]','吾道嗟牢落，斯文得主盟。',48,'全唐诗/poet.song.87000.json','["吾道嗟牢落，斯文得主盟。", "馬從西極到，鳯入九霄鳴。", "翰墨推前輩，篇章集大成。", "向來侯叔喜，何得有新聲。"]'),
('a4fcc252-c18c-4e60-8255-1c4152934d33','正月二十七日種木瓜五株','周紫芝','宋','宋诗','song-poetry','','[]','三峰真奥區，陸海富佳實。',156,'全唐诗/poet.song.87000.json','["三峰真奥區，陸海富佳實。", "此物冠九州，未數梨與栗。", "園丁力扶持，璀璨成妙質。", "鏤花淹宿露，紅暈生晚日。", "玉顔醉自頳，豐肌滑仍密。", "風味照盤飱，名字愈痺疾。", "衞侯報瓊瑤，盛德豈埋没。", "野人獻根株，春雨助芽蘖。", "何當垂露顆，照眼行突兀。", "疇敢與荔子，飛電爭置驛。", "况復具苞苴，緘封鑽巨室。", "一酌呼吾人，甘酸漬崖蜜。", "人生鮮知味，相餉不可失。"]'),
('9ab41e98-2418-49d0-80de-9274cf50446c','正月二十九日種柳三十五株','周紫芝','宋','宋诗','song-poetry','','[]','故國兵火餘，壤地日窘蹙。',156,'全唐诗/poet.song.87000.json','["故國兵火餘，壤地日窘蹙。", "千里無雞豚，遺禍及草木。", "火攻阨焚巢，雲棲急新卜。", "尺地無寸荄，山腰見茅屋。", "小徑臥修蛇，縈迂繞山麓。", "垂楊剪孫枝，封殖勤養育。", "正須清陰成，門巷森詰曲。", "微風惱春絮，細雨滋淺綠。", "悲涼聽殘蟬，徙倚捫飽腹。", "種德須百年，種木十年足。", "十年吾巳老，光景日夜速。", "吾事倘復濟，亦足快所欲。", "何必羡張緒，風流標簡牘。"]'),
('a8331b52-27f8-4f26-a380-e7c4f83b12b9','憫紅椒樹子作','周紫芝','宋','宋诗','song-poetry','','[]','東籬委榛菅，狼藉紛瑣碎。',132,'全唐诗/poet.song.87000.json','["東籬委榛菅，狼藉紛瑣碎。", "披叢得紅椒，磊落本誰藝。", "蓬窠頗自矜，枝葉相掩翳。", "日月空復明，雨露不霑施。", "結根一失所，埋没苦憔悴。", "移栽俯西軒，吾乃借一臂。", "要令遠條且，密葉敷晚翠。", "秋霜染丹砂，紅寔相點綴。", "馨香發潛德，錯節振淹滯。", "人生良可惜，會遇亦難值。", "生理倘復存，餘恨當棄置。"]'),
('c5f83353-cc8c-423e-87af-c030a86b170b','憫白菊兩枝作','周紫芝','宋','宋诗','song-poetry','','[]','鮮鮮凌霜菊，艶艶粲雲綺。',192,'全唐诗/poet.song.87000.json','["鮮鮮凌霜菊，艶艶粲雲綺。", "團欒雙毬枝，婆娑照窗几。", "頗訝銀臺俗，深憎澤蘭紫。", "瑣碎懸萬鈴，金錢坐堪擬。", "彼美誰家姝，軒然兩仙子。", "一登君子堂，衙官列桃李。", "殷勤極調護，出斛埋地底。", "結草障飛霜，分渠泄流水。", "那知病根株，咬齧遭蠧蟻。", "人生意外憂，多智亦謾爾。", "朝來踏雪泥，呼奴亟移徙。", "東株真已萎，西株有生理。", "萎者不自持，生者能有幾。", "君看金谷園，花木亘百里。", "忽然奇禍作，過眼盡荆杞。", "悠悠可奈何，歸步一笑喜。"]'),
('8caf448d-6aa9-444f-9c7d-0fd5fb522814','山居聞蛙','周紫芝','宋','宋诗','song-poetry','','[]','憶昔東南居，結屋古城背。',156,'全唐诗/poet.song.87000.json','["憶昔東南居，結屋古城背。", "野色带危牆，花陰弄寒砌。", "月彩淡微雲，春風入衣袂。", "萬籟悄無聲，獨立與誰對。", "殷勤古壕蛙，爲我作鼓吹。", "號昏初兩三，閙雨忽鼎沸。", "懸知世俗憎，自可幽人意。", "胡行如鬼速，十年滿天地。", "弊廬飛劫灰，生涯轉零替。", "邇來三間茅，風雨僅可蔽。", "青春不改色，人事有興廢。", "一聞羣蛙鳴，懷舊如夢寐。", "撫事爲嘆嗟，傷心極流涕。"]'),
('c423c1c5-e28c-4565-9598-b20b64e2e54f','二月四日大火吾廬獨免','周紫芝','宋','宋诗','song-poetry','','[]','顛風盡日惡，頑雲吹不開。',176,'全唐诗/poet.song.87000.json','["顛風盡日惡，頑雲吹不開。", "行人對面不相識，千嶺萬嶺沉風霾。", "不知誰縱一炬火，坐遣萬屋成飛灰。", "我聞人火曰火，天火曰災，茫然不復知從來。", "但見通衢半瓦礫，男呻女泣聲酸哀。", "避胡十年常作客，幾見連甍變荆棘。", "此生憂火復憂兵，一事不成頭雪白。", "學禪靈運本忘家，好賦子雲終有宅。", "向來窮巷冷如冰，今作權門手堪炙。", "驚魂可招烟欲消，茅茨猶在書脫厄。", "心知造物可憐生，留與雲窗看山色。"]'),
('5818c598-ad4a-4f65-b6d6-aa13b2a918e4','二月五日再火吾廬復免','周紫芝','宋','宋诗','song-poetry','','[]','昨日北風如箭疾，城南一燎三百室。',176,'全唐诗/poet.song.87000.json','["昨日北風如箭疾，城南一燎三百室。", "城西片瓦不復存，今日風高火仍急。", "池魚已作沸鼎焦，槁木那容飛鳥集。", "糗糧不峙恐民流，樓櫓俱空憂盗入。", "傳聞此火頗異常，宋衞陳鄭實同日。", "城中有屋無二三，道路横尸十六七。", "三州飛報急上聞，詔書亟下隆寛恩。", "既令折劵已逋責，復振倉廩蘇窮民。", "東南無事官失職，火政不脩户無耤。", "坐令惡少恣焚燒，更以深憂貽玉食。", "小人何幸獨晏然，飽食懷慚面仍赤。"]'),
('dfac932a-81a0-420f-8b28-8bd24bd5fdff','羣不逞乘時縱火以病良民有捕於官者輒送遣之或厚與之金使之出境二月二十八日敝廬爲惡少見焚雖復僅免而官不爲直不能言安三月六日徙居寓舍','周紫芝','宋','宋诗','song-poetry','','[]','平生有窟如屋鼠，亂後飄零無定所。',224,'全唐诗/poet.song.87000.json','["平生有窟如屋鼠，亂後飄零無定所。", "身隨海燕作去來，心似賓鴻識寒暑。", "異時無地着妻孥，晚得三間蔽風雨。", "邇來憂賊夜不眠，惡少屢來窺屋山。", "不知今夕定何夕，忽置束緼茅茨閑。", "念非曲突可得免，何由外户常不關。", "公庭得賊盡縱遣，上訴官曹多怒顔。", "青山元與我有約，俗駕苦遭神勒還。", "山光無情鳥不語，主人當去心依然。", "人生泛泛水中鳧，身如逆旅家蘧廬。", "東西南北皆可爾，夢幻泡影真須臾。", "只今兵猶滿天地，黔黎誰復能安居。", "鳴泉繞屋花滿眼，有窗况足翻吾書。", "暮年卜築倘未可，且借一椽聊自娛。"]'),
('06ef91de-db91-4d72-a54c-18bffef1ed2a','酴醿盛開伯潁許攜酒','周紫芝','宋','宋诗','song-poetry','','[]','洗雨梳風玉作肌，温泉初試太真妃。',64,'全唐诗/poet.song.87000.json','["洗雨梳風玉作肌，温泉初試太真妃。", "莫驚霧帳人方睡，怕作風軒雪又飛。", "未有酒樽酬玉艷，枉教春色到柴扉。", "詩成不爲花遊說，要看山翁倒載歸。"]'),
('c6c56e19-78d3-4b63-b966-6c7b3bbf75f5','上巳日雨中小集','周紫芝','宋','宋诗','song-poetry','','[]','老去傷春頭緒多，花前不醉奈渠何。',64,'全唐诗/poet.song.87000.json','["老去傷春頭緒多，花前不醉奈渠何。", "重來倦客還脩禊，已去蕃兵却渡河。", "薄酒爲人澆磈礧，惡風將雨作么魔。", "世閑何事非陳迹，莫謾相逢說永和。"]'),
('5ef805ba-4b8b-4b0d-8303-b632035a01b0','書淳師房六言三絕  其一','周紫芝','宋','宋诗','song-poetry','','[]','茗椀要看三昧，齋盂來飯伊蒲。',28,'全唐诗/poet.song.87000.json','["茗椀要看三昧，齋盂來飯伊蒲。", "坐對禪房花木，夢成午枕江湖。"]'),
('26fad54e-c4b9-4aba-a9a6-29a1b62f1cca','書淳師房六言三絕  其二','周紫芝','宋','宋诗','song-poetry','','[]','長卿自是倦客，支郎殊復可人。',28,'全唐诗/poet.song.87000.json','["長卿自是倦客，支郎殊復可人。", "懶識閑中味好，老於方外情親。"]');
